public class BaseCamera : NetworkBehaviour
{
	[Header("Settings")]
	public CameraType Type;

	[HideInInspector]
	public Camera UnityCamera;

	[HideInInspector]
	public AudioListener AudioListener;

	[HideInInspector]
	public bool IsEnabled;

	public virtual void Awake()
	{
		UnityCamera = GetComponent<Camera>();
		AudioListener = GetComponent<AudioListener>();
		UnityCamera.enabled = IsEnabled;
		AudioListener.enabled = IsEnabled;
	}

	public virtual void Start()
	{
		EventManager.TriggerEvent("Event_OnBaseCameraStarted", new Dictionary<string, object> { { "baseCamera", this } });
	}

	public override void OnDestroy()
	{
		Disable();
		EventManager.TriggerEvent("Event_OnBaseCameraDestroyed", new Dictionary<string, object> { { "baseCamera", this } });
		base.OnDestroy();
	}

	public virtual void OnTick(float deltaTime)
	{
	}

	public virtual bool Enable()
	{
		if (IsEnabled)
		{
			return false;
		}
		IsEnabled = true;
		UnityCamera.enabled = IsEnabled;
		AudioListener.enabled = IsEnabled;
		EventManager.TriggerEvent("Event_OnBaseCameraEnabled", new Dictionary<string, object> { { "baseCamera", this } });
		return true;
	}

	public virtual bool Disable()
	{
		if (!IsEnabled)
		{
			return false;
		}
		IsEnabled = false;
		UnityCamera.enabled = IsEnabled;
		AudioListener.enabled = IsEnabled;
		EventManager.TriggerEvent("Event_OnBaseCameraDisabled", new Dictionary<string, object> { { "baseCamera", this } });
		return true;
	}

	public virtual void SetFieldOfView(float fieldOfView)
	{
		UnityCamera.fieldOfView = fieldOfView;
	}

	protected override void __initializeVariables()
	{
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "BaseCamera";
	}
}
public class BaseCameraController : MonoBehaviour
{
	private BaseCamera baseCamera;

	public virtual void Awake()
	{
		baseCamera = GetComponent<BaseCamera>();
		SynchronizedObjectManager.OnSynchronizeObjects += OnSynchronizeObjects;
		EventManager.AddEventListener("Event_OnFovChanged", Event_OnFovChanged);
	}

	public virtual void Start()
	{
		baseCamera.SetFieldOfView(SettingsManager.Fov);
	}

	public virtual void OnDestroy()
	{
		SynchronizedObjectManager.OnSynchronizeObjects -= OnSynchronizeObjects;
		EventManager.RemoveEventListener("Event_OnFovChanged", Event_OnFovChanged);
	}

	public virtual void LateUpdate()
	{
		if (NetworkManager.Singleton == null || NetworkManager.Singleton.IsHost || SettingsManager.UseNetworkSmoothing)
		{
			baseCamera.OnTick(Time.deltaTime);
		}
	}

	private void OnSynchronizeObjects(float serverDeltaTime)
	{
		if (!SettingsManager.UseNetworkSmoothing)
		{
			baseCamera.OnTick(serverDeltaTime);
		}
	}

	private void Event_OnFovChanged(Dictionary<string, object> message)
	{
		float fieldOfView = (float)message["value"];
		baseCamera.SetFieldOfView(fieldOfView);
	}
}
public class CollisionRecorder : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float deferTime = 0.1f;

	[HideInInspector]
	public Action<GameObject, float> CollisionDeferred;

	[HideInInspector]
	public Rigidbody Rigidbody;

	private bool recording;

	private Dictionary<GameObject, float> collisionGameObjectForceMap = new Dictionary<GameObject, float>();

	private IEnumerator deferCollisionCoroutine;

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
	}

	private void OnDestroy()
	{
		StopDeferringCollision();
	}

	private void StartDeferringCollision()
	{
		StopDeferringCollision();
		deferCollisionCoroutine = IDeferCollision(deferTime);
		StartCoroutine(deferCollisionCoroutine);
	}

	private void StopDeferringCollision()
	{
		if (deferCollisionCoroutine != null)
		{
			StopCoroutine(deferCollisionCoroutine);
		}
	}

	private IEnumerator IDeferCollision(float duration)
	{
		yield return new WaitForSeconds(duration);
		KeyValuePair<GameObject, float> keyValuePair = collisionGameObjectForceMap.OrderByDescending((KeyValuePair<GameObject, float> x) => x.Value).FirstOrDefault();
		if ((bool)keyValuePair.Key)
		{
			CollisionDeferred?.Invoke(keyValuePair.Key, keyValuePair.Value);
		}
		recording = false;
		collisionGameObjectForceMap.Clear();
	}

	private void OnCollisionEnter(Collision collision)
	{
		if (!recording)
		{
			recording = true;
			StartDeferringCollision();
		}
		float collisionForce = Utils.GetCollisionForce(collision);
		GameObject gameObject = collision.collider.gameObject;
		if ((bool)gameObject)
		{
			if (collisionGameObjectForceMap.ContainsKey(gameObject))
			{
				collisionGameObjectForceMap[gameObject] = Mathf.Max(collisionGameObjectForceMap[gameObject], collisionForce);
			}
			else
			{
				collisionGameObjectForceMap.Add(gameObject, collisionForce);
			}
		}
	}
}
public class CrowdMember : MonoBehaviour
{
	[Header("References")]
	[SerializeField]
	private PlayerMesh playerMesh;

	[SerializeField]
	private Animator animator;

	[HideInInspector]
	public Transform LookTarget;

	private bool animationRequested;

	private double lastUpdateTime;

	private int[] headgearOptions = new int[4] { -1, 537, 538, 539 };

	private int[] teamJerseyOptions = new int[7] { 2048, 2049, 2050, 2051, 2052, 2053, 2054 };

	private int[] spectatorJerseyOptions = new int[5] { 2118, 2119, 2120, 2121, 2122 };

	private int[] mustacheOptions = new int[7] { -1, 1024, 1025, 1026, 1027, 1029, 1030 };

	private int[] beardOptions = new int[6] { -1, 1536, 1537, 1538, 1539, 1540 };

	private const float teamJerseyChance = 0.45f;

	private void Awake()
	{
		animator = GetComponent<Animator>();
		animator.playableGraph.SetTimeUpdateMode(DirectorUpdateMode.Manual);
	}

	public void PlayAnimation(string animationName)
	{
		StopAnimations();
		animator.SetBool(animationName, value: true);
		animationRequested = true;
	}

	public void StopAnimations()
	{
		animator.SetBool("Seated", value: false);
		animator.SetBool("Cheering", value: false);
		animator.SetBool("Standing", value: false);
		animationRequested = true;
	}

	public void UpdateAnimation()
	{
		if ((bool)playerMesh)
		{
			AnimatorStateInfo currentAnimatorStateInfo = animator.GetCurrentAnimatorStateInfo(0);
			bool num = currentAnimatorStateInfo.loop || currentAnimatorStateInfo.normalizedTime < 1f || animator.IsInTransition(0) || animationRequested;
			double num2 = Time.timeAsDouble - lastUpdateTime;
			if (num)
			{
				animator.Update((float)num2);
			}
			else
			{
				playerMesh.LookAt(LookTarget ? LookTarget.position : Vector3.zero, (float)num2, rotateTorso: false);
			}
			if (animationRequested)
			{
				animationRequested = false;
			}
			lastUpdateTime = Time.timeAsDouble;
		}
	}

	public void RandomizeAppearance()
	{
		playerMesh.SetUsername(null);
		playerMesh.SetNumber(null);
		playerMesh.SetLegsPadsActive(isActive: false);
		int headgearID = headgearOptions[UnityEngine.Random.Range(0, headgearOptions.Length)];
		playerMesh.SetHeadgearID(headgearID, PlayerRole.None);
		RandomizeJersey();
		int mustacheID = mustacheOptions[UnityEngine.Random.Range(0, mustacheOptions.Length)];
		playerMesh.SetMustacheID(mustacheID);
		int beardID = beardOptions[UnityEngine.Random.Range(0, beardOptions.Length)];
		playerMesh.SetBeardID(beardID);
	}

	private void RandomizeJersey()
	{
		int jerseyID = spectatorJerseyOptions[UnityEngine.Random.Range(0, spectatorJerseyOptions.Length)];
		playerMesh.PlayerGroin.SetJerseyID(jerseyID, PlayerTeam.None);
		if (UnityEngine.Random.value < 0.45f)
		{
			PlayerTeam team = ((UnityEngine.Random.value < 0.5f) ? PlayerTeam.Blue : PlayerTeam.Red);
			int jerseyID2 = teamJerseyOptions[UnityEngine.Random.Range(0, teamJerseyOptions.Length)];
			playerMesh.PlayerTorso.SetJerseyID(jerseyID2, team);
		}
		else
		{
			int jerseyID3 = spectatorJerseyOptions[UnityEngine.Random.Range(0, spectatorJerseyOptions.Length)];
			playerMesh.PlayerTorso.SetJerseyID(jerseyID3, PlayerTeam.None);
		}
	}
}
