public class EventDependencyTrigger : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("EventDependencyTrigger");

	[Header("Settings")]
	[SerializeField]
	private AYellowpaper.SerializedCollections.SerializedDictionary<string, bool> dependencyEvents = new AYellowpaper.SerializedCollections.SerializedDictionary<string, bool>();

	[SerializeField]
	private string triggerEventName;

	[SerializeField]
	private float timeout = 3f;

	[SerializeField]
	private bool isRepeating = true;

	private Tween timeoutTween;

	private void Start()
	{
		foreach (string key in dependencyEvents.Keys)
		{
			EventManager.AddEventListener(key, OnDependencyEvent);
		}
	}

	private void OnDestroy()
	{
		timeoutTween?.Kill();
		foreach (string key in dependencyEvents.Keys)
		{
			EventManager.RemoveEventListener(key, OnDependencyEvent);
		}
	}

	private void OnDependencyEvent(Dictionary<string, object> message)
	{
		string key = (string)message["eventName"];
		if (!dependencyEvents.ContainsValue(value: true))
		{
			timeoutTween?.Kill();
			timeoutTween = DOVirtual.DelayedCall(timeout, delegate
			{
				Logger.Warning("Event " + triggerEventName + " timed out waiting for dependencies");
				if (isRepeating)
				{
					Reset();
				}
			});
		}
		dependencyEvents[key] = true;
		if (!dependencyEvents.ContainsValue(value: false))
		{
			Logger.Info("All dependencies met, triggering event " + triggerEventName);
			EventManager.TriggerEvent(triggerEventName);
			if (isRepeating)
			{
				Reset();
			}
		}
	}

	private void Reset()
	{
		timeoutTween?.Kill();
		dependencyEvents.Keys.ToList().ForEach(delegate(string key)
		{
			dependencyEvents[key] = false;
		});
	}
}
public class Goal : MonoBehaviour
{
	[Header("Settings")]
	public PlayerTeam Team;

	[Header("References")]
	[SerializeField]
	private Cloth netCloth;

	public Cloth NetCloth => netCloth;

	public void Server_OnPuckEnterGoal(Puck puck)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			EventManager.TriggerEvent("Event_Server_OnPuckEnterGoal", new Dictionary<string, object>
			{
				{ "puck", puck },
				{ "team", Team }
			});
		}
	}

	public void Client_AddNetClothSphereCollider(SphereCollider sphereCollider)
	{
		if (NetworkManager.Singleton.IsClient && (bool)sphereCollider)
		{
			List<ClothSphereColliderPair> list = netCloth.sphereColliders.ToList();
			list.Add(new ClothSphereColliderPair(sphereCollider));
			netCloth.sphereColliders = list.ToArray();
		}
	}

	public void Client_RemoveNetClothSphereCollider(SphereCollider sphereCollider)
	{
		if (NetworkManager.Singleton.IsClient && (bool)sphereCollider)
		{
			List<ClothSphereColliderPair> list = netCloth.sphereColliders.ToList();
			list.RemoveAll((ClothSphereColliderPair pair) => pair.first == sphereCollider);
			netCloth.sphereColliders = list.ToArray();
		}
	}
}
