	[SerializeField]
	private MeshRenderer meshRenderer;

	[SerializeField]
	private string texturePropertyName = "_BaseMap";

	[SerializeField]
	private int materialIndex;

	private MaterialPropertyBlock propertyBlock;

	private void Awake()
	{
		if (!meshRenderer)
		{
			meshRenderer = GetComponent<MeshRenderer>();
		}
