	private float swingStartTime = float.MinValue;

	private float nextSwingTime;

	public Player Player { get; private set; }

	private void Awake()
	{
		Player = GetComponent<Player>();
		seed = (float)(Player.OwnerClientId % 100) * 0.63f;
		brain = BotManager.CreateBrain(BotManager.DefaultBehavior);
	}

	public void SetBrain(BotBrain newBrain)
	{
		brain = newBrain;
	}

	private void FixedUpdate()
	{
		if (!(NetworkManager.Singleton == null) && NetworkManager.Singleton.IsServer && (bool)Player && (bool)Player.PlayerInput && Player.IsCharacterSpawned)
		{
			if (Time.fixedTime >= nextTargetRefreshTime)
			{
				RefreshContext();
				nextTargetRefreshTime = Time.fixedTime + 0.5f;
			}
			brain?.Tick(in context, this);
		}
	}

	private void RefreshContext()
	{
		context.Seed = seed;
		context.TargetPuck = (MonoBehaviourSingleton<PuckManager>.Instance ? MonoBehaviourSingleton<PuckManager>.Instance.GetPuck() : null);
		if ((bool)Player.PlayerPosition)
		{
			context.HomePosition = Player.PlayerPosition.transform.position;
			context.HasHomePosition = true;
		}
		else
		{
			context.HasHomePosition = false;
		}
		context.IsClosestTeammateToPuck = false;
		context.TargetPlayerBody = null;
		PlayerBody playerBody = Player.PlayerBody;
		if (!playerBody || !MonoBehaviourSingleton<PlayerManager>.Instance)
		{
			return;
		}
		Vector3 position = playerBody.transform.position;
		bool num = context.TargetPuck;
		Vector3 vector = (num ? context.TargetPuck.transform.position : Vector3.zero);
		float num2 = (num ? (vector - position).sqrMagnitude : 0f);
		bool flag = num;
		float num3 = float.MaxValue;
		foreach (Player player in MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayers())
		{
			if (player == Player || !player.IsCharacterSpawned || !player.PlayerBody)
			{
				continue;
			}
			Vector3 position2 = player.PlayerBody.transform.position;
			if (player.OwnerClientId < 100000)
			{
				float sqrMagnitude = (position2 - position).sqrMagnitude;
				if (sqrMagnitude < num3)
				{
					num3 = sqrMagnitude;
					context.TargetPlayerBody = player.PlayerBody;
				}
			}
			if (flag && player.Team == Player.Team && player.Role != PlayerRole.Goalie && (vector - position2).sqrMagnitude < num2)
			{
				flag = false;
			}
		}
		context.IsClosestTeammateToPuck = flag;
	}

	public void Jump()
	{
		Player.PlayerBody.Jump();
	}

	public void MoveToward(Vector3 position, bool sprint)
	{
		PlayerInput playerInput = Player.PlayerInput;
		PlayerBody playerBody = Player.PlayerBody;
		Vector3 to = position - playerBody.transform.position;
		to.y = 0f;
		float num = Vector3.SignedAngle(playerBody.transform.forward, to, Vector3.up);
		playerInput.MoveInput.ServerValue = new Vector2(Mathf.Clamp(num / 45f, -1f, 1f), 1f);
		playerInput.SprintInput.ServerValue = sprint;
		playerInput.StopInput.ServerValue = false;
	}

	public void HoldFacing(Vector3 facePosition)
	{
		PlayerInput playerInput = Player.PlayerInput;
		PlayerBody playerBody = Player.PlayerBody;
		Vector3 to = facePosition - playerBody.transform.position;
		to.y = 0f;
		float num = Vector3.SignedAngle(playerBody.transform.forward, to, Vector3.up);
		playerInput.MoveInput.ServerValue = new Vector2(Mathf.Clamp(num / 45f, -1f, 1f), 0f);
		playerInput.SprintInput.ServerValue = false;
		playerInput.StopInput.ServerValue = playerBody.Rigidbody.linearVelocity.magnitude > 1f;
	}

	public void SkateForwardWeaving()
	{
		float num = Time.fixedTime + seed;
		Player.PlayerInput.MoveInput.ServerValue = new Vector2(Mathf.Sin(num * 0.7f), 1f);
	}

	public void WaveStick()
	{
		float num = Time.fixedTime + seed;
		Player.PlayerInput.StickRaycastOriginAngleInput.ServerValue = new Vector2(Mathf.Lerp(20f, 70f, (Mathf.Sin(num * 1.3f) + 1f) * 0.5f), Mathf.Sin(num * 0.9f) * 80f);
	}

	public void LookAround()
	{
		float num = Time.fixedTime + seed;
		Player.PlayerInput.LookAngleInput.ServerValue = new Vector2(30f, Mathf.Sin(num * 0.5f) * 90f);
	}

	public void AimStickAt(Puck puck, Vector3 toPuck, float puckDistance)
	{
		PlayerInput playerInput = Player.PlayerInput;
		PlayerBody playerBody = Player.PlayerBody;
		float num = Vector3.SignedAngle(playerBody.transform.forward, toPuck, Vector3.up);
		float x = 40f;
		StickPositioner stickPositioner = Player.StickPositioner;
		if ((bool)stickPositioner && (bool)puck)
		{
			Vector3 raycastOriginPosition = stickPositioner.RaycastOriginPosition;
			Vector3 vector = puck.transform.position - raycastOriginPosition;
			float magnitude = new Vector2(vector.x, vector.z).magnitude;
			float num2 = Mathf.Max(raycastOriginPosition.y - puck.transform.position.y, 0.1f);
			float a = Mathf.Acos(Mathf.Clamp01(magnitude / 2.5f)) * 57.29578f;
			float b = Mathf.Asin(Mathf.Clamp01(num2 / 2.5f)) * 57.29578f + 3f;
			x = Mathf.Max(a, b);
			num = Vector3.SignedAngle(playerBody.transform.forward, new Vector3(vector.x, 0f, vector.z), Vector3.up);
		}
		float y = num;
		if (puckDistance < 3.5f)
		{
			if (Time.fixedTime >= nextSwingTime)
			{
				swingStartTime = Time.fixedTime;
				nextSwingTime = Time.fixedTime + 0.4f + 1.2f + Mathf.Sin(seed * 13f) * 0.3f;
			}
			float num3 = (Time.fixedTime - swingStartTime) / 0.4f;
			if (num3 <= 1f)
			{
				y = num + Mathf.Lerp(-50f, 50f, num3);
			}
		}
		Vector2 serverValue = Utils.Vector2Clamp(new Vector2(x, y), playerInput.MinimumStickRaycastOriginAngle, playerInput.MaximumStickRaycastOriginAngle);
		playerInput.StickRaycastOriginAngleInput.ServerValue = serverValue;
		playerInput.LookAngleInput.ServerValue = new Vector2(25f, Mathf.Clamp(num, -90f, 90f));
	}
}
public static class BotManager
{
	public enum BotBehavior
	{
		Chase,
		Rookie,
		Destroy
	}

	public static BotBehavior DefaultBehavior = BotBehavior.Chase;

	public const ulong BotClientIdBase = 100000uL;

	private static ulong nextBotClientId = 100000uL;

	private static readonly string[] BotNames = new string[33]
	{
		"Sauce", "Dangles", "Wheels", "Mitts", "Biscuit", "Tendy", "Pylon", "Duster", "Grinder", "Sniper",
		"Celly", "Flow", "Chirp", "Hoser", "Clapper", "Stretch", "Bardown", "Chiclets", "Lettuce", "Twig",
		"Bucket", "Snipes", "Apple", "Ferda", "Wheelhouse", "Breakaway", "Deke", "Saucer", "Slapshot", "Crease",
		"Chel", "Gongshow", "Beauty"
	};

	public static BotBrain CreateBrain(BotBehavior behavior)
	{
		return behavior switch
		{
			BotBehavior.Rookie => new RookieBotBrain(), 
			BotBehavior.Destroy => new DestroyBotBrain(), 
			_ => new ChaseBotBrain(), 
		};
	}

	public static void Server_SetBotBehavior(BotBehavior behavior)
	{
		DefaultBehavior = behavior;
		BotInputDriver[] array = UnityEngine.Object.FindObjectsByType<BotInputDriver>(FindObjectsSortMode.None);
		for (int i = 0; i < array.Length; i++)
		{
			array[i].SetBrain(CreateBrain(behavior));
		}
	}

	public static int Server_SpawnBots(int count, PlayerTeam team = PlayerTeam.None)
	{
		PlayerManager instance = MonoBehaviourSingleton<PlayerManager>.Instance;
		if (!instance)
		{
			return 0;
		}
		List<PlayerPosition> list = (from position in UnityEngine.Object.FindObjectsByType<PlayerPosition>(FindObjectsSortMode.None)
			where !position.IsClaimed && (team == PlayerTeam.None || position.Team == team)
			orderby (position.Role == PlayerRole.Goalie) ? 1 : 0
			select position).ToList();
		int num = 0;
		foreach (PlayerPosition item in list)
		{
			if (num >= count)
			{
				break;
			}
			ulong num2 = nextBotClientId++;
			int num3 = (int)(num2 - 100000 + 1);
			instance.Server_SpawnPlayer(num2, new PlayerGameState
			{
				Phase = PlayerPhase.TeamSelect,
				Team = PlayerTeam.None,
				Role = PlayerRole.None
			}, CreateRandomCustomizationState(), PlayerHandedness.Right, $"BOT{num2}", GetRandomBotUsername(instance, num3), num3 % 100, 0, 0);
			Player playerByClientId = instance.GetPlayerByClientId(num2);
			if ((bool)playerByClientId)
			{
				playerByClientId.gameObject.AddComponent<BotInputDriver>();
				PlayerTeam? team2 = item.Team;
				playerByClientId.Server_SetGameState(null, team2);
				item.Server_Claim(playerByClientId);
				num++;
			}
		}
		return num;
	}

	private static string GetRandomBotUsername(PlayerManager playerManager, int botNumber)
	{
		int num = UnityEngine.Random.Range(0, BotNames.Length);
		for (int i = 0; i < BotNames.Length; i++)
		{
			string text = "Bot" + BotNames[(num + i) % BotNames.Length];
			if (!playerManager.GetPlayerByUsername(text))
			{
				return text;
			}
		}
		return $"Bot{botNumber}";
	}

	private static int GetRandomItemId(string category, PlayerRole role, float noneChance = 0f)
	{
		if (noneChance > 0f && UnityEngine.Random.value < noneChance)
		{
			return -1;
		}
		List<Item> list = ItemManager.GetItemsByCategories(new string[1] { category }).FindAll((Item item) => !item.IsUnlisted && ((role != PlayerRole.Goalie) ? item.IsAttackerItem : item.IsGoalieItem));
		if (list.Count == 0)
		{
			return -1;
		}
		return list[UnityEngine.Random.Range(0, list.Count)].id;
	}

	private static PlayerCustomizationState CreateRandomCustomizationState()
	{
		return new PlayerCustomizationState
		{
			FlagID = GetRandomItemId("flag", PlayerRole.Attacker),
			HeadgearIDBlueAttacker = GetRandomItemId("headgear", PlayerRole.Attacker),
			HeadgearIDRedAttacker = GetRandomItemId("headgear", PlayerRole.Attacker),
			HeadgearIDBlueGoalie = GetRandomItemId("headgear", PlayerRole.Goalie),
			HeadgearIDRedGoalie = GetRandomItemId("headgear", PlayerRole.Goalie),
			MustacheID = GetRandomItemId("mustache", PlayerRole.Attacker, 0.5f),
			BeardID = GetRandomItemId("beard", PlayerRole.Attacker, 0.5f),
			JerseyIDBlueAttacker = GetRandomItemId("jersey", PlayerRole.Attacker),
			JerseyIDRedAttacker = GetRandomItemId("jersey", PlayerRole.Attacker),
			JerseyIDBlueGoalie = GetRandomItemId("jersey", PlayerRole.Goalie),
			JerseyIDRedGoalie = GetRandomItemId("jersey", PlayerRole.Goalie),
			StickSkinIDBlueAttacker = GetRandomItemId("stickSkin", PlayerRole.Attacker),
			StickSkinIDRedAttacker = GetRandomItemId("stickSkin", PlayerRole.Attacker),
			StickSkinIDBlueGoalie = GetRandomItemId("stickSkin", PlayerRole.Goalie),
			StickSkinIDRedGoalie = GetRandomItemId("stickSkin", PlayerRole.Goalie),
			StickShaftTapeIDBlueAttacker = GetRandomItemId("stickShaftTape", PlayerRole.Attacker, 0.3f),
			StickShaftTapeIDRedAttacker = GetRandomItemId("stickShaftTape", PlayerRole.Attacker, 0.3f),
			StickShaftTapeIDBlueGoalie = GetRandomItemId("stickShaftTape", PlayerRole.Goalie, 0.3f),
			StickShaftTapeIDRedGoalie = GetRandomItemId("stickShaftTape", PlayerRole.Goalie, 0.3f),
			StickBladeTapeIDBlueAttacker = GetRandomItemId("stickBladeTape", PlayerRole.Attacker, 0.3f),
			StickBladeTapeIDRedAttacker = GetRandomItemId("stickBladeTape", PlayerRole.Attacker, 0.3f),
			StickBladeTapeIDBlueGoalie = GetRandomItemId("stickBladeTape", PlayerRole.Goalie, 0.3f),
			StickBladeTapeIDRedGoalie = GetRandomItemId("stickBladeTape", PlayerRole.Goalie, 0.3f)
		};
	}

	public static int Server_DespawnBots()
	{
		PlayerManager instance = MonoBehaviourSingleton<PlayerManager>.Instance;
		if (!instance)
		{
			return 0;
		}
		List<Player> list = (from botPlayer in instance.GetPlayers()
			where botPlayer.OwnerClientId >= 100000
			select botPlayer).ToList();
		foreach (Player item in list)
		{
			ulong ownerClientId = item.OwnerClientId;
			if (item.PlayerPosition != null)
			{
				item.PlayerPosition.Server_Unclaim();
			}
			if (item.IsCharacterSpawned)
			{
				item.Server_DespawnCharacter();
			}
			item.NetworkObject.Despawn();
			if (NetworkManager.Singleton.ConnectedClients.ContainsKey(ownerClientId))
			{
				NetworkManager.Singleton.DisconnectClient(ownerClientId);
			}
		}
		return list.Count;
	}
}
public class ChaseBotBrain : BotBrain
{
	public override void Tick(in BotContext context, BotInputDriver driver)
	{
		Puck targetPuck = context.TargetPuck;
		PlayerBody playerBody = driver.Player.PlayerBody;
		if ((bool)targetPuck && (bool)playerBody)
		{
			float magnitude = (targetPuck.transform.position - playerBody.transform.position).magnitude;
			driver.MoveToward(targetPuck.transform.position, magnitude > 10f);
		}
		else
		{
			driver.SkateForwardWeaving();
		}
		driver.WaveStick();
		driver.LookAround();
	}
}
public class DestroyBotBrain : BotBrain
{
	private enum Phase
	{
		Retreat,
		Charge
	}

	private const float RetreatDistance = 26f;

	private const float MaxRetreatDuration = 4f;

	private const float JumpRange = 2f;

	private const float ContactReached = 1.4f;

	private const float LeavingDistance = 3f;

	private const float MaxChargeDuration = 8f;

	private Phase phase;

	private bool isInitialized;

	private float phaseStartTime;

	private Vector3 retreatDirection = Vector3.forward;

	private bool hasRetreatDirection;

	private bool hasJumpedThisCharge;

	private float closestApproachThisCharge = float.MaxValue;

	public override void Tick(in BotContext context, BotInputDriver driver)
	{
		PlayerBody playerBody = driver.Player.PlayerBody;
		PlayerBody targetPlayerBody = context.TargetPlayerBody;
		if (!playerBody)
		{
			return;
		}
		if (!targetPlayerBody)
		{
			driver.HoldFacing(playerBody.transform.position + playerBody.transform.forward);
			return;
		}
		if (!isInitialized)
		{
			EnterPhase(Phase.Retreat);
			isInitialized = true;
		}
		Vector3 position = playerBody.transform.position;
		Vector3 position2 = targetPlayerBody.transform.position;
		Vector3 vector = position2 - position;
		vector.y = 0f;
		float magnitude = vector.magnitude;
		switch (phase)
		{
		case Phase.Retreat:
			TickRetreat(driver, position, position2, magnitude);
			break;
		case Phase.Charge:
			TickCharge(driver, playerBody, position2, magnitude);
			break;
		}
	}

	private void TickRetreat(BotInputDriver driver, Vector3 botPosition, Vector3 targetPosition, float distance)
	{
		if (!hasRetreatDirection)
		{
			Vector3 vector = botPosition - targetPosition;
			vector.y = 0f;
			retreatDirection = ((vector.sqrMagnitude > 0.01f) ? vector.normalized : Vector3.forward);
			hasRetreatDirection = true;
		}
		driver.MoveToward(botPosition + retreatDirection * 8f, sprint: true);
		if (distance >= 26f || Time.fixedTime - phaseStartTime >= 4f)
		{
			EnterPhase(Phase.Charge);
		}
	}

	private void TickCharge(BotInputDriver driver, PlayerBody body, Vector3 targetPosition, float distance)
	{
		driver.MoveToward(targetPosition, sprint: true);
		closestApproachThisCharge = Mathf.Min(closestApproachThisCharge, distance);
		if (!hasJumpedThisCharge && distance <= 2f && body.IsGrounded)
		{
			driver.Jump();
			hasJumpedThisCharge = true;
		}
		bool num = closestApproachThisCharge <= 1.4f;
		bool flag = distance > 3f;
		if ((num && flag) || Time.fixedTime - phaseStartTime >= 8f)
		{
			EnterPhase(Phase.Retreat);
		}
	}

	private void EnterPhase(Phase newPhase)
	{
		phase = newPhase;
		phaseStartTime = Time.fixedTime;
		if (newPhase == Phase.Retreat)
		{
			hasRetreatDirection = false;
		}
		if (newPhase == Phase.Charge)
		{
			hasJumpedThisCharge = false;
			closestApproachThisCharge = float.MaxValue;
		}
	}
}
public class CreaseGhostView : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float fullGhostDistance = 0.5f;

	[SerializeField]
	private float noGhostDistance = 2.5f;

	[SerializeField]
	private float fadeSpeed = 6f;

	private Zone creaseZone;

	private readonly HashSet<PlayerBody> enemiesInCrease = new HashSet<PlayerBody>();

	private readonly Dictionary<PlayerBody, float> strengthByEnemy = new Dictionary<PlayerBody, float>();

	private readonly List<PlayerBody> scratch = new List<PlayerBody>();

	public Zone CreaseZone => creaseZone;

	public void EnterCrease(Zone zone)
	{
		creaseZone = zone;
	}

	public void ExitCrease()
	{
		creaseZone = null;
		enemiesInCrease.Clear();
	}

	public void AddEnemy(PlayerBody enemy)
	{
		enemiesInCrease.Add(enemy);
	}

	public void RemoveEnemy(PlayerBody enemy)
	{
		enemiesInCrease.Remove(enemy);
	}

	public void ForgetEnemy(PlayerBody enemy)
	{
		enemiesInCrease.Remove(enemy);
		strengthByEnemy.Remove(enemy);
	}

	public void ResetAll()
	{
		foreach (PlayerBody key in strengthByEnemy.Keys)
		{
			if (key != null && key.PlayerMesh != null)
			{
				key.PlayerMesh.SetTransparency(0f);
			}
		}
		creaseZone = null;
		enemiesInCrease.Clear();
		strengthByEnemy.Clear();
	}

	private void Update()
	{
		bool flag = creaseZone != null;
		if (flag)
		{
			foreach (PlayerBody item in enemiesInCrease)
			{
				if (item != null && !strengthByEnemy.ContainsKey(item))
				{
					strengthByEnemy[item] = 0f;
				}
			}
		}
		if (strengthByEnemy.Count == 0)
		{
			return;
		}
		scratch.Clear();
		scratch.AddRange(strengthByEnemy.Keys);
		foreach (PlayerBody item2 in scratch)
		{
			float num = ((flag && item2 != null && enemiesInCrease.Contains(item2)) ? TargetStrength(item2) : 0f);
			float num2 = Mathf.MoveTowards(strengthByEnemy[item2], num, fadeSpeed * Time.deltaTime);
			if (item2 != null && item2.PlayerMesh != null)
			{
				item2.PlayerMesh.SetTransparency(num2);
			}
			if (num2 <= 0f && num <= 0f)
			{
				strengthByEnemy.Remove(item2);
			}
			else
			{
				strengthByEnemy[item2] = num2;
			}
		}
	}

	private float TargetStrength(PlayerBody enemy)
	{
		Vector3 vector = enemy.transform.position - creaseZone.Origin;
		vector.y = 0f;
		return Mathf.Clamp01(Mathf.InverseLerp(noGhostDistance, fullGhostDistance, vector.magnitude));
	}
}
[RequireComponent(typeof(CreaseGhostView))]
public class CreaseGhostViewController : MonoBehaviour
{
	private static readonly HashSet<string> CreaseZoneIds = new HashSet<string> { "Crease" };

	private PlayerBody playerBody;

	private CreaseGhostView creaseGhostView;

	private bool IsLocalGoalie
	{
		get
		{
			if (playerBody != null && playerBody.IsOwner && playerBody.Player != null)
			{
				return playerBody.Player.Role == PlayerRole.Goalie;
			}
			return false;
		}
	}

	private bool IsCreaseProtectionEnabled
	{
		get
		{
			if (NetworkBehaviourSingleton<GameModeManager>.Instance != null)
			{
				return NetworkBehaviourSingleton<GameModeManager>.Instance.ClientConfig.Value.GoalieCreaseProtection;
			}
			return false;
		}
	}

	private void Awake()
	{
		playerBody = GetComponent<PlayerBody>();
		creaseGhostView = GetComponent<CreaseGhostView>();
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			EventManager.AddEventListener("Event_Everyone_OnPlayerEnterZone", Event_Everyone_OnPlayerEnterZone);
			EventManager.AddEventListener("Event_Everyone_OnPlayerExitZone", Event_Everyone_OnPlayerExitZone);
			EventManager.AddEventListener("Event_Everyone_OnPlayerBodyDespawned", Event_Everyone_OnPlayerBodyDespawned);
		}
	}

	private void OnDestroy()
	{
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			EventManager.RemoveEventListener("Event_Everyone_OnPlayerEnterZone", Event_Everyone_OnPlayerEnterZone);
			EventManager.RemoveEventListener("Event_Everyone_OnPlayerExitZone", Event_Everyone_OnPlayerExitZone);
			EventManager.RemoveEventListener("Event_Everyone_OnPlayerBodyDespawned", Event_Everyone_OnPlayerBodyDespawned);
			creaseGhostView.ResetAll();
		}
	}

	private void Event_Everyone_OnPlayerEnterZone(Dictionary<string, object> message)
	{
		Zone zone = (Zone)message["zone"];
		if (!CreaseZoneIds.Contains(zone.ZoneId))
		{
			return;
		}
		PlayerBody playerBody = (PlayerBody)message["playerBody"];
		if (!IsLocalGoalie || !IsCreaseProtectionEnabled)
		{
			return;
		}
		if (playerBody == this.playerBody)
		{
			Goal componentInParent = zone.GetComponentInParent<Goal>();
			if (componentInParent == null || componentInParent.Team != this.playerBody.Player.Team)
			{
				return;
			}
			creaseGhostView.EnterCrease(zone);
			{
				foreach (PlayerBody occupant in zone.Occupants)
				{
					if (IsEnemy(occupant))
					{
						creaseGhostView.AddEnemy(occupant);
					}
				}
				return;
			}
		}
		if (zone == creaseGhostView.CreaseZone && IsEnemy(playerBody))
		{
			creaseGhostView.AddEnemy(playerBody);
		}
	}

	private void Event_Everyone_OnPlayerExitZone(Dictionary<string, object> message)
	{
		if (!((Zone)message["zone"] != creaseGhostView.CreaseZone))
		{
			PlayerBody playerBody = (PlayerBody)message["playerBody"];
			if (playerBody == this.playerBody)
			{
				creaseGhostView.ExitCrease();
			}
			else
			{
				creaseGhostView.RemoveEnemy(playerBody);
			}
		}
	}

	private void Event_Everyone_OnPlayerBodyDespawned(Dictionary<string, object> message)
	{
		PlayerBody enemy = (PlayerBody)message["playerBody"];
		creaseGhostView.ForgetEnemy(enemy);
	}

	private bool IsEnemy(PlayerBody body)
	{
		if (body == null || body.Player == null || playerBody.Player == null)
		{
			return false;
		}
		PlayerTeam team = body.Player.Team;
		if (body.Player.Role != PlayerRole.Goalie && (team == PlayerTeam.Blue || team == PlayerTeam.Red))
		{
			return team != playerBody.Player.Team;
		}
		return false;
	}
}
[RequireComponent(typeof(Rigidbody))]
public class Hover : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float maxForce = 40f;

	[SerializeField]
	private Vector3 raycastOffset = new Vector3(0f, 1f, 0f);

	[SerializeField]
	private float raycastDistance = 1.45f;

	[SerializeField]
	private LayerMask raycastLayerMask;

	[Space(20f)]
	[SerializeField]
	private float proportionalGain = 100f;

	[SerializeField]
	private float integralGain;

	[SerializeField]
	private float derivativeGain = 15f;

	[Space(20f)]
	public float TargetDistance = 1f;

	[HideInInspector]
	public bool IsGrounded;

	[HideInInspector]
	public Rigidbody Rigidbody;

	private PIDController pidController = new PIDController();

	private float currentDistance;

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
	}

	private void FixedUpdate()
	{
		pidController.proportionalGain = proportionalGain;
		pidController.integralGain = integralGain;
		pidController.derivativeGain = derivativeGain;
		Vector3 vector = base.transform.position + raycastOffset;
		Vector3 down = Vector3.down;
		UnityEngine.Debug.DrawRay(vector, down * raycastDistance, Color.black);
		if (Physics.Raycast(vector, down, out var hitInfo, raycastDistance, raycastLayerMask))
		{
			currentDistance = hitInfo.distance;
		}
		else
		{
			currentDistance = raycastDistance;
		}
		IsGrounded = currentDistance < raycastDistance;
		float value = pidController.Update(Time.fixedDeltaTime, currentDistance, TargetDistance);
		value = Mathf.Clamp(value, 0f, maxForce);
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.AddForce(Vector3.up * value, ForceMode.Acceleration);
		}
	}
}
[RequireComponent(typeof(Rigidbody))]
public class KeepUpright : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float proportionalGain = 50f;

	[SerializeField]
	private float integralGain;

	[SerializeField]
	private float derivativeGain = 5f;

	[HideInInspector]
	public float Balance = 1f;

	[HideInInspector]
	public Rigidbody Rigidbody;

	private Vector3PIDController pidController = new Vector3PIDController();

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
	}

	private void FixedUpdate()
	{
		pidController.proportionalGain = proportionalGain * Balance;
		pidController.integralGain = integralGain * Balance;
		pidController.derivativeGain = derivativeGain * Balance;
		Vector3 vector = Vector3.Cross(pidController.Update(Time.fixedDeltaTime, base.transform.up, Vector3.up), Vector3.up);
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.AddTorque(-vector, ForceMode.Acceleration);
		}
	}
}
[RequireComponent(typeof(Rigidbody))]
[RequireComponent(typeof(PlayerBody))]
[RequireComponent(typeof(Hover))]
public class Movement : MonoBehaviour
{
	[Header("Settings")]
	[Tooltip("Acceleration (m/s²) applied while skating forwards without sprinting, until maxForwardsSpeed is reached.")]
	[SerializeField]
	private float forwardsAcceleration = 2f;

	[Tooltip("Acceleration (m/s²) applied while sprinting forwards below maxForwardsSpeed.")]
	[SerializeField]
	private float forwardsSprintAcceleration = 4.75f;

	[Tooltip("Acceleration (m/s²) applied while sprinting forwards once already above maxForwardsSpeed - controls how quickly the sprint band between maxForwardsSpeed and maxForwardsSprintSpeed fills up.")]
	[SerializeField]
	private float forwardsSprintOverspeedAcceleration = 1f;

	[Tooltip("Acceleration (m/s²) applied while skating backwards without sprinting, until maxBackwardsSpeed is reached.")]
	[SerializeField]
	private float backwardsAcceleration = 1.8f;

	[Tooltip("Acceleration (m/s²) applied while sprinting backwards below maxForwardsSpeed.")]
	[SerializeField]
	private float backwardsSprintAcceleration = 2f;

	[Tooltip("Acceleration (m/s²) applied while sprinting backwards once already above maxForwardsSpeed.")]
	[SerializeField]
	private float backwardsSprintOverspeedAcceleration = 1f;

	[Tooltip("Deceleration (m/s²) applied when movement input opposes the current direction of travel (e.g. holding back while still gliding forwards). Higher = sharper stops.")]
	[SerializeField]
	private float brakeAcceleration = 5f;

	[Tooltip("Baseline velocity damping applied every physics tick (velocity *= 1 - drag * dt) - the 'ice friction' that makes a coasting player slowly glide to a stop.")]
	[SerializeField]
	private float drag = 0.025f;

	[Tooltip("Velocity damping applied instead of drag while above MaximumSpeed (e.g. after an external boost or collision) - how quickly excess speed bleeds off.")]
	[SerializeField]
	private float overspeedDrag = 0.025f;

	[Space(20f)]
	[Tooltip("Speed (m/s) above which forwards acceleration cuts off when not sprinting.")]
	[SerializeField]
	private float maxForwardsSpeed = 7.5f;

	[Tooltip("Speed (m/s) above which forwards acceleration cuts off while sprinting.")]
	[SerializeField]
	private float maxForwardsSprintSpeed = 8.75f;

	[Tooltip("Speed (m/s) above which backwards acceleration cuts off when not sprinting.")]
	[SerializeField]
	private float maxBackwardsSpeed = 7.25f;

	[Tooltip("Speed (m/s) above which backwards acceleration cuts off while sprinting.")]
	[SerializeField]
	private float maxBackwardsSprintSpeed = 7.25f;

	[Space(20f)]
	[Tooltip("Angular acceleration (rad/s²) applied while turning, until the turn speed cap is reached.")]
	[SerializeField]
	private float turnAcceleration = 1.625f;

	[Tooltip("Angular deceleration (rad/s²) applied when turn input opposes the current rotation direction - how sharply a turn can be reversed.")]
	[SerializeField]
	private float turnBrakeAcceleration = 3.25f;

	[Tooltip("Maximum turn rate (rad/s) around the player's up axis. Scaled at runtime by TurnMultiplier.")]
	[SerializeField]
	private float turnMaxSpeed = 1.375f;

	[Tooltip("Angular velocity damping applied every physics tick while no turn input is held - how quickly rotation settles once the keys are released.")]
	[SerializeField]
	private float turnDrag = 3f;

	[Tooltip("Angular velocity damping applied while spinning faster than the turn speed cap - bleeds off excess rotation.")]
	[SerializeField]
	private float turnOverspeedDrag = 2.25f;

	[HideInInspector]
	public Rigidbody Rigidbody;

	[HideInInspector]
	public PlayerBody PlayerBody;

	[HideInInspector]
	public Hover Hover;

	[HideInInspector]
	public bool MoveForwards;

	[HideInInspector]
	public bool MoveBackwards;

	[HideInInspector]
	public bool TurnLeft;

	[HideInInspector]
	public bool TurnRight;

	[HideInInspector]
	public float TurnMultiplier;

	[HideInInspector]
	public bool Sprint;

	[HideInInspector]
	public float AmbientDrag;

	[HideInInspector]
	public Transform MovementDirection;

	private float currentMaxSpeed;

	private float currentAcceleration;

	[HideInInspector]
	public float Speed => new Vector3(Rigidbody.linearVelocity.x, 0f, Rigidbody.linearVelocity.z).magnitude;

	[HideInInspector]
	public float NormalizedMaximumSpeed => Speed / MaximumSpeed;

	[HideInInspector]
	public float NormalizedMinimumSpeed => Speed / MinimumSpeed;

	[HideInInspector]
	public float TurnSpeed => Math.Abs(base.transform.InverseTransformVector(Rigidbody.angularVelocity).y);

	[HideInInspector]
	public float MaximumSpeed => Mathf.Max(Mathf.Max(maxForwardsSpeed, maxForwardsSprintSpeed), Mathf.Max(maxBackwardsSpeed, maxBackwardsSprintSpeed));

	[HideInInspector]
	public float MinimumSpeed => Mathf.Min(Mathf.Min(maxForwardsSpeed, maxForwardsSprintSpeed), Mathf.Min(maxBackwardsSpeed, maxBackwardsSprintSpeed));

	[HideInInspector]
	public bool IsMovingForwards => MovementDirection.InverseTransformVector(Rigidbody.linearVelocity).z > 0f;

	[HideInInspector]
	public bool IsMovingBackwards => MovementDirection.InverseTransformVector(Rigidbody.linearVelocity).z < 0f;

	[HideInInspector]
	public bool IsTurningLeft => base.transform.InverseTransformVector(Rigidbody.angularVelocity).y < 0f;

	[HideInInspector]
	public bool IsTurningRight => base.transform.InverseTransformVector(Rigidbody.angularVelocity).y > 0f;

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
		PlayerBody = GetComponent<PlayerBody>();
		Hover = GetComponent<Hover>();
	}

	private void Start()
	{
		currentMaxSpeed = maxForwardsSpeed;
		currentAcceleration = forwardsAcceleration;
	}

	private void FixedUpdate()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Move();
			Turn();
		}
	}

	private void Move()
	{
		if (!Hover.IsGrounded)
		{
			return;
		}
		if (IsMovingForwards)
		{
			if (Sprint)
			{
				currentMaxSpeed = maxForwardsSprintSpeed;
				currentAcceleration = ((Speed < maxForwardsSpeed) ? forwardsSprintAcceleration : forwardsSprintOverspeedAcceleration);
			}
			else
			{
				currentMaxSpeed = maxForwardsSpeed;
				currentAcceleration = forwardsAcceleration;
			}
		}
		else if (IsMovingBackwards)
		{
			if (Sprint)
			{
				currentMaxSpeed = maxBackwardsSprintSpeed;
				currentAcceleration = ((Speed < maxForwardsSpeed) ? backwardsSprintAcceleration : backwardsSprintOverspeedAcceleration);
			}
			else
			{
				currentMaxSpeed = maxBackwardsSpeed;
				currentAcceleration = backwardsAcceleration;
			}
		}
		if (MoveForwards)
		{
			if (IsMovingForwards)
			{
				float num = ((Speed < currentMaxSpeed) ? currentAcceleration : 0f);
				Rigidbody.AddForce(MovementDirection.forward * num, ForceMode.Acceleration);
			}
			else if (IsMovingBackwards)
			{
				float num2 = brakeAcceleration;
				Rigidbody.AddForce(MovementDirection.forward * num2, ForceMode.Acceleration);
			}
		}
		else if (MoveBackwards)
		{
			if (IsMovingBackwards)
			{
				float num3 = ((Speed < currentMaxSpeed) ? currentAcceleration : 0f);
				Rigidbody.AddForce(-MovementDirection.forward * num3, ForceMode.Acceleration);
			}
			else if (IsMovingForwards)
			{
				float num4 = brakeAcceleration;
				Rigidbody.AddForce(-MovementDirection.forward * num4, ForceMode.Acceleration);
			}
		}
		if (Speed > MaximumSpeed)
		{
			Rigidbody.linearVelocity *= 1f - overspeedDrag * Time.fixedDeltaTime;
		}
		else
		{
			Rigidbody.linearVelocity *= 1f - drag * Time.fixedDeltaTime;
		}
		Rigidbody.linearVelocity *= 1f - AmbientDrag * Time.fixedDeltaTime;
	}

	private void Turn()
	{
		if (TurnLeft)
		{
			if (IsTurningLeft)
			{
				float num = ((TurnSpeed < turnMaxSpeed * TurnMultiplier) ? turnAcceleration : 0f);
				Rigidbody.AddTorque(base.transform.up * (0f - num) * TurnMultiplier, ForceMode.Acceleration);
			}
			else if (IsTurningRight)
			{
				float num2 = turnBrakeAcceleration;
				Rigidbody.AddTorque(base.transform.up * (0f - num2) * TurnMultiplier, ForceMode.Acceleration);
			}
		}
		else if (TurnRight)
		{
			if (IsTurningRight)
			{
				float num3 = ((TurnSpeed < turnMaxSpeed * TurnMultiplier) ? turnAcceleration : 0f);
				Rigidbody.AddTorque(base.transform.up * num3 * TurnMultiplier, ForceMode.Acceleration);
			}
			else if (IsTurningLeft)
			{
				float num4 = turnBrakeAcceleration;
				Rigidbody.AddTorque(base.transform.up * num4 * TurnMultiplier, ForceMode.Acceleration);
			}
		}
		else if (TurnSpeed < turnMaxSpeed * TurnMultiplier)
		{
			Rigidbody.angularVelocity *= 1f - turnDrag * Time.fixedDeltaTime;
		}
		if (TurnSpeed > turnMaxSpeed * TurnMultiplier)
		{
			Rigidbody.angularVelocity *= 1f - turnOverspeedDrag * Time.fixedDeltaTime;
		}
	}
}
