[ExecuteInEditMode]
public class PlayerHead : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("PlayerHead");

	[Header("References")]
	[SerializeField]
	private List<Flag> flags = new List<Flag>();

	[SerializeField]
	private List<Headgear> headgear = new List<Headgear>();

	[SerializeField]
	private List<Mustache> mustaches = new List<Mustache>();

	[SerializeField]
	private List<Beard> beards = new List<Beard>();

	public void SetFlagID(int flagID)
	{
		headgear.ForEach(delegate(Headgear h)
		{
			if (h.FlagGameObject != null)
			{
				h.FlagGameObject.SetActive(value: false);
			}
		});
		if (flagID == -1)
		{
			return;
		}
		Flag flag = flags.FirstOrDefault((Flag f) => f.ID == flagID);
		if (flag == null)
		{
			Logger.Warning($"Tried to set invalid flagID {flagID}");
			return;
		}
		headgear.ForEach(delegate(Headgear h)
		{
			if (h.FlagGameObject != null)
			{
				h.FlagGameObject.SetActive(value: true);
				if (h.FlagMeshRendererTexturer != null)
				{
					h.FlagMeshRendererTexturer.SetTexture(flag.Texture);
				}
			}
		});
	}

	public void SetHeadgearID(int headgearID, PlayerRole role)
	{
		this.headgear.ForEach(delegate(Headgear h)
		{
			h.GameObject.SetActive(value: false);
		});
		if (headgearID != -1)
		{
			Headgear headgear = this.headgear.FirstOrDefault((Headgear h) => h.ID == headgearID && h.IsForRole(role));
			if (headgear == null)
			{
				Logger.Warning($"Tried to set invalid headgearID {headgearID} for role {role}");
			}
			else
			{
				headgear.GameObject.SetActive(value: true);
			}
		}
	}

	public void SetMustacheID(int mustacheID)
	{
		mustaches.ForEach(delegate(Mustache m)
		{
			m.GameObject.SetActive(value: false);
		});
		if (mustacheID != -1)
		{
			Mustache mustache = mustaches.FirstOrDefault((Mustache m) => m.ID == mustacheID);
			if (mustache == null)
			{
				Logger.Warning($"Tried to set invalid mustacheID {mustacheID}");
			}
			else
			{
				mustache.GameObject.SetActive(value: true);
			}
		}
	}

	public void SetBeardID(int beardID)
	{
		beards.ForEach(delegate(Beard b)
		{
			b.GameObject.SetActive(value: false);
		});
		if (beardID != -1)
		{
			Beard beard = beards.FirstOrDefault((Beard b) => b.ID == beardID);
			if (beard == null)
			{
				Logger.Warning($"Tried to set invalid beardID {beardID}");
			}
			else
			{
				beard.GameObject.SetActive(value: true);
			}
		}
	}
}
public class MeshGhoster : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("MeshGhoster");

	private static readonly int GhostFadeId = Shader.PropertyToID("_GhostFade");

	private static readonly int CameraFadeId = Shader.PropertyToID("_CameraFade");

	private static readonly int FadeNearId = Shader.PropertyToID("_FadeNear");

	private static readonly int FadeFarId = Shader.PropertyToID("_FadeFar");

	private static readonly int NearAlphaId = Shader.PropertyToID("_NearAlpha");

	private static readonly int FarAlphaId = Shader.PropertyToID("_FarAlpha");

	private static readonly int BaseMapId = Shader.PropertyToID("_BaseMap");

	private static readonly int BaseColorId = Shader.PropertyToID("_BaseColor");

	private static readonly int BumpMapId = Shader.PropertyToID("_BumpMap");

	private static readonly int BaseOpacityId = Shader.PropertyToID("_BaseOpacity");

	private static readonly int SurfaceId = Shader.PropertyToID("_Surface");

	private const string DepthShaderName = "Custom/Depth";

	[Header("References")]
	[SerializeField]
	private Material ghostMaterial;

	private Renderer[] ghostableRenderers;

	private TMP_Text[] ghostableTexts;

	private Material[][] preGhostMaterials;

	private Material[][] ghostInstances;

	private float[] preGhostTextAlphas;

	private float ghostFadeNear;

	private float ghostFadeFar;

	private float ghostNearAlpha;

	private float ghostFarAlpha;

	private float ghostCameraFade;

	private float strength;

	private Camera ghostCamera;

	private Camera GhostCamera
	{
		get
		{
			if (ghostCamera == null || !ghostCamera.isActiveAndEnabled)
			{
				ghostCamera = Camera.main;
			}
			return ghostCamera;
		}
	}

	public void SetTransparency(float strength)
	{
		strength = Mathf.Clamp01(strength);
		if (this.strength == strength)
		{
			return;
		}
		if (strength > 0f && ghostMaterial == null)
		{
			Logger.Warning("'" + base.name + "' has no ghost material assigned - can't render the crease ghost.");
			return;
		}
		bool flag = this.strength > 0f;
		this.strength = strength;
		if (strength > 0f && !flag)
		{
			ApplyGhostMaterials();
		}
		if (strength <= 0f)
		{
			RestoreMaterials();
		}
		else
		{
			ApplyGhostStrength();
		}
	}

	private void Update()
	{
		if (ghostInstances != null)
		{
			ApplyGhostTextAlpha();
		}
	}

	private void ApplyGhostMaterials()
	{
		if (ghostableRenderers == null)
		{
			ghostableRenderers = CollectGhostableRenderers();
			ghostableTexts = GetComponentsInChildren<TMP_Text>(includeInactive: true);
		}
		Shader shader = ghostMaterial.shader;
		ghostFadeNear = ghostMaterial.GetFloat(FadeNearId);
		ghostFadeFar = ghostMaterial.GetFloat(FadeFarId);
		ghostNearAlpha = ghostMaterial.GetFloat(NearAlphaId);
		ghostFarAlpha = ghostMaterial.GetFloat(FarAlphaId);
		ghostCameraFade = ghostMaterial.GetFloat(CameraFadeId);
		CaptureTextAlphas();
		preGhostMaterials = new Material[ghostableRenderers.Length][];
		ghostInstances = new Material[ghostableRenderers.Length][];
		for (int i = 0; i < ghostableRenderers.Length; i++)
		{
			Renderer renderer = ghostableRenderers[i];
			if (!(renderer == null))
			{
				Material[] sharedMaterials = renderer.sharedMaterials;
				preGhostMaterials[i] = sharedMaterials;
				Material[] array = new Material[sharedMaterials.Length];
				for (int j = 0; j < array.Length; j++)
				{
					array[j] = BuildGhostInstance(sharedMaterials[j], shader);
				}
				renderer.sharedMaterials = array;
				ghostInstances[i] = array;
			}
		}
	}

	private Renderer[] CollectGhostableRenderers()
	{
		Renderer[] componentsInChildren = GetComponentsInChildren<Renderer>(includeInactive: true);
		List<Renderer> list = new List<Renderer>(componentsInChildren.Length);
		Renderer[] array = componentsInChildren;
		foreach (Renderer renderer in array)
		{
			Shader shader = ((renderer != null && renderer.sharedMaterial != null) ? renderer.sharedMaterial.shader : null);
			if (!(shader != null) || !shader.name.StartsWith("TextMeshPro"))
			{
				list.Add(renderer);
			}
		}
		return list.ToArray();
	}

	private Material BuildGhostInstance(Material original, Shader ghostShader)
	{
		if (original == null)
		{
			return new Material(ghostShader)
			{
				hideFlags = HideFlags.HideAndDontSave
			};
		}
		if (original.shader != null && original.shader.name == "Custom/Depth")
		{
			return original;
		}
		Color color = original.color;
		Texture mainTexture = original.mainTexture;
		Vector2 mainTextureScale = original.mainTextureScale;
		Vector2 mainTextureOffset = original.mainTextureOffset;
		Texture texture = (original.HasProperty(BumpMapId) ? original.GetTexture(BumpMapId) : null);
		Material material = new Material(original)
		{
			hideFlags = HideFlags.HideAndDontSave
		};
		material.shader = ghostShader;
		material.SetColor(BaseColorId, color);
		material.SetTexture(BaseMapId, mainTexture);
		material.SetTextureScale(BaseMapId, mainTextureScale);
		material.SetTextureOffset(BaseMapId, mainTextureOffset);
		if (texture != null)
		{
			material.SetTexture(BumpMapId, texture);
		}
		bool flag = (original.HasProperty(SurfaceId) && original.GetFloat(SurfaceId) >= 0.5f) || original.renderQueue >= 2501;
		material.SetFloat(BaseOpacityId, flag ? Mathf.Clamp01(color.a) : 1f);
		if (flag)
		{
			material.SetShaderPassEnabled("SRPDefaultUnlit", enabled: false);
		}
		material.SetFloat(FadeNearId, ghostFadeNear);
		material.SetFloat(FadeFarId, ghostFadeFar);
		material.SetFloat(NearAlphaId, ghostNearAlpha);
		material.SetFloat(FarAlphaId, ghostFarAlpha);
		material.SetFloat(CameraFadeId, ghostCameraFade);
		material.SetFloat(GhostFadeId, strength);
		return material;
	}

	private void ApplyGhostStrength()
	{
		if (ghostInstances == null)
		{
			return;
		}
		Material[][] array = ghostInstances;
		foreach (Material[] array2 in array)
		{
			if (array2 == null)
			{
				continue;
			}
			Material[] array3 = array2;
			foreach (Material material in array3)
			{
				if (material != null)
				{
					material.SetFloat(GhostFadeId, strength);
				}
			}
		}
	}

	private void ApplyGhostTextAlpha()
	{
		if (ghostableTexts == null)
		{
			return;
		}
		Camera camera = GhostCamera;
		Vector3 cameraPosition = ((camera != null) ? camera.transform.position : Vector3.zero);
		TMP_Text[] array = ghostableTexts;
		foreach (TMP_Text tMP_Text in array)
		{
			if (!((UnityEngine.Object)(object)tMP_Text == null))
			{
				tMP_Text.alpha = ((camera != null) ? GhostAlphaAt(tMP_Text.transform.position, cameraPosition) : Mathf.Lerp(1f, ghostFarAlpha, strength));
			}
		}
	}

	private float GhostAlphaAt(Vector3 worldPosition, Vector3 cameraPosition)
	{
		float value = Vector3.Distance(worldPosition, cameraPosition);
		float t = Mathf.SmoothStep(0f, 1f, Mathf.InverseLerp(ghostFadeNear, ghostFadeFar, value));
		float b = Mathf.Lerp(ghostNearAlpha, ghostFarAlpha, t);
		float b2 = Mathf.Lerp(ghostFarAlpha, b, ghostCameraFade);
		return Mathf.Lerp(1f, b2, strength);
	}

	private void CaptureTextAlphas()
	{
		if (ghostableTexts != null)
		{
			preGhostTextAlphas = new float[ghostableTexts.Length];
			for (int i = 0; i < ghostableTexts.Length; i++)
			{
				preGhostTextAlphas[i] = (((UnityEngine.Object)(object)ghostableTexts[i] != null) ? ghostableTexts[i].alpha : 1f);
			}
		}
	}

	private void RestoreMaterials()
	{
		strength = 0f;
		if (ghostInstances == null)
		{
			return;
		}
		for (int i = 0; i < ghostableRenderers.Length; i++)
		{
			Renderer renderer = ghostableRenderers[i];
			if (renderer != null && preGhostMaterials[i] != null)
			{
				renderer.sharedMaterials = preGhostMaterials[i];
			}
			if (ghostInstances[i] == null)
			{
				continue;
			}
			for (int j = 0; j < ghostInstances[i].Length; j++)
			{
				Material material = ghostInstances[i][j];
				if (material != null && material != preGhostMaterials[i][j])
				{
					UnityEngine.Object.Destroy(material);
				}
			}
		}
		if (ghostableTexts != null && preGhostTextAlphas != null)
		{
			for (int k = 0; k < ghostableTexts.Length; k++)
			{
				if ((UnityEngine.Object)(object)ghostableTexts[k] != null)
				{
					ghostableTexts[k].alpha = preGhostTextAlphas[k];
				}
			}
		}
		preGhostMaterials = null;
		ghostInstances = null;
		preGhostTextAlphas = null;
	}
}
public enum PlayerLegPadState
{
	Idle,
	Butterfly,
	ButterflyExtended
}
public class PlayerLegPad : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float raycastDistance = 1f;

	[SerializeField]
	private float transitionDuration = 0.15f;

	[Space(20f)]
	[SerializeField]
	private LayerMask raycastLayerMask;

	[Header("References")]
	[SerializeField]
	private AYellowpaper.SerializedCollections.SerializedDictionary<PlayerLegPadState, Transform> positions = new AYellowpaper.SerializedCollections.SerializedDictionary<PlayerLegPadState, Transform>();

	private PlayerLegPadState state;

	private Vector3 localPosition = Vector3.zero;

	private float localYPosition;

	private Quaternion localRotation = Quaternion.identity;

	private Tween localPositionTween;

	private Tween localRotationTween;

	public PlayerLegPadState State
	{
		get
		{
			return state;
		}
		set
		{
			OnStateChanged(state, value);
			state = value;
		}
	}

	private void Awake()
	{
		localPosition = base.transform.localPosition;
		localRotation = base.transform.localRotation;
	}

	private void Update()
	{
		ShootLegPadRaycast();
		base.transform.localPosition = new Vector3(localPosition.x, localYPosition, localPosition.z);
		base.transform.localRotation = localRotation;
	}

	private void FixedUpdate()
	{
	}

	private void OnDestroy()
	{
		localPositionTween?.Kill();
		localRotationTween?.Kill();
	}

	public void ShootLegPadRaycast()
	{
		Vector3 vector = base.transform.parent.TransformPoint(localPosition);
		vector.y = base.transform.parent.position.y;
		vector += base.transform.parent.up;
		Vector3 vector2 = -base.transform.parent.up;
		UnityEngine.Debug.DrawRay(vector, vector2 * raycastDistance, Color.red);
		if (Physics.Raycast(vector, vector2, out var hitInfo, raycastDistance, raycastLayerMask))
		{
			localYPosition = base.transform.parent.InverseTransformPoint(hitInfo.point).y + localPosition.y;
		}
		else
		{
			localYPosition = base.transform.parent.InverseTransformPoint(vector + vector2 * raycastDistance).y + localPosition.y;
		}
	}

	private void OnStateChanged(PlayerLegPadState oldState, PlayerLegPadState newState)
	{
		localPositionTween?.Kill();
		localRotationTween?.Kill();
		if (oldState == PlayerLegPadState.Butterfly && newState == PlayerLegPadState.ButterflyExtended)
		{
			localPosition = positions[oldState].localPosition;
			localRotation = positions[oldState].localRotation;
		}
		localPositionTween = DOTween.To(() => localPosition, delegate(Vector3 value)
		{
			localPosition = value;
		}, positions[newState].localPosition, transitionDuration);
		localRotationTween = DOTween.To(PureQuaternionPlugin.Plug(), () => localRotation, delegate(Quaternion value)
		{
			localRotation = value;
		}, positions[newState].localRotation, transitionDuration);
	}
}
public class PlayerMesh : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float lookAtSpeed = 10f;

	[Header("References")]
	[SerializeField]
	private Transform groinBone;

	[SerializeField]
	private Transform torsoBone;

	[SerializeField]
	private Transform headBone;

	[SerializeField]
	public PlayerHead PlayerHead;

	[SerializeField]
	public PlayerTorso PlayerTorso;

	[SerializeField]
	public PlayerGroin PlayerGroin;

	[SerializeField]
	public PlayerLegPad PlayerLegPadLeft;

	[SerializeField]
	public PlayerLegPad PlayerLegPadRight;

	private MeshGhoster meshGhoster;

	private float stretch = 1f;

	private Vector3 initialGroinBonePosition;

	private Vector3 initialTorsoBonePosition;

	private Vector3 initialHeadBonePosition;

	public float Stretch
	{
		get
		{
			return stretch;
		}
		set
		{
			if (stretch != value)
			{
				stretch = value;
				OnStretchChanged();
			}
		}
	}

	private void Awake()
	{
		initialGroinBonePosition = groinBone.localPosition;
		initialTorsoBonePosition = torsoBone.localPosition;
		initialHeadBonePosition = headBone.localPosition;
		meshGhoster = GetComponent<MeshGhoster>();
	}

	public void SetTransparency(float strength)
	{
		if (meshGhoster != null)
		{
			meshGhoster.SetTransparency(strength);
		}
	}

	public void LookAt(Vector3 targetPosition, float deltaTime, bool rotateTorso = true, bool rotateHead = true)
	{
		Quaternion quaternion2 = Utils.GetLocalLookRotation(torsoBone, targetPosition);
		if (rotateTorso && rotateHead)
		{
			quaternion2 = Utils.GetLocalLookRotation(torsoBone, targetPosition);
			quaternion2 = Quaternion.Slerp(Quaternion.identity, quaternion2, 0.5f);
		}
		else if (rotateTorso)
		{
			quaternion2 = Utils.GetLocalLookRotation(torsoBone, targetPosition);
		}
		else if (rotateHead)
		{
			quaternion2 = Utils.GetLocalLookRotation(headBone, targetPosition);
		}
		Vector3 value = Utils.WrapEulerAngles(quaternion2.eulerAngles);
		value = Utils.Vector3Clamp(value, new Vector3(-11.25f, -45f, 0f), new Vector3(45f, 45f, 0f));
		if (rotateTorso)
		{
			torsoBone.localRotation = Quaternion.Lerp(torsoBone.localRotation, Quaternion.Euler(value), lookAtSpeed * deltaTime);
		}
		if (rotateHead)
		{
			headBone.localRotation = Quaternion.Lerp(headBone.localRotation, Quaternion.Euler(value), lookAtSpeed * deltaTime);
		}
	}

	public void SetUsername(string username)
	{
		PlayerTorso.SetUsername(username);
	}

	public void SetNumber(string number)
	{
		PlayerTorso.SetNumber(number);
	}

	public void SetLegsPadsActive(bool isActive)
	{
		PlayerLegPadLeft.gameObject.SetActive(isActive);
		PlayerLegPadRight.gameObject.SetActive(isActive);
	}

	public void SetFlagID(int flagID)
	{
		PlayerHead.SetFlagID(flagID);
	}

	public void SetHeadgearID(int headgearID, PlayerRole role)
	{
		PlayerHead.SetHeadgearID(headgearID, role);
	}

	public void SetMustacheID(int mustacheID)
	{
		PlayerHead.SetMustacheID(mustacheID);
	}

	public void SetBeardID(int beardID)
	{
		PlayerHead.SetBeardID(beardID);
	}

	public void SetJerseyID(int jerseyID, PlayerTeam team)
	{
		PlayerTorso.SetJerseyID(jerseyID, team);
		PlayerGroin.SetJerseyID(jerseyID, team);
	}

	private void OnStretchChanged()
	{
		groinBone.localPosition = initialGroinBonePosition * Stretch;
		torsoBone.localPosition = initialTorsoBonePosition * Stretch;
		headBone.localPosition = initialHeadBonePosition * Stretch;
	}
}
[Flags]
public enum JerseyTeam
{
	Blue = 1,
	Red = 2,
	Any = 4
}
[Serializable]
public class Jersey
{
	public int ID;

	public JerseyTeam Team;

	public Texture Texture;

	public bool IsForTeam(PlayerTeam team)
	{
		return team switch
		{
			PlayerTeam.Blue => (Team & JerseyTeam.Blue) != 0, 
			PlayerTeam.Red => (Team & JerseyTeam.Red) != 0, 
			_ => (Team & JerseyTeam.Any) != 0, 
		};
	}
}
[RequireComponent(typeof(MeshRendererTexturer))]
[ExecuteInEditMode]
public class PlayerTorso : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("PlayerTorso");

	[Header("Settings")]
	[SerializeField]
	private List<Jersey> jerseys = new List<Jersey>();

	[Header("References")]
	[SerializeField]
	private TMP_Text usernameText;

	[SerializeField]
	private TMP_Text numberText;

	private MeshRendererTexturer meshRendererTexturer;

	private void Awake()
	{
		meshRendererTexturer = GetComponent<MeshRendererTexturer>();
		if (ApplicationManager.IsDedicatedGameServer)
		{
			((UnityEngine.Component)(object)usernameText).gameObject.SetActive(value: false);
			((UnityEngine.Component)(object)numberText).gameObject.SetActive(value: false);
		}
	}

	public void SetUsername(string username)
	{
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			if (string.IsNullOrEmpty(username))
			{
				((UnityEngine.Component)(object)usernameText).gameObject.SetActive(value: false);
				return;
			}
			usernameText.text = username;
			((UnityEngine.Component)(object)usernameText).gameObject.SetActive(value: true);
		}
	}

	public void SetNumber(string number)
	{
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			if (string.IsNullOrEmpty(number))
			{
				((UnityEngine.Component)(object)numberText).gameObject.SetActive(value: false);
				return;
			}
			numberText.text = number;
			((UnityEngine.Component)(object)numberText).gameObject.SetActive(value: true);
		}
	}

	public void SetJerseyID(int jerseyID, PlayerTeam team)
	{
		Jersey jersey = jerseys.Find((Jersey j) => j.ID == jerseyID && j.IsForTeam(team));
		if (jersey == null)
		{
			Logger.Warning($"Tried to set invalid jerseyID {jerseyID} for team {team}");
		}
		else
		{
			meshRendererTexturer.SetTexture(jersey.Texture);
		}
	}
}
