[RequireComponent(typeof(Rigidbody))]
public class Skate : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float traction = 0.15f;

	[HideInInspector]
	public Rigidbody Rigidbody;

	[HideInInspector]
	public float Intensity = 1f;

	[HideInInspector]
	public bool IsTractionLost;

	[HideInInspector]
	public Transform MovementDirection;

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
	}

	private void FixedUpdate()
	{
		Vector3 vector = MovementDirection.InverseTransformVector(Rigidbody.linearVelocity);
		vector.y = 0f;
		vector.z = 0f;
		float num = 0f - vector.x;
		IsTractionLost = num > traction * Time.fixedDeltaTime;
		num = Mathf.Clamp(num, (0f - traction) * Time.fixedDeltaTime, traction * Time.fixedDeltaTime);
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.AddForce(MovementDirection.right * num * Intensity, ForceMode.VelocityChange);
		}
	}
}
[RequireComponent(typeof(Rigidbody))]
public class VelocityLean : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float linearForceMultiplier = 1f;

	[SerializeField]
	private float angularForceMultiplier = 6f;

	[HideInInspector]
	public Rigidbody Rigidbody;

	[HideInInspector]
	public float LinearIntensity = 1f;

	[HideInInspector]
	public float AngularIntensity = 1f;

	[HideInInspector]
	public bool Inverted;

	[HideInInspector]
	public bool UseWorldLinearVelocity;

	[HideInInspector]
	public Transform MovementDirection;

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
	}

	private void FixedUpdate()
	{
		float num = (UseWorldLinearVelocity ? Rigidbody.linearVelocity.magnitude : MovementDirection.InverseTransformVector(Rigidbody.linearVelocity).z);
		float y = MovementDirection.InverseTransformVector(Rigidbody.angularVelocity).y;
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.AddTorque(num * (Inverted ? (-base.transform.right) : base.transform.right) * linearForceMultiplier * LinearIntensity, ForceMode.Acceleration);
			Rigidbody.AddTorque((0f - y) * (Inverted ? (-base.transform.forward) : base.transform.forward) * angularForceMultiplier * AngularIntensity, ForceMode.Acceleration);
		}
	}
}
public class PlayerCamera : BaseCamera
{
	[HideInInspector]
	public NetworkVariable<NetworkObjectReference> PlayerReference;

	[HideInInspector]
	public Player Player;

	private bool isNetworkVariablesInitialized;

	[HideInInspector]
	public PlayerBody PlayerBody
	{
		get
		{
			if (!(Player == null))
			{
				return Player.PlayerBody;
			}
			return null;
		}
	}

	protected override void OnNetworkPreSpawn(ref NetworkManager networkManager)
	{
		InitializeNetworkVariables();
		base.OnNetworkPreSpawn(ref networkManager);
	}

	public override void OnNetworkSpawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Combine(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkSpawn();
	}

	protected override void OnNetworkPostSpawn()
	{
		NetworkObjectReference value = PlayerReference.Value;
		HandlePlayerReference(default(NetworkObjectReference), value);
		EventManager.TriggerEvent("Event_Everyone_OnPlayerCameraSpawned", new Dictionary<string, object> { { "playerCamera", this } });
		base.OnNetworkPostSpawn();
	}

	public override void OnNetworkDespawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Remove(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkDespawn();
	}

	public void InitializeNetworkVariables(NetworkObjectReference playerReference = default(NetworkObjectReference))
	{
		if (!isNetworkVariablesInitialized)
		{
			isNetworkVariablesInitialized = true;
			PlayerReference = new NetworkVariable<NetworkObjectReference>(playerReference);
		}
	}

	public override bool Enable()
	{
		bool num = base.Enable();
		if (num)
		{
			EventManager.TriggerEvent("Event_OnPlayerCameraEnabled", new Dictionary<string, object> { { "playerCamera", this } });
		}
		return num;
	}

	public override bool Disable()
	{
		bool num = base.Disable();
		if (num)
		{
			EventManager.TriggerEvent("Event_OnPlayerCameraDisabled", new Dictionary<string, object> { { "playerCamera", this } });
		}
		return num;
	}

	public override void OnTick(float deltaTime)
	{
		base.OnTick(deltaTime);
		if ((bool)Player)
		{
			PlayerInput playerInput = Player.PlayerInput;
			if ((bool)playerInput)
			{
				playerInput.UpdateLookAngle(deltaTime);
				base.transform.localRotation = Quaternion.Euler(Player.IsLocalPlayer ? playerInput.LookAngleInput.ClientValue : playerInput.LookAngleInput.ServerValue);
			}
		}
	}

	private void HandlePlayerReference(NetworkObjectReference oldPlayerReference = default(NetworkObjectReference), NetworkObjectReference newPlayerReference = default(NetworkObjectReference))
	{
		NetworkObject networkObject;
		Player player = (oldPlayerReference.TryGet(out networkObject) ? networkObject.GetComponent<Player>() : null);
		NetworkObject networkObject2;
		Player player2 = (newPlayerReference.TryGet(out networkObject2) ? networkObject2.GetComponent<Player>() : null);
		if ((bool)player)
		{
			player.PlayerCamera = null;
		}
		if ((bool)player2)
		{
			Player = player2;
			Player.PlayerCamera = this;
		}
		else
		{
			Player = null;
		}
	}

	private void OnPlayerReferenceChanged(NetworkObjectReference oldPlayerReference, NetworkObjectReference newPlayerReference)
	{
		HandlePlayerReference(oldPlayerReference, newPlayerReference);
	}

	protected override void __initializeVariables()
	{
		if (PlayerReference == null)
		{
			throw new Exception("PlayerCamera.PlayerReference cannot be null. All NetworkVariableBase instances must be initialized.");
		}
		PlayerReference.Initialize(this);
		__nameNetworkVariable(PlayerReference, "PlayerReference");
		NetworkVariableFields.Add(PlayerReference);
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "PlayerCamera";
	}
}
