	public void Server_ForceSynchronizeClientId(ulong clientId)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Server_MoveInputRpc(NetworkingUtils.CompressFloatToShort(MoveInput.ServerValue.x, -1f, 1f), NetworkingUtils.CompressFloatToShort(MoveInput.ServerValue.y, -1f, 1f), base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_RaycastOriginAngleInputRpc(NetworkingUtils.CompressFloatToShort(StickRaycastOriginAngleInput.ServerValue.x, minimumStickRaycastOriginAngle.x, maximumStickRaycastOriginAngle.x), NetworkingUtils.CompressFloatToShort(StickRaycastOriginAngleInput.ServerValue.y, minimumStickRaycastOriginAngle.y, maximumStickRaycastOriginAngle.y), base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_LookAngleInputRpc(NetworkingUtils.CompressFloatToShort(LookAngleInput.ServerValue.x, minimumLookAngle.x, maximumLookAngle.x), NetworkingUtils.CompressFloatToShort(LookAngleInput.ServerValue.y, minimumLookAngle.y, maximumLookAngle.y), base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_BladeAngleInputRpc(BladeAngleInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_SlideInputRpc(SlideInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_SprintInputRpc(SprintInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_TrackInputRpc(TrackInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_LookInputRpc(LookInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_ExtendLeftInputRpc(ExtendLeftInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_ExtendRightInputRpc(ExtendRightInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_LateralLeftInputRpc(LateralLeftInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_LateralRightInputRpc(LateralRightInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
			Server_TalkInputRpc(TalkInput.ServerValue, base.RpcTarget.Single(clientId, RpcTargetUse.Persistent));
		}
	}

