	public void Server_SpawnSpectatorCamera(Vector3 position, Quaternion rotation)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Logger.Info($"Spawning SpectatorCamera ({base.OwnerClientId})");
			if (IsCharacterSpawned)
			{
				Server_DespawnCharacter();
			}
			if (IsSpectatorCameraSpawned)
			{
				Server_DespawnSpectatorCamera();
			}
			SpectatorCamera spectatorCamera = UnityEngine.Object.Instantiate(spectatorCameraPrefab, position, rotation);
			spectatorCamera.InitializeNetworkVariables(new NetworkObjectReference(base.NetworkObject));
			spectatorCamera.PlayerReference.Value = new NetworkObjectReference(base.NetworkObject);
			spectatorCamera.NetworkObject.SpawnWithOwnership(base.OwnerClientId);
			if (!spectatorCamera.NetworkObject.TrySetParent(base.gameObject.transform))
			{
				Logger.Error($"Failed to set parent for SpectatorCamera ({base.OwnerClientId})");
			}
		}
	}

	public void Server_DespawnSpectatorCamera()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Logger.Info($"Despawning SpectatorCamera ({base.OwnerClientId})");
			if ((bool)SpectatorCamera && SpectatorCamera.NetworkObject.IsSpawned)
			{
				SpectatorCamera.NetworkObject.Despawn();
			}
		}
	}

	public void Server_GoalScored()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Goals.Value++;
		}
	}

	public void Server_AssistScored()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Assists.Value++;
		}
	}

	public void Server_ResetPoints()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Goals.Value = 0;
			Assists.Value = 0;
		}
	}

	public void Server_UpdatePing()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Ping.Value = NetworkManager.Singleton.NetworkConfig.NetworkTransport.GetCurrentRtt(base.OwnerClientId);
		}
	}

	public void Server_ConsumeChatTicket()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			ChatTickets = Mathf.Max(0f, ChatTickets - 1f);
		}
	}

