	private void Awake()
	{
		player = GetComponent<Player>();
	}

	public override void OnNetworkSpawn()
	{
		InputManager.PositionSelectAction.performed += OnPositionSelectActionPerformed;
		EventManager.AddEventListener("Event_OnTeamSelectClickTeam", Event_OnTeamSelectClickTeam);
		EventManager.AddEventListener("Event_OnPositionSelectClickPosition", Event_OnPositionSelectClickPosition);
		EventManager.AddEventListener("Event_OnPauseMenuClickSelectTeam", Event_OnPauseMenuClickSelectTeam);
		EventManager.AddEventListener("Event_OnPauseMenuClickSelectPosition", Event_OnPauseMenuClickSelectPosition);
		EventManager.AddEventListener("Event_OnPauseMenuClickForfeit", Event_OnPauseMenuClickForfeit);
		EventManager.AddEventListener("Event_OnHandednessChanged", Event_OnHandednessChanged);
		EventManager.AddEventListener("Event_Everyone_OnPlayerPositionClaimedByPlayerChanged", Event_Everyone_OnPlayerPositionClaimedByPlayerChanged);
		if (NetworkManager.Singleton.IsServer)
		{
			pingTween = DOVirtual.DelayedCall(1f, delegate
			{
				player.Server_UpdatePing();
			}).SetLoops(-1);
		}
		base.OnNetworkSpawn();
	}

	public override void OnNetworkDespawn()
	{
		InputManager.PositionSelectAction.performed -= OnPositionSelectActionPerformed;
		EventManager.RemoveEventListener("Event_OnTeamSelectClickTeam", Event_OnTeamSelectClickTeam);
		EventManager.RemoveEventListener("Event_OnPositionSelectClickPosition", Event_OnPositionSelectClickPosition);
		EventManager.RemoveEventListener("Event_OnPauseMenuClickSelectTeam", Event_OnPauseMenuClickSelectTeam);
		EventManager.RemoveEventListener("Event_OnPauseMenuClickSelectPosition", Event_OnPauseMenuClickSelectPosition);
		EventManager.RemoveEventListener("Event_OnPauseMenuClickForfeit", Event_OnPauseMenuClickForfeit);
		EventManager.RemoveEventListener("Event_OnHandednessChanged", Event_OnHandednessChanged);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerPositionClaimedByPlayerChanged", Event_Everyone_OnPlayerPositionClaimedByPlayerChanged);
		if (NetworkManager.Singleton.IsServer)
		{
			pingTween?.Kill();
		}
		base.OnNetworkDespawn();
	}

	private void OnPositionSelectActionPerformed(InputAction.CallbackContext context)
	{
		if (GlobalStateManager.UIState.Phase == UIPhase.Playing && !GlobalStateManager.UIState.IsInteracting && player.IsLocalPlayer)
		{
			player.Client_RequestPositionSelectRpc();
		}
	}

	private void Event_OnTeamSelectClickTeam(Dictionary<string, object> message)
	{
		PlayerTeam team = (PlayerTeam)message["team"];
		if (player.IsLocalPlayer)
		{
			player.Client_RequestTeamRpc(team);
		}
	}

	private void Event_OnPositionSelectClickPosition(Dictionary<string, object> message)
	{
		PlayerPosition playerPosition = (PlayerPosition)message["playerPosition"];
		if (player.IsLocalPlayer)
		{
			NetworkObjectReference playerPositionReference = new NetworkObjectReference(playerPosition.NetworkObject);
			player.Client_RequestClaimPositionRpc(playerPositionReference);
		}
	}

	private void Event_OnPauseMenuClickSelectTeam(Dictionary<string, object> message)
	{
		if (player.IsLocalPlayer)
		{
			player.Client_RequestTeamSelectRpc();
		}
	}

	private void Event_OnPauseMenuClickSelectPosition(Dictionary<string, object> message)
	{
		if (player.IsLocalPlayer)
		{
			player.Client_RequestPositionSelectRpc();
		}
	}

	private void Event_OnPauseMenuClickForfeit(Dictionary<string, object> message)
	{
		if (player.IsLocalPlayer)
		{
			player.Client_RequestForfeitRpc();
		}
	}

	private void Event_OnHandednessChanged(Dictionary<string, object> message)
	{
		PlayerHandedness handedness = (PlayerHandedness)message["value"];
		if (player.IsLocalPlayer)
		{
			player.Client_RequestHandednessRpc(handedness);
		}
	}

	private void Event_Everyone_OnPlayerPositionClaimedByPlayerChanged(Dictionary<string, object> message)
	{
		PlayerPosition playerPosition = (PlayerPosition)message["playerPosition"];
		Player player = (Player)message["oldClaimedByPlayer"];
		Player player2 = (Player)message["newClaimedByPlayer"];
		if (NetworkManager.Singleton.IsServer)
		{
			if (player2 == this.player)
			{
				this.player.PlayerPositionReference.Value = new NetworkObjectReference(playerPosition.NetworkObject);
			}
			else if (player == this.player && playerPosition == this.player.PlayerPosition)
			{
				this.player.PlayerPositionReference.Value = default(NetworkObjectReference);
			}
		}
	}

	protected override void __initializeVariables()
	{
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "PlayerController";
	}
}
public class RookieBotBrain : BotBrain
{
	public override void Tick(in BotContext context, BotInputDriver driver)
	{
		Player player = driver.Player;
		PlayerBody playerBody = player.PlayerBody;
		if ((bool)playerBody)
		{
			Puck targetPuck = context.TargetPuck;
			Vector3 position = playerBody.transform.position;
			Vector3 vector = (context.HasHomePosition ? context.HomePosition : position);
			Vector3 vector2 = (targetPuck ? targetPuck.transform.position : vector);
			Vector3 vector3;
			if (player.Role == PlayerRole.Goalie)
			{
				vector3 = vector;
				vector3.x += Mathf.Clamp(vector2.x - vector.x, -1.5f, 1.5f);
			}
			else if (context.IsClosestTeammateToPuck || !context.HasHomePosition)
			{
				vector3 = vector2;
			}
			else
			{
				Vector3 vector4 = new Vector3(Mathf.Sin(context.Seed * 7f), 0f, Mathf.Cos(context.Seed * 7f)) * 2f;
				vector3 = Vector3.Lerp(vector, vector2, 0.35f) + vector4;
			}
			Vector3 vector5 = vector3 - position;
			vector5.y = 0f;
			Vector3 toPuck = vector2 - position;
			toPuck.y = 0f;
			float magnitude = vector5.magnitude;
			if (magnitude < 1.5f)
			{
				driver.HoldFacing(vector2);
			}
			else
			{
				driver.MoveToward(vector3, magnitude > 8f);
			}
			driver.AimStickAt(targetPuck, toPuck, toPuck.magnitude);
		}
	}
}
[Flags]
public enum StickSkinTeam
{
	Blue = 1,
	Red = 2,
	Any = 4
}
[Serializable]
public class StickSkin
{
	public int ID;

	public StickSkinTeam Team;

	public Material Material;

	public bool IsForTeam(PlayerTeam team)
	{
		return team switch
		{
			PlayerTeam.Blue => (Team & StickSkinTeam.Blue) != 0, 
			PlayerTeam.Red => (Team & StickSkinTeam.Red) != 0, 
			_ => (Team & StickSkinTeam.Any) != 0, 
		};
	}
}
[Serializable]
public class StickTape
{
	public int ID;

	public Material Material;
}
public class StickMesh : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("StickMesh");

	[Header("Settings")]
	[SerializeField]
	private List<StickSkin> skins = new List<StickSkin>();

	[SerializeField]
	private List<StickTape> shaftTapes = new List<StickTape>();

	[SerializeField]
	private List<StickTape> bladeTapes = new List<StickTape>();

	[Header("References")]
	[SerializeField]
	private MeshRenderer stickMeshRenderer;

	[SerializeField]
	private GameObject shaftTapeGameObject;

	[SerializeField]
	private MeshRenderer shaftTapeMeshRenderer;

	[SerializeField]
	private GameObject bladeTapeGameObject;

	[SerializeField]
	private MeshRenderer bladeTapeMeshRenderer;

	[Space(20f)]
	[SerializeField]
	private Collider shaftCollider;

	[SerializeField]
	private Collider bladeCollider;

	[HideInInspector]
	public Collider ShaftCollider => shaftCollider;

	[HideInInspector]
	public Collider BladeCollider => bladeCollider;

	private void OnDestroy()
	{
		UnityEngine.Object.Destroy(stickMeshRenderer.material);
		UnityEngine.Object.Destroy(shaftTapeMeshRenderer.material);
		UnityEngine.Object.Destroy(bladeTapeMeshRenderer.material);
	}

	public void SetSkinID(int skinID, PlayerTeam team)
	{
		StickSkin stickSkin = skins.Find((StickSkin s) => s.ID == skinID && s.IsForTeam(team));
		if (stickSkin == null)
		{
			Logger.Warning($"Tried to set invalid skinID {skinID}");
		}
		else
		{
			Utils.SwapMaterial(stickMeshRenderer, stickSkin.Material);
		}
	}

	public void SetShaftTapeID(int shaftTapeID)
	{
		if (shaftTapeID == -1)
		{
			shaftTapeGameObject.SetActive(value: false);
			return;
		}
		StickTape stickTape = shaftTapes.Find((StickTape t) => t.ID == shaftTapeID && t.Material != null);
		if (stickTape == null)
		{
			Logger.Warning($"Tried to set invalid shaftTapeID {shaftTapeID}");
			return;
		}
		shaftTapeGameObject.SetActive(value: true);
		Utils.SwapMaterial(shaftTapeMeshRenderer, stickTape.Material);
	}

	public void SetBladeTapeID(int bladeTapeID)
	{
		if (bladeTapeID == -1)
		{
			bladeTapeGameObject.SetActive(value: false);
			return;
		}
		StickTape stickTape = bladeTapes.Find((StickTape t) => t.ID == bladeTapeID && t.Material != null);
		if (stickTape == null)
		{
			Logger.Warning($"Tried to set invalid bladeTapeID {bladeTapeID}");
			return;
		}
		bladeTapeGameObject.SetActive(value: true);
		Utils.SwapMaterial(bladeTapeMeshRenderer, stickTape.Material);
	}
}
public class Stick : NetworkBehaviour
{
	private static readonly Logger Logger = new Logger("Stick");

	[Header("Settings")]
	[SerializeField]
	private float bladeAngleStep = 12.5f;

	[Space(20f)]
	[SerializeField]
	private bool transferAngularVelocity = true;

	[SerializeField]
	private float angularVelocityTransferMultiplier = 0.25f;

	[Space(20f)]
	[SerializeField]
	private float shaftHandleProportionalGain = 500f;

	[SerializeField]
	private float shaftHandleIntegralGain;

	[SerializeField]
	private float shaftHandleIntegralSaturation;

	[SerializeField]
	private float shaftHandleDerivativeGain = 20f;

	[SerializeField]
	private float shaftHandleDerivativeSmoothing = 0.1f;

	[SerializeField]
	private float minShaftHandleProportionalGainMultiplier = 0.25f;

	[Space(20f)]
	[SerializeField]
	private float bladeHandleProportionalGain = 500f;

	[SerializeField]
	private float bladeHandleIntegralGain;

	[SerializeField]
	private float bladeHandleIntegralSaturation;

	[SerializeField]
	private float bladeHandleDerivativeGain = 20f;

	[SerializeField]
	private float bladeHandleDerivativeSmoothing = 0.1f;

	[Space(20f)]
	[SerializeField]
	private float linearVelocityTransferMultiplier = 0.25f;

	[Header("References")]
	[SerializeField]
	private GameObject shaftHandle;

	[SerializeField]
	private GameObject bladeHandle;

	[SerializeField]
	private GameObject rotationContainer;

	[SerializeField]
	private StickMesh stickMesh;

	[HideInInspector]
	public NetworkVariable<NetworkObjectReference> PlayerReference;

	[HideInInspector]
	public Player Player;

	[HideInInspector]
	public Rigidbody Rigidbody;

	[HideInInspector]
	public NetworkObjectCollisionRecorder NetworkObjectCollisionRecorder;

	[HideInInspector]
	public float Length;

	private bool isNetworkVariablesInitialized;

	private Vector3PIDController shaftHandlePIDController = new Vector3PIDController();

	private Vector3PIDController bladeHandlePIDController = new Vector3PIDController();

	private float shaftHandleProportionalGainMultiplier = 1f;

	private float bladeHandleProportionalGainMultiplier = 1f;

	private Vector3 shaftHandleForce = Vector3.zero;

	private Vector3 bladeHandleForce = Vector3.zero;

	[HideInInspector]
	public PlayerBody PlayerBody
	{
		get
		{
			if (!(Player == null))
			{
				return Player.PlayerBody;
			}
			return null;
		}
	}

	[HideInInspector]
	public StickPositioner StickPositioner
	{
		get
		{
			if (!(Player == null))
			{
				return Player.StickPositioner;
			}
			return null;
		}
	}

	[HideInInspector]
	public StickMesh StickMesh => stickMesh;

	[HideInInspector]
	public Vector3 ShaftHandleLocalPosition => shaftHandle.transform.localPosition;

	[HideInInspector]
	public Vector3 BladeHandleLocalPosition => bladeHandle.transform.localPosition;

	[HideInInspector]
	public Vector3 ShaftHandlePosition => shaftHandle.transform.position;

	[HideInInspector]
	public Vector3 BladeHandlePosition => bladeHandle.transform.position;

	[HideInInspector]
	public Quaternion BladeHandleRotation => bladeHandle.transform.rotation;

	[HideInInspector]
	public float BladeAngle
	{
		get
		{
			if (!(Player == null))
			{
				return (float)Player.PlayerInput.BladeAngleInput.ServerValue * bladeAngleStep;
			}
			return 0f;
		}
	}

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
		NetworkObjectCollisionRecorder = GetComponent<NetworkObjectCollisionRecorder>();
		Length = Vector3.Distance(ShaftHandlePosition, BladeHandlePosition);
	}

	protected override void OnNetworkPreSpawn(ref NetworkManager networkManager)
	{
		InitializeNetworkVariables();
		base.OnNetworkPreSpawn(ref networkManager);
	}

	public override void OnNetworkSpawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Combine(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkSpawn();
	}

	protected override void OnNetworkPostSpawn()
	{
		NetworkObjectReference value = PlayerReference.Value;
		HandlePlayerReference(default(NetworkObjectReference), value);
		EventManager.TriggerEvent("Event_Everyone_OnStickSpawned", new Dictionary<string, object> { { "stick", this } });
		base.OnNetworkPostSpawn();
	}

	public override void OnNetworkDespawn()
	{
		EventManager.TriggerEvent("Event_Everyone_OnStickDespawned", new Dictionary<string, object> { { "stick", this } });
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Remove(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkDespawn();
	}

	public override void OnDestroy()
	{
		base.transform.DOKill();
	}

	public void InitializeNetworkVariables(NetworkObjectReference playerReference = default(NetworkObjectReference))
	{
		if (!isNetworkVariablesInitialized)
		{
			isNetworkVariablesInitialized = true;
			PlayerReference = new NetworkVariable<NetworkObjectReference>(playerReference);
		}
	}

	private void FixedUpdate()
	{
		Server_FixedUpdate();
		if ((bool)Player)
		{
			float angle = (float)Player.PlayerInput.BladeAngleInput.ServerValue * bladeAngleStep;
			rotationContainer.transform.localRotation = Quaternion.AngleAxis(angle, Vector3.forward);
		}
	}

	public void ApplyCustomizations()
	{
		if (Player.Team != PlayerTeam.None && Player.Role != PlayerRole.None)
		{
			SetSkinID(Player.GetPlayerStickSkinID(), Player.Team);
			SetShaftTapeID(Player.GetPlayerStickShaftTapeID());
			SetBladeTapeID(Player.GetPlayerStickBladeTapeID());
		}
	}

	public void SetSkinID(int skinID, PlayerTeam team)
	{
		stickMesh.SetSkinID(skinID, team);
	}

	public void SetShaftTapeID(int shaftTapeID)
	{
		stickMesh.SetShaftTapeID(shaftTapeID);
	}

	public void SetBladeTapeID(int bladeTapeID)
	{
		stickMesh.SetBladeTapeID(bladeTapeID);
	}

	private void OnCollisionStay(Collision collision)
	{
		Server_OnCollisionStay(collision);
	}

	private void HandlePlayerReference(NetworkObjectReference oldPlayerReference = default(NetworkObjectReference), NetworkObjectReference newPlayerReference = default(NetworkObjectReference))
	{
		NetworkObject networkObject;
		Player player = (oldPlayerReference.TryGet(out networkObject) ? networkObject.GetComponent<Player>() : null);
		NetworkObject networkObject2;
		Player player2 = (newPlayerReference.TryGet(out networkObject2) ? networkObject2.GetComponent<Player>() : null);
		if ((bool)player)
		{
			player.Stick = null;
		}
		if ((bool)player2)
		{
			Player = player2;
			Player.Stick = this;
		}
		else
		{
			Player = null;
		}
		if ((bool)Player)
		{
			ApplyCustomizations();
			if (Player.IsReplay.Value)
			{
				Rigidbody.constraints = RigidbodyConstraints.FreezeAll;
				Rigidbody.interpolation = RigidbodyInterpolation.None;
			}
			else
			{
				Rigidbody.constraints = RigidbodyConstraints.None;
				Rigidbody.interpolation = RigidbodyInterpolation.Interpolate;
			}
		}
	}

	private void OnPlayerReferenceChanged(NetworkObjectReference oldPlayerReference, NetworkObjectReference newPlayerReference)
	{
		HandlePlayerReference(oldPlayerReference, newPlayerReference);
		EventManager.TriggerEvent("Event_Everyone_OnStickPlayerReferenceChanged", new Dictionary<string, object>
		{
			{ "stick", this },
			{ "oldPlayerReference", oldPlayerReference },
			{ "newPlayerReference", newPlayerReference }
		});
	}

	private void Server_FixedUpdate()
	{
		if (NetworkManager.Singleton.IsServer && (bool)Player && !Player.IsReplay.Value)
		{
			Server_UpdatePidControllers(Time.fixedDeltaTime);
			Server_ApplyForces();
			Server_ClearRollVelocity();
			Server_ResetRoll();
			Server_ApplyFeedbackForces();
			bladeHandleProportionalGainMultiplier = 1f;
		}
	}

	private void Server_UpdatePidControllers(float deltaTime)
	{
		if (NetworkManager.Singleton.IsServer && (bool)StickPositioner)
		{
			shaftHandlePIDController.proportionalGain = shaftHandleProportionalGain * shaftHandleProportionalGainMultiplier;
			shaftHandlePIDController.integralGain = shaftHandleIntegralGain;
			shaftHandlePIDController.integralSaturation = shaftHandleIntegralSaturation;
			shaftHandlePIDController.derivativeGain = shaftHandleDerivativeGain;
			shaftHandlePIDController.derivativeSmoothing = shaftHandleDerivativeSmoothing;
			bladeHandlePIDController.proportionalGain = bladeHandleProportionalGain * bladeHandleProportionalGainMultiplier;
			bladeHandlePIDController.integralGain = bladeHandleIntegralGain;
			bladeHandlePIDController.integralSaturation = bladeHandleIntegralSaturation;
			bladeHandlePIDController.derivativeGain = bladeHandleDerivativeGain;
			bladeHandlePIDController.derivativeSmoothing = bladeHandleDerivativeSmoothing;
			shaftHandleForce = shaftHandlePIDController.Update(deltaTime, ShaftHandlePosition, StickPositioner.ShaftTargetPosition);
			bladeHandleForce = bladeHandlePIDController.Update(deltaTime, BladeHandlePosition, StickPositioner.BladeTargetPosition);
		}
	}

	private void Server_ApplyForces()
	{
		if (NetworkManager.Singleton.IsServer && (bool)PlayerBody)
		{
			Rigidbody.AddForceAtPosition(PlayerBody.Rigidbody.GetPointVelocity(shaftHandle.transform.position) * linearVelocityTransferMultiplier * Time.fixedDeltaTime, shaftHandle.transform.position, ForceMode.VelocityChange);
			Rigidbody.AddForceAtPosition(PlayerBody.Rigidbody.GetPointVelocity(bladeHandle.transform.position) * linearVelocityTransferMultiplier * Time.fixedDeltaTime, bladeHandle.transform.position, ForceMode.VelocityChange);
			Rigidbody.AddForceAtPosition(shaftHandleForce * Time.fixedDeltaTime, ShaftHandlePosition, ForceMode.VelocityChange);
			Rigidbody.AddForceAtPosition(bladeHandleForce * Time.fixedDeltaTime, BladeHandlePosition, ForceMode.VelocityChange);
		}
	}

	private void Server_ClearRollVelocity()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Vector3 direction = base.transform.InverseTransformVector(Rigidbody.angularVelocity);
			direction.z = 0f;
			Rigidbody.angularVelocity = base.transform.TransformDirection(direction);
		}
	}

	private void Server_ResetRoll()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Vector3 vector = Utils.WrapEulerAngles(base.transform.eulerAngles);
			Quaternion rotation = Quaternion.Euler(new Vector3(vector.x, vector.y, 0f));
			Rigidbody.MoveRotation(rotation);
		}
	}

	private void Server_ApplyFeedbackForces()
	{
		if (NetworkManager.Singleton.IsServer && (bool)PlayerBody)
		{
			Vector3 vector = Vector3.Scale(Rigidbody.angularVelocity, new Vector3(0.5f, 1f, 0f)) * angularVelocityTransferMultiplier;
			if (transferAngularVelocity)
			{
				PlayerBody.Rigidbody.AddTorque(-vector, ForceMode.Acceleration);
			}
		}
	}

	public void Server_Teleport(Vector3 position, Quaternion rotation)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.position = position;
			Rigidbody.rotation = rotation;
			Rigidbody.linearVelocity = Vector3.zero;
			Rigidbody.angularVelocity = Vector3.zero;
			shaftHandlePIDController.Reset();
			bladeHandlePIDController.Reset();
		}
	}

	public void Server_Freeze(RigidbodyConstraints contstraints = RigidbodyConstraints.FreezeAll)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.constraints = contstraints;
		}
	}

	public void Server_Unfreeze()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			Rigidbody.constraints = RigidbodyConstraints.None;
		}
	}

	private void Server_OnCollisionStay(Collision collision)
	{
		if (NetworkManager.Singleton.IsServer && collision.gameObject.TryGetComponent<Stick>(out var component) && collision.contactCount != 0)
		{
			ContactPoint contact = collision.GetContact(0);
			Collider thisCollider = contact.thisCollider;
			Collider otherCollider = contact.otherCollider;
			if (thisCollider.CompareTag("Stick Blade") && otherCollider.CompareTag("Stick Shaft"))
			{
				Vector3 point = contact.point;
				float num = Mathf.Clamp(Vector3.Distance(component.ShaftHandlePosition, point) / Length, minShaftHandleProportionalGainMultiplier, 1f);
				bladeHandleProportionalGainMultiplier = num;
			}
		}
	}

	protected override void __initializeVariables()
	{
		if (PlayerReference == null)
		{
			throw new Exception("Stick.PlayerReference cannot be null. All NetworkVariableBase instances must be initialized.");
		}
		PlayerReference.Initialize(this);
		__nameNetworkVariable(PlayerReference, "PlayerReference");
		NetworkVariableFields.Add(PlayerReference);
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "Stick";
	}
}
public class StickController : NetworkBehaviour
{
	private Stick stick;

	private void Awake()
	{
		stick = GetComponent<Stick>();
	}

	public override void OnNetworkSpawn()
	{
		EventManager.AddEventListener("Event_Everyone_OnPlayerGameStateChanged", Event_Everyone_OnPlayerGameStateChanged);
		EventManager.AddEventListener("Event_Everyone_OnPlayerCustomizationStateChanged", Event_Everyone_OnPlayerCustomizationStateChanged);
		base.OnNetworkSpawn();
	}

	public override void OnNetworkDespawn()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerGameStateChanged", Event_Everyone_OnPlayerGameStateChanged);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerCustomizationStateChanged", Event_Everyone_OnPlayerCustomizationStateChanged);
		base.OnNetworkDespawn();
	}

	private void Event_Everyone_OnPlayerGameStateChanged(Dictionary<string, object> message)
	{
		Player player = (Player)message["player"];
		PlayerGameState playerGameState = (PlayerGameState)message["oldGameState"];
		PlayerGameState playerGameState2 = (PlayerGameState)message["newGameState"];
		if (base.OwnerClientId == player.OwnerClientId && (playerGameState.Team != playerGameState2.Team || playerGameState.Role != playerGameState2.Role))
		{
			stick.ApplyCustomizations();
		}
	}

	private void Event_Everyone_OnPlayerCustomizationStateChanged(Dictionary<string, object> message)
	{
		Player player = (Player)message["player"];
		if (base.OwnerClientId == player.OwnerClientId)
		{
			stick.ApplyCustomizations();
		}
	}

	protected override void __initializeVariables()
	{
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "StickController";
	}
}
public class StickPositioner : NetworkBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private float proportionalGain = 0.75f;

	[SerializeField]
	private float integralGain = 5f;

	[SerializeField]
	private float integralSaturation = 5f;

	[SerializeField]
	private DerivativeMeasurement derivativeMeasurement;

	[SerializeField]
	private float derivativeGain;

	[SerializeField]
	private float derivativeSmoothing;

	[SerializeField]
	private float outputMin = -15f;

	[SerializeField]
	private float outputMax = 15f;

	[Space(20f)]
	[SerializeField]
	private float maximumReach = 2.5f;

	[Space(20f)]
	[SerializeField]
	private float bladeTargetRotationThreshold = 25f;

	[SerializeField]
	private float bladeTargetMaxAngle = 45f;

	[Space(20f)]
	[SerializeField]
	private LayerMask raycastLayerMask;

	[Space(20f)]
	[SerializeField]
	private float raycastOriginPadding = 0.2f;

	[Space(20f)]
	[SerializeField]
	private bool applySoftCollision = true;

	[SerializeField]
	private float softCollisionForce = 1f;

	[Space(20f)]
	[SerializeField]
	private AnimationCurve windVolumeCurve;

	[SerializeField]
	private AnimationCurve windPitchCurve;

	[SerializeField]
	private AnimationCurve iceHitVolumeCurve;

	[SerializeField]
	private AnimationCurve iceHitPitchCurve;

	[SerializeField]
	private AnimationCurve iceDragVolumeCurve;

	[SerializeField]
	private AnimationCurve iceDragPitchCurve;

	[Header("References")]
	[SerializeField]
	private GameObject raycastOrigin;

	[SerializeField]
	private GameObject bladeTargetFocusPoint;

	[SerializeField]
	private GameObject bladeTarget;

	[SerializeField]
	private GameObject shaftTarget;

	[Space(20f)]
	[SerializeField]
	private SynchronizedAudio windAudioSource;

	[SerializeField]
	private SynchronizedAudio iceHitAudioSource;

	[SerializeField]
	private SynchronizedAudio iceDragAudioSource;

	[SerializeField]
	private float iceDragVolumeFallOffSpeed = 10f;

	[HideInInspector]
	public NetworkVariable<NetworkObjectReference> PlayerReference;

	[HideInInspector]
	public Player Player;

	[HideInInspector]
	public bool IsGrounded;

	[HideInInspector]
	public PlayerHandedness Handedness;

	private bool isNetworkVariablesInitialized;

	private Vector3 lastBladeTargetPosition = Vector3.zero;

	private Vector3 bladeTargetVelocity = Vector3.zero;

	private Vector3 bladeTargetFocusPointInitialLocalPosition = Vector3.zero;

	private Vector3 raycastOriginInitialLocalPosition = Vector3.zero;

	private Vector2 raycastOriginAngleTarget = Vector2.zero;

	private Vector2 raycastOriginAngle = Vector2.zero;

	private Vector2 raycastOriginAngleDelta = Vector3.zero;

	private float iceDragVolume;

	private float iceDragPitch;

	private Vector3PIDController pidController = new Vector3PIDController();

	[HideInInspector]
	public PlayerBody PlayerBody
	{
		get
		{
			if (!(Player == null))
			{
				return Player.PlayerBody;
			}
			return null;
		}
	}

	[HideInInspector]
	public Stick Stick
	{
		get
		{
			if (!(Player == null))
			{
				return Player.Stick;
			}
			return null;
		}
	}

	[HideInInspector]
	public Vector3 BladeTargetPosition => bladeTarget.transform.position;

	[HideInInspector]
	public Vector3 BladeTargetVelocity => bladeTargetVelocity;

	[HideInInspector]
	public Vector3 ShaftTargetPosition => shaftTarget.transform.position;

	[HideInInspector]
	public Vector3 RaycastOriginPosition => raycastOrigin.transform.position;

	private Vector3 BladeTargetFocusPointInitialLocalPosition
	{
		get
		{
			if (Handedness != PlayerHandedness.Left)
			{
				return bladeTargetFocusPointInitialLocalPosition;
			}
			return new Vector3(0f - bladeTargetFocusPointInitialLocalPosition.x, bladeTargetFocusPointInitialLocalPosition.y, bladeTargetFocusPointInitialLocalPosition.z);
		}
	}

	private Vector3 RaycastOriginInitialLocalPosition
	{
		get
		{
			if (Handedness != PlayerHandedness.Left)
			{
				return raycastOriginInitialLocalPosition;
			}
			return new Vector3(0f - raycastOriginInitialLocalPosition.x, raycastOriginInitialLocalPosition.y, raycastOriginInitialLocalPosition.z);
		}
	}

	private void Awake()
	{
		bladeTargetFocusPointInitialLocalPosition = bladeTargetFocusPoint.transform.localPosition;
		raycastOriginInitialLocalPosition = raycastOrigin.transform.localPosition;
	}

	protected override void OnNetworkPreSpawn(ref NetworkManager networkManager)
	{
		InitializeNetworkVariables();
		base.OnNetworkPreSpawn(ref networkManager);
	}

	public override void OnNetworkSpawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Combine(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkSpawn();
	}

	protected override void OnNetworkPostSpawn()
	{
		NetworkObjectReference value = PlayerReference.Value;
		HandlePlayerReference(default(NetworkObjectReference), value);
		EventManager.TriggerEvent("Event_Everyone_OnStickPositionerSpawned", new Dictionary<string, object> { { "stickPositioner", this } });
		base.OnNetworkPostSpawn();
	}

	public override void OnNetworkDespawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Remove(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkDespawn();
	}

	public void InitializeNetworkVariables(NetworkObjectReference playerReference = default(NetworkObjectReference))
	{
		if (!isNetworkVariablesInitialized)
		{
			isNetworkVariablesInitialized = true;
			PlayerReference = new NetworkVariable<NetworkObjectReference>(playerReference);
		}
	}

	private void FixedUpdate()
	{
		if ((bool)Player)
		{
			pidController.proportionalGain = proportionalGain;
			pidController.integralGain = integralGain;
			pidController.integralSaturation = integralSaturation;
			pidController.derivativeMeasurement = derivativeMeasurement;
			pidController.derivativeGain = derivativeGain;
			pidController.derivativeSmoothing = derivativeSmoothing;
			pidController.outputMin = outputMin;
			pidController.outputMax = outputMax;
			raycastOriginAngleTarget = Player.PlayerInput.StickRaycastOriginAngleInput.ServerValue;
			ShootPaddingRay();
			RotateRaycastOrigin();
			ShootRaycast();
			UpdateAudio();
		}
	}

	private void ShootPaddingRay()
	{
		Vector3 vector = new Vector3(0f, RaycastOriginInitialLocalPosition.y, 0f);
		Vector3 normalized = (RaycastOriginInitialLocalPosition - vector).normalized;
		float num = Vector3.Distance(vector, RaycastOriginInitialLocalPosition) + raycastOriginPadding;
		Vector3 vector2 = base.transform.TransformPoint(vector);
		Vector3 vector3 = base.transform.TransformDirection(normalized);
		UnityEngine.Debug.DrawRay(vector2, vector3 * num, Color.yellow);
		if (Physics.Raycast(vector2, vector3, out var hitInfo, num, raycastLayerMask))
		{
			raycastOrigin.transform.localPosition = vector + normalized * (hitInfo.distance - raycastOriginPadding);
		}
		else
		{
			raycastOrigin.transform.localPosition = RaycastOriginInitialLocalPosition;
		}
	}

	private void RotateRaycastOrigin()
	{
		raycastOriginAngleDelta = pidController.Update(Time.fixedDeltaTime, raycastOriginAngle, raycastOriginAngleTarget);
		raycastOriginAngle += raycastOriginAngleDelta * Time.fixedDeltaTime;
		raycastOrigin.transform.localRotation = Quaternion.Euler(raycastOriginAngle);
	}

	private void ShootRaycast()
	{
		Vector3 hitPosition;
		if (Physics.Raycast(raycastOrigin.transform.position, raycastOrigin.transform.forward, out var hitInfo, maximumReach, raycastLayerMask))
		{
			OnGrounded(hitInfo.transform.gameObject);
			Vector3 vector = raycastOrigin.transform.position + raycastOrigin.transform.forward * maximumReach;
			Vector3 vector2 = Vector3.Scale(Utils.Vector3Abs(hitInfo.normal), hitInfo.point);
			Vector3 vector3 = vector - Vector3.Scale(Utils.Vector3Abs(hitInfo.normal), vector) + vector2;
			UnityEngine.Debug.DrawRay(raycastOrigin.transform.position, raycastOrigin.transform.forward * hitInfo.distance, Color.red);
			Vector3 normalized = (vector3 - raycastOrigin.transform.position).normalized;
			if (Physics.Raycast(raycastOrigin.transform.position, normalized, out var hitInfo2, maximumReach, raycastLayerMask))
			{
				Vector3 vector4 = raycastOrigin.transform.position + raycastOrigin.transform.forward * maximumReach;
				Vector3 vector5 = Vector3.Scale(Utils.Vector3Abs(hitInfo2.normal), hitInfo2.point);
				Vector3 vector6 = vector4 - Vector3.Scale(Utils.Vector3Abs(hitInfo2.normal), vector4) + vector5;
				if (hitInfo.normal == Vector3.up && hitInfo2.normal == Vector3.up)
				{
					hitPosition = vector3;
				}
				else if (hitInfo.normal == Vector3.up && hitInfo2.normal != Vector3.up)
				{
					hitPosition = vector6;
					hitPosition.y = Mathf.Max(0f, hitPosition.y);
				}
				else
				{
					hitPosition = vector3;
					hitPosition.y = Mathf.Max(0f, hitPosition.y);
				}
				UnityEngine.Debug.DrawRay(raycastOrigin.transform.position, normalized * hitInfo2.distance, Color.blue);
			}
			else
			{
				hitPosition = hitInfo.point;
			}
			ApplySoftCollision(hitInfo, hitPosition);
		}
		else
		{
			OnUngrounded();
			hitPosition = raycastOrigin.transform.position + raycastOrigin.transform.forward * maximumReach;
			UnityEngine.Debug.DrawRay(raycastOrigin.transform.position, raycastOrigin.transform.forward * maximumReach, Color.red);
		}
		PositionBladeTarget(hitPosition);
		PositionBladeTargetFocusPoint(hitPosition);
		RotateBladeTargetFocusPoint();
	}

	private void PositionBladeTarget(Vector3 hitPosition)
	{
		bladeTarget.transform.position = hitPosition;
		bladeTarget.transform.rotation = Quaternion.LookRotation(bladeTarget.transform.position - bladeTargetFocusPoint.transform.position);
		bladeTargetVelocity = (bladeTarget.transform.position - lastBladeTargetPosition) / Time.fixedDeltaTime;
		lastBladeTargetPosition = bladeTarget.transform.position;
	}

	private void PositionBladeTargetFocusPoint(Vector3 hitPosition)
	{
		float num = Vector3.Distance(raycastOrigin.transform.position, new Vector3(hitPosition.x, raycastOrigin.transform.position.y, hitPosition.z));
		float num2 = maximumReach - num;
		Vector3 vector = raycastOrigin.transform.localPosition - base.transform.InverseTransformPoint(hitPosition);
		Vector3 normalized = new Vector3(vector.x, 0f, vector.z).normalized;
		Vector3 vector2 = base.transform.TransformDirection(normalized);
		UnityEngine.Debug.DrawRay(bladeTargetFocusPoint.transform.position, -vector2 * num2, Color.grey);
		Vector3 vector3 = normalized * num2;
		bladeTargetFocusPoint.transform.localPosition = BladeTargetFocusPointInitialLocalPosition + vector3;
	}

	private void RotateBladeTargetFocusPoint()
	{
		PlayerInput playerInput = Player.PlayerInput;
		if ((bool)playerInput)
		{
			float num = Mathf.Lerp(1f, 0f, (playerInput.MaximumStickRaycastOriginAngle.x - raycastOriginAngle.x) / bladeTargetRotationThreshold);
			num *= (float)((Handedness != PlayerHandedness.Left) ? 1 : (-1));
			bladeTargetFocusPoint.transform.localPosition = Utils.RotatePointAroundPivot(bladeTargetFocusPoint.transform.localPosition, bladeTarget.transform.localPosition, new Vector3(0f, bladeTargetMaxAngle * num, 0f));
		}
	}

	public void PrepareShaftTarget(Stick stick)
	{
		shaftTarget.transform.localPosition = stick.ShaftHandleLocalPosition - stick.BladeHandleLocalPosition;
	}

	private void ApplySoftCollision(RaycastHit hit, Vector3 hitPosition)
	{
		if (applySoftCollision && (bool)PlayerBody && hit.collider.CompareTag("Soft Collider"))
		{
			float num = maximumReach - hit.distance;
			float magnitude = Vector3.Cross(hit.normal, raycastOrigin.transform.forward).magnitude;
			float num2 = 1f - magnitude;
			UnityEngine.Debug.DrawRay(hitPosition, hit.normal * num * softCollisionForce, Color.green);
			PlayerBody.Rigidbody.AddForceAtPosition(hit.normal * num * (softCollisionForce * num2), hitPosition, ForceMode.Acceleration);
		}
	}

	private void UpdateAudio()
	{
		windAudioSource.transform.position = BladeTargetPosition;
		iceHitAudioSource.transform.position = BladeTargetPosition;
		iceDragAudioSource.transform.position = BladeTargetPosition;
		if ((bool)PlayerBody && PlayerBody.Rigidbody.constraints != RigidbodyConstraints.None && (bool)PlayerBody.Player && !PlayerBody.Player.IsReplay.Value)
		{
			windAudioSource.Server_SetVolume(0f);
			iceDragAudioSource.Server_SetVolume(0f);
			return;
		}
		float num = (IsGrounded ? iceDragVolumeCurve.Evaluate(BladeTargetVelocity.magnitude) : 0f);
		if (num > iceDragVolume)
		{
			iceDragVolume = num;
		}
		else
		{
			iceDragVolume = Mathf.Lerp(iceDragVolume, num, Time.fixedDeltaTime * iceDragVolumeFallOffSpeed);
		}
		iceDragPitch = iceDragPitchCurve.Evaluate(BladeTargetVelocity.magnitude);
		iceDragAudioSource.Server_SetVolume(iceDragVolume);
		iceDragAudioSource.Server_SetPitch(iceDragPitch);
		float volume = windVolumeCurve.Evaluate(raycastOriginAngleDelta.magnitude);
		float pitch = windPitchCurve.Evaluate(raycastOriginAngleDelta.magnitude);
		windAudioSource.Server_SetVolume(volume);
		windAudioSource.Server_SetPitch(pitch);
	}

	private void OnGrounded(GameObject ground)
	{
		if (!IsGrounded)
		{
			if (ground.layer == LayerMask.NameToLayer("Ice"))
			{
				float volume = iceHitVolumeCurve.Evaluate(Mathf.Abs(raycastOriginAngleDelta.x));
				float pitch = iceHitPitchCurve.Evaluate(Mathf.Abs(raycastOriginAngleDelta.x));
				iceHitAudioSource.Server_Play(volume, pitch, isOneShot: true, -1, 0f, randomClip: true);
			}
			IsGrounded = true;
		}
	}

	private void OnUngrounded()
	{
		if (IsGrounded)
		{
			IsGrounded = false;
		}
	}

	private void HandlePlayerReference(NetworkObjectReference oldPlayerReference = default(NetworkObjectReference), NetworkObjectReference newPlayerReference = default(NetworkObjectReference))
	{
		NetworkObject networkObject;
		Player player = (oldPlayerReference.TryGet(out networkObject) ? networkObject.GetComponent<Player>() : null);
		NetworkObject networkObject2;
		Player player2 = (newPlayerReference.TryGet(out networkObject2) ? networkObject2.GetComponent<Player>() : null);
		if ((bool)player)
		{
			player.StickPositioner = null;
		}
		if ((bool)player2)
		{
			Player = player2;
			Player.StickPositioner = this;
		}
		else
		{
			Player = null;
		}
		if ((bool)Player)
		{
			if ((bool)Player.Stick)
			{
				PrepareShaftTarget(Player.Stick);
			}
			Handedness = Player.Handedness.Value;
		}
	}

	private void OnPlayerReferenceChanged(NetworkObjectReference oldPlayerReference, NetworkObjectReference newPlayerReference)
	{
		HandlePlayerReference(oldPlayerReference, newPlayerReference);
	}

	protected override void __initializeVariables()
	{
		if (PlayerReference == null)
		{
			throw new Exception("StickPositioner.PlayerReference cannot be null. All NetworkVariableBase instances must be initialized.");
		}
		PlayerReference.Initialize(this);
		__nameNetworkVariable(PlayerReference, "PlayerReference");
		NetworkVariableFields.Add(PlayerReference);
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "StickPositioner";
	}
}
