public class ReplayTouchTracker : MonoBehaviour
{
	private HashSet<ulong> activeContactObjectIds = new HashSet<ulong>();

	private Dictionary<Player, float> lastContactTimeByPlayer = new Dictionary<Player, float>();

	public IReadOnlyDictionary<Player, float> LastContactTimeByPlayer => lastContactTimeByPlayer;

	private void OnCollisionEnter(Collision collision)
	{
		RecordContact(collision.gameObject, entering: true);
	}

	private void OnCollisionExit(Collision collision)
	{
		RecordContact(collision.gameObject, entering: false);
	}

	private void RecordContact(GameObject collisionObject, bool entering)
	{
		if (!NetworkManager.Singleton.IsServer || !collisionObject.TryGetComponent<NetworkObject>(out var component))
		{
			return;
		}
		Player player = ResolvePlayer(component);
		if ((bool)player)
		{
			if (entering)
			{
				activeContactObjectIds.Add(component.NetworkObjectId);
			}
			else
			{
				activeContactObjectIds.Remove(component.NetworkObjectId);
			}
			lastContactTimeByPlayer[player] = Time.time;
		}
	}

	private static Player ResolvePlayer(NetworkObject networkObject)
	{
		if (networkObject.TryGetComponent<PlayerBody>(out var component))
		{
			return component.Player;
		}
		if (networkObject.TryGetComponent<Stick>(out var component2))
		{
			return component2.Player;
		}
		return null;
	}

	public bool IsActivelyTouching(NetworkObject networkObject)
	{
		if (networkObject == null)
		{
			return false;
		}
		activeContactObjectIds.RemoveWhere((ulong id) => !NetworkManager.Singleton.SpawnManager.SpawnedObjects.ContainsKey(id));
		return activeContactObjectIds.Contains(networkObject.NetworkObjectId);
	}
}
public class PuckCollisionDetectionModeSwitcher : MonoBehaviour
{
	[HideInInspector]
	public Rigidbody Rigidbody;

	[HideInInspector]
	public bool IsContactingStick;

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
		Utils.SetRigidbodyCollisionDetectionMode(Rigidbody, CollisionDetectionMode.ContinuousDynamic);
	}

	private void FixedUpdate()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			if (IsContactingStick)
			{
				Utils.SetRigidbodyCollisionDetectionMode(Rigidbody, CollisionDetectionMode.ContinuousSpeculative);
			}
			else
			{
				Utils.SetRigidbodyCollisionDetectionMode(Rigidbody, CollisionDetectionMode.ContinuousDynamic);
			}
			IsContactingStick = false;
		}
	}

	private void OnCollisionEnter(Collision collision)
	{
		if (collision.gameObject.TryGetComponent<Stick>(out var _))
		{
			IsContactingStick = true;
			Utils.SetRigidbodyCollisionDetectionMode(Rigidbody, CollisionDetectionMode.ContinuousSpeculative);
		}
	}

	private void OnCollisionStay(Collision collision)
	{
		if (collision.gameObject.TryGetComponent<Stick>(out var _))
		{
			IsContactingStick = true;
			Utils.SetRigidbodyCollisionDetectionMode(Rigidbody, CollisionDetectionMode.ContinuousSpeculative);
		}
	}

	public void OnDrawGizmos()
	{
		if (Application.isEditor)
		{
			if ((bool)Rigidbody)
			{
				Gizmos.color = ((Rigidbody.collisionDetectionMode == CollisionDetectionMode.ContinuousSpeculative) ? Color.red : Color.green);
			}
			Gizmos.DrawWireSphere(base.transform.position, 0.5f);
		}
	}
}
public class ReplayCamera : BaseCamera
{
	[Header("Settings")]
	[SerializeField]
	private float followSpeed = 10f;

	[SerializeField]
	private float followDistance = 5f;

	[SerializeField]
	private float followHeight = 5f;

	[SerializeField]
	private float rotationSpeed = 10f;

	[Header("Celly Cam")]
	[SerializeField]
	private float cellyCamFollowSpeed = 2f;

	[SerializeField]
	private float cellyCamRotationSpeed = 2f;

	[HideInInspector]
	public Transform Target;

	[HideInInspector]
	public Vector3 CenterPoint = Vector3.zero;

	[HideInInspector]
	public bool IsCellyCam;

	public override void OnTick(float deltaTime)
	{
		base.OnTick(deltaTime);
		if ((bool)Target)
		{
			float num = (IsCellyCam ? cellyCamFollowSpeed : followSpeed);
			float num2 = (IsCellyCam ? cellyCamRotationSpeed : rotationSpeed);
			Vector3 normalized = (CenterPoint - Target.position).normalized;
			Vector3 b = Target.position + normalized * followDistance;
			b.y = followHeight;
			base.transform.position = Vector3.Lerp(base.transform.position, b, deltaTime * num);
			base.transform.rotation = Quaternion.Slerp(base.transform.rotation, Quaternion.LookRotation(Target.position - base.transform.position), deltaTime * num2);
		}
	}

	protected override void __initializeVariables()
	{
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "ReplayCamera";
	}
}
public class ReplayCameraController : BaseCameraController
{
	private ReplayCamera replayCamera;

	public override void Awake()
	{
		base.Awake();
		replayCamera = GetComponent<ReplayCamera>();
		EventManager.AddEventListener("Event_Everyone_OnPuckSpawned", Event_Everyone_OnPuckSpawned);
		EventManager.AddEventListener("Event_Everyone_OnReplayCellyCam", Event_Everyone_OnReplayCellyCam);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnPuckSpawned", Event_Everyone_OnPuckSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnReplayCellyCam", Event_Everyone_OnReplayCellyCam);
		base.OnDestroy();
	}

	private void Event_Everyone_OnPuckSpawned(Dictionary<string, object> message)
	{
		Puck puck = (Puck)message["puck"];
		replayCamera.IsCellyCam = false;
		replayCamera.Target = puck.transform;
	}

	private void Event_Everyone_OnReplayCellyCam(Dictionary<string, object> message)
	{
		ulong clientId = (ulong)message["scorerClientId"];
		Player replayPlayerByClientId = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(clientId);
		if ((bool)replayPlayerByClientId && (bool)replayPlayerByClientId.PlayerBody)
		{
			replayCamera.IsCellyCam = true;
			replayCamera.Target = replayPlayerByClientId.PlayerBody.transform;
		}
	}
}
