public class ScoreboardController : MonoBehaviour
{
	private Scoreboard scoreboard;

	private void Awake()
	{
		scoreboard = GetComponent<Scoreboard>();
		EventManager.AddEventListener("Event_Everyone_OnGameStateChanged", Event_Everyone_OnGameStateChanged);
	}

	private void Start()
	{
		scoreboard.TurnOff();
	}

	private void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnGameStateChanged", Event_Everyone_OnGameStateChanged);
	}

	private void Event_Everyone_OnGameStateChanged(Dictionary<string, object> message)
	{
		GameState gameState = (GameState)message["newGameState"];
		GamePhase phase = gameState.Phase;
		if ((uint)(phase - 2) <= 8u)
		{
			scoreboard.TurnOn();
		}
		else
		{
			scoreboard.TurnOff();
		}
		scoreboard.SetTick(gameState.Tick);
		scoreboard.SetPeriod(gameState.Period);
		scoreboard.SetBlueScore(gameState.BlueScore);
		scoreboard.SetRedScore(gameState.RedScore);
	}
}
public class SmoothPositioner : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("SmoothPositioner");

	[Header("Settings")]
	[SerializeField]
	private AYellowpaper.SerializedCollections.SerializedDictionary<string, Transform> positions = new AYellowpaper.SerializedCollections.SerializedDictionary<string, Transform>();

	[SerializeField]
	private string initialPosition;

	[SerializeField]
	private float transitionDuration = 0.5f;

	[SerializeField]
	private Ease transitionEase = Ease.Linear;

	private string currentPosition;

	private Tween positionTween;

	private Tween rotationTween;

	private void Start()
	{
		SetPosition(initialPosition, instant: true);
	}

	private void OnDestroy()
	{
		positionTween?.Kill();
		rotationTween?.Kill();
	}

	public void SetPosition(string positionName, bool instant = false)
	{
		if (!positions.ContainsKey(positionName))
		{
			Logger.Error("Target position " + positionName + " does not exist");
			return;
		}
		if (instant)
		{
			positionTween?.Kill();
			rotationTween?.Kill();
			base.transform.position = positions[positionName].position;
			base.transform.rotation = positions[positionName].rotation;
		}
		else
		{
			if (currentPosition == positionName)
			{
				return;
			}
			positionTween?.Kill();
			rotationTween?.Kill();
			positionTween = base.transform.DOMove(positions[positionName].position, transitionDuration).SetEase(transitionEase);
			rotationTween = base.transform.DORotateQuaternion(positions[positionName].rotation, transitionDuration).SetEase(transitionEase);
		}
		currentPosition = positionName;
	}

	private void OnDrawGizmos()
	{
		if (!Application.isEditor)
		{
			return;
		}
		foreach (KeyValuePair<string, Transform> position in positions)
		{
			_ = position.Key;
			Transform value = position.Value;
			Gizmos.color = Color.black;
			Gizmos.DrawSphere(value.position, 0.05f);
			Gizmos.matrix = value.localToWorldMatrix;
			Gizmos.DrawFrustum(Vector3.zero, 60f, 1f, 0f, 1f);
			Gizmos.matrix = Matrix4x4.identity;
			Gizmos.color = Color.green;
			Gizmos.DrawLine(value.position, value.position + value.forward * 1f);
		}
	}
}
public class SoftCollider : MonoBehaviour
{
	[Header("Settings")]
	[SerializeField]
	private Vector3 localOrigin = Vector3.zero;

	[SerializeField]
	private LayerMask layerMask;

	[SerializeField]
	private float distance = 0.5f;

	[SerializeField]
	private float force = 10f;

	[HideInInspector]
	public float Intensity = 1f;

	[HideInInspector]
	public Rigidbody Rigidbody;

	private readonly HashSet<Rigidbody> ignoredRigidbodies = new HashSet<Rigidbody>();

	private Vector3 worldOrigin = Vector3.zero;

	private readonly Vector3[] rayDirections = new Vector3[4];

	private void Awake()
	{
		Rigidbody = GetComponent<Rigidbody>();
	}

	public void SetSoftCollisionIgnored(Rigidbody other, bool ignored)
	{
		if (ignored && other != null)
		{
			ignoredRigidbodies.Add(other);
		}
		else
		{
			ignoredRigidbodies.Remove(other);
		}
		ignoredRigidbodies.RemoveWhere((Rigidbody rigidbody) => rigidbody == null);
	}

	private void FixedUpdate()
	{
		worldOrigin = base.transform.TransformPoint(localOrigin);
		Vector3 forward = base.transform.forward;
		Vector3 right = base.transform.right;
		rayDirections[0] = (forward + right).normalized;
		rayDirections[1] = (forward - right).normalized;
		rayDirections[2] = (-forward + right).normalized;
		rayDirections[3] = (-forward - right).normalized;
		Vector3[] array = rayDirections;
		foreach (Vector3 vector in array)
		{
			UnityEngine.Debug.DrawRay(worldOrigin, vector * distance, Color.black);
			if (Physics.Raycast(worldOrigin, vector, out var hitInfo, distance, layerMask) && (!(hitInfo.rigidbody != null) || !ignoredRigidbodies.Contains(hitInfo.rigidbody)))
			{
				UnityEngine.Debug.DrawRay(worldOrigin, vector * hitInfo.distance, Color.white);
				float num = distance - hitInfo.distance;
				float magnitude = Vector3.Cross(hitInfo.normal, vector).magnitude;
				float num2 = 1f - magnitude;
				UnityEngine.Debug.DrawRay(hitInfo.point, hitInfo.normal * num * force, Color.green);
				Rigidbody.AddForceAtPosition(hitInfo.normal * num * (force * num2), hitInfo.point, ForceMode.Acceleration);
			}
		}
	}
}
public class SpectatorCamera : BaseCamera
{
	[Header("Movement Settings")]
	[SerializeField]
	private float movementSpeed = 5f;

	[SerializeField]
	private float positionSmoothTime = 0.25f;

	[SerializeField]
	private float lookSmoothing = 10f;

	[SerializeField]
	private float pitchMin = -89f;

	[SerializeField]
	private float pitchMax = 89f;

	[HideInInspector]
	public NetworkVariable<NetworkObjectReference> PlayerReference;

	[HideInInspector]
	public Player Player;

	private Vector3 position = Vector3.zero;

	private Vector3 positionVelocity = Vector3.zero;

	private float pitch;

	private float yaw;

	private float targetPitch;

	private float targetYaw;

	private bool isNetworkVariablesInitialized;

	protected override void OnNetworkPreSpawn(ref NetworkManager networkManager)
	{
		InitializeNetworkVariables();
		base.OnNetworkPreSpawn(ref networkManager);
	}

	public override void OnNetworkSpawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Combine(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkSpawn();
	}

	protected override void OnNetworkPostSpawn()
	{
		position = base.transform.position;
		pitch = base.transform.eulerAngles.x;
		yaw = base.transform.eulerAngles.y;
		targetPitch = pitch;
		targetYaw = yaw;
		NetworkObjectReference value = PlayerReference.Value;
		HandlePlayerReference(default(NetworkObjectReference), value);
		EventManager.TriggerEvent("Event_Everyone_OnSpectatorCameraSpawned", new Dictionary<string, object> { { "spectatorCamera", this } });
		base.OnNetworkPostSpawn();
	}

	public override void OnNetworkDespawn()
	{
		NetworkVariable<NetworkObjectReference> playerReference = PlayerReference;
		playerReference.OnValueChanged = (NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate)Delegate.Remove(playerReference.OnValueChanged, new NetworkVariable<NetworkObjectReference>.OnValueChangedDelegate(OnPlayerReferenceChanged));
		base.OnNetworkDespawn();
	}

	public void InitializeNetworkVariables(NetworkObjectReference playerReference = default(NetworkObjectReference))
	{
		if (!isNetworkVariablesInitialized)
		{
			isNetworkVariablesInitialized = true;
			PlayerReference = new NetworkVariable<NetworkObjectReference>(playerReference);
		}
	}

	public override void OnTick(float deltaTime)
	{
		base.OnTick(deltaTime);
		if (base.IsOwner)
		{
			float num = (InputManager.TurnRightAction.IsPressed() ? 1 : 0) + (InputManager.TurnLeftAction.IsPressed() ? (-1) : 0);
			float num2 = (InputManager.JumpAction.IsPressed() ? 1 : (InputManager.SlideAction.IsPressed() ? (-1) : 0));
			float num3 = (InputManager.MoveForwardAction.IsPressed() ? 1 : 0) + (InputManager.MoveBackwardAction.IsPressed() ? (-1) : 0);
			bool flag = InputManager.SprintAction.IsPressed();
			Vector2 vector = InputManager.StickAction.ReadValue<Vector2>();
			vector = new Vector2(float.IsNaN(vector.x) ? 0f : (vector.x * SettingsManager.LookSensitivity), float.IsNaN(vector.y) ? 0f : (vector.y * SettingsManager.LookSensitivity));
			if (GlobalStateManager.UIState.IsMouseRequired)
			{
				num = 0f;
				num2 = 0f;
				num3 = 0f;
				flag = false;
				vector = Vector2.zero;
			}
			float num4 = (flag ? (movementSpeed * 2f) : movementSpeed);
			position += base.transform.right * num * num4 * deltaTime;
			position += base.transform.up * num2 * num4 * deltaTime;
			position += base.transform.forward * num3 * num4 * deltaTime;
			base.transform.position = Vector3.SmoothDamp(base.transform.position, position, ref positionVelocity, positionSmoothTime, float.PositiveInfinity, deltaTime);
			targetPitch = Mathf.Clamp(targetPitch - vector.y, pitchMin, pitchMax);
			targetYaw += vector.x;
			pitch = Mathf.Lerp(pitch, targetPitch, lookSmoothing * deltaTime);
			yaw = Mathf.Lerp(yaw, targetYaw, lookSmoothing * deltaTime);
			base.transform.rotation = Quaternion.Euler(pitch, yaw, 0f);
		}
	}

	private void HandlePlayerReference(NetworkObjectReference oldPlayerReference = default(NetworkObjectReference), NetworkObjectReference newPlayerReference = default(NetworkObjectReference))
	{
		NetworkObject networkObject;
		Player player = (oldPlayerReference.TryGet(out networkObject) ? networkObject.GetComponent<Player>() : null);
		NetworkObject networkObject2;
		Player player2 = (newPlayerReference.TryGet(out networkObject2) ? networkObject2.GetComponent<Player>() : null);
		if ((bool)player)
		{
			player.SpectatorCamera = null;
		}
		if ((bool)player2)
		{
			Player = player2;
			Player.SpectatorCamera = this;
		}
		else
		{
			Player = null;
		}
	}

	private void OnPlayerReferenceChanged(NetworkObjectReference oldPlayerReference, NetworkObjectReference newPlayerReference)
	{
		HandlePlayerReference(oldPlayerReference, newPlayerReference);
	}

	protected override void __initializeVariables()
	{
		if (PlayerReference == null)
		{
			throw new Exception("SpectatorCamera.PlayerReference cannot be null. All NetworkVariableBase instances must be initialized.");
		}
		PlayerReference.Initialize(this);
		__nameNetworkVariable(PlayerReference, "PlayerReference");
		NetworkVariableFields.Add(PlayerReference);
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "SpectatorCamera";
	}
}
