public class CompetitiveGameModeConfig : StandardGameModeConfig
{
	public Dictionary<PlayerTeam, string[]> teamAssignments { get; set; } = new Dictionary<PlayerTeam, string[]>();
}
public class CompetitiveGameMode<TConfig> : MatchableGameMode<TConfig> where TConfig : CompetitiveGameModeConfig, new()
{
	private Dictionary<PlayerTeam, string[]> teamAssignments = new Dictionary<PlayerTeam, string[]>();

	protected override bool AllowVotekick => false;

	public CompetitiveGameMode(string defaultConfigFilePath, string configFilePathCliArgument = null, string configCliArgument = null, string configEnvVariable = null)
		: base(defaultConfigFilePath, configFilePathCliArgument, configCliArgument, configEnvVariable)
	{
	}

	private PlayerTeam GetAssignedPlayerTeam(Player player)
	{
		foreach (PlayerTeam key in teamAssignments.Keys)
		{
			if (Enumerable.Contains(teamAssignments[key], player.SteamId.Value.ToString()))
			{
				return key;
			}
		}
		return PlayerTeam.None;
	}

	protected override void OnConfigLoaded()
	{
		base.OnConfigLoaded();
		teamAssignments = base.Config.teamAssignments;
	}

	protected override void OnPlayerJoined(Player player)
	{
		base.OnPlayerJoined(player);
		PlayerTeam assignedPlayerTeam = GetAssignedPlayerTeam(player);
		switch (assignedPlayerTeam)
		{
		case PlayerTeam.Blue:
		case PlayerTeam.Red:
		{
			PlayerTeam? team = assignedPlayerTeam;
			player.Server_SetGameState(null, team);
			if (CanPlayerEnterPhase(player, PlayerPhase.PositionSelect))
			{
				player.Server_SetGameState(PlayerPhase.PositionSelect);
			}
			break;
		}
		case PlayerTeam.None:
		case PlayerTeam.Spectator:
		{
			PlayerTeam? team = PlayerTeam.Spectator;
			player.Server_SetGameState(null, team);
			if (CanPlayerEnterPhase(player, PlayerPhase.Spectate))
			{
				player.Server_SetGameState(PlayerPhase.Spectate);
			}
			break;
		}
		}
	}

	protected override void OnMatchStarted()
	{
		base.OnMatchStarted();
		teamAssignments = new Dictionary<PlayerTeam, string[]>
		{
			{
				PlayerTeam.Blue,
				base.matchData.HomeSteamIds
			},
			{
				PlayerTeam.Red,
				base.matchData.AwaySteamIds
			}
		};
	}
}
public class CreaseProtection
{
	private class Crease
	{
		public PlayerTeam DefendingTeam;

		public PlayerBody Goalie;

		public readonly HashSet<PlayerBody> Enemies = new HashSet<PlayerBody>();

		public PlayerBody PhasedGoalie;

		public readonly HashSet<PlayerBody> Filtered = new HashSet<PlayerBody>();
	}

	private static readonly Logger Logger = new Logger("CreaseProtection");

	private static readonly HashSet<string> CreaseZoneIds = new HashSet<string> { "Crease" };

	private readonly Dictionary<Zone, Crease> creases = new Dictionary<Zone, Crease>();

	private readonly List<PlayerBody> restoreScratch = new List<PlayerBody>();

	private static bool IsServer
	{
		get
		{
			if (NetworkManager.Singleton != null)
			{
				return NetworkManager.Singleton.IsServer;
			}
			return false;
		}
	}

	public CreaseProtection()
	{
		EventManager.AddEventListener("Event_Everyone_OnPlayerBodyDespawned", OnPlayerBodyDespawned);
	}

	public void Dispose()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerBodyDespawned", OnPlayerBodyDespawned);
		foreach (Crease value in creases.Values)
		{
			value.Goalie = null;
			value.Enemies.Clear();
			Reconcile(value);
		}
		creases.Clear();
	}

	public void OnPlayerEnterZone(Zone zone, PlayerBody playerBody)
	{
		if (!IsServer || !CreaseZoneIds.Contains(zone.ZoneId))
		{
			return;
		}
		Crease orCreateCrease = GetOrCreateCrease(zone);
		if (orCreateCrease != null)
		{
			if (IsDefendingGoalie(playerBody, orCreateCrease.DefendingTeam))
			{
				orCreateCrease.Goalie = playerBody;
			}
			else if (IsEnemySkater(playerBody, orCreateCrease.DefendingTeam))
			{
				orCreateCrease.Enemies.Add(playerBody);
			}
			Reconcile(orCreateCrease);
		}
	}

	public void OnPlayerExitZone(Zone zone, PlayerBody playerBody)
	{
		if (IsServer && creases.TryGetValue(zone, out var value))
		{
			if (value.Goalie == playerBody)
			{
				value.Goalie = null;
			}
			else
			{
				value.Enemies.Remove(playerBody);
			}
			Reconcile(value);
		}
	}

	private void OnPlayerBodyDespawned(Dictionary<string, object> message)
	{
		if (!IsServer)
		{
			return;
		}
		PlayerBody playerBody = (PlayerBody)message["playerBody"];
		foreach (Crease value in creases.Values)
		{
			bool flag = value.Enemies.Remove(playerBody);
			if (value.Goalie == playerBody)
			{
				value.Goalie = null;
				flag = true;
			}
			if (flag)
			{
				Reconcile(value);
			}
		}
	}

	private void Reconcile(Crease crease)
	{
		restoreScratch.Clear();
		foreach (PlayerBody item in crease.Filtered)
		{
			if (crease.PhasedGoalie != crease.Goalie || crease.Goalie == null || !crease.Enemies.Contains(item))
			{
				restoreScratch.Add(item);
			}
		}
		foreach (PlayerBody item2 in restoreScratch)
		{
			if (crease.PhasedGoalie != null)
			{
				crease.PhasedGoalie.SetCollisionFilteredWith(item2, filtered: false);
			}
			crease.Filtered.Remove(item2);
		}
		crease.PhasedGoalie = crease.Goalie;
		if (crease.Goalie == null)
		{
			return;
		}
		foreach (PlayerBody enemy in crease.Enemies)
		{
			if (crease.Filtered.Add(enemy))
			{
				crease.Goalie.SetCollisionFilteredWith(enemy, filtered: true);
			}
		}
	}

	private Crease GetOrCreateCrease(Zone zone)
	{
		if (creases.TryGetValue(zone, out var value))
		{
			return value;
		}
		Goal componentInParent = zone.GetComponentInParent<Goal>();
		if (componentInParent == null)
		{
			Logger.Warning("Crease zone '" + zone.name + "' is not under a Goal - can't resolve a defending team.");
			return null;
		}
		value = new Crease
		{
			DefendingTeam = componentInParent.Team
		};
		creases[zone] = value;
		return value;
	}

	private static bool IsDefendingGoalie(PlayerBody playerBody, PlayerTeam defendingTeam)
	{
		if (playerBody != null && playerBody.Player != null && playerBody.Player.Role == PlayerRole.Goalie)
		{
			return playerBody.Player.Team == defendingTeam;
		}
		return false;
	}

	private static bool IsEnemySkater(PlayerBody playerBody, PlayerTeam defendingTeam)
	{
		if (playerBody == null || playerBody.Player == null)
		{
			return false;
		}
		PlayerTeam team = playerBody.Player.Team;
		if (playerBody.Player.Role != PlayerRole.Goalie && (team == PlayerTeam.Blue || team == PlayerTeam.Red))
		{
			return team != defendingTeam;
		}
		return false;
	}
}
public class MatchableGameMode<TConfig> : StandardGameMode<TConfig> where TConfig : StandardGameModeConfig, new()
{
	protected bool isMatchStarted;

	private Dictionary<string, Tween> steamIdAbandonmentTweenMap = new Dictionary<string, Tween>();

	private List<string> abandonedSteamIds = new List<string>();

	protected MatchData matchData => BackendManager.ServerState.MatchData;

	protected bool isMatch => matchData != null;

	public MatchableGameMode(string defaultConfigFilePath, string configFilePathCliArgument = null, string configCliArgument = null, string configEnvVariable = null)
		: base(defaultConfigFilePath, configFilePathCliArgument, configCliArgument, configEnvVariable)
	{
	}

	public override bool Initialize(Level level, ServerManager serverManager, GameManager gameManager, PlayerManager playerManager, PuckManager puckManager, ChatManager chatManager, ReplayManager replayManager, VoteManager voteManager)
	{
		if (!base.Initialize(level, serverManager, gameManager, playerManager, puckManager, chatManager, replayManager, voteManager))
		{
			return false;
		}
		if (isMatch)
		{
			StartMatch();
		}
		return true;
	}

	protected override void SubscribeEvents()
	{
		base.SubscribeEvents();
		EventManager.AddEventListener("Event_OnServerMatchDataChanged", Event_OnServerMatchDataChanged);
	}

	protected override void UnsubscribeEvents()
	{
		base.UnsubscribeEvents();
		EventManager.RemoveEventListener("Event_OnServerMatchDataChanged", Event_OnServerMatchDataChanged);
	}

	private void StartMatch()
	{
		if (!isMatchStarted)
		{
			isMatchStarted = true;
			OnMatchStarted();
		}
	}

	private void EndMatch()
	{
		if (isMatchStarted)
		{
			isMatchStarted = false;
			OnMatchEnded(gameResult);
		}
	}

	private void CancelMatch()
	{
		if (isMatchStarted)
		{
			isMatchStarted = false;
			OnMatchCancelled();
		}
	}

	private void IssueCooldown(string steamId)
	{
		if (isMatchStarted)
		{
			WebSocketManager.Emit("serverMatchIssueCooldown", new Dictionary<string, object> { { "steamId", steamId } });
			MatchPlayer matchPlayerBySteamId = matchData.GetMatchPlayerBySteamId(steamId);
			if (matchPlayerBySteamId != null)
			{
				ChatManager.Server_BroadcastChatMessage(matchPlayerBySteamId.username + " has been issued a matchmaking cooldown", "#b8b8b8");
			}
		}
	}

	private void StartAbandonmentTimeout(string steamId, float timeout)
	{
		if (!steamIdAbandonmentTweenMap.ContainsKey(steamId))
		{
			Tween value = DOVirtual.DelayedCall(timeout, delegate
			{
				steamIdAbandonmentTweenMap.Remove(steamId);
				OnSteamIdAbandonedMatch(steamId);
			});
			steamIdAbandonmentTweenMap.Add(steamId, value);
		}
	}

	private void StopAbandonmentTimeout(string steamId)
	{
		if (steamIdAbandonmentTweenMap.ContainsKey(steamId))
		{
			steamIdAbandonmentTweenMap[steamId].Kill();
			steamIdAbandonmentTweenMap.Remove(steamId);
		}
	}

	private void ClearAbandonmentTimeouts()
	{
		foreach (Tween value in steamIdAbandonmentTweenMap.Values)
		{
			value.Kill();
		}
		steamIdAbandonmentTweenMap.Clear();
	}

	protected virtual void OnMatchStarted()
	{
		WebSocketManager.Emit("serverMatchStart");
		UpdatePlayerResult(matchData.SteamIds);
		ServerManager.WhitelistManager.AddWhitelistedSteamIds(matchData.SteamIds);
	}

	protected virtual void OnMatchEnded(GameResult gameResult)
	{
		WebSocketManager.Emit("serverMatchEnd", new Dictionary<string, object> { { "gameResult", gameResult } });
		ClearAbandonmentTimeouts();
	}

	protected virtual void OnMatchCancelled()
	{
		WebSocketManager.Emit("serverMatchCancel");
		ClearAbandonmentTimeouts();
	}

	protected virtual void OnSteamIdAbandonedMatch(string steamId)
	{
		abandonedSteamIds.Add(steamId);
		IssueCooldown(steamId);
		string[] array = matchData.HomeSteamIds.Except(abandonedSteamIds).ToArray();
		string[] array2 = matchData.AwaySteamIds.Except(abandonedSteamIds).ToArray();
		if (array.Length == 0)
		{
			ForfeitGame(PlayerTeam.Blue);
		}
		else if (array2.Length == 0)
		{
			ForfeitGame(PlayerTeam.Red);
		}
	}

	protected override void OnWarmupTimedOut()
	{
		if (isMatchStarted)
		{
			string[] second = (from p in PlayerManager.GetPlayers()
				select p.SteamId.Value.ToString()).ToArray();
			string[] array = matchData.SteamIds.Except(second).ToArray();
			if (array.Length != 0)
			{
				ChatManager.Server_BroadcastChatMessage("Cancelling match due to players failing to join in time", "#b8b8b8");
				string[] array2 = array;
				foreach (string steamId in array2)
				{
					IssueCooldown(steamId);
				}
				CancelMatch();
				return;
			}
		}
		base.OnWarmupTimedOut();
	}

	protected override void OnGameOverEnded()
	{
		base.OnGameOverEnded();
		if (isMatch)
		{
			EndMatch();
		}
	}

	protected override void OnPlayerJoined(Player player)
	{
		base.OnPlayerJoined(player);
		if (isMatchStarted)
		{
			StopAbandonmentTimeout(player.SteamId.Value.ToString());
		}
	}

	protected override void OnPlayerLeft(Player player)
	{
		base.OnPlayerLeft(player);
		if (isMatchStarted && base.isGameInProgress)
		{
			StartAbandonmentTimeout(player.SteamId.Value.ToString(), 120f);
			ChatManager.Server_BroadcastChatMessage($"{player.Username.Value} has {120} seconds to reconnect before receiving a matchmaking cooldown", "#b8b8b8");
		}
	}

	private void Event_OnServerMatchDataChanged(Dictionary<string, object> message)
	{
		MatchData obj = (MatchData)message["oldServerMatchData"];
		MatchData matchData = (MatchData)message["newServerMatchData"];
		if (obj == null && matchData != null)
		{
			StartMatch();
		}
	}
}
public class PublicGameModeConfig : StandardGameModeConfig
{
}
public class PublicGameMode<TConfig> : StandardGameMode<TConfig> where TConfig : PublicGameModeConfig, new()
{
	public PublicGameMode(string defaultConfigFilePath, string configFilePathCliArgument = null, string configCliArgument = null, string configEnvVariable = null)
		: base(defaultConfigFilePath, configFilePathCliArgument, configCliArgument, configEnvVariable)
	{
	}

	protected override void OnWarmupTimedOut()
	{
		if (PlayerManager.GetPlayersByTeam(PlayerTeam.Blue).Count == 0 || PlayerManager.GetPlayersByTeam(PlayerTeam.Red).Count == 0)
		{
			GameManager.Server_SetGameState(GamePhase.Warmup, base.Config.phaseDurationMap[GamePhase.Warmup]);
			ChatManager.Server_BroadcastChatMessage("Not enough players to start the game. Extending warmup...", "#ffe97f");
		}
		else
		{
			base.OnWarmupTimedOut();
		}
	}

	protected override void OnPlayerJoined(Player player)
	{
		base.OnPlayerJoined(player);
		if (CanPlayerEnterPhase(player, PlayerPhase.TeamSelect))
		{
			player.Server_SetGameState(PlayerPhase.TeamSelect);
		}
	}

	protected override void OnPlayerRequestTeamSelect(Player player)
	{
		base.OnPlayerRequestTeamSelect(player);
		if (CanPlayerEnterPhase(player, PlayerPhase.TeamSelect))
		{
			player.Server_SetGameState(PlayerPhase.TeamSelect, PlayerTeam.None);
		}
	}

	protected override void OnPlayerRequestTeam(Player player, PlayerTeam team)
	{
		base.OnPlayerRequestTeam(player, team);
		switch (team)
		{
		case PlayerTeam.Blue:
		case PlayerTeam.Red:
		{
			PlayerTeam? team2 = team;
			player.Server_SetGameState(null, team2);
			if (CanPlayerEnterPhase(player, PlayerPhase.PositionSelect))
			{
				player.Server_SetGameState(PlayerPhase.PositionSelect);
			}
			break;
		}
		case PlayerTeam.Spectator:
		{
			PlayerTeam? team2 = team;
			player.Server_SetGameState(null, team2);
			if (CanPlayerEnterPhase(player, PlayerPhase.Spectate))
			{
				player.Server_SetGameState(PlayerPhase.Spectate);
			}
			break;
		}
		}
	}

	protected override void OnVoteRemoved(Vote vote)
	{
		base.OnVoteRemoved(vote);
		if (!vote.Passed)
		{
			return;
		}
		string name = vote.Name;
		if (!(name == "start"))
		{
			if (name == "warmup")
			{
				StartGame();
			}
		}
		else
		{
			StartGame(GamePhase.PreGame);
		}
	}

	protected override List<ChatCommandInfo> GetChatCommands()
	{
		List<ChatCommandInfo> chatCommands = base.GetChatCommands();
		chatCommands.Add(new ChatCommandInfo("/vs, /votestart", "Start a vote to start the game"));
		chatCommands.Add(new ChatCommandInfo("/vw, /votewarmup", "Start a vote to return to warmup"));
		return chatCommands;
	}

	protected override void OnChatCommand(Player player, string command, string[] args)
	{
		switch (command)
		{
		case "/vs":
		case "/votestart":
		{
			if (player.Team != PlayerTeam.Blue && player.Team != PlayerTeam.Red)
			{
				ChatManager.Server_SendChatMessage("You must be on a team to start this vote", "#e74c3c", player.OwnerClientId);
				break;
			}
			Vote vote2 = VoteManager.Server_GetTeamVoteByName("start", player.Team);
			if (vote2 != null)
			{
				vote2.CastVote(player.SteamId.Value.ToString(), inFavour: true);
				break;
			}
			VoteManager.Server_AddVote("start", "Start", "use /vs or /votestart", new PlayerTeam[2]
			{
				PlayerTeam.Blue,
				PlayerTeam.Red
			}, 30f, player.SteamId.Value.ToString(), Utils.GetVoteMajority(PlayerManager.GetPlayersByTeams(new PlayerTeam[2]
			{
				PlayerTeam.Blue,
				PlayerTeam.Red
			}).Count));
			break;
		}
		case "/vw":
		case "/votewarmup":
		{
			if (player.Team != PlayerTeam.Blue && player.Team != PlayerTeam.Red)
			{
				ChatManager.Server_SendChatMessage("You must be on a team to start this vote", "#e74c3c", player.OwnerClientId);
				break;
			}
			Vote vote = VoteManager.Server_GetTeamVoteByName("warmup", player.Team);
			if (vote != null)
			{
				vote.CastVote(player.SteamId.Value.ToString(), inFavour: true);
				break;
			}
			VoteManager.Server_AddVote("warmup", "Warmup", "use /vw or /votewarmup", new PlayerTeam[2]
			{
				PlayerTeam.Blue,
				PlayerTeam.Red
			}, 30f, player.SteamId.Value.ToString(), Utils.GetVoteMajority(PlayerManager.GetPlayersByTeams(new PlayerTeam[2]
			{
				PlayerTeam.Blue,
				PlayerTeam.Red
			}).Count));
			break;
		}
		default:
			base.OnChatCommand(player, command, args);
			break;
		}
	}
}
