	{
		base.OnBlueScoreStarted();
		Level.Server_PlayerCheerSound(base.Config.phaseDurationMap[GamePhase.BlueScore] + base.Config.phaseDurationMap[GamePhase.Replay]);
		Level.Server_PlayRedGoalSound();
