public class ChatManagerController : MonoBehaviour
{
	private ChatManager chatManager;

	private void Awake()
	{
		chatManager = GetComponent<ChatManager>();
		InputManager.QuickChat1Action.performed += OnQuickChatAction1Performed;
		InputManager.QuickChat2Action.performed += OnQuickChatAction2Performed;
		InputManager.QuickChat3Action.performed += OnQuickChatAction3Performed;
		InputManager.QuickChat4Action.performed += OnQuickChatAction4Performed;
		InputManager.QuickChat5Action.performed += OnQuickChatAction5Performed;
		EventManager.AddEventListener("Event_OnChatSubmitMessage", Event_OnChatSubmitMessage);
		EventManager.AddEventListener("Event_OnQuickChatCancel", Event_OnQuickChatCancel);
		EventManager.AddEventListener("Event_OnClientStopped", Event_OnClientStopped);
		EventManager.AddEventListener("Event_Server_OnChatMessageReceived", Event_Server_OnChatMessageReceived);
		WebSocketManager.AddMessageListener("playerAnnouncement", WebSocket_Event_OnPlayerAnnouncement);
	}

	private void OnDestroy()
	{
		InputManager.QuickChat1Action.performed -= OnQuickChatAction1Performed;
		InputManager.QuickChat2Action.performed -= OnQuickChatAction2Performed;
		InputManager.QuickChat3Action.performed -= OnQuickChatAction3Performed;
		InputManager.QuickChat4Action.performed -= OnQuickChatAction4Performed;
		InputManager.QuickChat5Action.performed -= OnQuickChatAction5Performed;
		EventManager.RemoveEventListener("Event_OnChatSubmitMessage", Event_OnChatSubmitMessage);
		EventManager.RemoveEventListener("Event_OnQuickChatCancel", Event_OnQuickChatCancel);
		EventManager.RemoveEventListener("Event_OnClientStopped", Event_OnClientStopped);
		EventManager.RemoveEventListener("Event_Server_OnChatMessageReceived", Event_Server_OnChatMessageReceived);
		WebSocketManager.RemoveMessageListener("playerAnnouncement", WebSocket_Event_OnPlayerAnnouncement);
	}

	private void OnQuickChatAction1Performed(InputAction.CallbackContext context)
	{
		if (GlobalStateManager.UIState.Phase == UIPhase.Playing && !GlobalStateManager.UIState.IsInteracting)
		{
			chatManager.Client_QuickChatAction(0);
		}
	}

	private void OnQuickChatAction2Performed(InputAction.CallbackContext context)
	{
		if (GlobalStateManager.UIState.Phase == UIPhase.Playing && !GlobalStateManager.UIState.IsInteracting)
		{
			chatManager.Client_QuickChatAction(1);
		}
	}

	private void OnQuickChatAction3Performed(InputAction.CallbackContext context)
	{
		if (GlobalStateManager.UIState.Phase == UIPhase.Playing && !GlobalStateManager.UIState.IsInteracting)
		{
			chatManager.Client_QuickChatAction(2);
		}
	}

	private void OnQuickChatAction4Performed(InputAction.CallbackContext context)
	{
		if (GlobalStateManager.UIState.Phase == UIPhase.Playing && !GlobalStateManager.UIState.IsInteracting)
		{
			chatManager.Client_QuickChatAction(3);
		}
	}

	private void OnQuickChatAction5Performed(InputAction.CallbackContext context)
	{
		if (GlobalStateManager.UIState.Phase == UIPhase.Playing && !GlobalStateManager.UIState.IsInteracting)
		{
			chatManager.Client_QuickChatAction(4);
		}
	}

	private void Event_OnChatSubmitMessage(Dictionary<string, object> message)
	{
		string content = (string)message["content"];
		bool isTeamChat = (bool)message["isTeamChat"];
		chatManager.Client_SendChatMessage(content, isQuickChat: false, isTeamChat);
	}

	private void Event_OnQuickChatCancel(Dictionary<string, object> message)
	{
		chatManager.SetQuickChatEnabled(isEnabled: false);
	}

	private void Event_OnClientStopped(Dictionary<string, object> message)
	{
		chatManager.ClearChatMessages();
	}

	private void Event_Server_OnChatMessageReceived(Dictionary<string, object> message)
	{
		ChatMessage chatMessage = (ChatMessage)message["chatMessage"];
		if (chatMessage.IsTeamChat)
		{
			if (!chatMessage.Team.HasValue)
			{
				return;
			}
			List<ulong> list = new List<ulong>();
			if (chatMessage.Team.Value == PlayerTeam.Spectator || chatMessage.Team.Value == PlayerTeam.None)
			{
				list.AddRange(MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayersByTeams(new PlayerTeam[2]
				{
					PlayerTeam.None,
					PlayerTeam.Spectator
				}).ConvertAll((Player player) => player.OwnerClientId));
			}
			else
			{
				list.AddRange(MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayersByTeam(chatMessage.Team.Value).ConvertAll((Player player) => player.OwnerClientId));
			}
			chatManager.Server_SendChatMessage(chatMessage, list.ToArray());
		}
		else
		{
			chatManager.Server_BroadcastChatMessage(chatMessage);
		}
	}

	private void WebSocket_Event_OnPlayerAnnouncement(Dictionary<string, object> message)
	{
		InMessage inMessage = (InMessage)message["inMessage"];
		ChatMessage chatMessage = new ChatMessage
		{
			SteamID = null,
			Username = null,
			Team = null,
			Content = inMessage.GetData<string>(),
			Timestamp = Utils.GetTimestamp(),
			IsQuickChat = false,
			IsTeamChat = false,
			IsSystem = true
		};
		chatManager.AddChatMessage(chatMessage);
	}
}
public class CrowdManager : MonoBehaviourSingleton<CrowdManager>
{
	[Header("Settings")]
	[SerializeField]
	private float crowdDensity = 0.25f;

	[SerializeField]
	private int crowdUpdatesPerFrame = 8;

	[Header("Prefabs")]
	[SerializeField]
	private CrowdMember crowdMemberPrefab;

	private Dictionary<CrowdPosition, CrowdMember> crowdPositionMemberMap = new Dictionary<CrowdPosition, CrowdMember>();

	private List<CrowdMember> crowdMembers = new List<CrowdMember>();

	private Transform currentLookTarget;

	private string currentAnimation = "Seated";

	private int updateBatch;

	private void Update()
	{
		int count = crowdMembers.Count;
		if (count != 0)
		{
			for (int i = 0; i < crowdUpdatesPerFrame; i++)
			{
				int index = (updateBatch + i) % count;
				crowdMembers[index].UpdateAnimation();
			}
			updateBatch = (updateBatch + crowdUpdatesPerFrame) % count;
		}
	}

	public void RegisterCrowdPosition(CrowdPosition position)
	{
		if (!crowdPositionMemberMap.ContainsKey(position) && !(UnityEngine.Random.value > crowdDensity))
		{
			CrowdMember crowdMember = UnityEngine.Object.Instantiate(crowdMemberPrefab, position.transform.position, position.transform.rotation, base.transform);
			crowdPositionMemberMap[position] = crowdMember;
			crowdMembers.Add(crowdMember);
			crowdMember.RandomizeAppearance();
			crowdMember.PlayAnimation(currentAnimation);
			crowdMember.LookTarget = currentLookTarget;
		}
	}

	public void UnregisterCrowdPosition(CrowdPosition position)
	{
		if (crowdPositionMemberMap.ContainsKey(position))
		{
			CrowdMember crowdMember = crowdPositionMemberMap[position];
			UnityEngine.Object.Destroy(crowdMember.gameObject);
			crowdPositionMemberMap.Remove(position);
			crowdMembers.Remove(crowdMember);
		}
	}

	public void SetCrowdLookTarget(Transform lookTarget)
	{
		currentLookTarget = lookTarget;
		foreach (CrowdMember value in crowdPositionMemberMap.Values)
		{
			value.LookTarget = currentLookTarget;
		}
	}

	public void SetCrowdAnimation(string animationName)
	{
		currentAnimation = animationName;
		foreach (CrowdMember value in crowdPositionMemberMap.Values)
		{
			value.PlayAnimation(currentAnimation);
		}
	}
}
public class CrowdManagerController : MonoBehaviour
{
	private CrowdManager crowdManager;

	private void Awake()
	{
		crowdManager = GetComponent<CrowdManager>();
		EventManager.AddEventListener("Event_OnCrowdPositionSpawned", Event_OnCrowdPositionSpawned);
		EventManager.AddEventListener("Event_OnCrowdPositionDespawned", Event_OnCrowdPositionDespawned);
		EventManager.AddEventListener("Event_Everyone_OnPuckSpawned", Event_Everyone_OnPuckSpawned);
		EventManager.AddEventListener("Event_Everyone_OnGameStateChanged", Event_Everyone_OnGameStateChanged);
	}

	private void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_OnCrowdPositionSpawned", Event_OnCrowdPositionSpawned);
		EventManager.RemoveEventListener("Event_OnCrowdPositionDespawned", Event_OnCrowdPositionDespawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPuckSpawned", Event_Everyone_OnPuckSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnGameStateChanged", Event_Everyone_OnGameStateChanged);
	}

	private void Event_OnCrowdPositionSpawned(Dictionary<string, object> message)
	{
		CrowdPosition position = (CrowdPosition)message["crowdPosition"];
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			crowdManager.RegisterCrowdPosition(position);
		}
	}

	private void Event_OnCrowdPositionDespawned(Dictionary<string, object> message)
	{
		CrowdPosition position = (CrowdPosition)message["crowdPosition"];
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			crowdManager.UnregisterCrowdPosition(position);
		}
	}

	private void Event_Everyone_OnPuckSpawned(Dictionary<string, object> message)
	{
		Puck puck = (Puck)message["puck"];
		crowdManager.SetCrowdLookTarget(puck.transform);
	}

	private void Event_Everyone_OnGameStateChanged(Dictionary<string, object> message)
	{
		GameState obj = (GameState)message["oldGameState"];
		GameState gameState = (GameState)message["newGameState"];
		if (obj.Phase != gameState.Phase)
		{
			GamePhase phase = gameState.Phase;
			if ((uint)(phase - 5) <= 1u)
			{
				crowdManager.SetCrowdAnimation("Cheering");
			}
			else
			{
				crowdManager.SetCrowdAnimation("Seated");
			}
		}
	}
}
public static class EventManager
{
	private static readonly Logger Logger = new Logger("EventManager");

	private static Dictionary<string, List<Action<Dictionary<string, object>>>> events = new Dictionary<string, List<Action<Dictionary<string, object>>>>();

	public static void Initialize()
	{
	}

	public static void Dispose()
	{
	}

	public static void AddEventListener(string eventName, Action<Dictionary<string, object>> listener)
	{
		if (!events.TryGetValue(eventName, out var value))
		{
			events.Add(eventName, new List<Action<Dictionary<string, object>>> { listener });
		}
		else
		{
			List<Action<Dictionary<string, object>>> list = new List<Action<Dictionary<string, object>>>(value);
			list.Add(listener);
			events[eventName] = list;
		}
	}

	public static void RemoveEventListener(string eventName, Action<Dictionary<string, object>> listener)
	{
		if (!events.TryGetValue(eventName, out var value))
		{
			Logger.Warning("Tried to remove listener for event " + eventName + ", but no listener was registered for it");
			return;
		}
		List<Action<Dictionary<string, object>>> list = new List<Action<Dictionary<string, object>>>(value);
		list.Remove(listener);
		if (list.Count == 0)
		{
			events.Remove(eventName);
		}
		else
		{
			events[eventName] = list;
		}
	}

	public static bool HasEventListeners(string eventName)
	{
		return events.ContainsKey(eventName);
	}

	public static void TriggerEvent(string eventName, Dictionary<string, object> message = null)
	{
		if (!events.TryGetValue(eventName, out var value))
		{
			return;
		}
		bool flag = eventName.StartsWith("Event_Server_", StringComparison.Ordinal);
		bool num = eventName.StartsWith("Event_Client_", StringComparison.Ordinal);
		bool flag2 = eventName.StartsWith("Event_Everyone_", StringComparison.Ordinal);
		if ((num || flag || flag2) && (!NetworkManager.Singleton || !NetworkManager.Singleton.IsListening))
		{
			Logger.Warning("Triggering network event " + eventName + " without a NetworkManager listening");
		}
		if (message == null)
		{
			message = new Dictionary<string, object> { { "eventName", eventName } };
		}
		else if (!message.ContainsKey("eventName"))
		{
			message.Add("eventName", eventName);
		}
		for (int i = 0; i < value.Count; i++)
		{
			try
			{
				value[i](message);
			}
			catch (Exception arg)
			{
				Logger.Error($"Listener for event {eventName} threw an exception: {arg}");
			}
		}
	}
}
public enum GamePhase
{
	None,
	Warmup,
	PreGame,
	FaceOff,
	Play,
	BlueScore,
	RedScore,
	Replay,
	Intermission,
	GameOver,
	PostGame
}
public struct GameState : INetworkSerializable, IEquatable<GameState>
{
	public GamePhase Phase;

	public int Tick;

	public int Period;

	public int BlueScore;

	public int RedScore;

	public bool IsOvertime;

	public void NetworkSerialize<T>(BufferSerializer<T> serializer) where T : IReaderWriter
	{
		if (serializer.IsReader)
		{
			FastBufferReader fastBufferReader = serializer.GetFastBufferReader();
			fastBufferReader.ReadValueSafe(out Phase, default(FastBufferWriter.ForEnums));
			fastBufferReader.ReadValueSafe(out Tick, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Period, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out BlueScore, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out RedScore, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out IsOvertime, default(FastBufferWriter.ForPrimitives));
		}
		else
		{
			FastBufferWriter fastBufferWriter = serializer.GetFastBufferWriter();
			fastBufferWriter.WriteValueSafe(in Phase, default(FastBufferWriter.ForEnums));
			fastBufferWriter.WriteValueSafe(in Tick, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Period, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in BlueScore, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in RedScore, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in IsOvertime, default(FastBufferWriter.ForPrimitives));
		}
	}

	public bool Equals(GameState other)
	{
		if (Phase.Equals(other.Phase) && Tick == other.Tick && Period == other.Period && BlueScore == other.BlueScore && RedScore == other.RedScore)
		{
			return IsOvertime == other.IsOvertime;
		}
		return false;
	}
}
public class GameManager : NetworkBehaviourSingleton<GameManager>
{
	[HideInInspector]
	public NetworkVariable<GameState> GameState;

	private Tween tickTween;

	private Sequence slowMotionSequence;

	[HideInInspector]
	public GamePhase Phase => GameState.Value.Phase;

	[HideInInspector]
	public int Tick => GameState.Value.Tick;

	[HideInInspector]
	public int Period => GameState.Value.Period;

	[HideInInspector]
	public int BlueScore => GameState.Value.BlueScore;

	[HideInInspector]
	public int RedScore => GameState.Value.RedScore;

	[HideInInspector]
	public bool IsOvertime => GameState.Value.IsOvertime;

	public bool IsTicking
	{
		get
		{
			if (tickTween != null)
			{
				return tickTween.IsActive();
			}
			return false;
		}
	}

	protected override void OnNetworkPreSpawn(ref NetworkManager networkManager)
	{
		if (GameState == null)
		{
			GameState = new NetworkVariable<GameState>();
		}
		if (networkManager.IsServer)
		{
			GameState.Value = default(GameState);
		}
		base.OnNetworkPreSpawn(ref networkManager);
	}

	public override void OnNetworkSpawn()
	{
		NetworkVariable<GameState> gameState = GameState;
		gameState.OnValueChanged = (NetworkVariable<GameState>.OnValueChangedDelegate)Delegate.Combine(gameState.OnValueChanged, new NetworkVariable<GameState>.OnValueChangedDelegate(OnGameStateChanged));
		base.OnNetworkSpawn();
	}

	protected override void OnNetworkPostSpawn()
	{
		if (NetworkManager.Singleton.IsServer || NetworkManager.Singleton.IsConnectedClient)
		{
			ProcessInitialNetworkVariableValues();
		}
		base.OnNetworkPostSpawn();
	}

	protected override void OnNetworkSessionSynchronized()
	{
		ProcessInitialNetworkVariableValues();
		base.OnNetworkSessionSynchronized();
	}

	public override void OnNetworkDespawn()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			tickTween?.Kill();
			Server_StopSlowMotion(notifyClients: false);
		}
		NetworkVariable<GameState> gameState = GameState;
		gameState.OnValueChanged = (NetworkVariable<GameState>.OnValueChangedDelegate)Delegate.Remove(gameState.OnValueChanged, new NetworkVariable<GameState>.OnValueChangedDelegate(OnGameStateChanged));
		base.OnNetworkDespawn();
	}

	private void ProcessInitialNetworkVariableValues()
	{
		OnGameStateChanged(default(GameState), GameState.Value);
	}

	private void OnGameStateChanged(GameState oldGameState, GameState newGameState)
	{
		EventManager.TriggerEvent("Event_Everyone_OnGameStateChanged", new Dictionary<string, object>
		{
			{ "oldGameState", oldGameState },
			{ "newGameState", newGameState }
		});
	}

	private void Server_Tick()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			if (GameState.Value.Tick <= 0)
			{
				Server_ExpirePhase();
				return;
			}
			int? tick = GameState.Value.Tick - 1;
			Server_SetGameState(null, tick);
		}
	}

	public void Server_ExpirePhase()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			EventManager.TriggerEvent("Event_Server_OnPhaseExpired", new Dictionary<string, object> { 
			{
				"phase",
				GameState.Value.Phase
			} });
		}
	}

	public void Server_StartTicking()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			tickTween?.Kill();
			tickTween = DOVirtual.DelayedCall(1f, Server_Tick).SetLoops(-1);
		}
	}

	public void Server_StopTicking()
	{
		if (NetworkManager.Singleton.IsServer)
		{
			tickTween?.Kill();
		}
	}

	public void Server_StartSlowMotion(float scale, float rampInSeconds, float holdSeconds, float rampOutSeconds, float audioPitchFloor = 1f, float cameraFovPunch = 0f)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			float timeScale = Time.timeScale;
			slowMotionSequence?.Kill();
			scale = Mathf.Clamp(scale, 0.01f, 1f);
			slowMotionSequence = TweenUtils.RampHoldRamp(timeScale, scale, 1f, rampInSeconds, holdSeconds, rampOutSeconds, Ease.InQuad, Ease.OutQuad, delegate(float value)
			{
				Time.timeScale = value;
			}).SetTarget(this);
			slowMotionSequence.OnKill(delegate
			{
				slowMotionSequence = null;
			});
			Server_NotifySlowMotionRpc(scale, rampInSeconds, holdSeconds, rampOutSeconds, audioPitchFloor, cameraFovPunch);
		}
	}

	[Rpc(SendTo.Everyone, InvokePermission = RpcInvokePermission.Server, DeferLocal = true)]
	private void Server_NotifySlowMotionRpc(float scale, float rampInSeconds, float holdSeconds, float rampOutSeconds, float audioPitchFloor, float cameraFovPunch)
	{
		NetworkManager networkManager = base.NetworkManager;
		if ((object)networkManager == null || !networkManager.IsListening)
		{
			UnityEngine.Debug.LogError("Rpc methods can only be invoked after starting the NetworkManager!");
			return;
		}
		if (__rpc_exec_stage != __RpcExecStage.Execute)
		{
			RpcAttribute.RpcAttributeParams attributeParams = new RpcAttribute.RpcAttributeParams
			{
				InvokePermission = RpcInvokePermission.Server,
				DeferLocal = true
			};
			RpcParams rpcParams = default(RpcParams);
			FastBufferWriter bufferWriter = __beginSendRpc(1445539067u, rpcParams, attributeParams, SendTo.Everyone, RpcDelivery.Reliable);
			bufferWriter.WriteValueSafe(in scale, default(FastBufferWriter.ForPrimitives));
			bufferWriter.WriteValueSafe(in rampInSeconds, default(FastBufferWriter.ForPrimitives));
