public class GameModeManager : NetworkBehaviourSingleton<GameModeManager>
{
	private static readonly Logger Logger = new Logger("GameModeManager");

	[Header("References")]
	[SerializeField]
	private ServerManager serverManager;

	[SerializeField]
	private GameManager gameManager;

	[SerializeField]
	private PlayerManager playerManager;

	[SerializeField]
	private PuckManager puckManager;

	[SerializeField]
	private ChatManager chatManager;

	[SerializeField]
	private ReplayManager replayManager;

	[SerializeField]
	private VoteManager voteManager;

	[HideInInspector]
	public Level Level;

	private Dictionary<string, IGameMode> gameModeMap = new Dictionary<string, IGameMode>();

	private IGameMode selectedGameMode;

	[HideInInspector]
	public NetworkVariable<GameModeClientConfig> ClientConfig;

	protected override void OnNetworkPreSpawn(ref NetworkManager networkManager)
	{
		if (ClientConfig == null)
		{
			ClientConfig = new NetworkVariable<GameModeClientConfig>();
		}
		if (networkManager.IsServer)
		{
			ClientConfig.Value = default(GameModeClientConfig);
		}
		base.OnNetworkPreSpawn(ref networkManager);
	}

	public override void Awake()
	{
		base.Awake();
		RegisterGameModes();
	}

	private void RegisterGameModes()
	{
		PublicGameMode<PublicGameModeConfig> value = new PublicGameMode<PublicGameModeConfig>("./public_game_mode_config.json", "--publicGameModeConfigPath", "--publicGameModeConfig", "PUCK_PUBLIC_GAME_MODE_CONFIG");
		CompetitiveGameMode<CompetitiveGameModeConfig> value2 = new CompetitiveGameMode<CompetitiveGameModeConfig>("./competitive_game_mode_config.json", "--competitiveGameModeConfigPath", "--competitiveGameModeConfig", "PUCK_COMPETITIVE_GAME_MODE_CONFIG");
		gameModeMap.Add("public", value);
		gameModeMap.Add("competitive", value2);
	}

	public void SelectGameMode(string name)
	{
		if (gameModeMap.ContainsKey(name))
		{
			selectedGameMode = gameModeMap[name];
			Logger.Info("Selected game mode " + Utils.GetReadableTypeName(selectedGameMode.GetType()));
		}
	}

	public void DeselectGameMode()
	{
		selectedGameMode = null;
		Logger.Info("Deselected game mode");
	}

	public void EnableSelectedGameMode()
	{
		if (selectedGameMode != null && !selectedGameMode.IsInitialized)
		{
			Logger.Info("Enabling game mode " + Utils.GetReadableTypeName(selectedGameMode.GetType()));
			selectedGameMode.Initialize(Level, serverManager, gameManager, playerManager, puckManager, chatManager, replayManager, voteManager);
		}
	}

	public void DisableSelectedGameMode()
	{
		if (selectedGameMode != null && selectedGameMode.IsInitialized)
		{
			Logger.Info("Disabling game mode " + Utils.GetReadableTypeName(selectedGameMode.GetType()));
			selectedGameMode.Dispose();
		}
	}

	protected override void __initializeVariables()
	{
		if (ClientConfig == null)
		{
			throw new Exception("GameModeManager.ClientConfig cannot be null. All NetworkVariableBase instances must be initialized.");
		}
		ClientConfig.Initialize(this);
		__nameNetworkVariable(ClientConfig, "ClientConfig");
		NetworkVariableFields.Add(ClientConfig);
		base.__initializeVariables();
	}

	protected override void __initializeRpcs()
	{
		base.__initializeRpcs();
	}

	protected internal override string __getTypeName()
	{
		return "GameModeManager";
	}
}
public class GameModeManagerController : MonoBehaviour
{
	private GameModeManager gameModeManager;

	private void Awake()
	{
		gameModeManager = GetComponent<GameModeManager>();
		EventManager.AddEventListener("Event_Server_OnServerStarted", Event_Server_OnServerStarted);
		EventManager.AddEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
		EventManager.AddEventListener("Event_Server_OnLoadSceneEventCompleted", Event_Server_OnLoadSceneEventCompleted);
		EventManager.AddEventListener("Event_Everyone_OnLevelSpawned", Event_Everyone_OnLevelSpawned);
		EventManager.AddEventListener("Event_Everyone_OnLevelDespawned", Event_Everyone_OnLevelDespawned);
	}

	private void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Server_OnServerStarted", Event_Server_OnServerStarted);
		EventManager.RemoveEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
		EventManager.RemoveEventListener("Event_Server_OnLoadSceneEventCompleted", Event_Server_OnLoadSceneEventCompleted);
		EventManager.RemoveEventListener("Event_Everyone_OnLevelSpawned", Event_Everyone_OnLevelSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnLevelDespawned", Event_Everyone_OnLevelDespawned);
	}

	private void Event_Server_OnServerStarted(Dictionary<string, object> message)
	{
		ServerConfig serverConfig = (ServerConfig)message["serverConfig"];
		gameModeManager.SelectGameMode(serverConfig.gameMode);
	}

	private void Event_Server_OnServerStopped(Dictionary<string, object> message)
	{
		gameModeManager.DisableSelectedGameMode();
		gameModeManager.DeselectGameMode();
	}

	private void Event_Server_OnLoadSceneEventCompleted(Dictionary<string, object> message)
	{
		gameModeManager.EnableSelectedGameMode();
	}

	private void Event_Everyone_OnLevelSpawned(Dictionary<string, object> message)
	{
		Level level = (Level)message["level"];
		if (NetworkManager.Singleton.IsServer)
		{
			gameModeManager.Level = level;
		}
	}

	private void Event_Everyone_OnLevelDespawned(Dictionary<string, object> message)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			gameModeManager.Level = null;
		}
	}
}
public struct UIState
{
	public UIPhase Phase = UIPhase.None;

	public bool IsMouseRequired = false;

	public bool IsMouseOverUI = false;

	public List<UIView> InteractingViews = new List<UIView>();

	public bool IsInteracting
	{
		get
		{
			if (InteractingViews != null)
			{
				return InteractingViews.Count > 0;
			}
			return false;
		}
	}

	public UIState()
	{
	}

	public bool IsViewInteracting<T>() where T : UIView
	{
		if (InteractingViews == null)
		{
			return false;
		}
		foreach (UIView interactingView in InteractingViews)
		{
			if (interactingView is T)
			{
				return true;
			}
		}
		return false;
	}

	public bool IsViewTopmostInteracting<T>() where T : UIView
	{
		if (InteractingViews == null || InteractingViews.Count == 0)
		{
			return false;
		}
		return InteractingViews[InteractingViews.Count - 1] is T;
	}

	public UIView GetTopmostInteractingView()
	{
		if (InteractingViews == null || InteractingViews.Count == 0)
		{
			return null;
		}
		return InteractingViews[InteractingViews.Count - 1];
	}

	public bool Equals(UIState other)
	{
		if (Phase == other.Phase && IsMouseRequired == other.IsMouseRequired && IsMouseOverUI == other.IsMouseOverUI)
		{
			return InteractingViews.SequenceEqual(other.InteractingViews);
		}
		return false;
	}

	public override bool Equals(object obj)
	{
		if (obj is UIState other)
		{
			return Equals(other);
		}
		return false;
	}

	public override int GetHashCode()
	{
		return HashCode.Combine(Phase, IsMouseRequired, IsMouseOverUI, InteractingViews);
	}

	public override string ToString()
	{
		return $"Phase: {Phase}, IsMouseRequired: {IsMouseRequired}, IsMouseOverUI: {IsMouseOverUI}, IsInteracting: {IsInteracting}";
	}
}
