		{
			return Enumerable.Contains(PendingEnablingModIds, modId);
		}
		return true;
	}

	public bool Equals(ReconnectionState other)
	{
		if (Phase == other.Phase && Password == other.Password && Enumerable.SequenceEqual(ClientRequiredModIds, other.ClientRequiredModIds) && Enumerable.SequenceEqual(PendingReadinessModIds, other.PendingReadinessModIds))
		{
			return Enumerable.SequenceEqual(PendingEnablingModIds, other.PendingEnablingModIds);
		}
		return false;
	}

	public override bool Equals(object obj)
	{
		if (obj is ReconnectionState other)
		{
			return Equals(other);
		}
		return false;
	}

	public override int GetHashCode()
	{
		return HashCode.Combine(Phase, Password, ClientRequiredModIds, PendingReadinessModIds, PendingEnablingModIds);
	}

	public override string ToString()
	{
		return string.Format("Phase: {0}, Password: {1}, ClientRequiredModIds: [{2}], PendingReadinessModIds: [{3}], PendingEnablingModIds: [{4}]", Phase, Password ?? "null", string.Join(", ", ClientRequiredModIds), string.Join(", ", PendingReadinessModIds), string.Join(", ", PendingEnablingModIds));
	}
}
public static class GlobalStateManager
{
	private static readonly Logger Logger = new Logger("GlobalStateManager");

	private static UIState uiState = new UIState();

	private static ConnectionState connectionState = new ConnectionState();

	private static ReconnectionState reconnectionState = new ReconnectionState();

	public static UIState UIState
	{
		get
		{
			return uiState;
		}
		set
		{
			if (!uiState.Equals(value))
			{
				UIState oldUIState = uiState;
				uiState = value;
				OnUIStateChanged(oldUIState, uiState);
			}
		}
	}

	public static ConnectionState ConnectionState
	{
		get
		{
			return connectionState;
		}
		set
		{
			if (!connectionState.Equals(value))
			{
				ConnectionState oldConnectionState = connectionState;
				connectionState = value;
				OnConnectionStateChanged(oldConnectionState, connectionState);
			}
		}
	}

	public static ReconnectionState ReconnectionState
	{
		get
		{
			return reconnectionState;
		}
		set
		{
			if (!reconnectionState.Equals(value))
			{
				ReconnectionState oldReconnectionState = reconnectionState;
				reconnectionState = value;
				OnReconnectionStateChanged(oldReconnectionState, reconnectionState);
			}
		}
	}

	public static void Initialize()
	{
		GlobalStateManagerController.Initialize();
	}

	public static void Dispose()
	{
		GlobalStateManagerController.Dispose();
	}

	public static void SetUIState(Dictionary<string, object> updates)
	{
		UIState uIState = new UIState();
		uIState.Phase = (updates.ContainsKey("phase") ? ((UIPhase)updates["phase"]) : UIState.Phase);
		uIState.IsMouseRequired = (updates.ContainsKey("isMouseRequired") ? ((bool)updates["isMouseRequired"]) : UIState.IsMouseRequired);
		uIState.IsMouseOverUI = (updates.ContainsKey("isMouseOverUI") ? ((bool)updates["isMouseOverUI"]) : UIState.IsMouseOverUI);
		uIState.InteractingViews = (updates.ContainsKey("interactingViews") ? ((List<UIView>)updates["interactingViews"]) : UIState.InteractingViews);
		UIState = uIState;
	}

	public static void ClearUIState()
	{
		UIState = new UIState();
	}

	public static void SetConnectionState(Dictionary<string, object> updates)
	{
		ConnectionState connectionState = new ConnectionState();
		connectionState.Connection = (updates.ContainsKey("connection") ? ((Connection)updates["connection"]) : ConnectionState.Connection);
		connectionState.LastConnection = (updates.ContainsKey("lastConnection") ? ((Connection)updates["lastConnection"]) : ConnectionState.LastConnection);
		connectionState.ConnectionRejection = (updates.ContainsKey("connectionRejection") ? ((ConnectionRejection)updates["connectionRejection"]) : ConnectionState.ConnectionRejection);
		connectionState.Disconnection = (updates.ContainsKey("disconnection") ? ((Disconnection)updates["disconnection"]) : ConnectionState.Disconnection);
		connectionState.PendingConnection = (updates.ContainsKey("pendingConnection") ? ((Connection)updates["pendingConnection"]) : ConnectionState.PendingConnection);
		connectionState.Phase = (updates.ContainsKey("phase") ? ((ConnectionPhase)updates["phase"]) : ConnectionState.Phase);
		ConnectionState = connectionState;
	}

	public static void ClearConnectionState()
	{
		ConnectionState = new ConnectionState();
	}

	public static void SetReconnectionState(Dictionary<string, object> updates)
	{
		ReconnectionState reconnectionState = new ReconnectionState();
		reconnectionState.Phase = (updates.ContainsKey("phase") ? ((ReconnectionPhase)updates["phase"]) : ReconnectionState.Phase);
		reconnectionState.Password = (updates.ContainsKey("password") ? ((string)updates["password"]) : ReconnectionState.Password);
		reconnectionState.ClientRequiredModIds = (updates.ContainsKey("clientRequiredModIds") ? ((string[])updates["clientRequiredModIds"]) : ReconnectionState.ClientRequiredModIds);
		reconnectionState.PendingReadinessModIds = (updates.ContainsKey("pendingReadinessModIds") ? ((string[])updates["pendingReadinessModIds"]) : ReconnectionState.PendingReadinessModIds);
		reconnectionState.PendingEnablingModIds = (updates.ContainsKey("pendingEnablingModIds") ? ((string[])updates["pendingEnablingModIds"]) : ReconnectionState.PendingEnablingModIds);
		ReconnectionState = reconnectionState;
	}

	public static void ClearReconnectionState()
	{
		ReconnectionState = new ReconnectionState();
	}

	private static void OnUIStateChanged(UIState oldUIState, UIState newUIState)
	{
		EventManager.TriggerEvent("Event_OnUIStateChanged", new Dictionary<string, object>
		{
			{ "oldUIState", oldUIState },
			{ "newUIState", newUIState }
		});
	}

	private static void OnConnectionStateChanged(ConnectionState oldConnectionState, ConnectionState newConnectionState)
	{
		EventManager.TriggerEvent("Event_OnConnectionStateChanged", new Dictionary<string, object>
		{
			{ "oldConnectionState", oldConnectionState },
			{ "newConnectionState", newConnectionState }
		});
	}

	private static void OnReconnectionStateChanged(ReconnectionState oldReconnectionState, ReconnectionState newReconnectionState)
	{
		Logger.Info($"Reconnection state changed \nFrom:{{{oldReconnectionState}}} \nTo:{{{newReconnectionState}}}");
		EventManager.TriggerEvent("Event_OnReconnectionStateChanged", new Dictionary<string, object>
		{
			{ "oldReconnectionState", oldReconnectionState },
			{ "newReconnectionState", newReconnectionState }
		});
	}
}
public static class GlobalStateManagerController
{
	private static readonly Logger Logger = new Logger("GlobalStateManagerController");

	public static void Initialize()
	{
		EventManager.AddEventListener("Event_OnSceneLoaded", Event_OnSceneLoaded);
		EventManager.AddEventListener("Event_OnPopupClickOk", Event_OnPopupClickOk);
		EventManager.AddEventListener("Event_OnPopupClickClose", Event_OnPopupClickClose);
		EventManager.AddEventListener("Event_OnModStateChanged", Event_OnModStateChanged);
		EventManager.AddEventListener("Event_OnModEnableFailed", Event_OnModEnableFailed);
	}

	public static void Dispose()
	{
		EventManager.RemoveEventListener("Event_OnSceneLoaded", Event_OnSceneLoaded);
		EventManager.RemoveEventListener("Event_OnPopupClickOk", Event_OnPopupClickOk);
		EventManager.RemoveEventListener("Event_OnPopupClickClose", Event_OnPopupClickClose);
		EventManager.RemoveEventListener("Event_OnModStateChanged", Event_OnModStateChanged);
		EventManager.RemoveEventListener("Event_OnModEnableFailed", Event_OnModEnableFailed);
	}

	private static void Event_OnSceneLoaded(Dictionary<string, object> message)
	{
		if (((Scene)message["scene"]).name == "level_default")
		{
			GlobalStateManager.SetUIState(new Dictionary<string, object> { 
			{
				"phase",
				UIPhase.Playing
			} });
		}
		else
		{
			GlobalStateManager.SetUIState(new Dictionary<string, object> { 
			{
				"phase",
				UIPhase.LockerRoom
			} });
		}
	}

	private static void Event_OnPopupClickOk(Dictionary<string, object> message)
	{
		Popup popup = (Popup)message["popup"];
		string name = popup.Name;
		if (!(name == "missingPassword"))
		{
			if (name == "missingMods" && GlobalStateManager.ReconnectionState.Phase == ReconnectionPhase.AwaitingMods)
			{
				string[] clientRequiredModIds = GlobalStateManager.ReconnectionState.ClientRequiredModIds;
				string[] second = ModManager.EnabledMods.Select((Mod mod) => mod.Id).ToArray();
				string[] second2 = ModManager.ReadyMods.Select((Mod mod) => mod.Id).ToArray();
				string[] array = clientRequiredModIds.Except(second2).ToArray();
				string[] value = clientRequiredModIds.Except(array).Except(second).ToArray();
				GlobalStateManager.SetReconnectionState(new Dictionary<string, object>
				{
					{ "pendingReadinessModIds", array },
					{ "pendingEnablingModIds", value }
				});
			}
		}
		else if (GlobalStateManager.ReconnectionState.Phase == ReconnectionPhase.AwaitingPassword)
		{
			PopupMissingPasswordContent popupMissingPasswordContent = (PopupMissingPasswordContent)popup.Content;
			if (string.IsNullOrEmpty(popupMissingPasswordContent.Password))
			{
				GlobalStateManager.ClearReconnectionState();
				return;
			}
			GlobalStateManager.SetReconnectionState(new Dictionary<string, object> { { "password", popupMissingPasswordContent.Password } });
		}
	}

	private static void Event_OnPopupClickClose(Dictionary<string, object> message)
	{
		string name = ((Popup)message["popup"]).Name;
		if ((name == "missingPassword" || name == "missingMods") && (GlobalStateManager.ReconnectionState.Phase == ReconnectionPhase.AwaitingPassword || GlobalStateManager.ReconnectionState.Phase == ReconnectionPhase.AwaitingMods))
		{
			GlobalStateManager.ClearReconnectionState();
		}
	}

	private static void Event_OnModStateChanged(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		BasePluginState basePluginState = (BasePluginState)message["oldState"];
		BasePluginState basePluginState2 = (BasePluginState)message["newState"];
		if (GlobalStateManager.ReconnectionState.Phase != ReconnectionPhase.AwaitingMods)
		{
			return;
		}
		bool num = Enumerable.Contains(GlobalStateManager.ReconnectionState.PendingReadinessModIds, mod.Id);
		bool flag = Enumerable.Contains(GlobalStateManager.ReconnectionState.PendingEnablingModIds, mod.Id);
		bool flag2 = basePluginState.IsEnabled != basePluginState2.IsEnabled;
		bool flag3 = basePluginState.IsReady != basePluginState2.IsReady;
		if (num && flag3 && basePluginState2.IsReady)
		{
			GlobalStateManager.SetReconnectionState(new Dictionary<string, object>
			{
				{
					"pendingReadinessModIds",
					GlobalStateManager.ReconnectionState.PendingReadinessModIds.Where((string id) => id != mod.Id).ToArray()
				},
				{
					"pendingEnablingModIds",
					GlobalStateManager.ReconnectionState.PendingEnablingModIds.Append(mod.Id).ToArray()
				}
			});
		}
		else if (flag && flag2 && basePluginState2.IsEnabled)
		{
			GlobalStateManager.SetReconnectionState(new Dictionary<string, object> { 
			{
				"pendingEnablingModIds",
				GlobalStateManager.ReconnectionState.PendingEnablingModIds.Where((string id) => id != mod.Id).ToArray()
			} });
		}
	}

	private static void Event_OnModEnableFailed(Dictionary<string, object> message)
	{
		if (GlobalStateManager.ReconnectionState.Phase == ReconnectionPhase.AwaitingMods)
		{
			GlobalStateManager.ClearReconnectionState();
		}
	}
}
public class DoublePressInteraction : IInputInteraction
{
	public float maxTapDuration = 0.2f;

	public float pressThreshold = 0.5f;

	public float releaseThreshold = 0.5f;

	private bool released;

	public void Process(ref InputInteractionContext context)
	{
		if (context.timerHasExpired)
		{
			context.Canceled();
			return;
		}
		switch (context.phase)
		{
		case InputActionPhase.Waiting:
			if (context.ReadValue<float>() > pressThreshold)
			{
				context.Started();
				context.SetTimeout(maxTapDuration);
			}
			break;
		case InputActionPhase.Started:
			if (released)
			{
				if (context.ReadValue<float>() > pressThreshold)
				{
					context.Performed();
				}
			}
			else if (context.ReadValue<float>() < releaseThreshold)
			{
				released = true;
			}
			break;
		}
	}

	public void Reset()
	{
		released = false;
	}
}
public class KeyBind
{
	[JsonIgnore]
	public InputAction InputAction;

	[JsonIgnore]
	public bool IsComposite => InputAction.bindings[0].isComposite;

	public string ModifierPath { get; set; }

	public string Path { get; set; }

	public string Interactions { get; set; }

	[JsonConstructor]
	public KeyBind()
	{
	}

	public KeyBind(InputAction inputAction)
	{
		InputAction = inputAction;
		Update(InputAction);
	}

	public void Update(InputAction inputAction)
	{
		InputAction = inputAction;
		ModifierPath = (IsComposite ? inputAction.bindings[1].effectivePath : null);
		Path = (IsComposite ? inputAction.bindings[2].effectivePath : inputAction.bindings[0].effectivePath);
		Interactions = inputAction.bindings[0].effectiveInteractions;
	}
}
