public class ReplayManager : MonoBehaviourSingleton<ReplayManager>
{
	private static readonly Logger Logger = new Logger("ReplayManager");

	[Header("Settings")]
	[SerializeField]
	private int tickRate = 15;

	public ReplayRecorder ReplayRecorder;

	public ReplayPlayer ReplayPlayer;

	public override void Awake()
	{
		base.Awake();
		ReplayRecorder = GetComponent<ReplayRecorder>();
		ReplayPlayer = GetComponent<ReplayPlayer>();
	}

	public void Server_StartRecording()
	{
		ReplayRecorder.Server_StartRecording(tickRate);
	}

	public void Server_StopRecording()
	{
		ReplayRecorder.Server_StopRecording();
	}

	public void Server_StartReplaying(float secondsToReplay)
	{
		SortedList<int, List<(string, object)>> sortedList = new SortedList<int, List<(string, object)>>(ReplayRecorder.EventMap);
		if (sortedList.Count != 0)
		{
			int num = sortedList.Keys.Max();
			int num2 = (int)((float)tickRate * secondsToReplay);
			int fromTick = num - num2;
			ReplayPlayer.Server_StartReplay(sortedList, tickRate, fromTick);
		}
	}

	public void Server_StopReplaying()
	{
		ReplayPlayer.Server_StopReplay();
	}

	public void Server_ScheduleSlowMotionAtWorldTime(float worldTime, float scale, float rampInSeconds, float holdSeconds, float rampOutSeconds, float audioPitchFloor = 1f, float cameraFovPunch = 0f)
	{
		if (ReplayRecorder.IsRecording)
		{
			int num = Mathf.RoundToInt((Time.time - worldTime) * (float)ReplayRecorder.TickRate);
			int tick = ReplayRecorder.Tick - num;
			ReplayRecorder.Server_AddReplayEventAtTick(tick, "SlowMotion", new ReplaySlowMotion
			{
				Scale = scale,
				RampInSeconds = rampInSeconds,
				HoldSeconds = holdSeconds,
				RampOutSeconds = rampOutSeconds,
				AudioPitchFloor = audioPitchFloor,
				CameraFovPunch = cameraFovPunch
			});
		}
	}

	public void Server_ScheduleCellyCam(ulong ownerClientId, float delaySeconds = 0f)
	{
		if (ReplayRecorder.IsRecording)
		{
			int num = Mathf.RoundToInt(delaySeconds * (float)ReplayRecorder.TickRate);
			ReplayRecorder.Server_AddReplayEventAtTick(ReplayRecorder.Tick + num, "CellyCam", new ReplayCellyCam
			{
				OwnerClientId = ownerClientId
			});
		}
	}
}
public class ReplayManagerController : MonoBehaviour
{
	private ReplayManager replayManager;

	private void Awake()
	{
		replayManager = GetComponent<ReplayManager>();
		EventManager.AddEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
	}

	private void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
	}

	private void Event_Server_OnServerStopped(Dictionary<string, object> message)
	{
		replayManager.Server_StopReplaying();
		replayManager.Server_StopRecording();
	}
}
public class ReplayPlayer : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("ReplayPlayer");

	[HideInInspector]
	public bool IsReplaying;

	[HideInInspector]
	public int TickRate = 15;

	[HideInInspector]
	public int Tick;

	[HideInInspector]
	public SortedList<int, List<(string, object)>> EventMap = new SortedList<int, List<(string, object)>>();

	private float tickAccumulator;

	private Dictionary<ulong, ulong> replayPuckNetworkObjectIdMap = new Dictionary<ulong, ulong>();

	private List<ReplayPlayerSpawned> replayPlayerSpawnedList = new List<ReplayPlayerSpawned>();

	private List<ReplayPlayerBodySpawned> replayPlayerBodySpawnedList = new List<ReplayPlayerBodySpawned>();

	private List<ReplayStickSpawned> replayStickSpawnedList = new List<ReplayStickSpawned>();

	private List<ReplayPuckSpawned> replayPuckSpawnedList = new List<ReplayPuckSpawned>();

	[HideInInspector]
	public float TickInterval => 1f / (float)TickRate;

	private void Update()
	{
		if (NetworkManager.Singleton == null || !NetworkManager.Singleton.IsServer || !IsReplaying)
		{
			return;
		}
		tickAccumulator += Time.deltaTime * (float)TickRate;
		if (tickAccumulator >= 1f)
		{
			while (tickAccumulator >= 1f)
			{
				tickAccumulator -= 1f;
			}
			Server_Tick(Tick);
			Tick++;
		}
	}

	public void Server_StartReplay(SortedList<int, List<(string, object)>> tickEventMap, int tickRate, int fromTick = 0)
	{
		if (NetworkManager.Singleton.IsServer && !IsReplaying && tickEventMap.Keys.Count != 0)
		{
			int num = tickEventMap.Keys.Min();
			int max = tickEventMap.Keys.Max();
			fromTick = Mathf.Clamp(fromTick, num, max);
			EventMap = tickEventMap;
			TickRate = tickRate;
			int i;
			for (i = num; i < fromTick; i++)
			{
				Server_Tick(i, skip: true);
				EventMap.Remove(i);
			}
			Tick = i;
			List<(string, object)> list = Server_GetSkippedEvents();
			if (list.Count > 0)
			{
				Tick--;
				EventMap.Add(Tick, list);
			}
			IsReplaying = true;
		}
	}

	public void Server_StopReplay()
	{
		if (NetworkManager.Singleton.IsServer && IsReplaying)
		{
			IsReplaying = false;
			if (NetworkBehaviourSingleton<GameManager>.Instance != null)
			{
				NetworkBehaviourSingleton<GameManager>.Instance.Server_StopSlowMotion();
			}
			Server_Dispose();
		}
	}

	private void Server_Tick(int tick, bool skip = false)
	{
		if (!NetworkManager.Singleton.IsServer)
		{
			return;
		}
		if (tick > EventMap.Keys.Max())
		{
			Server_StopReplay();
		}
		else
		{
			if (!EventMap.ContainsKey(tick))
			{
				return;
			}
			foreach (var (eventName, eventData) in EventMap[tick])
			{
				if (skip)
				{
					Server_SkipEvent(eventName, eventData);
				}
				else
				{
					Server_ReplayEvent(eventName, eventData);
				}
			}
		}
	}

	private List<(string, object)> Server_GetSkippedEvents()
	{
		List<(string, object)> list = new List<(string, object)>();
		foreach (ReplayPlayerSpawned replayPlayerSpawned in replayPlayerSpawnedList)
		{
			list.Add(("PlayerSpawned", replayPlayerSpawned));
		}
		foreach (ReplayPlayerBodySpawned replayPlayerBodySpawned in replayPlayerBodySpawnedList)
		{
			list.Add(("PlayerBodySpawned", replayPlayerBodySpawned));
		}
		foreach (ReplayStickSpawned replayStickSpawned in replayStickSpawnedList)
		{
			list.Add(("StickSpawned", replayStickSpawned));
		}
		foreach (ReplayPuckSpawned replayPuckSpawned in replayPuckSpawnedList)
		{
			list.Add(("PuckSpawned", replayPuckSpawned));
		}
		return list;
	}

	private void Server_SkipEvent(string eventName, object eventData)
	{
		if (!NetworkManager.Singleton.IsServer)
		{
			return;
		}
		switch (eventName)
		{
		case "PlayerSpawned":
		{
			ReplayPlayerSpawned item4 = (ReplayPlayerSpawned)eventData;
			replayPlayerSpawnedList.Add(item4);
			break;
		}
		case "PlayerDespawned":
		{
			ReplayPlayerDespawned playerDespawned = (ReplayPlayerDespawned)eventData;
			replayPlayerSpawnedList.RemoveAll((ReplayPlayerSpawned x) => x.OwnerClientId == playerDespawned.OwnerClientId);
			break;
		}
		case "PlayerBodySpawned":
		{
			ReplayPlayerBodySpawned item3 = (ReplayPlayerBodySpawned)eventData;
			replayPlayerBodySpawnedList.Add(item3);
			break;
		}
		case "PlayerBodyDespawned":
		{
			ReplayPlayerBodyDespawned playerBodyDespawned = (ReplayPlayerBodyDespawned)eventData;
			replayPlayerBodySpawnedList.RemoveAll((ReplayPlayerBodySpawned x) => x.OwnerClientId == playerBodyDespawned.OwnerClientId);
			break;
		}
		case "StickSpawned":
		{
			ReplayStickSpawned item2 = (ReplayStickSpawned)eventData;
			replayStickSpawnedList.Add(item2);
			break;
		}
		case "StickDespawned":
		{
			ReplayStickDespawned stickDespawned = (ReplayStickDespawned)eventData;
			replayStickSpawnedList.RemoveAll((ReplayStickSpawned x) => x.OwnerClientId == stickDespawned.OwnerClientId);
			break;
		}
		case "PuckSpawned":
		{
			ReplayPuckSpawned item = (ReplayPuckSpawned)eventData;
			replayPuckSpawnedList.Add(item);
			break;
		}
		case "PuckDespawned":
		{
			ReplayPuckDespawned puckDespawned = (ReplayPuckDespawned)eventData;
			replayPuckSpawnedList.RemoveAll((ReplayPuckSpawned x) => x.NetworkObjectId == puckDespawned.NetworkObjectId);
			break;
		}
		}
	}

	private void Server_ReplayEvent(string eventName, object eventData)
	{
		if (!NetworkManager.Singleton.IsServer)
		{
			return;
		}
		switch (eventName)
		{
		case "PlayerSpawned":
		{
			ReplayPlayerSpawned replayPlayerSpawned = (ReplayPlayerSpawned)eventData;
			MonoBehaviourSingleton<PlayerManager>.Instance.Server_SpawnPlayer(replayPlayerSpawned.OwnerClientId, replayPlayerSpawned.GameState, replayPlayerSpawned.CustomizationState, replayPlayerSpawned.Handedness, replayPlayerSpawned.SteamId.ToString(), replayPlayerSpawned.Username.ToString(), replayPlayerSpawned.Number, replayPlayerSpawned.PatreonLevel, replayPlayerSpawned.AdminLevel, replayPlayerSpawned.IsMuted, isReplay: true);
			break;
		}
		case "PlayerInput":
		{
			ReplayPlayerInput replayPlayerInput = (ReplayPlayerInput)eventData;
			Player replayPlayerByClientId8 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayPlayerInput.OwnerClientId);
			if ((bool)replayPlayerByClientId8)
			{
				replayPlayerByClientId8.PlayerInput.LookAngleInput.ClientValue = replayPlayerInput.LookAngleInput;
				replayPlayerByClientId8.PlayerInput.BladeAngleInput.ClientValue = replayPlayerInput.BladeAngleInput;
				replayPlayerByClientId8.PlayerInput.TrackInput.ClientValue = replayPlayerInput.TrackInput;
				replayPlayerByClientId8.PlayerInput.LookInput.ClientValue = replayPlayerInput.LookInput;
			}
			break;
		}
		case "PlayerDespawned":
		{
			ReplayPlayerDespawned replayPlayerDespawned = (ReplayPlayerDespawned)eventData;
			Player replayPlayerByClientId3 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayPlayerDespawned.OwnerClientId);
			if ((bool)replayPlayerByClientId3)
			{
				replayPlayerByClientId3.NetworkObject.Despawn();
				Logger.Info($"Despawned replay player {replayPlayerByClientId3.OwnerClientId}");
			}
			break;
		}
		case "PlayerBodySpawned":
		{
			ReplayPlayerBodySpawned replayPlayerBodySpawned = (ReplayPlayerBodySpawned)eventData;
			Player replayPlayerByClientId7 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayPlayerBodySpawned.OwnerClientId);
			if ((bool)replayPlayerByClientId7)
			{
				replayPlayerByClientId7.GameState.Value = replayPlayerBodySpawned.GameState;
				replayPlayerByClientId7.CustomizationState.Value = replayPlayerBodySpawned.CustomizationState;
				replayPlayerByClientId7.Username.Value = replayPlayerBodySpawned.Username;
				replayPlayerByClientId7.Number.Value = replayPlayerBodySpawned.Number;
				replayPlayerByClientId7.Server_SpawnPlayerBody(replayPlayerBodySpawned.Position, replayPlayerBodySpawned.Rotation, replayPlayerByClientId7.Role);
			}
			break;
		}
		case "PlayerBodyMove":
		{
			ReplayPlayerBodyMove replayPlayerBodyMove = (ReplayPlayerBodyMove)eventData;
			Player replayPlayerByClientId2 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayPlayerBodyMove.OwnerClientId);
			if ((bool)replayPlayerByClientId2 && (bool)replayPlayerByClientId2.PlayerBody)
			{
				replayPlayerByClientId2.PlayerBody.transform.DOKill(complete: true);
				replayPlayerByClientId2.PlayerBody.transform.DOMove(replayPlayerBodyMove.Position, TickInterval).SetEase(Ease.Linear);
				replayPlayerByClientId2.PlayerBody.transform.DORotateQuaternion(replayPlayerBodyMove.Rotation, TickInterval).SetEase(Ease.Linear);
				replayPlayerByClientId2.PlayerBody.Stamina.Value = replayPlayerBodyMove.Stamina;
				replayPlayerByClientId2.PlayerBody.Speed.Value = replayPlayerBodyMove.Speed;
				replayPlayerByClientId2.PlayerBody.IsSprinting.Value = replayPlayerBodyMove.IsSprinting;
				replayPlayerByClientId2.PlayerBody.IsSliding.Value = replayPlayerBodyMove.IsSliding;
				replayPlayerByClientId2.PlayerBody.IsStopping.Value = replayPlayerBodyMove.IsStopping;
				replayPlayerByClientId2.PlayerBody.IsExtendedLeft.Value = replayPlayerBodyMove.IsExtendedLeft;
				replayPlayerByClientId2.PlayerBody.IsExtendedRight.Value = replayPlayerBodyMove.IsExtendedRight;
			}
			break;
		}
		case "PlayerBodyDespawned":
		{
			ReplayPlayerBodyDespawned replayPlayerBodyDespawned = (ReplayPlayerBodyDespawned)eventData;
			Player replayPlayerByClientId5 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayPlayerBodyDespawned.OwnerClientId);
			if ((bool)replayPlayerByClientId5 && (bool)replayPlayerByClientId5.PlayerBody)
			{
				replayPlayerByClientId5.Server_DespawnPlayerBody();
			}
			break;
		}
		case "StickSpawned":
		{
			ReplayStickSpawned replayStickSpawned = (ReplayStickSpawned)eventData;
			Player replayPlayerByClientId4 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayStickSpawned.OwnerClientId);
			if ((bool)replayPlayerByClientId4)
			{
				replayPlayerByClientId4.Server_SpawnStick(replayStickSpawned.Position, replayStickSpawned.Rotation, replayPlayerByClientId4.Role);
			}
			break;
		}
		case "StickMove":
		{
			ReplayStickMove replayStickMove = (ReplayStickMove)eventData;
			Player replayPlayerByClientId = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayStickMove.OwnerClientId);
			if ((bool)replayPlayerByClientId && (bool)replayPlayerByClientId.Stick)
			{
				replayPlayerByClientId.Stick.transform.DOKill(complete: true);
				replayPlayerByClientId.Stick.transform.DOMove(replayStickMove.Position, TickInterval).SetEase(Ease.Linear);
				replayPlayerByClientId.Stick.transform.DORotateQuaternion(replayStickMove.Rotation, TickInterval).SetEase(Ease.Linear);
			}
			break;
		}
		case "StickDespawned":
		{
			ReplayStickDespawned replayStickDespawned = (ReplayStickDespawned)eventData;
			Player replayPlayerByClientId6 = MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayerByClientId(replayStickDespawned.OwnerClientId);
			if ((bool)replayPlayerByClientId6 && (bool)replayPlayerByClientId6.Stick)
			{
				replayPlayerByClientId6.Server_DespawnStick();
			}
			break;
		}
		case "PuckSpawned":
		{
			ReplayPuckSpawned replayPuckSpawned = (ReplayPuckSpawned)eventData;
			Puck puck = MonoBehaviourSingleton<PuckManager>.Instance.Server_SpawnPuck(replayPuckSpawned.Position, replayPuckSpawned.Rotation, isReplay: true);
			replayPuckNetworkObjectIdMap.Add(replayPuckSpawned.NetworkObjectId, puck.NetworkObjectId);
			puck.transform.position = replayPuckSpawned.Position;
			puck.transform.rotation = replayPuckSpawned.Rotation;
			break;
		}
		case "PuckMove":
		{
			ReplayPuckMove replayPuckMove = (ReplayPuckMove)eventData;
			if (replayPuckNetworkObjectIdMap.ContainsKey(replayPuckMove.NetworkObjectId))
			{
				Puck replayPuckByNetworkObjectId2 = MonoBehaviourSingleton<PuckManager>.Instance.GetReplayPuckByNetworkObjectId(replayPuckNetworkObjectIdMap[replayPuckMove.NetworkObjectId]);
				if ((bool)replayPuckByNetworkObjectId2)
				{
					replayPuckByNetworkObjectId2.transform.DOKill(complete: true);
					replayPuckByNetworkObjectId2.transform.DOMove(replayPuckMove.Position, TickInterval).SetEase(Ease.Linear);
					replayPuckByNetworkObjectId2.transform.DORotateQuaternion(replayPuckMove.Rotation, TickInterval).SetEase(Ease.Linear);
				}
			}
			break;
		}
		case "PuckDespawned":
		{
			ReplayPuckDespawned replayPuckDespawned = (ReplayPuckDespawned)eventData;
			if (replayPuckNetworkObjectIdMap.ContainsKey(replayPuckDespawned.NetworkObjectId))
			{
				Puck replayPuckByNetworkObjectId = MonoBehaviourSingleton<PuckManager>.Instance.GetReplayPuckByNetworkObjectId(replayPuckNetworkObjectIdMap[replayPuckDespawned.NetworkObjectId]);
				if ((bool)replayPuckByNetworkObjectId)
				{
					MonoBehaviourSingleton<PuckManager>.Instance.Server_DespawnPuck(replayPuckByNetworkObjectId);
				}
			}
			break;
		}
		case "SlowMotion":
		{
			ReplaySlowMotion replaySlowMotion = (ReplaySlowMotion)eventData;
			if (!(NetworkBehaviourSingleton<GameManager>.Instance == null))
			{
				NetworkBehaviourSingleton<GameManager>.Instance.Server_StartSlowMotion(replaySlowMotion.Scale, replaySlowMotion.RampInSeconds, replaySlowMotion.HoldSeconds, replaySlowMotion.RampOutSeconds, replaySlowMotion.AudioPitchFloor, replaySlowMotion.CameraFovPunch);
			}
			break;
		}
		case "CellyCam":
		{
			ReplayCellyCam replayCellyCam = (ReplayCellyCam)eventData;
			if (!(NetworkBehaviourSingleton<GameManager>.Instance == null))
			{
				NetworkBehaviourSingleton<GameManager>.Instance.Server_NotifyReplayCellyCamRpc(replayCellyCam.OwnerClientId);
			}
			break;
		}
		}
	}

	private void Server_DisposeReplayObjects()
	{
		foreach (Player replayPlayer in MonoBehaviourSingleton<PlayerManager>.Instance.GetReplayPlayers())
		{
			if ((bool)replayPlayer.PlayerBody)
			{
				replayPlayer.PlayerBody.transform.DOKill();
				replayPlayer.Server_DespawnPlayerBody();
			}
			if ((bool)replayPlayer.Stick)
			{
				replayPlayer.Stick.transform.DOKill();
				replayPlayer.Server_DespawnStick();
			}
			replayPlayer.NetworkObject.Despawn();
			Logger.Info($"Despawned replay player {replayPlayer.OwnerClientId}");
		}
		foreach (Puck replayPuck in MonoBehaviourSingleton<PuckManager>.Instance.GetReplayPucks())
		{
			replayPuck.transform.DOKill();
			MonoBehaviourSingleton<PuckManager>.Instance.Server_DespawnPuck(replayPuck);
			Logger.Info($"Despawned replay puck {replayPuck.OwnerClientId}");
		}
	}

	private void Server_Dispose()
	{
		Server_DisposeReplayObjects();
		Tick = 0;
		EventMap.Clear();
		replayPuckNetworkObjectIdMap.Clear();
		replayPlayerSpawnedList.Clear();
		replayPlayerBodySpawnedList.Clear();
		replayStickSpawnedList.Clear();
		replayPuckSpawnedList.Clear();
	}
}
public class ReplayRecorder : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("ReplayRecorder");

	[HideInInspector]
	public bool IsRecording;

	[HideInInspector]
	public int TickRate = 15;

	[HideInInspector]
	public int Tick;

	[HideInInspector]
	public SortedList<int, List<(string, object)>> EventMap = new SortedList<int, List<(string, object)>>();

	private float tickAccumulator;

	private void Update()
	{
		if (NetworkManager.Singleton == null || !NetworkManager.Singleton.IsServer || !IsRecording)
		{
			return;
		}
		tickAccumulator += Time.deltaTime * (float)TickRate;
		if (tickAccumulator >= 1f)
		{
			while (tickAccumulator >= 1f)
			{
				tickAccumulator -= 1f;
			}
			Server_Tick();
			Tick++;
		}
	}

	public void Server_StartRecording(int tickRate)
	{
		if (!NetworkManager.Singleton.IsServer || IsRecording)
		{
			return;
		}
		Logger.Info($"Replay recording started at {TickRate} ticks per second");
		EventMap.Clear();
		TickRate = tickRate;
		Tick = 0;
		IsRecording = true;
		foreach (Player player in MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayers())
		{
			Server_AddPlayerSpawnedEvent(player);
			if ((bool)player.PlayerBody)
			{
				Server_AddPlayerBodySpawnedEvent(player.PlayerBody);
			}
			if ((bool)player.Stick)
			{
				Server_AddStickSpawnedEvent(player.Stick);
			}
		}
		foreach (Puck puck in MonoBehaviourSingleton<PuckManager>.Instance.GetPucks())
		{
			Server_AddPuckSpawnedEvent(puck);
		}
	}

	public void Server_StopRecording()
	{
		if (NetworkManager.Singleton.IsServer && IsRecording)
		{
			Logger.Info("Replay recording stopped");
			Tick = 0;
			IsRecording = false;
		}
	}

	private void Server_Tick()
	{
		if (!NetworkManager.Singleton.IsServer)
		{
			return;
		}
		foreach (Player spawnedPlayer in MonoBehaviourSingleton<PlayerManager>.Instance.GetSpawnedPlayers())
		{
			Server_AddReplayEvent("PlayerBodyMove", new ReplayPlayerBodyMove
			{
				OwnerClientId = spawnedPlayer.OwnerClientId,
				Position = spawnedPlayer.PlayerBody.transform.position,
				Rotation = spawnedPlayer.PlayerBody.transform.rotation,
				Stamina = spawnedPlayer.PlayerBody.Stamina.Value,
				Speed = spawnedPlayer.PlayerBody.Speed.Value,
				IsSprinting = spawnedPlayer.PlayerBody.IsSprinting.Value,
				IsSliding = spawnedPlayer.PlayerBody.IsSliding.Value,
				IsStopping = spawnedPlayer.PlayerBody.IsStopping.Value,
				IsExtendedLeft = spawnedPlayer.PlayerBody.IsExtendedLeft.Value,
				IsExtendedRight = spawnedPlayer.PlayerBody.IsExtendedRight.Value
			});
			Server_AddReplayEvent("StickMove", new ReplayStickMove
			{
				OwnerClientId = spawnedPlayer.OwnerClientId,
				Position = spawnedPlayer.Stick.transform.position,
				Rotation = spawnedPlayer.Stick.transform.rotation
			});
			Server_AddReplayEvent("PlayerInput", new ReplayPlayerInput
			{
				OwnerClientId = spawnedPlayer.OwnerClientId,
				LookAngleInput = spawnedPlayer.PlayerInput.LookAngleInput.ServerValue,
				BladeAngleInput = spawnedPlayer.PlayerInput.BladeAngleInput.ServerValue,
				TrackInput = spawnedPlayer.PlayerInput.TrackInput.ServerValue,
				LookInput = spawnedPlayer.PlayerInput.LookInput.ServerValue
			});
		}
		foreach (Puck puck in MonoBehaviourSingleton<PuckManager>.Instance.GetPucks())
		{
			Server_AddReplayEvent("PuckMove", new ReplayPuckMove
			{
				NetworkObjectId = puck.NetworkObjectId,
				Position = puck.transform.position,
				Rotation = puck.transform.rotation
			});
		}
	}

	public void Server_AddReplayEvent(string eventName, object eventData)
	{
		if (NetworkManager.Singleton.IsServer && IsRecording)
		{
			if (EventMap.ContainsKey(Tick))
			{
				EventMap[Tick].Add((eventName, eventData));
				return;
			}
			List<(string, object)> value = new List<(string, object)> { (eventName, eventData) };
			EventMap.Add(Tick, value);
		}
	}

	public void Server_AddReplayEventAtTick(int tick, string eventName, object eventData)
	{
		if (NetworkManager.Singleton.IsServer && IsRecording && tick >= 0)
		{
			if (EventMap.ContainsKey(tick))
			{
				EventMap[tick].Add((eventName, eventData));
				return;
			}
			List<(string, object)> value = new List<(string, object)> { (eventName, eventData) };
			EventMap.Add(tick, value);
		}
	}

	public void Server_AddPlayerSpawnedEvent(Player player)
	{
		Server_AddReplayEvent("PlayerSpawned", new ReplayPlayerSpawned
		{
			OwnerClientId = player.OwnerClientId,
			GameState = player.GameState.Value,
			CustomizationState = player.CustomizationState.Value,
			Handedness = player.Handedness.Value,
			SteamId = player.SteamId.Value,
			Username = player.Username.Value,
			Number = player.Number.Value,
			PatreonLevel = player.PatreonLevel.Value,
			AdminLevel = player.AdminLevel.Value,
			IsMuted = player.IsMuted.Value
		});
	}

	public void Server_AddPlayerDespawnedEvent(Player player)
	{
		Server_AddReplayEvent("PlayerDespawned", new ReplayPlayerDespawned
		{
			OwnerClientId = player.OwnerClientId
		});
	}

	public void Server_AddPlayerBodySpawnedEvent(PlayerBody playerBody)
	{
		Server_AddReplayEvent("PlayerBodySpawned", new ReplayPlayerBodySpawned
		{
			OwnerClientId = playerBody.OwnerClientId,
			Position = playerBody.transform.position,
			Rotation = playerBody.transform.rotation,
			GameState = playerBody.Player.GameState.Value,
			CustomizationState = playerBody.Player.CustomizationState.Value,
			Username = playerBody.Player.Username.Value,
			Number = playerBody.Player.Number.Value
		});
	}

	public void Server_AddPlayerBodyDespawnedEvent(PlayerBody playerBody)
	{
		Server_AddReplayEvent("PlayerBodyDespawned", new ReplayPlayerBodyDespawned
		{
			OwnerClientId = playerBody.OwnerClientId
		});
	}

	public void Server_AddStickSpawnedEvent(Stick stick)
	{
		Server_AddReplayEvent("StickSpawned", new ReplayStickSpawned
		{
			OwnerClientId = stick.OwnerClientId,
			Position = stick.transform.position,
			Rotation = stick.transform.rotation
		});
	}

	public void Server_AddStickDespawnedEvent(Stick stick)
	{
		Server_AddReplayEvent("StickDespawned", new ReplayStickDespawned
		{
			OwnerClientId = stick.OwnerClientId
		});
	}

	public void Server_AddPuckSpawnedEvent(Puck puck)
	{
		Server_AddReplayEvent("PuckSpawned", new ReplayPuckSpawned
		{
			NetworkObjectId = puck.NetworkObjectId,
			Position = puck.transform.position,
			Rotation = puck.transform.rotation
		});
	}

	public void Server_AddPuckDespawnedEvent(Puck puck)
	{
		Server_AddReplayEvent("PuckDespawned", new ReplayPuckDespawned
		{
			NetworkObjectId = puck.NetworkObjectId
		});
	}
}
