public static class SaveManager
{
	private static Tween saveDebounceTween;

	public static void Initialize()
	{
	}

	public static void Dispose()
	{
		saveDebounceTween?.Kill();
	}

	public static void SetBool(string key, bool value)
	{
		PlayerPrefs.SetInt(key, value ? 1 : 0);
		Save();
	}

	public static bool GetBool(string key, bool defaultValue)
	{
		int defaultValue2 = (defaultValue ? 1 : 0);
		return PlayerPrefs.GetInt(key, defaultValue2) == 1;
	}

	public static void SetInt(string key, int value)
	{
		PlayerPrefs.SetInt(key, value);
		Save();
	}

	public static int GetInt(string key, int defaultValue)
	{
		return PlayerPrefs.GetInt(key, defaultValue);
	}

	public static void SetFloat(string key, float value)
	{
		PlayerPrefs.SetFloat(key, value);
		Save();
	}

	public static float GetFloat(string key, float defaultValue)
	{
		return PlayerPrefs.GetFloat(key, defaultValue);
	}

	public static void SetString(string key, string value)
	{
		PlayerPrefs.SetString(key, value);
		Save();
	}

	public static string GetString(string key, string defaultValue)
	{
		return PlayerPrefs.GetString(key, defaultValue);
	}

	public static void SetEnum<T>(string key, T value) where T : Enum
	{
		PlayerPrefs.SetInt(key, Convert.ToInt32(value));
		Save();
	}

	public static T GetEnum<T>(string key, T defaultValue) where T : Enum
	{
		int defaultValue2 = Convert.ToInt32(defaultValue);
		int value = PlayerPrefs.GetInt(key, defaultValue2);
		return (T)Enum.ToObject(typeof(T), value);
	}

	private static void Save()
	{
		saveDebounceTween?.Kill();
		saveDebounceTween = DOVirtual.DelayedCall(0f, delegate
		{
			PlayerPrefs.Save();
		});
	}
}
public static class SceneManager
{
	private static readonly Logger Logger = new Logger("SceneManager");

	public static bool IsSceneLoadInProgress;

	public static bool IsInitialSceneLoaded;

	public static bool IsNetworkSceneManagerAvailable
	{
		get
		{
			if (NetworkManager.Singleton != null && NetworkManager.Singleton.SceneManager != null)
			{
				return NetworkManager.Singleton.IsServer;
			}
			return false;
		}
	}

	public static void Initialize()
	{
		UnityEngine.SceneManagement.SceneManager.sceneLoaded += OnSceneLoaded;
		UnityEngine.SceneManagement.SceneManager.sceneUnloaded += OnSceneUnloaded;
		SceneManagerController.Initialize();
	}

	public static void Dispose()
	{
		UnityEngine.SceneManagement.SceneManager.sceneLoaded -= OnSceneLoaded;
		UnityEngine.SceneManagement.SceneManager.sceneUnloaded -= OnSceneUnloaded;
		SceneManagerController.Dispose();
	}

	public static void InitializeServer()
	{
		if (IsNetworkSceneManagerAvailable)
		{
			IsSceneLoadInProgress = false;
			IsInitialSceneLoaded = false;
			NetworkManager.Singleton.SceneManager.OnSceneEvent += Server_OnSceneEvent;
		}
	}

	public static void DisposeServer()
	{
		if (IsNetworkSceneManagerAvailable)
		{
			NetworkManager.Singleton.SceneManager.OnSceneEvent -= Server_OnSceneEvent;
			IsSceneLoadInProgress = false;
			IsInitialSceneLoaded = false;
		}
	}

	public static void LoadScene(string sceneName)
	{
		if (IsNetworkSceneManagerAvailable)
		{
			Logger.Info("Loading server scene " + sceneName);
			NetworkManager.Singleton.SceneManager.LoadScene(sceneName, LoadSceneMode.Single);
		}
		else
		{
			Logger.Info("Loading scene " + sceneName);
			UnityEngine.SceneManagement.SceneManager.LoadScene(sceneName);
		}
	}

	private static void OnSceneLoaded(Scene scene, LoadSceneMode loadSceneMode)
	{
		EventManager.TriggerEvent("Event_OnSceneLoaded", new Dictionary<string, object> { { "scene", scene } });
	}

	private static void OnSceneUnloaded(Scene scene)
	{
		EventManager.TriggerEvent("Event_OnSceneUnloaded", new Dictionary<string, object> { { "scene", scene } });
	}

	private static void Server_OnSceneEvent(SceneEvent sceneEvent)
	{
		switch (sceneEvent.SceneEventType)
		{
		case SceneEventType.Load:
			Server_OnLoadScene();
			break;
		case SceneEventType.LoadComplete:
			Server_OnClientSceneLoadComplete(sceneEvent.ClientId);
			break;
		case SceneEventType.SynchronizeComplete:
			Server_OnClientSceneSynchronizeComplete(sceneEvent.ClientId);
			break;
		case SceneEventType.UnloadComplete:
			Server_OnClientSceneUnloadComplete(sceneEvent.ClientId);
			break;
		case SceneEventType.LoadEventCompleted:
			Server_OnLoadSceneEventCompleted(sceneEvent.ClientsThatCompleted, sceneEvent.ClientsThatTimedOut);
			break;
		case SceneEventType.Unload:
		case SceneEventType.Synchronize:
		case SceneEventType.ReSynchronize:
		case SceneEventType.UnloadEventCompleted:
			break;
		}
	}

	private static void Server_OnLoadScene()
	{
		IsSceneLoadInProgress = true;
		Logger.Info("Server started loading scene");
		EventManager.TriggerEvent("Event_Server_OnLoadScene");
	}

	private static void Server_OnClientSceneLoadComplete(ulong clientId)
	{
		Logger.Info($"Client {clientId} completed scene load");
		EventManager.TriggerEvent("Event_Server_OnClientSceneLoadComplete", new Dictionary<string, object> { { "clientId", clientId } });
	}

	private static void Server_OnClientSceneUnloadComplete(ulong clientId)
	{
		Logger.Info($"Client {clientId} completed scene unload");
		EventManager.TriggerEvent("Event_Server_OnClientSceneUnloadComplete", new Dictionary<string, object> { { "clientId", clientId } });
	}

	private static void Server_OnClientSceneSynchronizeComplete(ulong clientId)
	{
		Logger.Info($"Client {clientId} completed scene synchronization");
		EventManager.TriggerEvent("Event_Server_OnClientSceneSynchronizeComplete", new Dictionary<string, object> { { "clientId", clientId } });
	}

	private static void Server_OnLoadSceneEventCompleted(List<ulong> clientsThatCompleted, List<ulong> clientsThatTimedOut)
	{
		Logger.Info("Scene load event completed on server");
		IsSceneLoadInProgress = false;
		bool flag = !IsInitialSceneLoaded;
		IsInitialSceneLoaded = true;
		EventManager.TriggerEvent("Event_Server_OnLoadSceneEventCompleted", new Dictionary<string, object>
		{
			{ "clientsThatCompleted", clientsThatCompleted },
			{ "clientsThatTimedOut", clientsThatTimedOut },
			{ "isInitialScene", flag }
		});
	}
}
public static class SceneManagerController
{
	public static void Initialize()
	{
		EventManager.AddEventListener("Event_Server_OnServerStarted", Event_Server_OnServerStarted);
		EventManager.AddEventListener("Event_Server_OnReady", Event_Server_OnReady);
		EventManager.AddEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
		EventManager.AddEventListener("Event_OnClientStopped", Event_OnClientStopped);
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			SceneManager.LoadScene("locker_room");
		}
	}

	public static void Dispose()
	{
		EventManager.RemoveEventListener("Event_Server_OnServerStarted", Event_Server_OnServerStarted);
		EventManager.RemoveEventListener("Event_Server_OnReady", Event_Server_OnReady);
		EventManager.RemoveEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
		EventManager.RemoveEventListener("Event_OnClientStopped", Event_OnClientStopped);
	}

	private static void Event_Server_OnServerStarted(Dictionary<string, object> message)
	{
		SceneManager.InitializeServer();
	}

	private static void Event_Server_OnReady(Dictionary<string, object> message)
	{
		if (((ServerConfig)message["serverConfig"]).level == "default")
		{
			SceneManager.LoadScene("level_default");
		}
	}

	private static void Event_Server_OnServerStopped(Dictionary<string, object> message)
	{
		SceneManager.DisposeServer();
	}

	private static void Event_OnClientStopped(Dictionary<string, object> message)
	{
		SceneManager.LoadScene("locker_room");
	}
}
public class AdminManager : MonoBehaviourSingleton<AdminManager>
{
	private static readonly Logger Logger = new Logger("AdminManager");

	private List<string> adminSteamIds = new List<string>();

	private string adminSteamIdsFilePath;

	private FileSystemWatcher adminSteamIdsWatcher;

	public override void Awake()
	{
		base.Awake();
		adminSteamIdsFilePath = Utils.GetCommandLineArgument("--adminSteamIdsPath") ?? "./admin_steam_ids.json";
		adminSteamIdsFilePath = Path.GetFullPath(adminSteamIdsFilePath);
	}

	public void Dispose()
	{
		adminSteamIds.Clear();
		if (adminSteamIdsWatcher != null)
		{
			adminSteamIdsWatcher.Dispose();
			adminSteamIdsWatcher = null;
		}
	}

	public void LoadAdminSteamIds()
	{
		if (!File.Exists(adminSteamIdsFilePath))
		{
			Logger.Warning("Admin steam ids file not found at " + adminSteamIdsFilePath + ", creating default...");
			File.AppendAllText(adminSteamIdsFilePath, JsonSerializer.Serialize(new List<string>(), new JsonSerializerOptions
			{
				WriteIndented = true
			}));
		}
		ReadAdminSteamIds();
		WatchAdminSteamIds(adminSteamIdsFilePath);
	}

	public void SaveAdminSteamIds()
	{
		File.WriteAllText(adminSteamIdsFilePath, JsonSerializer.Serialize(adminSteamIds, new JsonSerializerOptions
		{
			WriteIndented = true
		}));
	}

	public void ReadAdminSteamIds()
	{
		if (ConfigUtils.TryLoadFromFile<List<string>>(adminSteamIdsFilePath, out var result))
		{
			adminSteamIds = result ?? new List<string>();
		}
		else
		{
			Logger.Error("Could not load admin Steam IDs (see the error above); keeping the previous list.");
		}
	}

	public void WatchAdminSteamIds(string adminSteamIdsFilePath)
	{
		if (adminSteamIdsWatcher == null)
		{
			string fileName = Path.GetFileName(adminSteamIdsFilePath);
			string path = adminSteamIdsFilePath.Replace(fileName, string.Empty);
			adminSteamIdsWatcher = new FileSystemWatcher(path);
			adminSteamIdsWatcher.NotifyFilter = NotifyFilters.LastWrite;
			adminSteamIdsWatcher.Filter = fileName;
			adminSteamIdsWatcher.EnableRaisingEvents = true;
			adminSteamIdsWatcher.Changed += OnAdminSteamIdsFileChanged;
			Logger.Info("Watching admin Steam IDs file " + fileName);
		}
	}

	private void OnAdminSteamIdsFileChanged(object sender, FileSystemEventArgs e)
	{
		Logger.Info("Admin Steam IDs file changed: " + e.FullPath);
		if (ConfigUtils.TryLoadFromFile<List<string>>(e.FullPath, out var result))
		{
			adminSteamIds = result ?? new List<string>();
		}
	}

	public void AddAdminSteamId(string steamId)
	{
		if (!adminSteamIds.Contains(steamId))
		{
			adminSteamIds.Add(steamId);
			SaveAdminSteamIds();
		}
	}

	public void RemoveAdminSteamId(string steamId)
	{
		if (adminSteamIds.Contains(steamId))
		{
			adminSteamIds.Remove(steamId);
			SaveAdminSteamIds();
		}
	}

	public bool IsSteamIdAdmin(string steamId)
	{
		return adminSteamIds.Contains(steamId);
	}
}
