public class ConnectionApproval
{
	public NetworkManager.ConnectionApprovalRequest Request;

	public NetworkManager.ConnectionApprovalResponse Response;

	public ConnectionData ConnectionData;

	public PlayerData PlayerData;

	public string IpAddress;

	public bool IsApproved;

	public bool IsInProgress;

	public ulong ClientID => Request.ClientNetworkId;

	public bool IsHost => ClientID == 0;

	public void Halt()
	{
		IsInProgress = true;
		Response.Pending = IsInProgress;
	}

	public void Approve(PlayerData playerData)
	{
		PlayerData = playerData;
		IsApproved = true;
		IsInProgress = false;
		Response.Approved = IsApproved;
		Response.Pending = IsInProgress;
	}

	public void Reject(string reason)
	{
		IsApproved = false;
		IsInProgress = false;
		Response.Reason = reason;
		Response.Approved = IsApproved;
		Response.Pending = IsInProgress;
	}
}
[RequireComponent(typeof(ServerManager))]
[RequireComponent(typeof(TimeoutManager))]
[RequireComponent(typeof(BanManager))]
public class ConnectionApprovalManager : MonoBehaviourSingleton<ConnectionApprovalManager>
{
	private static readonly Logger Logger = new Logger("ConnectionApprovalManager");

	[HideInInspector]
	public ServerManager ServerManager;

	[HideInInspector]
	public TimeoutManager TimeoutManager;

	[HideInInspector]
	public BanManager BanManager;

	[HideInInspector]
	public WhitelistManager WhitelistManager;

	private Dictionary<ulong, ConnectionApproval> clientIdConnectionApprovalMap = new Dictionary<ulong, ConnectionApproval>();

	private bool bufferConnectionApprovals = true;

	private List<(NetworkManager.ConnectionApprovalRequest, NetworkManager.ConnectionApprovalResponse)> bufferedConnectionApprovals = new List<(NetworkManager.ConnectionApprovalRequest, NetworkManager.ConnectionApprovalResponse)>();

	public override void Awake()
	{
		base.Awake();
		ServerManager = GetComponent<ServerManager>();
		TimeoutManager = GetComponent<TimeoutManager>();
		BanManager = GetComponent<BanManager>();
		WhitelistManager = GetComponent<WhitelistManager>();
	}

	private void Start()
	{
		bufferConnectionApprovals = true;
		NetworkManager.Singleton.ConnectionApprovalCallback = ConnectionApprovalCallback;
	}

	public void Dispose()
	{
		clientIdConnectionApprovalMap.Clear();
		bufferConnectionApprovals = true;
		bufferedConnectionApprovals.Clear();
	}

	private void ConnectionApprovalCallback(NetworkManager.ConnectionApprovalRequest request, NetworkManager.ConnectionApprovalResponse response)
	{
		if (request.ClientNetworkId != 0 && !ServerReadinessManager.IsReady)
		{
			Logger.Info($"Rejected connection for client {request.ClientNetworkId}: server is starting up");
			response.Reason = GetRejectionReason(ConnectionRejectionCode.ServerStarting);
			response.Approved = false;
			response.Pending = false;
		}
		else if (bufferConnectionApprovals)
		{
			bufferedConnectionApprovals.Add((request, response));
		}
		else
		{
			HandleConnectionApproval(request, response);
		}
	}

	private void HandleConnectionApproval(NetworkManager.ConnectionApprovalRequest request, NetworkManager.ConnectionApprovalResponse response)
	{
		ulong clientNetworkId = request.ClientNetworkId;
		ConnectionData connectionData = null;
		try
		{
			connectionData = JsonSerializer.Deserialize<ConnectionData>(Encoding.UTF8.GetString(request.Payload));
		}
		catch (Exception ex)
		{
			Logger.Error($"Error deserializing connection data for client {clientNetworkId}: {ex.Message}");
		}
		AddConnectionApproval(clientNetworkId, request, response, connectionData);
	}

	private void AddConnectionApproval(ulong clientId, NetworkManager.ConnectionApprovalRequest request, NetworkManager.ConnectionApprovalResponse response, ConnectionData connectionData)
	{
		if (!clientIdConnectionApprovalMap.ContainsKey(clientId))
		{
			ConnectionApproval connectionApproval = new ConnectionApproval
			{
				Request = request,
				Response = response,
				ConnectionData = connectionData,
				IpAddress = ((clientId == 0L) ? "127.0.0.1" : ServerManager.UnityTransport.GetEndpoint(clientId).Address)
			};
			clientIdConnectionApprovalMap.Add(clientId, connectionApproval);
			OnConnectionApprovalStarted(clientId, connectionApproval);
		}
	}

	public void ConsumeBufferedConnectionApprovals(bool stopBuffering = true)
	{
		Logger.Info($"Consuming {bufferedConnectionApprovals.Count} buffered connection approvals");
		bufferConnectionApprovals = !stopBuffering;
		foreach (var (connectionApprovalRequest, connectionApprovalResponse) in bufferedConnectionApprovals.ToList())
		{
			HandleConnectionApproval(connectionApprovalRequest, connectionApprovalResponse);
			bufferedConnectionApprovals.Remove((connectionApprovalRequest, connectionApprovalResponse));
		}
	}

	public void RemoveConnectionApproval(ulong clientId)
	{
		if (clientIdConnectionApprovalMap.ContainsKey(clientId))
		{
			clientIdConnectionApprovalMap.Remove(clientId);
		}
	}

	public ConnectionApproval GetConnectionApprovalByClientId(ulong clientId)
	{
		if (!clientIdConnectionApprovalMap.ContainsKey(clientId))
		{
			return null;
		}
		return clientIdConnectionApprovalMap[clientId];
	}

	public ConnectionApproval GetConnectionApprovalBySteamId(string steamId)
	{
		return clientIdConnectionApprovalMap.Values.FirstOrDefault((ConnectionApproval approval) => approval.ConnectionData.SteamId == steamId);
	}

	public void ApproveConnection(ulong clientId, PlayerData playerData)
	{
		if (clientIdConnectionApprovalMap.ContainsKey(clientId))
		{
			ConnectionApproval connectionApproval = clientIdConnectionApprovalMap[clientId];
			connectionApproval.Approve(playerData);
			Logger.Info($"Approved connection for client {clientId}");
			EventManager.TriggerEvent("Event_Server_OnConnectionApproved", new Dictionary<string, object>
			{
				{ "clientId", clientId },
				{ "connectionApproval", connectionApproval }
			});
		}
	}

	public string GetRejectionReason(ConnectionRejectionCode code, string message = null)
	{
		ConnectionRejection connectionRejection = new ConnectionRejection
		{
			code = code,
			message = message,
			data = null
		};
		if (code == ConnectionRejectionCode.MissingMods)
		{
			connectionRejection.data = new ConnectionRejectionData
			{
				clientRequiredModIds = ServerManager.ServerConfig.ClientRequiredModIds
			};
		}
		return JsonSerializer.Serialize(connectionRejection, new JsonSerializerOptions
		{
			WriteIndented = true
		});
	}

	public void RejectConnection(ulong clientId, ConnectionRejectionCode code, string message = null)
	{
		if (clientIdConnectionApprovalMap.ContainsKey(clientId))
		{
			ConnectionApproval connectionApproval = clientIdConnectionApprovalMap[clientId];
			connectionApproval.Reject(GetRejectionReason(code, message));
			Logger.Info($"Rejected connection for client {clientId}: {Utils.GetConnectionRejectionMessage(code, message)}");
			EventManager.TriggerEvent("Event_Server_OnConnectionRejected", new Dictionary<string, object>
			{
				{ "clientId", clientId },
				{ "connectionApproval", connectionApproval },
				{ "rejectionCode", code }
			});
			RemoveConnectionApproval(clientId);
		}
	}

	public ConnectionRejectionCode? GetConnectionRejectionCode(ConnectionApproval connectionApproval)
	{
		int num = NetworkManager.Singleton.ConnectedClientsList.Count((NetworkClient c) => c.ClientId != connectionApproval.ClientID);
		bool flag = !string.IsNullOrEmpty(ServerManager.ServerConfig.password);
		bool useWhitelist = ServerManager.ServerConfig.useWhitelist;
		if (connectionApproval.ConnectionData == null || connectionApproval.ConnectionData.SteamId == null || connectionApproval.ConnectionData.EnabledModIds == null)
		{
			return ConnectionRejectionCode.Unknown;
		}
		bool flag2 = ServerManager.AdminManager.IsSteamIdAdmin(connectionApproval.ConnectionData.SteamId);
		bool num2 = num >= ServerManager.ServerConfig.maxPlayers;
		bool flag3 = TimeoutManager.IsSteamIdTimedOut(connectionApproval.ConnectionData.SteamId);
		bool flag4 = BanManager.IsSteamIdBanned(connectionApproval.ConnectionData.SteamId);
		bool flag5 = BanManager.IsIpAddressBanned(connectionApproval.IpAddress);
		bool flag6 = WhitelistManager.IsSteamIdWhitelisted(connectionApproval.ConnectionData.SteamId);
		bool flag7 = string.IsNullOrEmpty(connectionApproval.ConnectionData.Password) && flag;
		bool flag8 = connectionApproval.ConnectionData.Password == ServerManager.ServerConfig.password || !flag;
		bool flag9 = ServerManager.ServerConfig.ClientRequiredModIds.Any((string modId) => !Enumerable.Contains(connectionApproval.ConnectionData.EnabledModIds, modId));
		if (num2 && !flag2)
		{
			return ConnectionRejectionCode.ServerFull;
		}
		if (flag3)
		{
			return ConnectionRejectionCode.TimedOut;
		}
		if (flag4 || flag5)
		{
			return ConnectionRejectionCode.Banned;
		}
		if (useWhitelist && !flag6)
		{
			return ConnectionRejectionCode.NotWhitelisted;
		}
		if (flag7)
		{
			return ConnectionRejectionCode.MissingPassword;
		}
		if (!flag8)
		{
			return ConnectionRejectionCode.InvalidPassword;
		}
		if (flag9)
		{
			return ConnectionRejectionCode.MissingMods;
		}
		return null;
	}

	private void OnConnectionApprovalStarted(ulong clientId, ConnectionApproval connectionApproval)
	{
		Logger.Info($"Started connection approval for client {clientId}");
		ConnectionRejectionCode? connectionRejectionCode = GetConnectionRejectionCode(connectionApproval);
		if (!connectionRejectionCode.HasValue)
		{
			connectionApproval.Halt();
			WebSocketManager.Emit("serverConnectionApprovalRequest", new Dictionary<string, object>
			{
				{
					"steamId",
					connectionApproval.ConnectionData.SteamId
				},
				{
					"key",
					connectionApproval.ConnectionData.Key
				}
			}, "serverConnectionApprovalResponse");
		}
		else
		{
			RejectConnection(clientId, connectionRejectionCode.Value);
		}
	}
}
public class ConnectionApprovalManagerController : MonoBehaviour
{
	private ConnectionApprovalManager connectionApprovalManager;

	private void Awake()
	{
		connectionApprovalManager = GetComponent<ConnectionApprovalManager>();
		EventManager.AddEventListener("Event_Everyone_OnClientConnected", Event_Everyone_OnClientConnected);
		EventManager.AddEventListener("Event_Everyone_OnClientDisconnected", Event_Everyone_OnClientDisconnected);
		EventManager.AddEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
		EventManager.AddEventListener("Event_Server_OnLoadSceneEventCompleted", Event_Server_OnLoadSceneEventCompleted);
		EventManager.AddEventListener("Event_Server_OnConnectionApproved", Event_Server_OnConnectionApproved);
		WebSocketManager.AddMessageListener("serverConnectionApprovalResponse", WebSocket_Event_OnServerConnectionApprovalResponse);
	}

	private void Start()
	{
	}

	private void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnClientConnected", Event_Everyone_OnClientConnected);
		EventManager.RemoveEventListener("Event_Everyone_OnClientDisconnected", Event_Everyone_OnClientDisconnected);
		EventManager.RemoveEventListener("Event_Server_OnServerStopped", Event_Server_OnServerStopped);
		EventManager.RemoveEventListener("Event_Server_OnLoadSceneEventCompleted", Event_Server_OnLoadSceneEventCompleted);
		EventManager.RemoveEventListener("Event_Server_OnConnectionApproved", Event_Server_OnConnectionApproved);
		WebSocketManager.RemoveMessageListener("serverConnectionApprovalResponse", WebSocket_Event_OnServerConnectionApprovalResponse);
	}

	private void Event_Everyone_OnClientConnected(Dictionary<string, object> message)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			ulong num = (ulong)message["clientId"];
			ConnectionApproval connectionApprovalByClientId = connectionApprovalManager.GetConnectionApprovalByClientId(num);
			if (connectionApprovalByClientId != null && connectionApprovalByClientId.IsApproved && !connectionApprovalByClientId.IsHost)
			{
				EventManager.TriggerEvent("Event_Server_OnApprovedClientConnected", new Dictionary<string, object>
				{
					{ "clientId", num },
					{ "connectionApproval", connectionApprovalByClientId }
				});
			}
		}
	}

	private void Event_Everyone_OnClientDisconnected(Dictionary<string, object> message)
	{
		if (NetworkManager.Singleton.IsServer)
		{
			ulong num = (ulong)message["clientId"];
			ConnectionApproval connectionApprovalByClientId = connectionApprovalManager.GetConnectionApprovalByClientId(num);
			if (connectionApprovalByClientId != null && connectionApprovalByClientId.IsApproved)
			{
				EventManager.TriggerEvent("Event_Server_OnApprovedClientDisconnected", new Dictionary<string, object>
				{
					{ "clientId", num },
					{ "connectionApproval", connectionApprovalByClientId }
				});
				connectionApprovalManager.RemoveConnectionApproval(num);
			}
		}
	}

	private void Event_Server_OnServerStopped(Dictionary<string, object> message)
	{
		connectionApprovalManager.Dispose();
	}

	private void Event_Server_OnLoadSceneEventCompleted(Dictionary<string, object> message)
	{
		if ((bool)message["isInitialScene"])
		{
			connectionApprovalManager.ConsumeBufferedConnectionApprovals();
		}
	}

	private void Event_Server_OnConnectionApproved(Dictionary<string, object> message)
	{
		ulong num = (ulong)message["clientId"];
		ConnectionApproval connectionApproval = (ConnectionApproval)message["connectionApproval"];
		if (connectionApproval.IsHost)
		{
			EventManager.TriggerEvent("Event_Server_OnApprovedClientConnected", new Dictionary<string, object>
			{
				{ "clientId", num },
				{ "connectionApproval", connectionApproval }
			});
		}
	}

	private void WebSocket_Event_OnServerConnectionApprovalResponse(Dictionary<string, object> message)
	{
		OutMessage obj = (OutMessage)message["outMessage"];
		ServerConnectionApprovalResponse data = ((InMessage)message["inMessage"]).GetData<ServerConnectionApprovalResponse>();
		string steamId = (string)obj.Data["steamId"];
		ConnectionApproval connectionApprovalBySteamId = connectionApprovalManager.GetConnectionApprovalBySteamId(steamId);
		if (connectionApprovalBySteamId == null)
		{
			return;
		}
		ulong clientID = connectionApprovalBySteamId.ClientID;
		if (data.success)
		{
			ConnectionRejectionCode? connectionRejectionCode = connectionApprovalManager.GetConnectionRejectionCode(connectionApprovalBySteamId);
			bool flag = !connectionRejectionCode.HasValue;
			if (flag && BackendUtils.GetActivePlayerDataBan(data.data.playerData) != null)
			{
				connectionRejectionCode = ConnectionRejectionCode.Banned;
				flag = false;
			}
			if (flag)
			{
				connectionApprovalManager.ApproveConnection(clientID, data.data.playerData);
			}
			else
			{
				connectionApprovalManager.RejectConnection(clientID, connectionRejectionCode.Value);
			}
		}
		else
		{
			connectionApprovalManager.RejectConnection(clientID, ConnectionRejectionCode.Unknown, data.errorData.message);
		}
	}
}
public enum DeploymentProvider
{
	None,
	Edgegap,
	PuckOrchestrator
}
public class DeploymentManager : MonoBehaviour
{
	private static readonly Logger Logger = new Logger("DeploymentManager");

	private Tween emptyTween;

	private Tween authenticationTween;

	public DeploymentProvider Provider { get; private set; }

	public ushort DeploymentPort { get; private set; }

	public string DeploymentId { get; private set; }

	public bool StopWhenEmpty { get; private set; }

	public bool IsDeployment => Provider != DeploymentProvider.None;

	public bool BindsDeploymentPort => Provider == DeploymentProvider.PuckOrchestrator;

	private void Awake()
	{
		string environmentVariable = Environment.GetEnvironmentVariable("ARBITRIUM_PORT_PUCK_EXTERNAL");
		string environmentVariable2 = Environment.GetEnvironmentVariable("PUCK_DEPLOYMENT_PORT");
		string environmentVariable3 = Environment.GetEnvironmentVariable("PUCK_DEPLOYMENT_STOP_WHEN_EMPTY");
		StopWhenEmpty = string.Equals(environmentVariable3, "true", StringComparison.OrdinalIgnoreCase);
		DeploymentId = Environment.GetEnvironmentVariable("PUCK_DEPLOYMENT_ID") ?? Utils.GetCommandLineArgument("--deploymentId");
		if (!string.IsNullOrEmpty(environmentVariable))
		{
			Provider = DeploymentProvider.Edgegap;
			DeploymentPort = ushort.Parse(environmentVariable);
			Logger.Info($"Running in Edgegap deployment (Provider: {Provider}, DeploymentPort: {DeploymentPort}, StopWhenEmpty: {StopWhenEmpty})");
		}
		else if (!string.IsNullOrEmpty(environmentVariable2))
		{
			Provider = DeploymentProvider.PuckOrchestrator;
			DeploymentPort = ushort.Parse(environmentVariable2);
			Logger.Info($"Running in Puck Orchestrator deployment (Provider: {Provider}, DeploymentPort: {DeploymentPort}, StopWhenEmpty: {StopWhenEmpty})");
		}
	}

	public void StartEmptyTimeout()
	{
		if (StopWhenEmpty)
		{
			Logger.Info("Starting empty timeout");
			emptyTween?.Kill();
			emptyTween = DOVirtual.DelayedCall(60f, delegate
			{
				StopDeployment();
			});
		}
	}

	public void StopEmptyTimeout()
	{
		if (StopWhenEmpty)
		{
			Logger.Info("Stopping empty timeout");
			emptyTween?.Kill();
		}
	}

	public void StartAuthenticationTimeout()
	{
		if (IsDeployment)
		{
			Logger.Info("Starting authentication timeout");
			authenticationTween?.Kill();
			authenticationTween = DOVirtual.DelayedCall(60f, delegate
			{
				StopDeployment();
			});
		}
	}

	public void StopAuthenticationTimeout()
	{
		if (IsDeployment)
		{
			Logger.Info("Stopping authentication timeout");
			authenticationTween?.Kill();
		}
	}

	public void StopDeployment()
	{
		if (IsDeployment)
		{
			Logger.Info($"Stopping deployment (Provider: {Provider})");
			Application.Quit();
		}
	}
}
public class DeploymentManagerController : MonoBehaviour
{
	private DeploymentManager deploymentManager;

	public void Awake()
	{
		deploymentManager = GetComponent<DeploymentManager>();
		EventManager.AddEventListener("Event_OnServerStateChanged", Event_OnServerStateChanged);
		EventManager.AddEventListener("Event_Everyone_OnPlayerAdded", Event_Everyone_OnPlayerAdded);
		EventManager.AddEventListener("Event_Everyone_OnPlayerRemoved", Event_Everyone_OnPlayerRemoved);
	}

	private void Start()
	{
		deploymentManager.StartEmptyTimeout();
		deploymentManager.StartAuthenticationTimeout();
	}

	private void OnDestroy()
	{
		deploymentManager.StopEmptyTimeout();
		deploymentManager.StopAuthenticationTimeout();
		EventManager.RemoveEventListener("Event_OnServerStateChanged", Event_OnServerStateChanged);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerAdded", Event_Everyone_OnPlayerAdded);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerRemoved", Event_Everyone_OnPlayerRemoved);
	}

	private void Event_OnServerStateChanged(Dictionary<string, object> message)
	{
		ServerState obj = (ServerState)message["oldServerState"];
		ServerState serverState = (ServerState)message["newServerState"];
		if (obj.AuthenticationPhase != serverState.AuthenticationPhase)
		{
			if (serverState.AuthenticationPhase == AuthenticationPhase.Authenticated)
			{
				deploymentManager.StopAuthenticationTimeout();
			}
			else
			{
				deploymentManager.StopDeployment();
			}
		}
	}

	private void Event_Everyone_OnPlayerAdded(Dictionary<string, object> message)
	{
		deploymentManager.StopEmptyTimeout();
	}

	private void Event_Everyone_OnPlayerRemoved(Dictionary<string, object> message)
	{
		if (MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayers().Count == 0)
		{
			deploymentManager.StartEmptyTimeout();
		}
	}
}
public class ModConfig
