	private static void OnDownloadItemResult(DownloadItemResult_t response)
	{
		if (!(response.m_unAppID != new AppId_t(2994020u)) && response.m_eResult == EResult.k_EResultOK)
		{
			string value = response.m_nPublishedFileId.ToString();
			EventManager.TriggerEvent("Event_OnSteamWorkshopItemDownloaded", new Dictionary<string, object> { { "itemId", value } });
		}
	}

	private static void OnUserSubscribedItemsListChanged(UserSubscribedItemsListChanged_t response)
	{
		if (!(response.m_nAppID != new AppId_t(2994020u)))
		{
			EventManager.TriggerEvent("Event_OnSteamWorkshopSubscribedItemsListChanged");
		}
	}

	private static void OnRemoteStorageSubscribePublishedFileResult(RemoteStorageSubscribePublishedFileResult_t response)
	{
		if (response.m_eResult == EResult.k_EResultOK)
		{
			string value = response.m_nPublishedFileId.ToString();
			EventManager.TriggerEvent("Event_OnSteamWorkshopItemSubscribed", new Dictionary<string, object> { { "itemId", value } });
		}
	}

	private static void OnRemoteStorageUnsubscribePublishedFileResult(RemoteStorageUnsubscribePublishedFileResult_t response)
	{
		if (response.m_eResult == EResult.k_EResultOK)
		{
			string value = response.m_nPublishedFileId.ToString();
			EventManager.TriggerEvent("Event_OnSteamWorkshopItemUnsubscribed", new Dictionary<string, object> { { "itemId", value } });
		}
	}

	private static void OnUGCQueryCompleted(SteamUGCQueryCompleted_t response, bool bIOFailure)
	{
		if (response.m_eResult != EResult.k_EResultOK)
		{
			return;
		}
		for (uint num = 0u; num < response.m_unNumResultsReturned; num++)
		{
			if (GetQueryUGCResult(response.m_handle, num, out var details) && details.m_eResult == EResult.k_EResultOK)
			{
				PublishedFileId_t nPublishedFileId = details.m_nPublishedFileId;
				string rgchTitle = details.m_rgchTitle;
				string rgchDescription = details.m_rgchDescription;
				int unVotesUp = (int)details.m_unVotesUp;
				int unVotesDown = (int)details.m_unVotesDown;
				GetQueryUGCPreviewURL(response.m_handle, num, out var previewUrl);
				GetQueryUGCStatistic(response.m_handle, num, EItemStatistic.k_EItemStatistic_NumSubscriptions, out var statValue);
				GetQueryUGCMetadata(response.m_handle, num, out var metadata);
				EventManager.TriggerEvent("Event_OnSteamWorkshopItemDetails", new Dictionary<string, object>
				{
					{
						"id",
						nPublishedFileId.ToString()
					},
					{ "title", rgchTitle },
					{ "description", rgchDescription },
					{ "previewUrl", previewUrl },
					{
						"subscriptions",
						(int)statValue
					},
					{ "upvotes", unVotesUp },
					{ "downvotes", unVotesDown },
					{ "metadata", metadata }
				});
			}
		}
		if (ugcQueryCompletedCallResultMap.ContainsKey(response.m_handle))
		{
			ugcQueryCompletedCallResultMap[response.m_handle].Dispose();
			ugcQueryCompletedCallResultMap.Remove(response.m_handle);
		}
		if (ApplicationManager.IsDedicatedGameServer)
		{
			SteamGameServerUGC.ReleaseQueryUGCRequest(response.m_handle);
		}
		else
		{
			SteamUGC.ReleaseQueryUGCRequest(response.m_handle);
		}
	}
}
public static class SteamWorkshopManagerController
{
	private static readonly Logger Logger = new Logger("SteamWorkshopManagerController");

	public static void Initialize()
	{
		EventManager.AddEventListener("Event_OnSteamConnected", Event_OnSteamConnected);
		EventManager.AddEventListener("Event_OnSteamWorkshopSubscribedItemsListChanged", Event_OnSteamWorkshopSubscribedItemsListChanged);
		EventManager.AddEventListener("Event_OnSteamWorkshopItemDownloaded", Event_OnSteamWorkshopItemDownloaded);
		EventManager.AddEventListener("Event_OnModsClickRefresh", Event_OnModsClickRefresh);
		EventManager.AddEventListener("Event_OnReconnectionStateChanged", Event_OnReconnectionStateChanged);
		EventManager.AddEventListener("Event_Server_OnServerStarted", Event_Server_OnServerStarted);
	}

	public static void Dispose()
	{
		EventManager.RemoveEventListener("Event_OnSteamConnected", Event_OnSteamConnected);
		EventManager.RemoveEventListener("Event_OnSteamWorkshopSubscribedItemsListChanged", Event_OnSteamWorkshopSubscribedItemsListChanged);
		EventManager.RemoveEventListener("Event_OnSteamWorkshopItemDownloaded", Event_OnSteamWorkshopItemDownloaded);
		EventManager.RemoveEventListener("Event_OnModsClickRefresh", Event_OnModsClickRefresh);
		EventManager.RemoveEventListener("Event_OnReconnectionStateChanged", Event_OnReconnectionStateChanged);
		EventManager.RemoveEventListener("Event_Server_OnServerStarted", Event_Server_OnServerStarted);
	}

	private static void Event_OnSteamConnected(Dictionary<string, object> message)
	{
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			SteamWorkshopManager.VerifyIntegrity();
		}
	}

	private static void Event_OnSteamWorkshopSubscribedItemsListChanged(Dictionary<string, object> message)
	{
		SteamWorkshopManager.VerifyIntegrity();
	}

	private static void Event_OnSteamWorkshopItemDownloaded(Dictionary<string, object> message)
	{
		SteamWorkshopManager.VerifyItemIntegrity((string)message["itemId"]);
	}

	private static void Event_OnModsClickRefresh(Dictionary<string, object> message)
	{
		SteamWorkshopManager.VerifyIntegrity();
	}

	private static void Event_OnReconnectionStateChanged(Dictionary<string, object> message)
	{
		ReconnectionState reconnectionState = (ReconnectionState)message["oldReconnectionState"];
		ReconnectionState reconnectionState2 = (ReconnectionState)message["newReconnectionState"];
		if (reconnectionState2.Phase != ReconnectionPhase.AwaitingMods || Enumerable.SequenceEqual(reconnectionState.PendingReadinessModIds, reconnectionState2.PendingReadinessModIds))
		{
			return;
		}
		string[] array = reconnectionState2.PendingReadinessModIds.Except(reconnectionState.PendingReadinessModIds).ToArray();
		foreach (string text in array)
		{
			if (ModManager.GetModById(text) == null)
			{
				SteamWorkshopManager.SubscribeItem(text);
			}
		}
	}

	private static void Event_Server_OnServerStarted(Dictionary<string, object> message)
	{
		ServerConfig serverConfig = (ServerConfig)message["serverConfig"];
		if (ApplicationManager.IsDedicatedGameServer)
		{
			string[] enabledModIds = serverConfig.EnabledModIds;
			for (int i = 0; i < enabledModIds.Length; i++)
			{
				SteamWorkshopManager.DownloadItem(enabledModIds[i]);
			}
		}
	}
}
public struct SynchronizedObjectData : INetworkSerializable, IEquatable<SynchronizedObjectData>
{
	public ushort NetworkObjectId;

	public short X;

	public short Y;

	public short Z;

	public short Rx;

	public short Ry;

	public short Rz;

	public short Rw;

	public void NetworkSerialize<T>(BufferSerializer<T> serializer) where T : IReaderWriter
	{
		if (serializer.IsReader)
		{
			FastBufferReader fastBufferReader = serializer.GetFastBufferReader();
			fastBufferReader.ReadValueSafe(out NetworkObjectId, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out X, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Y, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Z, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Rx, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Ry, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Rz, default(FastBufferWriter.ForPrimitives));
			fastBufferReader.ReadValueSafe(out Rw, default(FastBufferWriter.ForPrimitives));
		}
		else
		{
			FastBufferWriter fastBufferWriter = serializer.GetFastBufferWriter();
			fastBufferWriter.WriteValueSafe(in NetworkObjectId, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in X, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Y, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Z, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Rx, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Ry, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Rz, default(FastBufferWriter.ForPrimitives));
			fastBufferWriter.WriteValueSafe(in Rw, default(FastBufferWriter.ForPrimitives));
		}
	}

	public bool Equals(SynchronizedObjectData other)
	{
		if (NetworkObjectId == other.NetworkObjectId && X == other.X && Y == other.Y && Z == other.Z && Rx == other.Rx && Ry == other.Ry && Rz == other.Rz)
		{
			return Rw == other.Rw;
		}
		return false;
	}
}
public class SynchronizedObjectManager : NetworkBehaviourSingleton<SynchronizedObjectManager>
{
	private static readonly Logger Logger = new Logger("SynchronizedObjectManager");

	[Header("Settings")]
	[SerializeField]
	private SnapshotInterpolationSettings snapshotInterpolationSettings;

	[SerializeField]
	private bool skipLateTicks = true;

	private int tickRate = 100;

	private bool useNetworkSmoothing;

	[HideInInspector]
	public int NetworkSmoothingStrength = 1;

	private float serverTickAccumulator;

	private ushort serverLastSentTickId;

	private double serverLastSentServerTime;

	private ushort clientLastReceivedTickId;

	private double clientLastReceivedServerTime;

	private bool clientHasReceivedFirstTick;

	private float clientAccumulatedDeltaTime;

	private double clientLocalTimeline;

	private double clientLocalTimescale = 1.0;

	private List<SynchronizedObject> synchronizedObjects = new List<SynchronizedObject>();

	private Dictionary<ulong, SynchronizedObject> networkObjectIdSynchronizedObjectMap = new Dictionary<ulong, SynchronizedObject>();

	private List<SynchronizedObjectData> serverGatherBuffer = new List<SynchronizedObjectData>();

	private Dictionary<int, SynchronizedObjectData[]> serverGatherResultsByLength = new Dictionary<int, SynchronizedObjectData[]>();

	private BaseRpcTarget serverSynchronizedClientsRpcTarget;

	private List<ulong> synchronizedClientIds = new List<ulong>();

	private SortedList<double, SynchronizedObjectsSnapshot> snapshots = new SortedList<double, SynchronizedObjectsSnapshot>();

	private ExponentialMovingAverage driftEma;

	private ExponentialMovingAverage deliveryTimeEma;

	[HideInInspector]
	public int TickRate
	{
		get
		{
			return tickRate;
		}
		set
		{
			if (tickRate != value)
			{
				driftEma = new ExponentialMovingAverage(value * snapshotInterpolationSettings.driftEmaDuration);
				deliveryTimeEma = new ExponentialMovingAverage(value * snapshotInterpolationSettings.deliveryTimeEmaDuration);
				tickRate = value;
			}
		}
	}

	[HideInInspector]
	public bool UseNetworkSmoothing
	{
		get
		{
			return useNetworkSmoothing;
		}
		set
		{
			if (useNetworkSmoothing != value)
			{
				snapshots.Clear();
			}
			useNetworkSmoothing = value;
		}
	}

	[HideInInspector]
