	{
		UIState obj = (UIState)message["oldUIState"];
		UIState uIState = (UIState)message["newUIState"];
		if (obj.Phase != uIState.Phase)
		{
			uiManager.ShowPhaseViews(uIState.Phase);
		}
	}

