public class UIAnnouncements : UIView
{
	private VisualElement announcements;

	private VisualElement score;

	private Label headerLabel;

	private Label goalLabel;

	private Label assistLabel;

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("AnnouncementsView");
		announcements = base.View.Query<VisualElement>("Announcements");
		score = announcements.Query<VisualElement>("Score");
		headerLabel = score.Query<Label>("HeaderLabel");
		goalLabel = score.Query<Label>("GoalLabel");
		assistLabel = score.Query<Label>("AssistLabel");
		HideScore();
	}

	public override bool Show()
	{
		if (!SettingsManager.ShowGameUserInterface)
		{
			return false;
		}
		return base.Show();
	}

	public void ShowScore(PlayerTeam team, Player goalPlayer, Player assistPlayer, Player secondAssistPlayer)
	{
		headerLabel.text = string.Empty;
		goalLabel.text = string.Empty;
		assistLabel.text = string.Empty;
		score.style.display = DisplayStyle.Flex;
		UIUtils.SetTeamClass(score, team);
		switch (team)
		{
		case PlayerTeam.Blue:
			headerLabel.text = "BLUE SCORES!";
			break;
		case PlayerTeam.Red:
			headerLabel.text = "RED SCORES!";
			break;
		}
		if ((bool)goalPlayer)
		{
			goalLabel.text = $"#{goalPlayer.Number.Value} {goalPlayer.Username.Value}";
		}
		if ((bool)assistPlayer)
		{
			assistLabel.text = $"#{assistPlayer.Number.Value} {assistPlayer.Username.Value}";
		}
		if ((bool)secondAssistPlayer)
		{
			assistLabel.text += $" & #{secondAssistPlayer.Number.Value} {secondAssistPlayer.Username.Value}";
		}
	}

	public void HideScore()
	{
		headerLabel.text = string.Empty;
		goalLabel.text = string.Empty;
		assistLabel.text = string.Empty;
		score.style.display = DisplayStyle.None;
	}
}
internal class UIAnnouncementsController : UIViewController<UIAnnouncements>
{
	private UIAnnouncements uiAnnouncements;

	public override void Awake()
	{
		base.Awake();
		uiAnnouncements = GetComponent<UIAnnouncements>();
		EventManager.AddEventListener("Event_Everyone_OnGoalScored", Event_Everyone_OnGoalScored);
		EventManager.AddEventListener("Event_Everyone_OnGameStateChanged", Event_Everyone_OnGameStateChanged);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnGoalScored", Event_Everyone_OnGoalScored);
		EventManager.RemoveEventListener("Event_Everyone_OnGameStateChanged", Event_Everyone_OnGameStateChanged);
		base.OnDestroy();
	}

	public void Event_Everyone_OnGoalScored(Dictionary<string, object> message)
	{
		PlayerTeam team = (PlayerTeam)message["byTeam"];
		Player goalPlayer = (Player)message["goalPlayer"];
		Player assistPlayer = (Player)message["assistPlayer"];
		Player secondAssistPlayer = (Player)message["secondAssistPlayer"];
		uiAnnouncements.ShowScore(team, goalPlayer, assistPlayer, secondAssistPlayer);
	}

	public void Event_Everyone_OnGameStateChanged(Dictionary<string, object> message)
	{
		GameState gameState = (GameState)message["oldGameState"];
		GameState gameState2 = (GameState)message["newGameState"];
		bool num = gameState.Phase == GamePhase.BlueScore || gameState.Phase == GamePhase.RedScore;
		bool flag = gameState2.Phase == GamePhase.BlueScore || gameState2.Phase == GamePhase.RedScore;
		if (num && !flag)
		{
			uiAnnouncements.HideScore();
		}
	}
}
