public class UIDirectConnect : UIView
{
	private VisualElement directConnect;

	private IconButton closeIconButton;

	private Button connectButton;

	private TextField ipAddressTextField;

	private IntegerField portIntegerField;

	private string ipAddress = string.Empty;

	private int port = 30609;

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("DirectConnectView");
		directConnect = base.View.Query<VisualElement>("DirectConnect");
		closeIconButton = directConnect.Query<TemplateContainer>("CloseIconButtonContainer").First().Query<IconButton>();
		closeIconButton.clicked += OnClickClose;
		connectButton = directConnect.Query<Button>("ConnectButton");
		connectButton.clicked += OnClickConnect;
		ipAddressTextField = directConnect.Query<VisualElement>("IpAddressTextFieldInput").First().Query<TextField>();
		ipAddressTextField.RegisterValueChangedCallback(OnIpAddressChanged);
		ipAddressTextField.value = ipAddress;
		portIntegerField = directConnect.Query<VisualElement>("PortIntegerFieldInput").First().Query<IntegerField>();
		portIntegerField.RegisterValueChangedCallback(OnPortChanged);
		portIntegerField.value = port;
		RefreshConnectButton();
	}

	private void RefreshConnectButton()
	{
		connectButton.SetEnabled(!string.IsNullOrWhiteSpace(ipAddress));
	}

	private void OnClickClose()
	{
		EventManager.TriggerEvent("Event_OnDirectConnectClickClose");
	}

	private void OnClickConnect()
	{
		if (!string.IsNullOrWhiteSpace(ipAddress))
		{
			EventManager.TriggerEvent("Event_OnDirectConnectClickConnect", new Dictionary<string, object>
			{
				{
					"ipAddress",
					ipAddress.Trim()
				},
				{ "port", port }
			});
		}
	}

	private void OnIpAddressChanged(ChangeEvent<string> changeEvent)
	{
		ipAddress = changeEvent.newValue;
		RefreshConnectButton();
	}

	private void OnPortChanged(ChangeEvent<int> changeEvent)
	{
		port = Mathf.Clamp(changeEvent.newValue, 1, 65535);
		portIntegerField.SetValueWithoutNotify(port);
	}
}
public class UIFooter : UIView
{
	[Header("References")]
	public VisualTreeAsset userAsset;

	private VisualElement footer;

	private VisualElement left;

	private VisualElement center;

	private VisualElement right;

	private VisualElement localUserContainer;

	private Mmr mmr;

	private VisualElement party;

	private VisualElement partyUsers;

	private TemplateContainer createPartyIconButtonInstance;

	private IconButton createPartyIconButton;

	private TemplateContainer inviteIconButtonInstance;

	private IconButton inviteIconButton;

	private TemplateContainer leavePartyIconButtonInstance;

	private IconButton leavePartyIconButton;

	private TemplateContainer disbandPartyIconButtonInstance;

	private IconButton disbandPartyIconButton;

	private Dictionary<string, TemplateContainer> partyUserMap = new Dictionary<string, TemplateContainer>();

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("FooterView");
		footer = base.View.Query<VisualElement>("Footer");
		left = footer.Query<VisualElement>("Left");
		center = footer.Query<VisualElement>("Center");
		right = footer.Query<VisualElement>("Right");
		localUserContainer = left.Query<VisualElement>("LocalUserContainer");
		mmr = left.Query<VisualElement>("LocalUserMmr").First().Query<Mmr>();
		party = right.Query<VisualElement>("Party");
		partyUsers = party.Query<VisualElement>("Users");
		createPartyIconButtonInstance = party.Query<TemplateContainer>("CreatePartyIconButtonContainer");
		createPartyIconButton = createPartyIconButtonInstance.Query<IconButton>();
		createPartyIconButton.clicked += OnClickCreateParty;
		inviteIconButtonInstance = party.Query<TemplateContainer>("InviteIconButtonContainer");
		inviteIconButton = inviteIconButtonInstance.Query<IconButton>();
		inviteIconButton.clicked += OnClickInvite;
		leavePartyIconButtonInstance = party.Query<TemplateContainer>("LeavePartyIconButtonContainer");
		leavePartyIconButton = leavePartyIconButtonInstance.Query<IconButton>();
		leavePartyIconButton.clicked += OnClickLeaveParty;
		disbandPartyIconButtonInstance = party.Query<TemplateContainer>("DisbandPartyIconButtonContainer");
		disbandPartyIconButton = disbandPartyIconButtonInstance.Query<IconButton>();
		disbandPartyIconButton.clicked += OnClickDisbandParty;
		ClearLocalUser();
		ClearPartyUsers();
		SetCreatePartyButtonVisibility(show: false);
		SetInviteButtonVisibility(show: false);
		SetDisbandPartyButtonVisibility(show: false);
		SetLeavePartyButtonVisibility(show: false);
	}

	public void SetLocalUser(string username, Texture2D avatar)
	{
		ClearLocalUser();
		TemplateContainer child = CreateUser(username, avatar);
		localUserContainer.Add(child);
	}

	public void ClearLocalUser()
	{
		localUserContainer.Clear();
	}

	public void SetMmr(int value)
	{
		mmr.TargetValue = value;
	}

	public void AddPartyUser(string steamId, string username, Texture2D texture)
	{
		if (!partyUserMap.ContainsKey(steamId))
		{
			TemplateContainer templateContainer = CreateUser(username, texture, small: true, hideUsername: true);
			partyUsers.Add(templateContainer);
			partyUsers.style.display = DisplayStyle.Flex;
			partyUserMap.Add(steamId, templateContainer);
		}
	}

	public void RemovePartyUser(string steamId)
	{
		if (partyUserMap.ContainsKey(steamId))
		{
			VisualElement element = partyUserMap[steamId];
			partyUsers.Remove(element);
			partyUsers.style.display = ((partyUsers.childCount <= 0) ? DisplayStyle.None : DisplayStyle.Flex);
			partyUserMap.Remove(steamId);
		}
	}

	public void ClearPartyUsers()
	{
		partyUsers.Clear();
		partyUserMap.Clear();
		partyUsers.style.display = DisplayStyle.None;
	}

	private TemplateContainer CreateUser(string username, Texture2D texture, bool small = false, bool hideUsername = false)
	{
		TemplateContainer templateContainer = userAsset.Instantiate();
		User user = templateContainer.Query<User>();
		user.AvatarTexture = texture;
		user.Username = username;
		templateContainer.EnableInClassList("small", small);
		templateContainer.EnableInClassList("hideUsername", hideUsername);
		return templateContainer;
	}

	public void SetCreatePartyButtonVisibility(bool show)
	{
		createPartyIconButtonInstance.style.display = ((!show) ? DisplayStyle.None : DisplayStyle.Flex);
	}

	public void SetInviteButtonVisibility(bool show)
	{
		inviteIconButtonInstance.style.display = ((!show) ? DisplayStyle.None : DisplayStyle.Flex);
	}

	public void SetLeavePartyButtonVisibility(bool show)
	{
		leavePartyIconButtonInstance.style.display = ((!show) ? DisplayStyle.None : DisplayStyle.Flex);
	}

	public void SetDisbandPartyButtonVisibility(bool show)
	{
		disbandPartyIconButtonInstance.style.display = ((!show) ? DisplayStyle.None : DisplayStyle.Flex);
	}

	private void OnClickCreateParty()
	{
		EventManager.TriggerEvent("Event_OnFooterClickCreateParty");
	}

	private void OnClickInvite()
	{
		EventManager.TriggerEvent("Event_OnFooterClickInvite");
	}

	private void OnClickLeaveParty()
	{
		EventManager.TriggerEvent("Event_OnFooterClickLeaveParty");
	}

	private void OnClickDisbandParty()
	{
		EventManager.TriggerEvent("Event_OnFooterClickDisbandParty");
	}
}
public class UIFooterController : UIViewController<UIFooter>
{
	private UIFooter uiFooter;

	private Texture2D localAvatar;

	public override void Awake()
	{
		base.Awake();
		uiFooter = GetComponent<UIFooter>();
		EventManager.AddEventListener("Event_OnSteamConnected", Event_OnSteamConnected);
		EventManager.AddEventListener("Event_OnPlayerDataChanged", Event_OnPlayerDataChanged);
		EventManager.AddEventListener("Event_OnPlayerPartyDataChanged", Event_OnPlayerPartyDataChanged);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_OnSteamConnected", Event_OnSteamConnected);
		EventManager.RemoveEventListener("Event_OnPlayerDataChanged", Event_OnPlayerDataChanged);
		EventManager.RemoveEventListener("Event_OnPlayerPartyDataChanged", Event_OnPlayerPartyDataChanged);
		base.OnDestroy();
	}

	private void Event_OnSteamConnected(Dictionary<string, object> message)
	{
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			uiFooter.SetCreatePartyButtonVisibility(show: true);
			string steamId = SteamIntegrationManager.GetSteamId();
			if (!string.IsNullOrEmpty(steamId))
			{
				localAvatar = SteamIntegrationManager.GetAvatar(steamId, AvatarSize.Medium);
				RefreshLocalUser();
			}
		}
	}

	private void Event_OnPlayerDataChanged(Dictionary<string, object> message)
	{
		_ = (PlayerData)message["oldPlayerData"];
		PlayerData playerData = (PlayerData)message["newPlayerData"];
		if (playerData != null)
		{
			uiFooter.SetMmr(playerData.mmr);
			RefreshLocalUser();
		}
	}

	private void RefreshLocalUser()
	{
		string steamId = SteamIntegrationManager.GetSteamId();
		if (!string.IsNullOrEmpty(steamId))
		{
			PlayerData playerData = BackendManager.PlayerState.PlayerData;
			string username = ((playerData != null && !string.IsNullOrEmpty(playerData.username)) ? playerData.username : SteamIntegrationManager.GetUsername(steamId));
			uiFooter.SetLocalUser(username, localAvatar);
		}
	}

	private void Event_OnPlayerPartyDataChanged(Dictionary<string, object> message)
	{
		_ = (PlayerPartyData)message["oldPlayerPartyData"];
		PlayerPartyData playerPartyData = (PlayerPartyData)message["newPlayerPartyData"];
		if (playerPartyData == null)
		{
			uiFooter.ClearPartyUsers();
			uiFooter.SetCreatePartyButtonVisibility(show: true);
			uiFooter.SetInviteButtonVisibility(show: false);
			uiFooter.SetLeavePartyButtonVisibility(show: false);
			uiFooter.SetDisbandPartyButtonVisibility(show: false);
			return;
		}
		bool flag = BackendManager.PlayerState.PlayerData.steamId == playerPartyData.ownerSteamId;
		uiFooter.ClearPartyUsers();
		string[] memberSteamIds = playerPartyData.memberSteamIds;
		foreach (string steamId in memberSteamIds)
		{
			string username = SteamIntegrationManager.GetUsername(steamId);
			Texture2D avatar = SteamIntegrationManager.GetAvatar(steamId, AvatarSize.Medium);
			uiFooter.AddPartyUser(steamId, username, avatar);
		}
		uiFooter.SetCreatePartyButtonVisibility(show: false);
		uiFooter.SetInviteButtonVisibility(show: true);
		uiFooter.SetLeavePartyButtonVisibility(!flag);
		uiFooter.SetDisbandPartyButtonVisibility(flag);
	}
}
public class UIFriends : UIView
{
	[Header("References")]
	public VisualTreeAsset friendAsset;

	private VisualElement friends;

	private VisualElement friendsList;

	private IconButton closeIconButton;

	private Dictionary<string, TemplateContainer> friendsMap = new Dictionary<string, TemplateContainer>();

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("FriendsView");
		friends = base.View.Query<VisualElement>("Friends");
		friendsList = friends.Query<VisualElement>("FriendsList");
		closeIconButton = friends.Query<TemplateContainer>("CloseIconButtonContainer").First().Query<IconButton>();
		closeIconButton.clicked += OnCloseIconButtonClicked;
		friendsList.Clear();
		friendsMap.Clear();
	}

	public void AddFriend(string steamId, string username, Texture2D avatar)
	{
		if (!friendsMap.ContainsKey(steamId))
		{
			TemplateContainer templateContainer = CreateFriend(steamId, username, avatar);
			friendsList.Add(templateContainer);
			friendsMap.Add(steamId, templateContainer);
			SortFriends();
		}
	}

	public void UpdateFriend(string steamId, string username, Texture2D texture)
	{
		if (friendsMap.ContainsKey(steamId))
		{
			Friend friend = friendsMap[steamId].Query<Friend>("Friend");
			friend.Texture = texture;
			friend.Username = username;
			friend.InviteButtonClicked = delegate
			{
				OnFriendInviteButtonClicked(steamId);
			};
			SortFriends();
		}
	}

	public void RemoveFriend(string steamId)
	{
		if (friendsMap.ContainsKey(steamId))
		{
			TemplateContainer element = friendsMap[steamId];
			friendsList.Remove(element);
			friendsMap.Remove(steamId);
		}
	}

	public bool IsFriendListed(string steamId)
	{
		return friendsMap.ContainsKey(steamId);
	}

	private TemplateContainer CreateFriend(string steamId, string username, Texture2D texture)
	{
		TemplateContainer templateContainer = friendAsset.Instantiate();
		Friend friend = templateContainer.Query<Friend>("Friend");
		friend.Texture = texture;
		friend.Username = username;
		friend.InviteButtonClicked = delegate
		{
			OnFriendInviteButtonClicked(steamId);
		};
		return templateContainer;
	}

	private void SortFriends()
	{
		friendsList.Sort(delegate(VisualElement a, VisualElement b)
		{
			Friend friend = a.Query<Friend>("Friend").First();
			return string.Compare(strB: b.Query<Friend>("Friend").First().Username, strA: friend.Username);
		});
	}

	private void OnCloseIconButtonClicked()
	{
		EventManager.TriggerEvent("Event_OnFriendsClickClose");
	}

	private void OnFriendInviteButtonClicked(string steamId)
	{
		EventManager.TriggerEvent("Event_OnFriendInviteButtonClicked", new Dictionary<string, object> { { "steamId", steamId } });
	}
}
public class UIFriendsController : UIViewController<UIFriends>
{
	private UIFriends uiFriends;

	public override void Awake()
	{
		base.Awake();
		uiFriends = GetComponent<UIFriends>();
		EventManager.AddEventListener("Event_OnSteamConnected", Event_OnSteamConnected);
		EventManager.AddEventListener("Event_OnPersonaStateChange", Event_OnPersonaStateChange);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_OnSteamConnected", Event_OnSteamConnected);
		EventManager.RemoveEventListener("Event_OnPersonaStateChange", Event_OnPersonaStateChange);
		base.OnDestroy();
	}

	private void ParseSteamId(string steamId)
	{
		bool num = uiFriends.IsFriendListed(steamId);
		bool flag = SteamIntegrationManager.IsFriend(steamId);
		bool flag2 = SteamIntegrationManager.IsFriendOnline(steamId);
		bool flag3 = !num && flag && flag2;
		bool flag4 = num && flag && flag2;
		bool flag5 = num && (!flag || !flag2);
		if (flag3)
		{
			string username = SteamIntegrationManager.GetUsername(steamId);
			Texture2D avatar = SteamIntegrationManager.GetAvatar(steamId, AvatarSize.Medium);
			uiFriends.AddFriend(steamId, username, avatar);
		}
		else if (flag4)
		{
			string username2 = SteamIntegrationManager.GetUsername(steamId);
			Texture2D avatar2 = SteamIntegrationManager.GetAvatar(steamId, AvatarSize.Medium);
			uiFriends.UpdateFriend(steamId, username2, avatar2);
		}
		else if (flag5)
		{
			uiFriends.RemoveFriend(steamId);
		}
	}

	private void Event_OnSteamConnected(Dictionary<string, object> message)
	{
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			SteamIntegrationManager.GetFriendSteamIds().ForEach(delegate(string steamId)
			{
				ParseSteamId(steamId);
			});
		}
	}

	private void Event_OnPersonaStateChange(Dictionary<string, object> message)
	{
		string steamId = (string)message["steamId"];
		if (!ApplicationManager.IsDedicatedGameServer)
		{
			ParseSteamId(steamId);
		}
	}
}
public class UIGameState : UIView
{
	private VisualElement gameState;

	private Label blueScoreLabel;

	private Label redScoreLabel;

	private Label timeLabel;

	private Label phaseLabel;

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("GameStateView");
		gameState = base.View.Query<VisualElement>("GameState");
		blueScoreLabel = gameState.Query<Label>("BlueScoreLabel");
		redScoreLabel = gameState.Query<Label>("RedScoreLabel");
		timeLabel = gameState.Query<Label>("TimeLabel");
		phaseLabel = gameState.Query<Label>("PhaseLabel");
	}

	public override bool Show()
	{
		if (!SettingsManager.ShowGameUserInterface)
		{
			return false;
		}
		return base.Show();
	}

	public void SetScore(PlayerTeam team, int score)
	{
		switch (team)
		{
		case PlayerTeam.Blue:
			blueScoreLabel.text = $"{score}";
			break;
		case PlayerTeam.Red:
			redScoreLabel.text = $"{score}";
			break;
		}
	}

	public void SetTick(int tick)
	{
		TimeSpan timeSpan = TimeSpan.FromSeconds(tick);
		if (timeSpan.TotalHours < 1.0)
		{
			timeLabel.text = $"{timeSpan.Minutes:D2}:{timeSpan.Seconds:D2}";
		}
		else
		{
			timeLabel.text = $"{(int)timeSpan.TotalHours:D2}:{timeSpan.Minutes:D2}:{timeSpan.Seconds:D2}";
		}
	}

	public void SetPhase(string text)
	{
		phaseLabel.text = text;
	}
}
public class UIGameStateController : UIViewController<UIGameState>
{
