	}

	private void Event_Everyone_OnGameStateChanged(Dictionary<string, object> message)
	{
		GameState gameState = (GameState)message["newGameState"];
		uiGameState.SetPhase(Utils.GetHumanizedGamePhase(gameState.Phase, gameState.Period, gameState.IsOvertime));
		uiGameState.SetTick(gameState.Tick);
