public class UIMatchmakingController : UIViewController<UIMatchmaking>
{
	private UIMatchmaking uiMatchmaking;

	public override void Awake()
	{
		base.Awake();
		uiMatchmaking = GetComponent<UIMatchmaking>();
		EventManager.AddEventListener("Event_OnPlayerGroupDataChanged", Event_OnPlayerGroupDataChanged);
		EventManager.AddEventListener("Event_OnPlayerMatchDataChanged", Event_OnPlayerMatchDataChanged);
		EventManager.AddEventListener("Event_OnConnectionStateChanged", Event_OnConnectionStateChanged);
		EventManager.AddEventListener("Event_OnMatchingTickerStarted", Event_OnMatchingTickerStarted);
		EventManager.AddEventListener("Event_OnMatchingTickerTick", Event_OnMatchingTickerTick);
		EventManager.AddEventListener("Event_OnMatchingTickerStopped", Event_OnMatchingTickerStopped);
		EventManager.AddEventListener("Event_OnMatchJoinTimeoutTickerStarted", Event_OnMatchJoinTimeoutTickerStarted);
		EventManager.AddEventListener("Event_OnMatchJoinTimeoutTickerTick", Event_OnMatchJoinTimeoutTickerTick);
		EventManager.AddEventListener("Event_OnMatchJoinTimeoutTickerStopped", Event_OnMatchJoinTimeoutTickerStopped);
	}

	private void Start()
	{
		uiMatchmaking.SetMatchingVisibility(isVisible: false);
		uiMatchmaking.SetMatchingPhaseText(string.Empty);
		uiMatchmaking.SetMatchingTimeVisibility(isVisible: false);
		uiMatchmaking.SetMatchingTimeText(0);
		uiMatchmaking.SetMatchingConnectButtonVisibility(isVisible: false);
		uiMatchmaking.SetMatchingCloseButtonVisibility(isVisible: false);
	}

	public override void OnDestroy()
	{
		base.OnDestroy();
		EventManager.RemoveEventListener("Event_OnPlayerGroupDataChanged", Event_OnPlayerGroupDataChanged);
		EventManager.RemoveEventListener("Event_OnPlayerMatchDataChanged", Event_OnPlayerMatchDataChanged);
		EventManager.RemoveEventListener("Event_OnConnectionStateChanged", Event_OnConnectionStateChanged);
		EventManager.RemoveEventListener("Event_OnMatchingTickerStarted", Event_OnMatchingTickerStarted);
		EventManager.RemoveEventListener("Event_OnMatchingTickerTick", Event_OnMatchingTickerTick);
		EventManager.RemoveEventListener("Event_OnMatchingTickerStopped", Event_OnMatchingTickerStopped);
		EventManager.RemoveEventListener("Event_OnMatchJoinTimeoutTickerStarted", Event_OnMatchJoinTimeoutTickerStarted);
		EventManager.RemoveEventListener("Event_OnMatchJoinTimeoutTickerTick", Event_OnMatchJoinTimeoutTickerTick);
		EventManager.RemoveEventListener("Event_OnMatchJoinTimeoutTickerStopped", Event_OnMatchJoinTimeoutTickerStopped);
	}

	private void UpdateMatching()
	{
		PlayerGroupData groupData = BackendManager.PlayerState.GroupData;
		PlayerMatchData matchData = BackendManager.PlayerState.MatchData;
		if (groupData != null)
		{
			uiMatchmaking.SetMatchingVisibility(isVisible: true);
			uiMatchmaking.SetMatchingPhaseText("LOOKING FOR A MATCH...");
			uiMatchmaking.SetMatchingConnectButtonVisibility(isVisible: false);
			uiMatchmaking.SetMatchingCloseButtonVisibility(isVisible: true);
		}
		else if (matchData != null && !BackendUtils.IsConnectedToMatchEndPoint())
		{
			uiMatchmaking.SetMatchingVisibility(isVisible: true);
			uiMatchmaking.SetMatchingCloseButtonVisibility(isVisible: false);
			if (matchData.endPoint == null)
			{
				uiMatchmaking.SetMatchingPhaseText("MATCH FOUND! DEPLOYING MATCH SERVER...");
				uiMatchmaking.SetMatchingConnectButtonVisibility(isVisible: false);
			}
			else
			{
				uiMatchmaking.SetMatchingPhaseText("MATCH READY!");
				uiMatchmaking.SetMatchingConnectButtonVisibility(isVisible: true);
			}
		}
		else
		{
			uiMatchmaking.SetMatchingVisibility(isVisible: false);
			uiMatchmaking.SetMatchingPhaseText(string.Empty);
			uiMatchmaking.SetMatchingConnectButtonVisibility(isVisible: false);
			uiMatchmaking.SetMatchingCloseButtonVisibility(isVisible: false);
		}
	}

	private void Event_OnPlayerGroupDataChanged(Dictionary<string, object> message)
	{
		UpdateMatching();
	}

	private void Event_OnPlayerMatchDataChanged(Dictionary<string, object> message)
	{
		UpdateMatching();
	}

	private void Event_OnConnectionStateChanged(Dictionary<string, object> message)
	{
		UpdateMatching();
	}

	private void Event_OnMatchingTickerStarted(Dictionary<string, object> message)
	{
		int matchingTimeText = (int)message["startingTick"];
		uiMatchmaking.SetMatchingTimeVisibility(isVisible: true);
		uiMatchmaking.SetMatchingTimeText(matchingTimeText);
	}

	private void Event_OnMatchingTickerTick(Dictionary<string, object> message)
	{
		int matchingTimeText = (int)message["tick"];
		uiMatchmaking.SetMatchingTimeText(matchingTimeText);
	}

	private void Event_OnMatchingTickerStopped(Dictionary<string, object> message)
	{
		uiMatchmaking.SetMatchingTimeVisibility(isVisible: false);
		uiMatchmaking.SetMatchingTimeText(0);
	}

	private void Event_OnMatchJoinTimeoutTickerStarted(Dictionary<string, object> message)
	{
		int matchingTimeText = (int)message["startingTick"];
		uiMatchmaking.SetMatchingTimeVisibility(isVisible: true);
		uiMatchmaking.SetMatchingTimeText(matchingTimeText);
	}

	private void Event_OnMatchJoinTimeoutTickerTick(Dictionary<string, object> message)
	{
		int matchingTimeText = (int)message["tick"];
		uiMatchmaking.SetMatchingTimeText(matchingTimeText);
	}

	private void Event_OnMatchJoinTimeoutTickerStopped(Dictionary<string, object> message)
	{
		uiMatchmaking.SetMatchingTimeVisibility(isVisible: false);
		uiMatchmaking.SetMatchingTimeText(0);
	}
}
public class UIMinimap : UIView
{
	[Header("Settings")]
	[SerializeField]
	private int updateRate = 120;

	[Header("References")]
	[SerializeField]
	private VisualTreeAsset playerAsset;

	[SerializeField]
	private VisualTreeAsset puckAsset;

	[SerializeField]
	private VisualTreeAsset stickAsset;

	[HideInInspector]
	public PlayerTeam Team;

	[HideInInspector]
	public Bounds Bounds;

	private VisualElement minimap;

	private VisualElement background;

	private VisualElement foreground;

	private VisualElement content;

	private Dictionary<PlayerBody, (VisualElement Root, VisualElement Body)> playerBodyVisualElementMap = new Dictionary<PlayerBody, (VisualElement, VisualElement)>();

	private Dictionary<Puck, VisualElement> puckVisualElementMap = new Dictionary<Puck, VisualElement>();

	private Dictionary<Stick, VisualElement> stickVisualElementMap = new Dictionary<Stick, VisualElement>();

	private float updateAccumulator;

	[HideInInspector]
	public Vector2 Position => new Vector2(minimap.style.left.value.value, minimap.style.top.value.value);

	private void Update()
	{
		if (ApplicationManager.IsDedicatedGameServer || !base.IsVisible)
		{
			return;
		}
		updateAccumulator += Time.deltaTime;
		if (updateAccumulator < 1f / (float)updateRate)
		{
			return;
		}
		updateAccumulator = Mathf.Min(updateAccumulator - 1f / (float)updateRate, 1f / (float)updateRate);
		foreach (KeyValuePair<PlayerBody, (VisualElement, VisualElement)> item3 in playerBodyVisualElementMap)
		{
			PlayerBody key = item3.Key;
			VisualElement item = item3.Value.Item1;
			VisualElement item2 = item3.Value.Item2;
			if ((bool)key)
			{
				float num = ((Team == PlayerTeam.Blue) ? key.transform.rotation.eulerAngles.y : (key.transform.rotation.eulerAngles.y + 180f));
				ApplyMinimapTranslate(item, key.transform.position);
				item2.style.rotate = new Rotate(num);
				bool flag = SettingsManager.ShowMinimapFallenIndicator && key.HasFallen.Value;
				item.style.opacity = (flag ? 0.4f : 1f);
			}
		}
		foreach (KeyValuePair<Stick, VisualElement> item4 in stickVisualElementMap)
		{
			Stick key2 = item4.Key;
			VisualElement value = item4.Value;
			if (!key2 || !key2.Player)
			{
				continue;
			}
			if (!SettingsManager.ShowMinimapSticks)
			{
				value.parent.style.display = DisplayStyle.None;
				continue;
			}
			value.parent.style.display = DisplayStyle.Flex;
			Vector3 bladeHandlePosition = key2.BladeHandlePosition;
			float num2 = key2.BladeHandleRotation.eulerAngles.y;
			if (Team == PlayerTeam.Red)
			{
				num2 += 180f;
			}
			num2 -= key2.BladeAngle;
			ApplyMinimapTranslate(value.parent, bladeHandlePosition);
			value.style.rotate = new Rotate(num2);
			float num3 = HeightToScale(bladeHandlePosition.y, 3f, 0.5f);
			float num4 = num3;
			if (SettingsManager.ShowMinimapFallenIndicator && (bool)key2.Player.PlayerBody && key2.Player.PlayerBody.HasFallen.Value)
			{
				num4 *= 0.4f;
			}
			value.style.scale = new StyleScale(new Scale(new Vector2(num3, 1f)));
			value.style.opacity = num4;
		}
		foreach (KeyValuePair<Puck, VisualElement> item5 in puckVisualElementMap)
		{
			Puck key3 = item5.Key;
			VisualElement value2 = item5.Value;
			if ((bool)key3)
			{
				ApplyMinimapTranslate(value2, key3.transform.position);
				if (SettingsManager.ShowMinimapPuckElevation)
				{
					float num5 = HeightToScale(key3.transform.position.y, 8f, 0.6f);
					value2.style.opacity = num5;
					value2.style.scale = new StyleScale(new Scale(new Vector2(num5, num5)));
				}
				else
				{
					value2.style.opacity = 1f;
					value2.style.scale = new StyleScale(new Scale(Vector2.one));
				}
			}
		}
	}

	private void ApplyMinimapTranslate(VisualElement element, Vector3 worldPosition)
	{
		Vector3 position = ((Team == PlayerTeam.Blue) ? worldPosition : (-worldPosition));
		Vector2 vector = WorldPositionToMinimapPosition(position, Bounds);
		element.style.translate = new Translate(0f - vector.x, vector.y);
	}

	private static float HeightToScale(float worldY, float maxHeight, float minScale)
	{
		return Mathf.Lerp(1f, minScale, Mathf.Clamp01(Mathf.Abs(worldY) / maxHeight));
	}

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("MinimapView");
		minimap = base.View.Query<VisualElement>("Minimap");
		background = minimap.Query<VisualElement>("Background");
		foreground = minimap.Query<VisualElement>("Foreground");
		content = minimap.Query<VisualElement>("Content");
		content.Clear();
	}

	public override bool Show()
	{
		if (!SettingsManager.ShowGameUserInterface)
		{
			return false;
		}
		return base.Show();
	}

	public void AddPlayerBody(PlayerBody playerBody)
	{
		if ((bool)playerBody && !playerBodyVisualElementMap.ContainsKey(playerBody))
		{
			TemplateContainer templateContainer = playerAsset.Instantiate();
			playerBodyVisualElementMap.Add(playerBody, (templateContainer, templateContainer.Query<VisualElement>("Body")));
			content.Add(templateContainer);
			templateContainer.SendToBack();
			StylePlayer(playerBody);
		}
	}

	public void StylePlayer(PlayerBody playerBody)
	{
		if ((bool)playerBody && playerBodyVisualElementMap.ContainsKey(playerBody))
		{
			Player player = playerBody.Player;
			if ((bool)player)
			{
				VisualElement visualElement = playerBodyVisualElementMap[playerBody].Root.Query<VisualElement>("Player");
				Label label = visualElement.Query<Label>("NumberLabel");
				UIUtils.SetTeamClass(visualElement, player.Team);
				visualElement.EnableInClassList("isLocalPlayer", player.IsLocalPlayer);
				label.text = player.Number.Value.ToString();
			}
		}
	}

	public void RemovePlayerBody(PlayerBody playerBody)
	{
		if ((bool)playerBody && playerBodyVisualElementMap.ContainsKey(playerBody))
		{
			content.Remove(playerBodyVisualElementMap[playerBody].Root);
			playerBodyVisualElementMap.Remove(playerBody);
		}
	}

	public void AddPuck(Puck puck)
	{
		if ((bool)puck && !puckVisualElementMap.ContainsKey(puck))
		{
			TemplateContainer templateContainer = puckAsset.Instantiate();
			VisualElement visualElement = templateContainer.Q(null, "minimapPuck");
			if (visualElement != null)
			{
				visualElement.generateVisualContent = DrawPuckDot;
			}
			puckVisualElementMap.Add(puck, templateContainer);
			content.Add(templateContainer);
			templateContainer.BringToFront();
		}
	}

	private static void DrawPuckDot(MeshGenerationContext context)
	{
		Rect contentRect = context.visualElement.contentRect;
		if (!(contentRect.width <= 0f) && !(contentRect.height <= 0f))
		{
			float radius = Mathf.Min(contentRect.width, contentRect.height) / 2f;
			Painter2D painter2D = context.painter2D;
			painter2D.fillColor = Color.black;
			painter2D.BeginPath();
			painter2D.Arc(contentRect.center, radius, new Angle(0f, AngleUnit.Degree), new Angle(360f, AngleUnit.Degree));
			painter2D.Fill();
		}
	}

	public void RemovePuck(Puck puck)
	{
		if ((bool)puck && puckVisualElementMap.ContainsKey(puck))
		{
			content.Remove(puckVisualElementMap[puck]);
			puckVisualElementMap.Remove(puck);
		}
	}

	public void AddStick(Stick stick)
	{
		if ((bool)stick && !stickVisualElementMap.ContainsKey(stick))
		{
			TemplateContainer templateContainer = stickAsset.Instantiate();
			VisualElement visualElement = templateContainer.Q(null, "minimapStick");
			UIUtils.SetTeamClass(visualElement, stick.Player ? stick.Player.Team : PlayerTeam.None);
			stickVisualElementMap.Add(stick, visualElement);
			content.Add(templateContainer);
			templateContainer.SendToBack();
		}
	}

	public void RemoveStick(Stick stick)
	{
		if ((bool)stick && stickVisualElementMap.ContainsKey(stick))
		{
			content.Remove(stickVisualElementMap[stick].parent);
			stickVisualElementMap.Remove(stick);
		}
	}

	private Vector2 WorldPositionToMinimapPosition(Vector3 position, Bounds bounds)
	{
		Vector2 vector = new Vector2((position.x + bounds.center.x) / bounds.size.x, (position.z + bounds.center.z) / bounds.size.z);
		Vector2 vector2 = new Vector2(content.resolvedStyle.width, content.resolvedStyle.height);
		return new Vector2(vector2.x * vector.x, vector2.y * vector.y);
	}

	public void SetOpacity(float opacity)
	{
		if (minimap != null)
		{
			minimap.style.opacity = opacity;
		}
	}

	public void SetPosition(Vector2 position)
	{
		if (minimap != null)
		{
			Length x = new Length(Utils.Map(position.x, 0f, 100f, 0f, -100f), LengthUnit.Percent);
			Length y = new Length(Utils.Map(position.y, 0f, 100f, 0f, -100f), LengthUnit.Percent);
			Length x2 = new Length(0f - x.value, LengthUnit.Percent);
			Length y2 = new Length(0f - y.value, LengthUnit.Percent);
			minimap.style.left = new Length(position.x, LengthUnit.Percent);
			minimap.style.top = new Length(position.y, LengthUnit.Percent);
			minimap.style.translate = new Translate(x, y);
			minimap.style.transformOrigin = new TransformOrigin(x2, y2);
		}
	}

	public void SetBackgroundOpacity(float opacity)
	{
		if (background != null)
		{
			background.style.opacity = opacity;
		}
	}

	public void SetScale(float scale)
	{
		if (minimap != null)
		{
			minimap.style.scale = new Vector2(scale, scale);
		}
	}
}
internal class UIMinimapController : UIViewController<UIMinimap>
{
	private UIMinimap uiMinimap;

	public override void Awake()
	{
		base.Awake();
		uiMinimap = GetComponent<UIMinimap>();
		EventManager.AddEventListener("Event_Everyone_OnLevelSpawned", Event_Everyone_OnLevelSpawned);
		EventManager.AddEventListener("Event_Everyone_OnPlayerBodySpawned", Event_Everyone_OnPlayerBodySpawned);
		EventManager.AddEventListener("Event_Everyone_OnPlayerSpawned", Event_Everyone_OnPlayerSpawned);
		EventManager.AddEventListener("Event_Everyone_OnPlayerGameStateChanged", Event_Everyone_OnPlayerGameStateChanged);
		EventManager.AddEventListener("Event_Everyone_OnPlayerNumberChanged", Event_Everyone_OnPlayerNumberChanged);
		EventManager.AddEventListener("Event_Everyone_OnPlayerBodyDespawned", Event_Everyone_OnPlayerBodyDespawned);
		EventManager.AddEventListener("Event_Everyone_OnPuckSpawned", Event_Everyone_OnPuckSpawned);
		EventManager.AddEventListener("Event_Everyone_OnPuckDespawned", Event_Everyone_OnPuckDespawned);
		EventManager.AddEventListener("Event_Everyone_OnStickSpawned", Event_Everyone_OnStickSpawned);
		EventManager.AddEventListener("Event_Everyone_OnStickDespawned", Event_Everyone_OnStickDespawned);
		EventManager.AddEventListener("Event_OnShowMinimapChanged", Event_OnShowMinimapChanged);
		EventManager.AddEventListener("Event_OnMinimapOpacityChanged", Event_OnMinimapOpacityChanged);
		EventManager.AddEventListener("Event_OnShowGameUserInterfaceChanged", Event_OnShowGameUserInterfaceChanged);
		EventManager.AddEventListener("Event_OnMinimapHorizontalPositionChanged", Event_OnMinimapHorizontalPositionChanged);
		EventManager.AddEventListener("Event_OnMinimapVerticalPositionChanged", Event_OnMinimapVerticalPositionChanged);
		EventManager.AddEventListener("Event_OnMinimapBackgroundOpacityChanged", Event_OnMinimapBackgroundOpacityChanged);
		EventManager.AddEventListener("Event_OnMinimapScaleChanged", Event_OnMinimapScaleChanged);
	}

	private void Start()
	{
		uiMinimap.SetOpacity(SettingsManager.MinimapOpacity);
		uiMinimap.SetBackgroundOpacity(SettingsManager.MinimapBackgroundOpacity);
		uiMinimap.SetPosition(new Vector2(SettingsManager.MinimapHorizontalPosition, SettingsManager.MinimapVerticalPosition));
		uiMinimap.SetScale(SettingsManager.MinimapScale);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnLevelSpawned", Event_Everyone_OnLevelSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerBodySpawned", Event_Everyone_OnPlayerBodySpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerSpawned", Event_Everyone_OnPlayerSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerGameStateChanged", Event_Everyone_OnPlayerGameStateChanged);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerNumberChanged", Event_Everyone_OnPlayerNumberChanged);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerBodyDespawned", Event_Everyone_OnPlayerBodyDespawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPuckSpawned", Event_Everyone_OnPuckSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPuckDespawned", Event_Everyone_OnPuckDespawned);
		EventManager.RemoveEventListener("Event_Everyone_OnStickSpawned", Event_Everyone_OnStickSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnStickDespawned", Event_Everyone_OnStickDespawned);
		EventManager.RemoveEventListener("Event_OnShowMinimapChanged", Event_OnShowMinimapChanged);
		EventManager.RemoveEventListener("Event_OnMinimapOpacityChanged", Event_OnMinimapOpacityChanged);
		EventManager.RemoveEventListener("Event_OnShowGameUserInterfaceChanged", Event_OnShowGameUserInterfaceChanged);
		EventManager.RemoveEventListener("Event_OnMinimapHorizontalPositionChanged", Event_OnMinimapHorizontalPositionChanged);
		EventManager.RemoveEventListener("Event_OnMinimapVerticalPositionChanged", Event_OnMinimapVerticalPositionChanged);
		EventManager.RemoveEventListener("Event_OnMinimapBackgroundOpacityChanged", Event_OnMinimapBackgroundOpacityChanged);
		EventManager.RemoveEventListener("Event_OnMinimapScaleChanged", Event_OnMinimapScaleChanged);
		base.OnDestroy();
	}

	private void HandlePlayerGameState(Player player)
	{
		PlayerGameState value = player.GameState.Value;
		uiMinimap.Team = value.Team;
	}

	private void Event_Everyone_OnLevelSpawned(Dictionary<string, object> message)
	{
		Level level = (Level)message["level"];
		uiMinimap.Bounds = level.Bounds;
	}

	private void Event_Everyone_OnPlayerBodySpawned(Dictionary<string, object> message)
	{
		PlayerBody playerBody = (PlayerBody)message["playerBody"];
		uiMinimap.AddPlayerBody(playerBody);
	}

	private void Event_Everyone_OnPlayerSpawned(Dictionary<string, object> message)
	{
		Player player = (Player)message["player"];
		if (player.IsLocalPlayer)
		{
			HandlePlayerGameState(player);
		}
	}

	private void Event_Everyone_OnPlayerGameStateChanged(Dictionary<string, object> message)
	{
		Player player = (Player)message["player"];
		if (player.IsLocalPlayer)
		{
			HandlePlayerGameState(player);
		}
		uiMinimap.StylePlayer(player.PlayerBody);
	}

	private void Event_Everyone_OnPlayerNumberChanged(Dictionary<string, object> message)
	{
		Player player = (Player)message["player"];
		uiMinimap.StylePlayer(player.PlayerBody);
	}

	private void Event_Everyone_OnPlayerBodyDespawned(Dictionary<string, object> message)
	{
		PlayerBody playerBody = (PlayerBody)message["playerBody"];
		uiMinimap.RemovePlayerBody(playerBody);
	}

	private void Event_Everyone_OnPuckSpawned(Dictionary<string, object> message)
	{
		Puck puck = (Puck)message["puck"];
		uiMinimap.AddPuck(puck);
	}

	private void Event_Everyone_OnPuckDespawned(Dictionary<string, object> message)
	{
		Puck puck = (Puck)message["puck"];
		uiMinimap.RemovePuck(puck);
	}

	private void Event_Everyone_OnStickSpawned(Dictionary<string, object> message)
	{
		Stick stick = (Stick)message["stick"];
		uiMinimap.AddStick(stick);
	}

	private void Event_Everyone_OnStickDespawned(Dictionary<string, object> message)
	{
		Stick stick = (Stick)message["stick"];
		uiMinimap.RemoveStick(stick);
	}

	private void Event_OnMinimapOpacityChanged(Dictionary<string, object> message)
	{
		float opacity = (float)message["value"];
		uiMinimap.SetOpacity(opacity);
	}

	private void Event_OnShowMinimapChanged(Dictionary<string, object> message)
	{
		if (GlobalStateManager.UIState.Phase != UIPhase.LockerRoom)
		{
			if ((bool)message["value"])
			{
				uiMinimap.Show();
			}
			else
			{
				uiMinimap.Hide();
			}
		}
	}

	private void Event_OnShowGameUserInterfaceChanged(Dictionary<string, object> message)
	{
		if (GlobalStateManager.UIState.Phase != UIPhase.LockerRoom)
		{
			if ((bool)message["value"])
			{
				uiMinimap.Show();
			}
			else
			{
				uiMinimap.Hide();
			}
		}
	}

	private void Event_OnMinimapHorizontalPositionChanged(Dictionary<string, object> message)
	{
		float x = (float)message["value"];
		uiMinimap.SetPosition(new Vector2(x, uiMinimap.Position.y));
	}

	private void Event_OnMinimapVerticalPositionChanged(Dictionary<string, object> message)
	{
		float y = (float)message["value"];
		uiMinimap.SetPosition(new Vector2(uiMinimap.Position.x, y));
	}

	private void Event_OnMinimapBackgroundOpacityChanged(Dictionary<string, object> message)
	{
		float backgroundOpacity = (float)message["value"];
		uiMinimap.SetBackgroundOpacity(backgroundOpacity);
	}

	private void Event_OnMinimapScaleChanged(Dictionary<string, object> message)
	{
		float scale = (float)message["value"];
		uiMinimap.SetScale(scale);
	}
}
public class UIMods : UIView
{
	private static readonly Logger Logger = new Logger("UIMods");

	[Header("References")]
	[SerializeField]
	private VisualTreeAsset modAsset;

	[SerializeField]
	private StyleBackground defaultPreviewTexture;

	private VisualElement mods;

	private VisualElement modsList;

	private VisualElement noMods;

	private IconButton closeIconButton;

	private Button findModsButton;

	private Button refreshButton;

	private Dictionary<Mod, TemplateContainer> modTemplateContainerMap = new Dictionary<Mod, TemplateContainer>();

	private Dictionary<Plugin, TemplateContainer> pluginTemplateContainerMap = new Dictionary<Plugin, TemplateContainer>();

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("ModsView");
		mods = base.View.Query<VisualElement>("Mods");
		modsList = mods.Query<VisualElement>("ModsList");
		noMods = mods.Query<VisualElement>("NoMods");
		closeIconButton = mods.Query<TemplateContainer>("CloseIconButtonContainer").First().Query<IconButton>();
		closeIconButton.clicked += OnClickClose;
		findModsButton = mods.Query<Button>("FindModsButton");
		findModsButton.clicked += OnClickFindMods;
		refreshButton = mods.Query<Button>("RefreshButton");
		refreshButton.clicked += OnClickRefresh;
		modsList.Clear();
	}

	public override bool Show()
	{
		bool num = base.Show();
		if (num)
		{
			EventManager.TriggerEvent("Event_OnModsShow");
		}
		return num;
	}

	public void AddPlugin(Plugin plugin)
	{
		if (pluginTemplateContainerMap.ContainsKey(plugin))
		{
			return;
		}
		TemplateContainer templateContainer = modAsset.Instantiate();
		UI.Mod uiMod = templateContainer.Query<UI.Mod>();
		UI.Mod mod = uiMod;
		mod.Ready = (Action)Delegate.Combine(mod.Ready, (Action)delegate
		{
			uiMod.Toggle.value = plugin.IsEnabled;
			uiMod.Toggle.RegisterValueChangedCallback(delegate(ChangeEvent<bool> e)
			{
				OnPluginToggleChanged(plugin, e.newValue);
			});
			UpdatePlugin(plugin);
		});
		pluginTemplateContainerMap.Add(plugin, templateContainer);
		modsList.Add(templateContainer);
		UpdateNoMods();
	}

	public void UpdatePlugin(Plugin plugin)
	{
		if (pluginTemplateContainerMap.ContainsKey(plugin))
		{
			UI.Mod mod = pluginTemplateContainerMap[plugin].Query<UI.Mod>();
			mod.Description = string.Empty;
			mod.PreviewTexture = defaultPreviewTexture;
			mod.HasFiles = true;
			mod.Toggle.enabledSelf = plugin.HasAssembly;
			mod.Toggle.value = plugin.IsEnabled;
			mod.ModPreview.Link.enabledSelf = false;
			mod.ModPreview.Link.Text = plugin.Id;
			mod.ModPreview.IsStatisticsVisible = false;
			mod.Refresh();
		}
	}

	public void RemovePlugin(Plugin plugin)
	{
		if (pluginTemplateContainerMap.ContainsKey(plugin))
		{
			TemplateContainer element = pluginTemplateContainerMap[plugin];
			modsList.Remove(element);
			pluginTemplateContainerMap.Remove(plugin);
			UpdateNoMods();
		}
	}

	public void AddMod(Mod mod)
	{
		if (modTemplateContainerMap.ContainsKey(mod))
		{
			return;
		}
		TemplateContainer templateContainer = modAsset.Instantiate();
		UI.Mod uiMod = templateContainer.Query<UI.Mod>();
		UI.Mod mod2 = uiMod;
		mod2.Ready = (Action)Delegate.Combine(mod2.Ready, (Action)delegate
		{
			uiMod.Toggle.value = mod.IsEnabled;
			uiMod.Toggle.RegisterValueChangedCallback(delegate(ChangeEvent<bool> e)
			{
				OnModToggleChanged(mod, e.newValue);
			});
			Link link = uiMod.ModPreview.Link;
			link.Clicked = (Action)Delegate.Combine(link.Clicked, (Action)delegate
			{
				OnModPreviewLinkClicked(mod);
			});
			UpdateMod(mod);
		});
		modTemplateContainerMap.Add(mod, templateContainer);
		modsList.Add(templateContainer);
		UpdateNoMods();
	}

	public void UpdateMod(Mod mod)
	{
		if (modTemplateContainerMap.ContainsKey(mod))
		{
			UI.Mod mod2 = modTemplateContainerMap[mod].Query<UI.Mod>();
			mod2.Description = mod.SteamWorkshopItem?.Details?.Description ?? string.Empty;
			Texture2D texture2D = mod.SteamWorkshopItem?.Details?.PreviewTexture;
			mod2.PreviewTexture = (((object)texture2D != null) ? ((StyleBackground)texture2D) : defaultPreviewTexture);
			mod2.HasFiles = mod.HasLocalFiles;
			mod2.Toggle.enabledSelf = mod.HasAssembly;
			mod2.Toggle.value = mod.IsEnabled;
			mod2.ModPreview.Link.Text = mod.SteamWorkshopItem?.Details?.Title ?? mod.Id;
			mod2.ModPreview.IsStatisticsVisible = mod.SteamWorkshopItem?.Details != null;
			mod2.ModPreview.Subscriptions = (mod.SteamWorkshopItem?.Details?.Subscriptions).GetValueOrDefault();
			mod2.ModPreview.Upvotes = (mod.SteamWorkshopItem?.Details?.Upvotes).GetValueOrDefault();
			mod2.ModPreview.Downvotes = (mod.SteamWorkshopItem?.Details?.Downvotes).GetValueOrDefault();
			mod2.Refresh();
		}
	}

	public void RemoveMod(Mod mod)
	{
		if (modTemplateContainerMap.ContainsKey(mod))
		{
			TemplateContainer element = modTemplateContainerMap[mod];
			modsList.Remove(element);
			modTemplateContainerMap.Remove(mod);
			UpdateNoMods();
		}
	}

	private void UpdateNoMods()
	{
		noMods.style.display = ((modTemplateContainerMap.Count > 0 || pluginTemplateContainerMap.Count > 0) ? DisplayStyle.None : DisplayStyle.Flex);
	}

	private void OnClickClose()
	{
		EventManager.TriggerEvent("Event_OnModsClickClose");
	}

	private void OnClickFindMods()
	{
		EventManager.TriggerEvent("Event_OnModsClickFindMods");
	}

	private void OnClickRefresh()
	{
		EventManager.TriggerEvent("Event_OnModsClickRefresh");
	}

	private void OnModToggleChanged(Mod mod, bool value)
	{
		if (value)
		{
			EventManager.TriggerEvent("Event_OnModsModEnabled", new Dictionary<string, object> { { "mod", mod } });
		}
		else
		{
			EventManager.TriggerEvent("Event_OnModsModDisabled", new Dictionary<string, object> { { "mod", mod } });
		}
	}

	private void OnModPreviewLinkClicked(Mod mod)
	{
		EventManager.TriggerEvent("Event_OnModPreviewLinkClicked", new Dictionary<string, object> { { "id", mod.Id } });
	}

	private void OnPluginToggleChanged(Plugin plugin, bool value)
	{
		if (value)
		{
			EventManager.TriggerEvent("Event_OnModsPluginEnabled", new Dictionary<string, object> { { "plugin", plugin } });
		}
		else
		{
			EventManager.TriggerEvent("Event_OnModsPluginDisabled", new Dictionary<string, object> { { "plugin", plugin } });
		}
	}
}
public class UIModsController : UIViewController<UIMods>
{
	private UIMods uiMods;

	public override void Awake()
	{
		base.Awake();
		uiMods = GetComponent<UIMods>();
		EventManager.AddEventListener("Event_OnPluginAdded", Event_OnPluginAdded);
		EventManager.AddEventListener("Event_OnPluginStateChanged", Event_OnPluginStateChanged);
		EventManager.AddEventListener("Event_OnPluginEnableFailed", Event_OnPluginEnableFailed);
		EventManager.AddEventListener("Event_OnPluginDisableFailed", Event_OnPluginDisableFailed);
		EventManager.AddEventListener("Event_OnPluginRemoved", Event_OnPluginRemoved);
		EventManager.AddEventListener("Event_OnModAdded", Event_OnModAdded);
		EventManager.AddEventListener("Event_OnModStateChanged", Event_OnModStateChanged);
		EventManager.AddEventListener("Event_OnModSteamWorkshopItemStateChanged", Event_OnModSteamWorkshopItemStateChanged);
		EventManager.AddEventListener("Event_OnModSteamWorkshopItemDetailsStateChanged", Event_OnModSteamWorkshopItemDetailsStateChanged);
		EventManager.AddEventListener("Event_OnModEnableFailed", Event_OnModEnableFailed);
		EventManager.AddEventListener("Event_OnModDisableFailed", Event_OnModDisableFailed);
		EventManager.AddEventListener("Event_OnModRemoved", Event_OnModRemoved);
		EventManager.AddEventListener("Event_OnModsShow", Event_OnModsShow);
	}

	private void Start()
	{
		ModManager.Plugins.ForEach(delegate(Plugin plugin)
		{
			uiMods.AddPlugin(plugin);
		});
		ModManager.Mods.ForEach(delegate(Mod mod)
		{
			uiMods.AddMod(mod);
		});
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_OnPluginAdded", Event_OnPluginAdded);
		EventManager.RemoveEventListener("Event_OnPluginStateChanged", Event_OnPluginStateChanged);
		EventManager.RemoveEventListener("Event_OnPluginEnableFailed", Event_OnPluginEnableFailed);
		EventManager.RemoveEventListener("Event_OnPluginDisableFailed", Event_OnPluginDisableFailed);
		EventManager.RemoveEventListener("Event_OnPluginRemoved", Event_OnPluginRemoved);
		EventManager.RemoveEventListener("Event_OnModAdded", Event_OnModAdded);
		EventManager.RemoveEventListener("Event_OnModStateChanged", Event_OnModStateChanged);
		EventManager.RemoveEventListener("Event_OnModSteamWorkshopItemStateChanged", Event_OnModSteamWorkshopItemStateChanged);
		EventManager.RemoveEventListener("Event_OnModSteamWorkshopItemDetailsStateChanged", Event_OnModSteamWorkshopItemDetailsStateChanged);
		EventManager.RemoveEventListener("Event_OnModEnableFailed", Event_OnModEnableFailed);
		EventManager.RemoveEventListener("Event_OnModDisableFailed", Event_OnModDisableFailed);
		EventManager.RemoveEventListener("Event_OnModRemoved", Event_OnModRemoved);
		EventManager.RemoveEventListener("Event_OnModsShow", Event_OnModsShow);
		base.OnDestroy();
	}

	private void Event_OnModsShow(Dictionary<string, object> message)
	{
		ModManager.Plugins.ForEach(delegate(Plugin plugin)
		{
			uiMods.UpdatePlugin(plugin);
		});
		ModManager.Mods.ForEach(delegate(Mod mod)
		{
			uiMods.UpdateMod(mod);
		});
	}

	private void Event_OnPluginAdded(Dictionary<string, object> message)
	{
		Plugin plugin = (Plugin)message["plugin"];
		uiMods.AddPlugin(plugin);
	}

	private void Event_OnPluginStateChanged(Dictionary<string, object> message)
	{
		Plugin plugin = (Plugin)message["plugin"];
		uiMods.UpdatePlugin(plugin);
	}

	private void Event_OnPluginEnableFailed(Dictionary<string, object> message)
	{
		Plugin plugin = (Plugin)message["plugin"];
		uiMods.UpdatePlugin(plugin);
	}

	private void Event_OnPluginDisableFailed(Dictionary<string, object> message)
	{
		Plugin plugin = (Plugin)message["plugin"];
		uiMods.UpdatePlugin(plugin);
	}

	private void Event_OnPluginRemoved(Dictionary<string, object> message)
	{
		Plugin plugin = (Plugin)message["plugin"];
		uiMods.RemovePlugin(plugin);
	}

	private void Event_OnModAdded(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		uiMods.AddMod(mod);
	}

	private void Event_OnModStateChanged(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		uiMods.UpdateMod(mod);
	}

	private void Event_OnModSteamWorkshopItemStateChanged(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		uiMods.UpdateMod(mod);
	}

	private void Event_OnModSteamWorkshopItemDetailsStateChanged(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		uiMods.UpdateMod(mod);
	}

	private void Event_OnModEnableFailed(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		uiMods.UpdateMod(mod);
	}

	private void Event_OnModDisableFailed(Dictionary<string, object> message)
	{
		Mod mod = (Mod)message["mod"];
		uiMods.UpdateMod(mod);
	}

