	public BasePopupContent(VisualTreeAsset asset)
	{
		this.asset = asset;
	}

	public virtual void Initialize()
	{
		VisualElement = asset.Instantiate();
		Initialized?.Invoke();
	}

	public virtual void Dispose()
	{
		Disposed?.Invoke();
	}

	internal virtual void Update()
	{
	}
}
