public class PopupMissingModsPopupContent : BasePopupContent
{
	private static readonly Logger Logger = new Logger("PopupMissingModsPopupContent");

	private string text;

	private string notice;

	private VisualTreeAsset modPreviewAsset;

	private Label textLabel;

	private Label noticeLabel;

	private VisualElement missingModsList;

	private SteamWorkshopItem[] steamWorkshopItems;

	private Dictionary<SteamWorkshopItem, TemplateContainer> steamWorkshopItemTemplateContainerMap = new Dictionary<SteamWorkshopItem, TemplateContainer>();

	public string Text
	{
		get
		{
			return text;
		}
		set
		{
			if (!(text == value))
			{
				text = value;
				Update();
			}
		}
	}

	public string Notice
	{
		get
		{
			return notice;
		}
		set
		{
			if (!(notice == value))
			{
				notice = value;
				Update();
			}
		}
	}

	public PopupMissingModsPopupContent(VisualTreeAsset asset, VisualTreeAsset modPreviewAsset, string text, string notice, string[] missingModIds)
		: base(asset)
	{
		this.modPreviewAsset = modPreviewAsset;
		this.text = text;
		this.notice = notice;
		steamWorkshopItems = missingModIds.Select((string modId) => new SteamWorkshopItem(modId)).ToArray();
	}

	public override void Initialize()
	{
		base.Initialize();
		textLabel = base.VisualElement.Query<Label>("TextLabel");
		noticeLabel = base.VisualElement.Query<Label>("NoticeLabel");
		missingModsList = base.VisualElement.Query<VisualElement>("MissingModsList");
		SteamWorkshopItem[] array = steamWorkshopItems;
		foreach (SteamWorkshopItem steamWorkshopItem in array)
		{
			AddModPreview(steamWorkshopItem);
			SteamWorkshopItem steamWorkshopItem2 = steamWorkshopItem;
			steamWorkshopItem2.StateChanged = (Action<SteamWorkshopItemState, SteamWorkshopItemState>)Delegate.Combine(steamWorkshopItem2.StateChanged, (Action<SteamWorkshopItemState, SteamWorkshopItemState>)delegate(SteamWorkshopItemState oldState, SteamWorkshopItemState newState)
			{
				OnSteamWorkshopItemStateChanged(steamWorkshopItem.Id, oldState, newState);
			});
			SteamWorkshopItem steamWorkshopItem3 = steamWorkshopItem;
			steamWorkshopItem3.DetailsStateChanged = (Action<SteamWorkshopItemDetailsState, SteamWorkshopItemDetailsState>)Delegate.Combine(steamWorkshopItem3.DetailsStateChanged, (Action<SteamWorkshopItemDetailsState, SteamWorkshopItemDetailsState>)delegate(SteamWorkshopItemDetailsState oldDetailsState, SteamWorkshopItemDetailsState newDetailsState)
			{
				OnSteamWorkshopItemDetailsStateChanged(steamWorkshopItem.Id, oldDetailsState, newDetailsState);
			});
			steamWorkshopItem.Initialize();
		}
		Update();
	}

	internal override void Update()
	{
		base.Update();
		if (textLabel != null)
		{
			textLabel.text = Text;
		}
		if (noticeLabel != null)
		{
			noticeLabel.text = Notice;
		}
	}

	public override void Dispose()
	{
		base.Dispose();
		SteamWorkshopItem[] array = steamWorkshopItems;
		foreach (SteamWorkshopItem steamWorkshopItem in array)
		{
			steamWorkshopItem.Dispose();
			RemoveMod(steamWorkshopItem);
		}
	}

	private void AddModPreview(SteamWorkshopItem steamWorkshopItem)
	{
		TemplateContainer templateContainer = modPreviewAsset.Instantiate();
		ModPreview uiModPreview = templateContainer.Query<ModPreview>();
		ModPreview modPreview = uiModPreview;
		modPreview.Ready = (Action)Delegate.Combine(modPreview.Ready, (Action)delegate
		{
			Link link = uiModPreview.Link;
			link.Clicked = (Action)Delegate.Combine(link.Clicked, (Action)delegate
			{
				OnModLinkClicked(steamWorkshopItem);
			});
			UpdateMod(steamWorkshopItem);
		});
		steamWorkshopItemTemplateContainerMap.Add(steamWorkshopItem, templateContainer);
		missingModsList.Add(templateContainer);
	}

	private void UpdateMod(SteamWorkshopItem steamWorkshopItem)
	{
		if (steamWorkshopItemTemplateContainerMap.ContainsKey(steamWorkshopItem))
		{
			ModPreview modPreview = steamWorkshopItemTemplateContainerMap[steamWorkshopItem].Query<ModPreview>();
			modPreview.IsStatisticsVisible = steamWorkshopItem.Details != null;
			modPreview.Subscriptions = steamWorkshopItem.Details?.Subscriptions ?? 0;
			modPreview.Upvotes = steamWorkshopItem.Details?.Upvotes ?? 0;
			modPreview.Downvotes = steamWorkshopItem.Details?.Downvotes ?? 0;
			modPreview.Link.Text = steamWorkshopItem.Details?.Title ?? steamWorkshopItem.Id.ToString();
		}
	}

	private void RemoveMod(SteamWorkshopItem steamWorkshopItem)
	{
		if (steamWorkshopItemTemplateContainerMap.ContainsKey(steamWorkshopItem))
		{
			TemplateContainer element = steamWorkshopItemTemplateContainerMap[steamWorkshopItem];
			missingModsList.Remove(element);
			steamWorkshopItemTemplateContainerMap.Remove(steamWorkshopItem);
		}
	}

	private void OnSteamWorkshopItemStateChanged(string id, SteamWorkshopItemState oldState, SteamWorkshopItemState newState)
	{
		SteamWorkshopItem steamWorkshopItem = steamWorkshopItems.FirstOrDefault((SteamWorkshopItem item) => item.Id == id);
		if (steamWorkshopItem != null)
		{
			UpdateMod(steamWorkshopItem);
		}
	}

	private void OnSteamWorkshopItemDetailsStateChanged(string id, SteamWorkshopItemDetailsState oldDetailsState, SteamWorkshopItemDetailsState newDetailsState)
	{
		SteamWorkshopItem steamWorkshopItem = steamWorkshopItems.FirstOrDefault((SteamWorkshopItem item) => item.Id == id);
		if (steamWorkshopItem != null)
		{
			UpdateMod(steamWorkshopItem);
		}
	}

	private void OnSteamWorkshopItemPropertyChanged(object sender, PropertyChangedEventArgs e)
	{
		SteamWorkshopItem steamWorkshopItem = (SteamWorkshopItem)sender;
		UpdateMod(steamWorkshopItem);
	}

	private void OnModLinkClicked(SteamWorkshopItem steamWorkshopItem)
	{
		EventManager.TriggerEvent("Event_OnModPreviewLinkClicked", new Dictionary<string, object> { { "id", steamWorkshopItem.Id } });
	}
}
public class Popup
{
	public TemplateContainer TemplateContainer;

	public VisualElement VisualElement;

	public string Name;

	public string Title;

	public BasePopupContent Content;

	public bool ShowOkButton;

	public bool ShowCloseButton;

	public object Data;

	private VisualElement header;

	private VisualElement content;

	private VisualElement footer;

	private Label titleLabel;

	private Button okButton;

	private IconButton closeIconButton;

	public Popup(VisualElement visualElement, string name, string title, BasePopupContent content, bool showOkButton, bool showCloseButton, object data = null)
	{
		VisualElement = visualElement;
		Name = name;
		Title = title;
		Content = content;
		ShowOkButton = showOkButton;
		ShowCloseButton = showCloseButton;
		Data = data;
	}

	public void Initialize()
	{
		header = VisualElement.Query<VisualElement>("Header");
		content = VisualElement.Query<VisualElement>("Content");
		footer = VisualElement.Query<VisualElement>("Footer");
		titleLabel = header.Query<Label>();
		titleLabel.text = Title;
		closeIconButton = header.Query<VisualElement>("CloseIconButtonContainer").First().Query<IconButton>();
		closeIconButton.clicked += OnClickClose;
		okButton = footer.Query<Button>("OkButton");
		okButton.clicked += OnClickOk;
		if (!ShowOkButton)
		{
			okButton.style.display = DisplayStyle.None;
		}
		if (!ShowCloseButton)
		{
			closeIconButton.style.display = DisplayStyle.None;
		}
		Content.Initialize();
		content.Add(Content.VisualElement);
	}

	public void Dispose()
	{
		closeIconButton.clicked -= OnClickClose;
		okButton.clicked -= OnClickOk;
		content.Remove(Content.VisualElement);
		Content.Dispose();
	}

	private void OnClickClose()
	{
		EventManager.TriggerEvent("Event_OnPopupClickClose", new Dictionary<string, object> { { "popup", this } });
	}

	private void OnClickOk()
	{
		EventManager.TriggerEvent("Event_OnPopupClickOk", new Dictionary<string, object> { { "popup", this } });
	}
}
public class UIPopupManager : UIView
{
	[Header("References")]
	[SerializeField]
	private VisualTreeAsset popupAsset;

	[SerializeField]
	private VisualTreeAsset notificationContentAsset;

	[SerializeField]
	private VisualTreeAsset missingPasswordContentAsset;

	[SerializeField]
	private VisualTreeAsset missingModsContentAsset;

	[SerializeField]
	private VisualTreeAsset modPreviewAsset;

	private VisualElement popups;

	private Dictionary<string, Popup> namePopupMap = new Dictionary<string, Popup>();

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("PopupsView");
		popups = base.View.Query<VisualElement>("Popups");
		popups.Clear();
		UpdateFocus();
		UpdateVisibility();
	}

	public void ShowPopup(string name, string title, BasePopupContent content, bool showOkButton, bool showCloseButton, object data = null)
	{
		if (GetPopupByName(name) == null)
		{
			Popup popup = new Popup(popupAsset.Instantiate(), name, title, content, showOkButton, showCloseButton, data);
			popups.Add(popup.VisualElement);
			namePopupMap.Add(name, popup);
			popup.Initialize();
			popup.VisualElement.BringToFront();
			UpdateFocus();
			UpdateVisibility();
			EventManager.TriggerEvent("Event_OnPopupShow", new Dictionary<string, object> { { "name", name } });
		}
	}

	public void HidePopup(string name)
	{
		Popup popupByName = GetPopupByName(name);
		if (popupByName != null)
		{
			popups.Remove(popupByName.VisualElement);
			namePopupMap.Remove(name);
			popupByName.Dispose();
			UpdateFocus();
			UpdateVisibility();
			EventManager.TriggerEvent("Event_OnPopupHide", new Dictionary<string, object> { { "name", name } });
		}
	}

	public Popup GetPopupByName(string name)
	{
		if (namePopupMap.ContainsKey(name))
		{
			return namePopupMap[name];
		}
		return null;
	}

	private void UpdateFocus()
	{
		base.IsFocused = namePopupMap.Count > 0;
	}

	private void UpdateVisibility()
	{
		popups.style.display = ((namePopupMap.Count <= 0) ? DisplayStyle.None : DisplayStyle.Flex);
	}

	public PopupNotificationContent CreateNotificationContent(string text)
	{
		return new PopupNotificationContent(notificationContentAsset, text);
	}

	public PopupMissingPasswordContent CreateMissingPasswordContent()
	{
		return new PopupMissingPasswordContent(missingPasswordContentAsset);
	}

	public PopupMissingModsPopupContent CreateMissingModsContent(string text, string notice, string[] missingModIds)
	{
		return new PopupMissingModsPopupContent(missingModsContentAsset, modPreviewAsset, text, notice, missingModIds);
	}
}
