public class UIServerBrowserController : UIViewController<UIServerBrowser>
{
	private UIServerBrowser uiServerBrowser;

	public override void Awake()
	{
		base.Awake();
		uiServerBrowser = GetComponent<UIServerBrowser>();
		EventManager.AddEventListener("Event_OnServerBrowserShow", Event_OnServerBrowserShow);
		EventManager.AddEventListener("Event_OnServerBrowserClickRefresh", Event_OnServerBrowserClickRefresh);
		WebSocketManager.AddMessageListener("playerGetServerBrowserEndPointsResponse", WebSocket_Event_OnPlayerGetServerBrowserEndPointsResponse);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_OnServerBrowserShow", Event_OnServerBrowserShow);
		EventManager.RemoveEventListener("Event_OnServerBrowserClickRefresh", Event_OnServerBrowserClickRefresh);
		WebSocketManager.RemoveMessageListener("playerGetServerBrowserEndPointsResponse", WebSocket_Event_OnPlayerGetServerBrowserEndPointsResponse);
		base.OnDestroy();
	}

	private void Event_OnServerBrowserShow(Dictionary<string, object> message)
	{
		if (uiServerBrowser.ServerCount == 0)
		{
			uiServerBrowser.Refresh();
		}
	}

	private void Event_OnServerBrowserClickRefresh(Dictionary<string, object> message)
	{
		uiServerBrowser.Refresh();
	}

	private void WebSocket_Event_OnPlayerGetServerBrowserEndPointsResponse(Dictionary<string, object> message)
	{
		ServerBrowserEndPointsResponse data = ((InMessage)message["inMessage"]).GetData<ServerBrowserEndPointsResponse>();
		List<EndPoint> list = new List<EndPoint>(data.data.endPoints);
		if (data.success)
		{
			uiServerBrowser.UpdateEndPoints(list.ToArray());
		}
	}
}
public class MicTester : MonoBehaviour
{
	private uint sampleRate;

	private byte[] decompressBuffer;

	private bool ownsRecording;

	private float level;

	private readonly VoiceLevelMeter meter = new VoiceLevelMeter();

	public bool IsActive { get; private set; }

	public event Action<float> OnLevelChanged;

	private void Update()
	{
		if (!IsActive)
		{
			return;
		}
		PlayerVoiceRecorder localPlayerRecorder = GetLocalPlayerRecorder();
		if (localPlayerRecorder != null && localPlayerRecorder.IsRecording)
		{
			ReleaseRecording(playerStillRecording: true);
			meter.Reset();
			SetLevel(localPlayerRecorder.TransmitLevel);
			return;
		}
		if (!ownsRecording)
		{
			SteamUser.StartVoiceRecording();
			ownsRecording = true;
		}
		bool hasVoice;
		float rawLevel = Capture(out hasVoice);
		SetLevel(meter.Update(rawLevel, hasVoice, Time.deltaTime));
	}

	private void OnDestroy()
	{
		Stop();
	}

	public void SetActive(bool value)
	{
		if (value)
		{
			Begin();
		}
		else
		{
			Stop();
		}
	}

	private void Begin()
	{
		if (!IsActive && SteamManager.IsInitialized)
		{
			IsActive = true;
			sampleRate = SteamUser.GetVoiceOptimalSampleRate();
			if (sampleRate != 0)
			{
				decompressBuffer = new byte[sampleRate * 2];
			}
		}
	}

	private void Stop()
	{
		if (IsActive)
		{
			IsActive = false;
			ReleaseRecording(playerStillRecording: false);
			meter.Reset();
			SetLevel(0f);
		}
	}

	private float Capture(out bool hasVoice)
	{
		hasVoice = false;
		SteamUser.GetAvailableVoice(out var pcbCompressed);
		if (pcbCompressed == 0)
		{
			return 0f;
		}
		byte[] array = new byte[pcbCompressed];
		SteamUser.GetVoice(bWantCompressed: true, array, pcbCompressed, out var nBytesWritten);
		if (nBytesWritten == 0)
		{
			return 0f;
		}
		hasVoice = true;
		return VoiceUtils.ComputeLevel(array, nBytesWritten, sampleRate, decompressBuffer);
	}

	private void ReleaseRecording(bool playerStillRecording)
	{
		if (ownsRecording && !playerStillRecording)
		{
			SteamUser.StopVoiceRecording();
		}
		ownsRecording = false;
	}

	private void SetLevel(float value)
	{
		level = value;
		this.OnLevelChanged?.Invoke(value);
	}

	private PlayerVoiceRecorder GetLocalPlayerRecorder()
	{
		Player player = ((MonoBehaviourSingleton<PlayerManager>.Instance != null) ? MonoBehaviourSingleton<PlayerManager>.Instance.GetLocalPlayer() : null);
		if (!(player != null))
		{
			return null;
		}
		return player.GetComponent<PlayerVoiceRecorder>();
	}
}
