public class UITeamSelect : UIView
{
	private VisualElement teamSelect;

	private Button blueButton;

	private Button redButton;

	private Button spectatorButton;

	private Label blueCountLabel;

	private Label redCountLabel;

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("TeamSelectView");
		teamSelect = base.View.Query<VisualElement>("TeamSelect");
		blueButton = teamSelect.Query<Button>("BlueButton");
		blueButton.clicked += OnClickTeamBlue;
		blueCountLabel = blueButton.Query<Label>("CountLabel");
		redButton = teamSelect.Query<Button>("RedButton");
		redButton.clicked += OnClickTeamRed;
		redCountLabel = redButton.Query<Label>("CountLabel");
		spectatorButton = teamSelect.Query<Button>("SpectatorButton");
		spectatorButton.clicked += OnClickTeamSpectator;
	}

	public override bool Show()
	{
		bool num = base.Show();
		if (num)
		{
			EventManager.TriggerEvent("Event_OnTeamSelectShow");
		}
		return num;
	}

	public void StyleTeamCounts(int blueCount, int redCount)
	{
		blueCountLabel.text = FormatPlayerCount(blueCount);
		redCountLabel.text = FormatPlayerCount(redCount);
	}

	private string FormatPlayerCount(int count)
	{
		if (count != 1)
		{
			return $"{count} PLAYERS";
		}
		return "1 PLAYER";
	}

	private void OnClickTeamBlue()
	{
		EventManager.TriggerEvent("Event_OnTeamSelectClickTeam", new Dictionary<string, object> { 
		{
			"team",
			PlayerTeam.Blue
		} });
	}

	private void OnClickTeamRed()
	{
		EventManager.TriggerEvent("Event_OnTeamSelectClickTeam", new Dictionary<string, object> { 
		{
			"team",
			PlayerTeam.Red
		} });
	}

	private void OnClickTeamSpectator()
	{
		EventManager.TriggerEvent("Event_OnTeamSelectClickTeam", new Dictionary<string, object> { 
		{
			"team",
			PlayerTeam.Spectator
		} });
	}
}
public class UITeamSelectController : UIViewController<UITeamSelect>
{
	private UITeamSelect uiTeamSelect;

	public override void Awake()
	{
		base.Awake();
		uiTeamSelect = GetComponent<UITeamSelect>();
		EventManager.AddEventListener("Event_OnTeamSelectShow", Event_OnTeamSelectShow);
		EventManager.AddEventListener("Event_Everyone_OnPlayerAdded", Event_Everyone_OnPlayerAdded);
		EventManager.AddEventListener("Event_Everyone_OnPlayerRemoved", Event_Everyone_OnPlayerRemoved);
		EventManager.AddEventListener("Event_Everyone_OnPlayerGameStateChanged", Event_Everyone_OnPlayerGameStateChanged);
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_OnTeamSelectShow", Event_OnTeamSelectShow);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerAdded", Event_Everyone_OnPlayerAdded);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerRemoved", Event_Everyone_OnPlayerRemoved);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerGameStateChanged", Event_Everyone_OnPlayerGameStateChanged);
		base.OnDestroy();
	}

	private void StyleTeamCounts()
	{
		uiTeamSelect.StyleTeamCounts(MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayersByTeam(PlayerTeam.Blue).Count, MonoBehaviourSingleton<PlayerManager>.Instance.GetPlayersByTeam(PlayerTeam.Red).Count);
	}

	private void Event_OnTeamSelectShow(Dictionary<string, object> message)
	{
		StyleTeamCounts();
	}

	private void Event_Everyone_OnPlayerAdded(Dictionary<string, object> message)
	{
		if (!((Player)message["player"]).IsReplay.Value)
		{
			StyleTeamCounts();
		}
	}

	private void Event_Everyone_OnPlayerRemoved(Dictionary<string, object> message)
	{
		if (!((Player)message["player"]).IsReplay.Value)
		{
			StyleTeamCounts();
		}
	}

	private void Event_Everyone_OnPlayerGameStateChanged(Dictionary<string, object> message)
	{
		StyleTeamCounts();
	}
}
public class Toast
{
	public UIToastManager UIToastManager;

	public VisualElement VisualElement;

	public string Name;

	public string Content;

	public float HideDelay;

	private IEnumerator hideCoroutine;

	private Label contentLabel;

	public Toast(UIToastManager uiToastManager, VisualElement visualElement, string name, string content, float hideDelay)
	{
		UIToastManager = uiToastManager;
		VisualElement = visualElement;
		Name = name;
		Content = content;
		HideDelay = hideDelay;
		Initialize();
	}

	public void Initialize()
	{
		VisualElement.RegisterCallback<ClickEvent>(OnClick);
		contentLabel = VisualElement.Query<Label>("ContentLabel");
		contentLabel.text = Content;
		Hide();
	}

	public void Hide()
	{
		hideCoroutine = IHide();
		UIToastManager.StartCoroutine(hideCoroutine);
	}

	private IEnumerator IHide()
	{
		yield return new WaitForSeconds(HideDelay);
		UIToastManager.HideToast(Name);
		hideCoroutine = null;
	}

	public void Dispose()
	{
		VisualElement.UnregisterCallback<ClickEvent>(OnClick);
		if (hideCoroutine != null)
		{
			UIToastManager.StopCoroutine(hideCoroutine);
			hideCoroutine = null;
		}
	}

	private void OnClick(ClickEvent clickEvent)
	{
		UIToastManager.HideToast(Name);
	}
}
public class UIToastManager : UIView
{
	[Header("References")]
	[SerializeField]
	public VisualTreeAsset toastAsset;

	private Dictionary<string, Toast> nameToastMap = new Dictionary<string, Toast>();

	private VisualElement toasts;

	public void Initialize(VisualElement rootVisualElement)
	{
		base.View = rootVisualElement.Query<VisualElement>("ToastsView");
		toasts = base.View.Query<VisualElement>("Toasts");
		toasts.Clear();
	}

	public void ShowToast(string name, string content, float hideDelay = 3f)
	{
		if (nameToastMap.ContainsKey(name))
		{
			HideToast(name);
		}
		VisualElement visualElement = toastAsset.Instantiate();
		Toast toast = new Toast(this, visualElement, name, content.ToUpper(), hideDelay);
		toasts.Add(toast.VisualElement);
		nameToastMap.Add(name, toast);
	}

	public void HideToast(string name)
	{
		if (nameToastMap.ContainsKey(name))
		{
			toasts.Remove(nameToastMap[name].VisualElement);
			nameToastMap[name].Dispose();
			nameToastMap.Remove(name);
		}
	}
}
