public class UIUsernames : UIView
{
	private static readonly Logger Logger = new Logger("UIUsernames");

	[Header("Settings")]
	[SerializeField]
	private float yOffset = 2.5f;

	[Header("References")]
	[SerializeField]
	private VisualTreeAsset playerUsernameAsset;

	[HideInInspector]
	public float FadeThreshold = 0.5f;

	[HideInInspector]
	public Bounds Bounds;

	private Dictionary<PlayerBody, VisualElement> playerBodyVisualElementMap = new Dictionary<PlayerBody, VisualElement>();

	private VisualElement usernames;

	[HideInInspector]
	public float MaximumDistance => Mathf.Max(Bounds.size.x, Bounds.size.z);

	[HideInInspector]
	public float FadeRange => MaximumDistance / 4f;

	public void Initialize(VisualElement rootVisualElement)
	{
		RootVisualElement = rootVisualElement;
		base.View = rootVisualElement.Query<VisualElement>("UsernamesView");
		usernames = base.View.Query<VisualElement>("Usernames");
		usernames.Clear();
	}

	private void Update()
	{
		if (ApplicationManager.IsDedicatedGameServer)
		{
			return;
		}
		foreach (KeyValuePair<PlayerBody, VisualElement> item in playerBodyVisualElementMap)
		{
			PlayerBody key = item.Key;
			VisualElement value = item.Value;
			if (!(key == null))
			{
				UsernameWorldToScreen(value, key);
			}
		}
	}

	public override bool Show()
	{
		if (!SettingsManager.ShowPlayerUsernames)
		{
			return false;
		}
		return base.Show();
	}

	public void AddPlayerBody(PlayerBody playerBody)
	{
		TemplateContainer templateContainer = playerUsernameAsset.Instantiate();
		playerBodyVisualElementMap.Add(playerBody, templateContainer);
		StyleUsername(playerBody);
		usernames.Add(templateContainer);
	}

	public void RemovePlayerBody(PlayerBody playerBody)
	{
		if (playerBodyVisualElementMap.ContainsKey(playerBody))
		{
			VisualElement element = playerBodyVisualElementMap[playerBody];
			playerBodyVisualElementMap.Remove(playerBody);
			usernames.Remove(element);
		}
	}

	public void StyleUsername(PlayerBody playerBody)
	{
		if (playerBodyVisualElementMap.ContainsKey(playerBody))
		{
			((Label)playerBodyVisualElementMap[playerBody].Query<Label>("UsernameLabel")).text = $"#{playerBody.Player.Number.Value} {playerBody.Player.Username.Value}";
		}
	}

	private void UsernameWorldToScreen(VisualElement playerVisualElement, PlayerBody playerBody)
	{
		if (!(Camera.main == null))
		{
			Vector3 position = Camera.main.transform.position;
			Vector3 position2 = playerBody.transform.position;
			float value = Vector3.Distance(position, position2);
			Vector3 vector = Camera.main.WorldToScreenPoint(position2 + Vector3.up * yOffset);
			vector.y = (float)Screen.height - vector.y;
			RuntimePanelUtils.ScreenToPanel(RootVisualElement.panel, vector);
			Vector2 vector2 = RuntimePanelUtils.ScreenToPanel(RootVisualElement.panel, vector);
			if (vector.z < 0f)
			{
				playerVisualElement.style.display = DisplayStyle.None;
				return;
			}
			float value2 = Utils.Map(value, MaximumDistance * FadeThreshold, MaximumDistance * FadeThreshold + FadeRange, 1f, 0f);
			value2 = Mathf.Clamp01(value2);
			playerVisualElement.style.display = DisplayStyle.Flex;
			playerVisualElement.style.left = vector2.x;
			playerVisualElement.style.top = vector2.y;
			playerVisualElement.style.opacity = new StyleFloat(value2);
		}
	}
}
public class UIUsernamesController : UIViewController<UIUsernames>
{
	private static readonly Logger Logger = new Logger("UIUsernamesController");

	private UIUsernames uiUsernames;

	public override void Awake()
	{
		base.Awake();
		uiUsernames = GetComponent<UIUsernames>();
		EventManager.AddEventListener("Event_Everyone_OnLevelSpawned", Event_Everyone_OnLevelSpawned);
		EventManager.AddEventListener("Event_Everyone_OnPlayerBodySpawned", Event_Everyone_OnPlayerBodySpawned);
		EventManager.AddEventListener("Event_Everyone_OnPlayerBodyDespawned", Event_Everyone_OnPlayerBodyDespawned);
		EventManager.AddEventListener("Event_Everyone_OnPlayerUsernameChanged", Event_Everyone_OnPlayerUsernameChanged);
		EventManager.AddEventListener("Event_Everyone_OnPlayerNumberChanged", Event_Everyone_OnPlayerNumberChanged);
		EventManager.AddEventListener("Event_OnShowPlayerUsernamesChanged", Event_OnShowPlayerUsernamesChanged);
		EventManager.AddEventListener("Event_OnPlayerUsernamesFadeThresholdChanged", Event_OnPlayerUsernamesFadeThresholdChanged);
	}

	private void Start()
	{
		uiUsernames.FadeThreshold = SettingsManager.PlayerUsernamesFadeThreshold;
	}

	public override void OnDestroy()
	{
		EventManager.RemoveEventListener("Event_Everyone_OnLevelSpawned", Event_Everyone_OnLevelSpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerBodySpawned", Event_Everyone_OnPlayerBodySpawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerBodyDespawned", Event_Everyone_OnPlayerBodyDespawned);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerUsernameChanged", Event_Everyone_OnPlayerUsernameChanged);
		EventManager.RemoveEventListener("Event_Everyone_OnPlayerNumberChanged", Event_Everyone_OnPlayerNumberChanged);
		EventManager.RemoveEventListener("Event_OnShowPlayerUsernamesChanged", Event_OnShowPlayerUsernamesChanged);
		EventManager.RemoveEventListener("Event_OnPlayerUsernamesFadeThresholdChanged", Event_OnPlayerUsernamesFadeThresholdChanged);
		base.OnDestroy();
	}

	private void Event_Everyone_OnLevelSpawned(Dictionary<string, object> message)
	{
		Level level = (Level)message["level"];
		uiUsernames.Bounds = level.Bounds;
	}

	private void Event_Everyone_OnPlayerBodySpawned(Dictionary<string, object> message)
	{
		PlayerBody playerBody = (PlayerBody)message["playerBody"];
		uiUsernames.AddPlayerBody(playerBody);
	}

	private void Event_Everyone_OnPlayerBodyDespawned(Dictionary<string, object> message)
	{
		PlayerBody playerBody = (PlayerBody)message["playerBody"];
		uiUsernames.RemovePlayerBody(playerBody);
	}

	private void Event_Everyone_OnPlayerUsernameChanged(Dictionary<string, object> message)
	{
		PlayerBody playerBody = ((Player)message["player"]).PlayerBody;
		if ((bool)playerBody)
		{
			uiUsernames.StyleUsername(playerBody);
		}
	}

	private void Event_Everyone_OnPlayerNumberChanged(Dictionary<string, object> message)
	{
		PlayerBody playerBody = ((Player)message["player"]).PlayerBody;
		if ((bool)playerBody)
		{
			uiUsernames.StyleUsername(playerBody);
		}
	}

	private void Event_OnShowPlayerUsernamesChanged(Dictionary<string, object> message)
	{
		if ((bool)message["value"])
		{
			uiUsernames.Show();
		}
		else
		{
			uiUsernames.Hide();
		}
	}

	private void Event_OnPlayerUsernamesFadeThresholdChanged(Dictionary<string, object> message)
	{
		float fadeThreshold = (float)message["value"];
		uiUsernames.FadeThreshold = fadeThreshold;
	}
}
public static class BackendUtils
{
	public static PlayerBan GetActivePlayerDataBan(PlayerData playerData)
	{
		return playerData?.bans.FirstOrDefault((PlayerBan ban) => Utils.GetTimestamp() <= ban.expiresAt);
	}

	public static PlayerMute GetActivePlayerDataMute(PlayerData playerData)
	{
		return playerData?.mutes.FirstOrDefault((PlayerMute mute) => Utils.GetTimestamp() <= mute.expiresAt);
	}

	public static PlayerCooldown GetActivePlayerDataCooldown(PlayerData playerData)
	{
		return playerData?.cooldowns.FirstOrDefault((PlayerCooldown cooldown) => Utils.GetTimestamp() <= cooldown.expiresAt);
	}

	public static bool IsConnectedToMatchEndPoint()
	{
		EndPoint endPoint = GlobalStateManager.ConnectionState.Connection?.EndPoint;
		EndPoint endPoint2 = BackendManager.PlayerState.MatchData?.endPoint;
		if (endPoint != null)
		{
			return endPoint == endPoint2;
		}
		return false;
	}
}
public class CompressedNetworkVariable<TRaw, TNetwork> : NetworkVariable<TNetwork> where TRaw : struct where TNetwork : struct
{
	private readonly Func<TRaw, TNetwork> compressor;

	private readonly Func<TNetwork, TRaw> decompressor;

	private TRaw cachedValue;

	public new TRaw Value
	{
		get
		{
			return cachedValue;
		}
		set
		{
			TRaw val = cachedValue;
			cachedValue = value;
			base.Value = compressor(value);
			if (!EqualityComparer<TRaw>.Default.Equals(cachedValue, val))
			{
				this.OnRawValueChanged?.Invoke(val, cachedValue);
			}
		}
	}

	public event Action<TRaw, TRaw> OnRawValueChanged;

	public CompressedNetworkVariable(Func<TRaw, TNetwork> compressor, Func<TNetwork, TRaw> decompressor, TRaw initialValue = default(TRaw), NetworkVariableReadPermission readPerm = NetworkVariableReadPermission.Everyone, NetworkVariableWritePermission writePerm = NetworkVariableWritePermission.Server)
		: base(compressor(initialValue), readPerm, writePerm)
	{
		this.compressor = compressor;
		this.decompressor = decompressor;
		cachedValue = initialValue;
		OnValueChanged = (OnValueChangedDelegate)Delegate.Combine(OnValueChanged, new OnValueChangedDelegate(OnCompressedValueChanged));
	}

	private void OnCompressedValueChanged(TNetwork previousCompressed, TNetwork newCompressed)
	{
		TRaw arg = cachedValue;
		cachedValue = decompressor(newCompressed);
		this.OnRawValueChanged?.Invoke(arg, cachedValue);
	}

	public static CompressedNetworkVariable<float, short> CreateFloatToShort(float minValue, float maxValue, float initialValue = 0f, NetworkVariableReadPermission readPerm = NetworkVariableReadPermission.Everyone, NetworkVariableWritePermission writePerm = NetworkVariableWritePermission.Server)
	{
		return new CompressedNetworkVariable<float, short>(delegate(float value)
		{
			float val = (value - minValue) / (maxValue - minValue);
			return (short)(Math.Max(0f, Math.Min(1f, val)) * 32767f);
		}, delegate(short compressed)
		{
			float num = (float)compressed / 32767f;
			return minValue + num * (maxValue - minValue);
		}, initialValue, readPerm, writePerm);
	}

	public static CompressedNetworkVariable<float, byte> CreateFloatToByte(float minValue, float maxValue, float initialValue = 0f, NetworkVariableReadPermission readPerm = NetworkVariableReadPermission.Everyone, NetworkVariableWritePermission writePerm = NetworkVariableWritePermission.Server)
	{
		return new CompressedNetworkVariable<float, byte>(delegate(float value)
		{
			float val = (value - minValue) / (maxValue - minValue);
			return (byte)(Math.Max(0f, Math.Min(1f, val)) * 255f);
		}, delegate(byte compressed)
		{
			float num = (float)(int)compressed / 255f;
			return minValue + num * (maxValue - minValue);
		}, initialValue, readPerm, writePerm);
	}
}
public static class ConfigUtils
{
	private static readonly Logger Logger = new Logger("ConfigUtils");

	public static T LoadConfigFromFile<T>(string filePath, bool createIfNotExists = true) where T : class, new()
	{
		if (string.IsNullOrEmpty(filePath))
		{
			return null;
		}
		if (!File.Exists(filePath) && createIfNotExists)
		{
			SaveConfigToFile(filePath, new T());
		}
		if (!TryReadFile(filePath, out var contents))
		{
			return null;
		}
		return LoadConfigFromSerializedString<T>(contents, filePath);
	}

	public static T LoadConfigFromSerializedString<T>(string serializedString, string source = "serialized string") where T : class, new()
	{
		if (string.IsNullOrEmpty(serializedString))
		{
			return null;
		}
		if (!TryDeserialize<T>(serializedString, source, out var result))
		{
			return null;
		}
		return result;
	}

	public static bool TryLoadFromFile<T>(string filePath, out T result)
	{
		result = default(T);
		if (!TryReadFile(filePath, out var contents))
		{
			return false;
		}
		return TryDeserialize<T>(contents, filePath, out result);
	}

	public static bool TryDeserialize<T>(string serializedString, string source, out T result)
	{
		result = default(T);
		try
		{
			result = JsonSerializer.Deserialize<T>(serializedString);
			return true;
		}
		catch (JsonException exception)
		{
			Logger.Error("Malformed JSON in " + source + ": " + DescribeJsonError(exception));
			return false;
		}
		catch (Exception ex)
		{
			Logger.Error("Error loading config from " + source + ": " + ex.Message);
			return false;
		}
	}

	private static bool TryReadFile(string filePath, out string contents)
	{
		contents = null;
		try
		{
			contents = File.ReadAllText(filePath);
			return true;
		}
		catch (Exception ex)
		{
			Logger.Error("Could not read config file " + filePath + ": " + ex.Message);
			return false;
		}
	}

	private static string DescribeJsonError(JsonException exception)
	{
		string text = "";
		if (exception.LineNumber.HasValue)
		{
			text = $"line {exception.LineNumber + 1}";
			if (exception.BytePositionInLine.HasValue)
			{
				text += $", position {exception.BytePositionInLine + 1}";
			}
		}
		if (!string.IsNullOrEmpty(exception.Path) && exception.Path != "$")
		{
			text += (string.IsNullOrEmpty(text) ? ("at " + exception.Path) : (" (at " + exception.Path + ")"));
		}
		if (!string.IsNullOrEmpty(text))
		{
			return text + ": " + exception.Message;
		}
		return exception.Message;
	}

	public static void SaveConfigToFile<T>(string filePath, T config)
	{
		try
		{
			JsonSerializerOptions jsonSerializerOptions = new JsonSerializerOptions
			{
				WriteIndented = true
			};
			jsonSerializerOptions.Converters.Add(new JsonStringEnumConverter());
			string text = JsonSerializer.Serialize(config, jsonSerializerOptions);
			Logger.Info("Serialized config " + typeof(T).Name + ": " + text);
			File.WriteAllText(filePath, text);
		}
		catch (Exception ex)
		{
			Logger.Error("Error saving config to " + filePath + ": " + ex.Message);
		}
	}
}
