public class Country
{
	private static readonly Logger Logger = new Logger("Country");

	public string capital { get; set; }

	public string code { get; set; }

	public string continent { get; set; }

	public string name { get; set; }
}
public static class CountryUtils
{
	private static readonly Logger Logger;

	public static List<Country> Countries { get; private set; }

	static CountryUtils()
	{
		Logger = new Logger("CountryUtils");
		Countries = new List<Country>();
		LoadCountries();
	}

	public static Country GetCountryByCode(string code)
	{
		return Countries.Find((Country country) => country.code.Equals(code, StringComparison.OrdinalIgnoreCase));
	}

	public static Country GetCountryByName(string name)
	{
		return Countries.Find((Country country) => country.name.Equals(name, StringComparison.OrdinalIgnoreCase));
	}

	private static void LoadCountries()
	{
		try
		{
			Countries = JsonSerializer.Deserialize<List<Country>>(UnityEngine.Resources.Load<TextAsset>("countries").text);
			Logger.Info($"Loaded {Countries.Count} countries");
		}
		catch (Exception ex)
		{
			Logger.Error("Error loading countries asset: " + ex.Message);
		}
	}
}
public readonly struct Logger
{
	private readonly string prefix;

	private static string GetColor(LogType type)
	{
		if (Application.isEditor)
		{
			return "<color=white>";
		}
		if (!TerminalUtils.SupportsAnsiColor)
		{
			return "";
		}
		return "\u001b[37m";
	}

	private static string GetReset()
	{
		if (Application.isEditor)
		{
			return "</color>";
		}
		if (!TerminalUtils.SupportsAnsiColor)
		{
			return "";
		}
		return "\u001b[0m";
	}

	public Logger(string tag)
	{
		string color = GetColor(LogType.Log);
		string reset = GetReset();
		prefix = color + "[" + tag + "]" + reset + " ";
	}

	[HideInCallstack]
	public void Info(string message)
	{
		UnityEngine.Debug.Log(prefix + message);
	}

	[HideInCallstack]
	public void Warning(string message)
	{
		UnityEngine.Debug.LogWarning(prefix + message);
	}

	[HideInCallstack]
	public void Error(string message)
	{
		UnityEngine.Debug.LogError(prefix + message);
	}

	[HideInCallstack]
	public void Exception(Exception exception)
	{
		UnityEngine.Debug.LogException(exception);
	}
}
public class MonoBehaviourSingleton<T> : MonoBehaviour where T : MonoBehaviour
{
	private static T instance;

	public static T Instance => instance;

	public virtual void Awake()
	{
		if (instance != null && instance != this)
		{
			UnityEngine.Object.Destroy(base.gameObject);
		}
		else if (instance == null)
		{
			instance = this as T;
			UnityEngine.Object.DontDestroyOnLoad(base.gameObject);
		}
	}

	public void AllowSceneDestruction()
	{
		UnityEngine.SceneManagement.SceneManager.MoveGameObjectToScene(base.gameObject, UnityEngine.SceneManagement.SceneManager.GetActiveScene());
	}
}
public class MoveAlongSpline : MonoBehaviour
{
	[Header("Settings")]
	public float speed = 1f;

	[Header("References")]
	public SplineContainer spline;

	private float splinePosition;

	private void Update()
	{
		splinePosition += Time.deltaTime * speed;
		if (splinePosition >= 1f)
		{
			splinePosition = 0f;
		}
		Vector3 position = spline.EvaluatePosition(splinePosition);
		base.transform.position = position;
		base.transform.LookAt(Vector3.zero);
	}
}
