	public static byte CompressFloatToByte(float value, float minValue, float maxValue)
	{
		int num = -128;
		int num2 = 127;
		float t = Mathf.InverseLerp(minValue, maxValue, value);
		return (byte)(sbyte)Mathf.Clamp(Mathf.RoundToInt(Mathf.Lerp(num, num2, t)), num, num2);
	}

	public static short CompressFloatToShort(float value, float minValue, float maxValue)
	{
		int num = -32768;
		int num2 = 32767;
		float t = Mathf.InverseLerp(minValue, maxValue, value);
		return (short)Mathf.Clamp(Mathf.RoundToInt(Mathf.Lerp(num, num2, t)), num, num2);
	}

	public static float DecompressByteToFloat(byte compressedValue, float minValue, float maxValue)
	{
		int num = 127;
		float t = Mathf.InverseLerp(-128f, num, (sbyte)compressedValue);
		return Mathf.Lerp(minValue, maxValue, t);
	}

	public static float DecompressShortToFloat(short compressedValue, float minValue, float maxValue)
	{
		int num = 32767;
		float t = Mathf.InverseLerp(-32768f, num, compressedValue);
		return Mathf.Lerp(minValue, maxValue, t);
	}
}
public class NetworkedInput<T>
{
	public delegate bool HasChangedDelegate(T LastSentValue, T ClientValue);

	public delegate bool ShouldChangeDelegate(T LastSentValue, double lastReceivedTime, T ClientValue);

	public T ClientValue;

	public T ServerValue;

	public T LastSentValue;

	public double LastSentTime;

	public T LastReceivedValue;

	public double LastReceivedTime;

	private HasChangedDelegate HasChangedValidator;

	private ShouldChangeDelegate ShouldChangeValidator;

	public bool HasChanged => HasChangedValidator(LastSentValue, ClientValue);

	public bool ShouldChange => ShouldChangeValidator(LastReceivedValue, LastReceivedTime, ServerValue);

	public NetworkedInput(T initialValue = default(T), HasChangedDelegate hasChangedValidator = null, ShouldChangeDelegate shouldChangeValidator = null)
	{
		ClientValue = initialValue;
		LastSentValue = default(T);
		ServerValue = default(T);
		if (hasChangedValidator != null)
		{
			HasChangedValidator = hasChangedValidator;
		}
		else
		{
			HasChangedValidator = delegate
			{
				ref T clientValue2 = ref ClientValue;
				object obj = LastSentValue;
				return !clientValue2.Equals(obj);
			};
		}
		if (shouldChangeValidator != null)
		{
			ShouldChangeValidator = shouldChangeValidator;
			return;
		}
		ShouldChangeValidator = delegate
		{
			ref T serverValue2 = ref ServerValue;
			object obj = LastReceivedValue;
			return !serverValue2.Equals(obj);
		};
	}

	public void ClientTick()
	{
		LastSentValue = ClientValue;
		LastSentTime = Time.timeAsDouble;
	}

	public void ServerTick()
	{
		LastReceivedValue = ServerValue;
		LastReceivedTime = Time.timeAsDouble;
	}
}
internal class ObservableList<T> : List<T> where T : INotifyPropertyChanged
{
	public delegate void OnAdd(T item);

	public delegate void OnRemove(T item);

	public delegate void OnClear();

	public delegate void OnModify(T item, PropertyChangedEventArgs e);

	public event OnAdd onAdd;

	public event OnRemove onRemove;

	public event OnClear onClear;

	public event OnModify onModify;

	public new void Add(T item)
	{
		base.Add(item);
		this.onAdd?.Invoke(item);
		ref T reference = ref item;
		PropertyChangedEventHandler value = delegate(object sender, PropertyChangedEventArgs e)
		{
			this.onModify?.Invoke(item, e);
		};
		reference.PropertyChanged += value;
	}

	public new void Remove(T item)
	{
		base.Remove(item);
		this.onRemove?.Invoke(item);
	}

	public new void Clear()
	{
		base.Clear();
		this.onClear?.Invoke();
	}
}
public enum DerivativeMeasurement
{
	Velocity,
	ErrorRateOfChange
}
public class PIDController
{
	public float proportionalGain;

	public float integralGain;

	public float integralSaturation = float.MaxValue;

	public float derivativeGain;

	public float derivativeSmoothing = 1f;

	public float outputMin = float.MinValue;

	public float outputMax = float.MaxValue;

	private float errorLast;

	private float valueLast;

	private float integrationStored;

	private float derivativeLast;

	private bool derivativeInitialized;

	public DerivativeMeasurement derivativeMeasurement;

	public PIDController(float proportionalGain = 0f, float integralGain = 0f, float derivativeGain = 0f)
	{
		this.proportionalGain = proportionalGain;
		this.integralGain = integralGain;
		this.derivativeGain = derivativeGain;
	}

	public float Update(float deltaTime, float currentValue, float targetValue)
	{
		if (deltaTime <= 0f)
		{
			return 0f;
		}
		float num = targetValue - currentValue;
		float num2 = (num - errorLast) / deltaTime;
		errorLast = num;
		float num3 = (currentValue - valueLast) / deltaTime;
		valueLast = currentValue;
		float value = integrationStored + num * deltaTime;
		integrationStored = Mathf.Clamp(value, 0f - integralSaturation, integralSaturation);
		float num4 = 0f;
		if (derivativeInitialized)
		{
			num4 = (derivativeLast = Mathf.Lerp(b: (derivativeMeasurement != DerivativeMeasurement.Velocity) ? num2 : (0f - num3), a: derivativeLast, t: derivativeSmoothing));
		}
		else
		{
			derivativeInitialized = true;
			derivativeLast = 0f;
		}
		float num5 = proportionalGain * num;
		float num6 = integralGain * integrationStored;
		float num7 = derivativeGain * num4;
		return Mathf.Clamp(num5 + num6 + num7, outputMin, outputMax);
	}

	public float UpdateAngle(float deltaTime, float currentValue, float targetValue)
	{
		if (deltaTime <= 0f)
		{
			return 0f;
		}
		float num = AngleDifference(targetValue, currentValue);
		float num2 = AngleDifference(num, errorLast) / deltaTime;
		errorLast = num;
		float num3 = AngleDifference(currentValue, valueLast) / deltaTime;
		valueLast = currentValue;
		float value = integrationStored + num * deltaTime;
		integrationStored = Mathf.Clamp(value, 0f - integralSaturation, integralSaturation);
		float num4 = 0f;
		if (derivativeInitialized)
		{
			num4 = (derivativeLast = Mathf.Lerp(b: (derivativeMeasurement != DerivativeMeasurement.Velocity) ? num2 : (0f - num3), a: derivativeLast, t: derivativeSmoothing));
		}
		else
		{
			derivativeInitialized = true;
			derivativeLast = 0f;
		}
		float num5 = proportionalGain * num;
		float num6 = integralGain * integrationStored;
		float num7 = derivativeGain * num4;
		return Mathf.Clamp(num5 + num6 + num7, outputMin, outputMax);
	}

	public void Reset()
	{
		derivativeInitialized = false;
		errorLast = 0f;
		valueLast = 0f;
		integrationStored = 0f;
		derivativeLast = 0f;
	}

	private float AngleDifference(float a, float b)
	{
		return Mathf.DeltaAngle(b, a);
	}
}
public struct ExponentialMovingAverage(int n)
{
	private readonly double alpha = 2.0 / (double)(n + 1);

	private bool initialized = false;

	public double Value = 0.0;

	public double Variance = 0.0;

	public double StandardDeviation = 0.0;

	public void Add(double newValue)
	{
		if (initialized)
		{
			double num = newValue - Value;
			Value += alpha * num;
			Variance = (1.0 - alpha) * (Variance + alpha * num * num);
			StandardDeviation = Math.Sqrt(Variance);
		}
		else
		{
			Value = newValue;
			initialized = true;
		}
	}

	public void Reset()
	{
		initialized = false;
		Value = 0.0;
		Variance = 0.0;
		StandardDeviation = 0.0;
	}
}
