public static class SnapshotInterpolation
{
	public static double Timescale(double drift, double catchupSpeed, double slowdownSpeed, double absoluteCatchupNegativeThreshold, double absoluteCatchupPositiveThreshold)
	{
		if (drift > absoluteCatchupPositiveThreshold)
		{
			return 1.0 + catchupSpeed;
		}
		if (drift < absoluteCatchupNegativeThreshold)
		{
			return 1.0 - slowdownSpeed;
		}
		return 1.0;
	}

	public static double DynamicAdjustment(double sendInterval, double jitterStandardDeviation, double dynamicAdjustmentTolerance)
	{
		return (sendInterval + jitterStandardDeviation) / sendInterval + dynamicAdjustmentTolerance;
	}

	public static bool InsertIfNotExists<T>(SortedList<double, T> buffer, int bufferLimit, T snapshot) where T : Snapshot
	{
		if (buffer.Count >= bufferLimit)
		{
			return false;
		}
		int count = buffer.Count;
		buffer[snapshot.remoteTime] = snapshot;
		return buffer.Count > count;
	}

	public static double TimelineClamp(double localTimeline, double bufferTime, double latestRemoteTime)
	{
		double num = latestRemoteTime - bufferTime;
		double min = num - bufferTime;
		double max = num + bufferTime;
		return Math.Clamp(localTimeline, min, max);
	}

	public static void InsertAndAdjust<T>(SortedList<double, T> buffer, int bufferLimit, T snapshot, ref double localTimeline, ref double localTimescale, float sendInterval, double bufferTime, double catchupSpeed, double slowdownSpeed, ref ExponentialMovingAverage driftEma, float catchupNegativeThreshold, float catchupPositiveThreshold, ref ExponentialMovingAverage deliveryTimeEma) where T : Snapshot
	{
		if (buffer.Count == 0)
		{
			localTimeline = snapshot.remoteTime - bufferTime;
		}
		if (InsertIfNotExists(buffer, bufferLimit, snapshot))
		{
			if (buffer.Count >= 2)
			{
				double localTime = buffer.Values[buffer.Count - 2].localTime;
				double newValue = buffer.Values[buffer.Count - 1].localTime - localTime;
				deliveryTimeEma.Add(newValue);
			}
			double remoteTime = snapshot.remoteTime;
			localTimeline = TimelineClamp(localTimeline, bufferTime, remoteTime);
			double newValue2 = remoteTime - localTimeline;
			driftEma.Add(newValue2);
			double drift = driftEma.Value - bufferTime;
			double absoluteCatchupNegativeThreshold = sendInterval * catchupNegativeThreshold;
			double absoluteCatchupPositiveThreshold = sendInterval * catchupPositiveThreshold;
			localTimescale = Timescale(drift, catchupSpeed, slowdownSpeed, absoluteCatchupNegativeThreshold, absoluteCatchupPositiveThreshold);
		}
	}

	public static void Sample<T>(SortedList<double, T> buffer, double localTimeline, out int from, out int to, out double t) where T : Snapshot
	{
		from = -1;
		to = -1;
		t = 0.0;
		for (int i = 0; i < buffer.Count - 1; i++)
		{
			T val = buffer.Values[i];
			T val2 = buffer.Values[i + 1];
			if (localTimeline >= val.remoteTime && localTimeline <= val2.remoteTime)
			{
				from = i;
				to = i + 1;
				t = Mathf.InverseLerp((float)val.remoteTime, (float)val2.remoteTime, (float)localTimeline);
				return;
			}
		}
		if (buffer.Values[0].remoteTime > localTimeline)
		{
			from = (to = 0);
			t = 0.0;
		}
		else
		{
			from = (to = buffer.Count - 1);
			t = 0.0;
		}
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	public static void StepTime(double deltaTime, ref double localTimeline, double localTimescale)
	{
		localTimeline += deltaTime * localTimescale;
	}

	public static void StepInterpolation<T>(SortedList<double, T> buffer, double localTimeline, out T fromSnapshot, out T toSnapshot, out double t) where T : Snapshot
	{
		Sample(buffer, localTimeline, out var from, out var to, out t);
		fromSnapshot = buffer.Values[from];
		toSnapshot = buffer.Values[to];
		buffer.RemoveRange(from);
	}

	public static void Step<T>(SortedList<double, T> buffer, double deltaTime, ref double localTimeline, double localTimescale, out T fromSnapshot, out T toSnapshot, out double t) where T : Snapshot
	{
		StepTime(deltaTime, ref localTimeline, localTimescale);
		StepInterpolation(buffer, localTimeline, out fromSnapshot, out toSnapshot, out t);
	}
}
[Serializable]
public class SnapshotInterpolationSettings
{
	[Header("Buffering")]
	[Tooltip("Local simulation is behind by sendInterval * multiplier seconds.\n\nThis guarantees that we always have enough snapshots in the buffer to mitigate lags & jitter.\n\nIncrease this if the simulation isn't smooth. By default, it should be around 2.")]
	public double bufferTimeMultiplier = 2.0;

	[Tooltip("If a client can't process snapshots fast enough, don't store too many.")]
	public int bufferLimit = 32;

	[Header("Catchup / Slowdown")]
	[Tooltip("Slowdown begins when the local timeline is moving too fast towards remote time. Threshold is in frames worth of snapshots.\n\nThis needs to be negative.\n\nDon't modify unless you know what you are doing.")]
	public float catchupNegativeThreshold = -1f;

	[Tooltip("Catchup begins when the local timeline is moving too slow and getting too far away from remote time. Threshold is in frames worth of snapshots.\n\nThis needs to be positive.\n\nDon't modify unless you know what you are doing.")]
	public float catchupPositiveThreshold = 1f;

	[Tooltip("Local timeline acceleration in % while catching up.")]
	[Range(0f, 1f)]
	public double catchupSpeed = 0.019999999552965164;

	[Tooltip("Local timeline slowdown in % while slowing down.")]
	[Range(0f, 1f)]
	public double slowdownSpeed = 0.03999999910593033;

	[Tooltip("Catchup/Slowdown is adjusted over n-second exponential moving average.")]
	public int driftEmaDuration = 1;

	[Header("Dynamic Adjustment")]
	[Tooltip("Automatically adjust bufferTimeMultiplier for smooth results.\nSets a low multiplier on stable connections, and a high multiplier on jittery connections.")]
	public bool dynamicAdjustment = true;

	[Tooltip("Safety buffer that is always added to the dynamic bufferTimeMultiplier adjustment.")]
	public float dynamicAdjustmentTolerance = 1f;

	[Tooltip("Dynamic adjustment is computed over n-second exponential moving average standard deviation.")]
	public int deliveryTimeEmaDuration = 2;
}
public static class StringUtils
{
	private static readonly Logger Logger;

	private static Regex profanityRegex;

	static StringUtils()
	{
		Logger = new Logger("StringUtils");
		LoadProfanityWords();
	}

	private static void LoadProfanityWords()
	{
		try
		{
			string[] array = JsonSerializer.Deserialize<string[]>(UnityEngine.Resources.Load<TextAsset>("profanity_words").text);
			string[] value = (from w in array
				where !string.IsNullOrWhiteSpace(w)
				orderby w.Length descending
				select Regex.Escape(w)).ToArray();
			profanityRegex = new Regex("(?<![a-zA-Z])(" + string.Join("|", value) + ")(?![a-zA-Z])", RegexOptions.IgnoreCase | RegexOptions.Compiled);
			Logger.Info($"Loaded {array.Length} profanity words and compiled regex");
		}
		catch (Exception ex)
		{
			Logger.Error("Error loading profanity words asset: " + ex.Message);
		}
	}

	public static string FilterStringNotLetters(string text)
	{
		if (string.IsNullOrEmpty(text))
		{
			return text;
		}
		StringBuilder stringBuilder = new StringBuilder(text.Length);
		foreach (char c in text)
		{
			if (char.IsLetter(c))
			{
				stringBuilder.Append(c);
			}
		}
		return stringBuilder.ToString();
	}

	public static string FilterStringSpecialCharacters(string text, string[] characterWhitelist = null, string[] characterBlacklist = null)
	{
		if (string.IsNullOrEmpty(text))
		{
			return text;
		}
		StringBuilder stringBuilder = new StringBuilder(text.Length);
		TextElementEnumerator textElementEnumerator = StringInfo.GetTextElementEnumerator(text);
		while (textElementEnumerator.MoveNext())
		{
			string textElement = textElementEnumerator.GetTextElement();
			if (characterBlacklist == null || !Enumerable.Contains(characterBlacklist, textElement))
			{
				UnicodeCategory unicodeCategory = CharUnicodeInfo.GetUnicodeCategory(textElement, 0);
				if (textElement.All(char.IsLetterOrDigit) || textElement.All(char.IsWhiteSpace) || unicodeCategory == UnicodeCategory.ConnectorPunctuation || unicodeCategory == UnicodeCategory.DashPunctuation || unicodeCategory == UnicodeCategory.OpenPunctuation || unicodeCategory == UnicodeCategory.ClosePunctuation || unicodeCategory == UnicodeCategory.InitialQuotePunctuation || unicodeCategory == UnicodeCategory.FinalQuotePunctuation || unicodeCategory == UnicodeCategory.OtherPunctuation || unicodeCategory == UnicodeCategory.MathSymbol || unicodeCategory == UnicodeCategory.CurrencySymbol || (characterWhitelist != null && Enumerable.Contains(characterWhitelist, textElement)))
				{
					stringBuilder.Append(textElement);
				}
			}
		}
		return stringBuilder.ToString();
	}

	public static string FilterStringProfanity(string text, bool replaceWithStars = false)
	{
		if (string.IsNullOrEmpty(text))
		{
			return text;
		}
		if (profanityRegex == null)
		{
			return text;
		}
		string text2 = ((!replaceWithStars) ? profanityRegex.Replace(text, string.Empty) : profanityRegex.Replace(text, (Match match) => new string('*', match.Length)));
		if (!replaceWithStars)
		{
			text2 = Regex.Replace(text2, "\\s+", " ").Trim();
		}
		return text2;
	}

	public static string FilterStringRichText(string text)
	{
		if (string.IsNullOrEmpty(text))
		{
			return text;
		}
		string[] richTextTags = new string[37]
		{
			"a", "align", "allcaps", "alpha", "b", "br", "color", "cspace", "font", "font-weight",
			"gradient", "i", "indent", "line-height", "line-indent", "link", "lowercase", "margin", "margin-left", "margin-right",
			"mark", "mspace", "nobr", "noparse", "pos", "s", "size", "smallcaps", "space", "sprite",
			"style", "sub", "sup", "u", "uppercase", "voffset", "width"
		};
		string pattern = "</?(#[0-9a-fA-F]*|\\w+(?:-\\w+)?)(?:[\\s=][^>]*)?>";
		MatchEvaluator evaluator = delegate(Match match)
		{
			string text4 = match.Groups[1].Value.ToLower();
			if (text4.StartsWith("#"))
			{
				return string.Empty;
			}
			return Enumerable.Contains(richTextTags, text4) ? string.Empty : match.Value;
		};
		string text2 = text;
		string text3;
		do
		{
			text3 = text2;
			text2 = Regex.Replace(text3, pattern, evaluator, RegexOptions.IgnoreCase);
		}
		while (text2 != text3);
		return text2;
	}

	public static string WrapInColor(string text, string color)
	{
		if (string.IsNullOrEmpty(color))
		{
			return text;
		}
		return "<color=" + color + ">" + text + "</color>";
	}

	public static List<string> ChunkLinesByByteBudget(IReadOnlyList<string> lines, int maxBytes)
	{
		List<string> list = new List<string>();
		StringBuilder stringBuilder = new StringBuilder();
		int num = 0;
		foreach (string line in lines)
		{
			int byteCount = Encoding.UTF8.GetByteCount(line);
			int num2 = ((stringBuilder.Length > 0) ? 1 : 0);
			if (stringBuilder.Length > 0 && num + num2 + byteCount > maxBytes)
			{
				list.Add(stringBuilder.ToString());
				stringBuilder.Clear();
				num = 0;
			}
			if (stringBuilder.Length > 0)
			{
				stringBuilder.Append('\n');
				num++;
			}
			stringBuilder.Append(line);
			num += byteCount;
		}
		if (stringBuilder.Length > 0)
		{
			list.Add(stringBuilder.ToString());
		}
		return list;
	}

	public static string WrapInTeamColor(string text, PlayerTeam team)
	{
		string text2 = team switch
		{
			PlayerTeam.Blue => "#3b82f6", 
			PlayerTeam.Red => "#d13333", 
			_ => "#404040", 
		};
		if (text2 == null)
		{
			return text;
		}
		return "<color=" + text2 + ">" + text + "</color>";
	}
}
public class SynchronizedObjectSnapshot
{
	public SynchronizedObject SynchronizedObject;

	public Vector3 Position;

	public Quaternion Rotation;

	public Vector3 LinearVelocity;

	public Vector3 AngularVelocity;
}
public struct SynchronizedObjectsSnapshot : Snapshot
{
	public double remoteTime { get; set; }

	public double localTime { get; set; }

	public List<SynchronizedObjectSnapshot> snapshots { get; set; }

	public SynchronizedObjectsSnapshot(double remoteTime, double localTime, List<SynchronizedObjectSnapshot> snapshots)
	{
		this.remoteTime = remoteTime;
		this.localTime = localTime;
		this.snapshots = snapshots;
	}

	public static void Interpolate(SynchronizedObjectsSnapshot from, SynchronizedObjectsSnapshot to, double t)
	{
		for (int i = 0; i < to.snapshots.Count; i++)
		{
			SynchronizedObjectSnapshot synchronizedObjectSnapshot = to.snapshots[i];
			SynchronizedObjectSnapshot synchronizedObjectSnapshot2 = null;
			if (i < from.snapshots.Count && from.snapshots[i].SynchronizedObject == synchronizedObjectSnapshot.SynchronizedObject)
			{
				synchronizedObjectSnapshot2 = from.snapshots[i];
			}
			else
			{
				for (int j = 0; j < from.snapshots.Count; j++)
				{
					if (from.snapshots[j].SynchronizedObject == synchronizedObjectSnapshot.SynchronizedObject)
					{
						synchronizedObjectSnapshot2 = from.snapshots[j];
						break;
					}
				}
			}
			if ((synchronizedObjectSnapshot2 != null && !(synchronizedObjectSnapshot2.SynchronizedObject == null)) || (synchronizedObjectSnapshot != null && !(synchronizedObjectSnapshot.SynchronizedObject == null)))
			{
				if (synchronizedObjectSnapshot2 == null || synchronizedObjectSnapshot2.SynchronizedObject == null)
				{
					synchronizedObjectSnapshot.SynchronizedObject.transform.position = synchronizedObjectSnapshot.Position;
					synchronizedObjectSnapshot.SynchronizedObject.transform.rotation = synchronizedObjectSnapshot.Rotation;
					synchronizedObjectSnapshot.SynchronizedObject.PredictedLinearVelocity = synchronizedObjectSnapshot.LinearVelocity;
					synchronizedObjectSnapshot.SynchronizedObject.PredictedAngularVelocity = synchronizedObjectSnapshot.AngularVelocity;
				}
				else if (synchronizedObjectSnapshot == null || synchronizedObjectSnapshot.SynchronizedObject == null)
				{
					synchronizedObjectSnapshot2.SynchronizedObject.transform.position = synchronizedObjectSnapshot.Position;
					synchronizedObjectSnapshot2.SynchronizedObject.transform.rotation = synchronizedObjectSnapshot.Rotation;
					synchronizedObjectSnapshot2.SynchronizedObject.PredictedLinearVelocity = synchronizedObjectSnapshot.LinearVelocity;
					synchronizedObjectSnapshot2.SynchronizedObject.PredictedAngularVelocity = synchronizedObjectSnapshot.AngularVelocity;
				}
				else
				{
					synchronizedObjectSnapshot.SynchronizedObject.transform.position = Vector3.LerpUnclamped(synchronizedObjectSnapshot2.Position, synchronizedObjectSnapshot.Position, (float)t);
					synchronizedObjectSnapshot.SynchronizedObject.transform.rotation = Quaternion.SlerpUnclamped(synchronizedObjectSnapshot2.Rotation, synchronizedObjectSnapshot.Rotation, (float)t);
					synchronizedObjectSnapshot.SynchronizedObject.PredictedLinearVelocity = Vector3.LerpUnclamped(synchronizedObjectSnapshot2.LinearVelocity, synchronizedObjectSnapshot.LinearVelocity, (float)t);
					synchronizedObjectSnapshot.SynchronizedObject.PredictedAngularVelocity = Vector3.LerpUnclamped(synchronizedObjectSnapshot2.AngularVelocity, synchronizedObjectSnapshot.AngularVelocity, (float)t);
				}
			}
		}
	}
}
public class TCPClient
{
	private static readonly Logger Logger = new Logger("TCPClient");

	public SimpleTcpClient Client;

	public EndPoint EndPoint;

	public bool IsConnecting { get; private set; }

	public bool IsConnected => Client.IsConnected;

	public event Action OnConnected;

	public event Action OnConnectionFailed;

	public event Action OnDisconnected;

	public event Action<string> OnMessageReceived;

	public event Action<string> OnMessageSent;

	public TCPClient(EndPoint endPoint, int connectTimeoutMs = 1000, int readTimeoutMs = 1000)
	{
		EndPoint = endPoint;
		Client = new SimpleTcpClient(EndPoint.ipAddress, EndPoint.port);
		Client.Settings.NoDelay = true;
		Client.Settings.UseAsyncDataReceivedEvents = false;
		Client.Settings.ConnectTimeoutMs = connectTimeoutMs;
		Client.Settings.ReadTimeoutMs = readTimeoutMs;
		Client.Events.Connected += delegate
		{
			this.OnConnected?.Invoke();
		};
		Client.Events.Disconnected += delegate
		{
			this.OnDisconnected?.Invoke();
		};
		Client.Events.DataReceived += delegate(object sender, SuperSimpleTcp.DataReceivedEventArgs args)
		{
			OnDataReceived(sender, args);
		};
	}

	public void Connect()
	{
		try
		{
			if (!IsConnecting)
			{
				IsConnecting = true;
				Client.Connect();
				IsConnecting = false;
			}
		}
		catch (TimeoutException)
		{
			IsConnecting = false;
			Logger.Error($"Connection to server {EndPoint} timed out");
			this.OnConnectionFailed?.Invoke();
		}
		catch (Exception ex2)
		{
			IsConnecting = false;
			Logger.Error($"Connection to server {EndPoint} failed: {ex2.Message}");
			this.OnConnectionFailed?.Invoke();
		}
	}

	public void ConnectAsync()
	{
		Task.Run(delegate
		{
			Connect();
		});
	}

	public void Disconnect()
	{
		try
		{
			Client.Disconnect();
		}
		catch (Exception ex)
		{
			Logger.Error("Error disconnecting: " + ex.Message);
		}
	}

	public void DisconnectAsync()
	{
		Task.Run(delegate
		{
			Disconnect();
		});
	}

	public void SendMessage(string message)
	{
		try
		{
			byte[] bytes = Encoding.UTF8.GetBytes(message);
			Client.Send(bytes);
			this.OnMessageSent?.Invoke(message);
		}
		catch (Exception ex)
		{
			Logger.Error($"Error sending message to server {EndPoint}: {ex.Message}");
		}
	}

	public void SendMessageAsync(string message)
	{
		Task.Run(delegate
		{
			SendMessage(message);
		});
	}

	private void OnDataReceived(object sender, SuperSimpleTcp.DataReceivedEventArgs args)
	{
		try
		{
			string obj = Encoding.UTF8.GetString(args.Data);
			this.OnMessageReceived?.Invoke(obj);
		}
		catch (Exception ex)
		{
			Logger.Error($"Error deserializing message from server {EndPoint}: {ex.Message}");
		}
	}
}
public class TCPServer
{
	private static readonly Logger Logger = new Logger("TCPServer");

	public SimpleTcpServer Server;

	public event Action<ushort> OnServerStarted;

	public event Action<Exception> OnServerStartFailed;

	public event Action<ushort> OnServerStopped;

	public event Action<string> OnClientConnected;

	public event Action<string> OnClientDisconnected;

	public event Action<string, string> OnMessageReceived;

	public event Action<string, string> OnMessageSent;

	public TCPServer(ushort port)
	{
		Server = new SimpleTcpServer("0.0.0.0", port);
		Server.Settings.IdleClientTimeoutMs = 1000;
		Server.Settings.NoDelay = true;
		Server.Settings.UseAsyncDataReceivedEvents = false;
		Server.Events.ClientConnected += delegate(object sender, ConnectionEventArgs args)
		{
			this.OnClientConnected?.Invoke(args.IpPort);
		};
		Server.Events.ClientDisconnected += delegate(object sender, ConnectionEventArgs args)
		{
			this.OnClientDisconnected?.Invoke(args.IpPort);
		};
		Server.Events.DataReceived += delegate(object sender, SuperSimpleTcp.DataReceivedEventArgs args)
		{
			OnDataReceived(sender, args);
		};
	}

	public void Start()
	{
		try
		{
			if (!Server.IsListening)
			{
				Server.Start();
				Logger.Info(string.Format("Started TCP listener on {0}:{1}", "0.0.0.0", Server.Port));
				this.OnServerStarted?.Invoke((ushort)Server.Port);
			}
		}
		catch (Exception ex)
		{
			Logger.Error($"Server start failed on port {Server.Port}: {ex.Message}");
			this.OnServerStartFailed?.Invoke(ex);
		}
	}

	public void StartAsync()
	{
		Task.Run(delegate
		{
			Start();
		});
	}

	public void Stop()
	{
		Server.Stop();
		Logger.Info($"Server stopped on port {Server.Port}");
		this.OnServerStopped?.Invoke((ushort)Server.Port);
	}

	public void StopAsync()
	{
		Task.Run(delegate
		{
			Stop();
		});
	}

	public void SendMessage(string ipPort, string message)
	{
		try
		{
			byte[] bytes = Encoding.UTF8.GetBytes(message);
			Server.Send(ipPort, bytes);
			this.OnMessageSent?.Invoke(ipPort, message);
		}
		catch (Exception ex)
		{
			Logger.Error("Error sending message to client " + ipPort + ": " + ex.Message);
		}
	}

	public void SendMessageAsync(string ipPort, string message)
	{
		Task.Run(delegate
		{
			SendMessage(ipPort, message);
		});
	}

	public void DisconnectClient(string ipPort)
	{
		try
		{
			Server.DisconnectClient(ipPort);
		}
		catch (Exception ex)
		{
			Logger.Error("Error disconnecting client " + ipPort + ": " + ex.Message);
		}
	}

	private void OnDataReceived(object sender, SuperSimpleTcp.DataReceivedEventArgs args)
	{
		try
		{
			string arg = Encoding.UTF8.GetString(args.Data);
			this.OnMessageReceived?.Invoke(args.IpPort, arg);
		}
		catch (Exception ex)
		{
			Logger.Error("Error deserializing message from client " + args.IpPort + ": " + ex.Message);
		}
	}
}
public static class TerminalUtils
{
	public static readonly bool SupportsAnsiColor = DetectAnsiSupport();

	private static readonly Regex AnsiColorRegex = new Regex("\\x1b\\[[0-9;]*m", RegexOptions.Compiled);

	private static readonly Regex RichTextColorRegex = new Regex("</?color(=[^>]*)?>", RegexOptions.Compiled);

	private static readonly Logger Log = new Logger("TerminalUtils");

	private const int STD_OUTPUT_HANDLE = -11;

	private const uint ENABLE_VIRTUAL_TERMINAL_PROCESSING = 4u;

	private const uint CP_UTF8 = 65001u;

	public static void TryEnableUtf8Output()
	{
		if (!IsWindowsPlatform())
		{
			return;
		}
		try
		{
			uint consoleOutputCP = GetConsoleOutputCP();
			if (consoleOutputCP != 65001)
			{
				if (SetConsoleOutputCP(65001u))
				{
					Log.Info($"Set console output code page to UTF-8 (was {consoleOutputCP})");
				}
				else
				{
					Log.Warning($"SetConsoleOutputCP(UTF-8) failed (code page stays {consoleOutputCP})");
				}
			}
		}
		catch (Exception ex)
		{
			Log.Warning("Failed to set UTF-8 console output: " + ex.GetType().Name + ": " + ex.Message);
		}
	}

	private static bool IsWindowsPlatform()
	{
		RuntimePlatform platform = Application.platform;
		if (platform == RuntimePlatform.WindowsPlayer || platform == RuntimePlatform.WindowsEditor || platform == RuntimePlatform.WindowsServer)
		{
			return true;
		}
		return false;
	}

	public static string StripColors(string input)
	{
		if (string.IsNullOrEmpty(input))
		{
			return input;
		}
		return RichTextColorRegex.Replace(AnsiColorRegex.Replace(input, string.Empty), string.Empty);
	}

	private static bool DetectAnsiSupport()
	{
		try
		{
			string value = Utils.GetCommandLineArgument("--logColor") ?? Environment.GetEnvironmentVariable("PUCK_LOG_COLOR");
			if (!string.IsNullOrEmpty(value))
			{
				return !IsFalsey(value);
			}
			if (Environment.GetEnvironmentVariable("NO_COLOR") != null)
			{
				return false;
			}
			if (IsPipeBasedColorTerminal())
			{
				TryEnableWindowsVirtualTerminal();
				return true;
			}
			if (Console.IsOutputRedirected)
			{
				return false;
			}
			RuntimePlatform platform = Application.platform;
			if (platform == RuntimePlatform.WindowsPlayer || platform == RuntimePlatform.WindowsEditor || platform == RuntimePlatform.WindowsServer)
			{
				return TryEnableWindowsVirtualTerminal();
			}
			string environmentVariable = Environment.GetEnvironmentVariable("TERM");
			return !string.IsNullOrEmpty(environmentVariable) && environmentVariable != "dumb";
		}
		catch
		{
			return false;
		}
	}

	private static bool IsPipeBasedColorTerminal()
	{
		if (!string.IsNullOrEmpty(Environment.GetEnvironmentVariable("MSYSTEM")))
		{
			return true;
		}
		if (string.Equals(Environment.GetEnvironmentVariable("ConEmuANSI"), "ON", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		return false;
	}

	private static bool IsFalsey(string value)
	{
		string text = value.Trim().ToLowerInvariant();
		if (!(text == "0"))
		{
			return text == "false";
		}
		return true;
	}

	[DllImport("kernel32.dll", SetLastError = true)]
	private static extern uint GetConsoleOutputCP();

	[DllImport("kernel32.dll", SetLastError = true)]
	private static extern bool SetConsoleOutputCP(uint wCodePageID);

	[DllImport("kernel32.dll", SetLastError = true)]
	private static extern IntPtr GetStdHandle(int nStdHandle);

	[DllImport("kernel32.dll", SetLastError = true)]
	private static extern bool GetConsoleMode(IntPtr hConsoleHandle, out uint lpMode);

	[DllImport("kernel32.dll", SetLastError = true)]
	private static extern bool SetConsoleMode(IntPtr hConsoleHandle, uint dwMode);

	private static bool TryEnableWindowsVirtualTerminal()
	{
		IntPtr stdHandle = GetStdHandle(-11);
		if (stdHandle == IntPtr.Zero || stdHandle == new IntPtr(-1))
		{
			return false;
		}
		if (!GetConsoleMode(stdHandle, out var lpMode))
		{
			return false;
		}
		if ((lpMode & 4) != 0)
		{
			return true;
		}
		return SetConsoleMode(stdHandle, lpMode | 4);
	}
}
public static class TweenUtils
{
	public static Sequence RampHoldRamp(float rest, float depth, float rampInSeconds, float holdSeconds, float rampOutSeconds, Ease rampInEase, Ease rampOutEase, TweenCallback<float> onValue)
	{
		return RampHoldRamp(rest, depth, rest, rampInSeconds, holdSeconds, rampOutSeconds, rampInEase, rampOutEase, onValue);
	}

	public static Sequence RampHoldRamp(float from, float depth, float to, float rampInSeconds, float holdSeconds, float rampOutSeconds, Ease rampInEase, Ease rampOutEase, TweenCallback<float> onValue)
	{
		Sequence sequence = DOTween.Sequence().SetUpdate(isIndependentUpdate: true);
		sequence.Append(DOVirtual.Float(from, depth, rampInSeconds, onValue).SetEase(rampInEase));
		sequence.AppendInterval(holdSeconds);
		sequence.Append(DOVirtual.Float(depth, to, rampOutSeconds, onValue).SetEase(rampOutEase));
		return sequence;
	}
}
public static class UIUtils
{
	public static void SetTeamClass(VisualElement element, PlayerTeam team)
	{
		foreach (PlayerTeam value in Enum.GetValues(typeof(PlayerTeam)))
		{
			element.EnableInClassList(GetClassFromTeam(value), enable: false);
		}
		element.EnableInClassList(GetClassFromTeam(team), enable: true);
	}

	public static string GetClassFromTeam(PlayerTeam team)
	{
		return "team" + team;
	}

	public static List<VisualElement> GetVisualElementChildren(VisualElement element, bool recursive = false)
	{
		if (recursive)
		{
			List<VisualElement> list = new List<VisualElement>();
			{
				foreach (VisualElement item in element.hierarchy.Children())
				{
					list.Add(item);
					list.AddRange(GetVisualElementChildren(item, recursive: true));
				}
				return list;
			}
		}
		return new List<VisualElement>(element.hierarchy.Children());
	}
}
public static class Utils
{
	private static readonly Logger uPnPLogger = new Logger("uPnPHelper");

	public static string GetReadableTypeName(Type type)
	{
		return type.Name.Split('`')[0];
	}

	public static float WrapEulerAngle(float angle)
	{
		angle %= 360f;
		if (angle > 180f)
		{
			angle -= 360f;
		}
		if (angle < -180f)
		{
			angle += 360f;
		}
		return angle;
	}

	public static Vector3 WrapEulerAngles(Vector3 eulerAngles)
	{
		eulerAngles.x %= 360f;
		if (eulerAngles.x > 180f)
		{
			eulerAngles.x -= 360f;
		}
		if (eulerAngles.x < -180f)
		{
			eulerAngles.x += 360f;
		}
		eulerAngles.y %= 360f;
		if (eulerAngles.y > 180f)
		{
			eulerAngles.y -= 360f;
		}
		if (eulerAngles.y < -180f)
		{
			eulerAngles.y += 360f;
		}
		eulerAngles.z %= 360f;
		if (eulerAngles.z > 180f)
		{
			eulerAngles.z -= 360f;
		}
		if (eulerAngles.z < -180f)
		{
			eulerAngles.z += 360f;
		}
		return eulerAngles;
	}

	public static Vector3 RotatePointAroundPivot(Vector3 point, Vector3 pivot, Vector3 angles)
	{
		Vector3 vector = point - pivot;
		vector = Quaternion.Euler(angles) * vector;
		point = vector + pivot;
		return point;
	}

	public static Vector3 Vector2Clamp(Vector2 value, Vector2 min, Vector2 max)
	{
		return new Vector3(Mathf.Clamp(value.x, min.x, max.x), Mathf.Clamp(value.y, min.y, max.y));
	}

	public static Vector3 Vector3Clamp(Vector3 value, Vector3 min, Vector3 max)
	{
		return new Vector3(Mathf.Clamp(value.x, min.x, max.x), Mathf.Clamp(value.y, min.y, max.y), Mathf.Clamp(value.z, min.z, max.z));
	}

	public static Vector3 Vector3Abs(Vector3 value)
	{
		return new Vector3(Mathf.Abs(value.x), Mathf.Abs(value.y), Mathf.Abs(value.z));
	}

	public static Vector3 Vector3Slerp3(Vector3 a, Vector3 b, Vector3 c, float t)
	{
		if (t <= 0f)
		{
			return Vector3.Slerp(a, b, t + 1f);
		}
		return Vector3.Slerp(b, c, t);
	}

	public static float Map(float value, float from1, float to1, float from2, float to2)
	{
		return (value - from1) / (to1 - from1) * (to2 - from2) + from2;
	}

	public static Quaternion GetLocalLookRotation(Transform transform, Vector3 target)
	{
		if (transform.parent == null)
		{
			return Quaternion.LookRotation(target - transform.position);
		}
		Quaternion quaternion2 = Quaternion.LookRotation(target - transform.position);
		return Quaternion.Inverse(transform.parent.rotation) * quaternion2;
	}

