		private void OnHierarchyChanged(HierarchyChangedEvent e)
		{
			List<VisualElement> visibleChildren = GetVisibleChildren();
			SetChildClasses(visibleChildren);
		}

		private void OnChildRenderingToggled(RenderingToggledEvent e)
		{
